-- Questions
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-001',
      'python',
      'What is the difference between a list and a tuple in Python?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Lists are mutable (can be changed) while tuples are immutable (cannot be changed). Tuples are faster, use less memory, and can be used as dictionary keys (because they are hashable). Lists are for homogeneous data, tuples for heterogeneous data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-002',
      'python',
      'Explain the Global Interpreter Lock (GIL).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The GIL is a mutex in CPython that allows only one thread to execute Python bytecode at a time. It exists because CPython memory management is not thread-safe. Implications: CPU-bound multithreaded programs don''t achieve parallelism. I/O-bound programs still benefit from threading. Solution: Use multiprocessing for CPU-bound tasks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-003',
      'python',
      'What are decorators and how do they work?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Decorators are functions that modify the behavior of other functions without changing their source code. They take a function as input and return a wrapper function. They use the @decorator syntax.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-004',
      'python',
      'Explain generators and the yield keyword.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Generators are functions that return an iterator using the yield keyword. They generate values lazily (on demand) rather than computing all values at once. Memory efficient for large datasets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-005',
      'python',
      'What is the difference between deepcopy and shallow copy?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Shallow copy creates a new object but references the same nested objects. Deep copy creates a new object and recursively copies all nested objects.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-006',
      'python',
      'What are *args and **kwargs?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '*args collects positional arguments into a tuple. **kwargs collects keyword arguments into a dictionary. Allows variable numbers of arguments.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-007',
      'python',
      'Explain Python''s Method Resolution Order (MRO).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'MRO defines the order in which base classes are searched when looking up a method. Python uses the C3 linearization algorithm to ensure parents are searched after children and in the order defined.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-008',
      'python',
      'What are context managers?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Context managers handle setup and teardown of resources automatically using the `with` statement. Implement `__enter__` and `__exit__` methods.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-009',
      'python',
      'Difference between __str__ and __repr__?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '__repr__ is for developers (unambiguous, code-like). __str__ is for end users (readable). If __str__ is missing, falls back to __repr__.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-010',
      'python',
      'What are metaclasses?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Metaclasses are classes of classes. They define how classes behave. `type` is the default metaclass. They intercept class creation via `__new__` and `__init__`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-011',
      'python',
      'How does Python memory management work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Uses reference counting as primary mechanism. When count drops to 0, memory is freed. Also has a generational garbage collector to handle cyclic references.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-012',
      'python',
      'List comprehensions vs generator expressions?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'List comprehensions `[x for x in data]` compute all values in memory. Generator expressions `(x for x in data)` compute lazily, saving memory.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-013',
      'python',
      'What is duck typing?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"If it walks like a duck and quacks like a duck, it is a duck." Python determines type by behavior/methods, not explicit inheritance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-014',
      'python',
      'is vs == ?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`==` checks for value equality. `is` checks for object identity (same memory address). Use `is` for None.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-015',
      'python',
      'Explain asyncio and async/await.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Single-threaded cooperative multitasking. `async def` defines a coroutine. `await` yields control back to the event loop until the awaited I/O operation completes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-016',
      'python',
      'What are dataclasses?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Auto-generates boilerplate like `__init__`, `__repr__`, `__eq__` for data-heavy classes. Introduced in 3.7.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-017',
      'python',
      'What are descriptors?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Objects that define `__get__`, `__set__`, or `__delete__`. They power properties, classmethods, and slots.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-018',
      'python',
      'staticmethod vs classmethod?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`@classmethod` receives the class (`cls`) as first arg, used for factories. `@staticmethod` receives neither class nor instance, used for utility functions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-019',
      'python',
      'What is the walrus operator (:=)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Assignment expression (3.8+). Assigns a value to a variable within a larger expression. Great for while loops and list comprehensions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-020',
      'python',
      'What is monkey patching?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Dynamically modifying a class or module at runtime. Often used for mocking in tests.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-021',
      'python',
      'What are __slots__?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Replaces the dynamic `__dict__` attribute dictionary with a fixed set of attributes, significantly reducing memory per instance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-022',
      'python',
      'Process vs Thread vs Coroutine in Python?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Process: multi-core, high overhead. Thread: single-core (GIL), medium overhead, preemptive. Coroutine: single-core, low overhead, cooperative.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-023',
      'python',
      'Purpose of __init__.py?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Marks a directory as a Python package. Can execute initialization code or restrict wildcard imports using `__all__`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-024',
      'python',
      'How do type hints work?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Optional static typing (PEP 484). Not enforced at runtime. Checked via tools like mypy to catch bugs early.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-025',
      'python',
      'What is monkey patching?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Dynamic modifications of a class or module at runtime. Used for testing/mocking.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-026',
      'python',
      'Explain virtual environments.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Isolated spaces for project dependencies to avoid version conflicts between projects. Created via `venv` or `virtualenv`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-027',
      'python',
      'What are map, filter, and reduce?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`map` applies function to all items. `filter` keeps items where function is true. `reduce` (in functools) cumulatively applies function to reduce sequence to single value.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-028',
      'python',
      'What is PEP 8?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The official style guide for Python code. Specifies indentation (4 spaces), line length (79 chars), naming conventions (snake_case for variables, PascalCase for classes).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-029',
      'python',
      'How to sort a dictionary by value?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use `sorted(d.items(), key=lambda item: item[1])`. Returns a list of tuples, which can be cast back to a dict in Python 3.7+.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-030',
      'python',
      'What is the purpose of the pass statement?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A null operation. Used as a placeholder when a statement is syntactically required but no code needs to be executed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-031',
      'python',
      'Difference between append() and extend()?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`append(x)` adds x as a single element to the end of the list. `extend(iterable)` unpacks the iterable and adds its elements to the list.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-032',
      'python',
      'Explain try, except, else, finally.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`try`: code to execute. `except`: catches exceptions. `else`: runs only if no exception occurred. `finally`: runs no matter what (used for cleanup).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-033',
      'python',
      'What is pickling?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Serialization of Python objects to a byte stream via the `pickle` module. Unpickling is deserialization. Warning: do not unpickle untrusted data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-034',
      'python',
      'How do you handle missing dictionary keys?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Using `d.get(key, default)`, `d.setdefault(key, default)`, or `collections.defaultdict`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-035',
      'python',
      'What are lambda functions?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Small anonymous functions defined with the `lambda` keyword. Can take any number of args but contain only one expression.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-036',
      'python',
      'What is the yield from keyword?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Introduced in 3.3. Allows a generator to delegate part of its operations to another generator. Flattens nested generators easily.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-037',
      'python',
      'What are f-strings?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Formatted string literals (`f"..."`). Introduced in 3.6. Evaluate expressions at runtime and are faster than `%` or `.format()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-038',
      'python',
      'Explain the single underscore prefix (_var).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A convention indicating an attribute is intended for internal use (protected). Does not enforce access control.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-039',
      'python',
      'Explain the double underscore prefix (__var).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Triggers name mangling to prevent accidental overriding in subclasses. `__var` in class `Foo` becomes `_Foo__var`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-040',
      'python',
      'What is multiple inheritance?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A class inheriting from more than one base class. Python supports this. Method resolution follows MRO (C3 Linearization).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-041',
      'python',
      'What is a lambda closure?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Lambdas capture variables by reference, not value. If created in a loop, they all refer to the last value of the loop variable. Fix: `lambda x=i: x`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-042',
      'python',
      'What is string interning?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Python caches short strings and identifiers to save memory. `a = "sys"; b = "sys"; a is b` is True.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-043',
      'python',
      'Difference between local and global variables?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Local: defined inside a function, accessible only there. Global: defined outside, accessible everywhere. Use `global` keyword to modify global inside a function.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-044',
      'python',
      'What is the nonlocal keyword?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Allows a nested function to modify a variable in the outer (enclosing) function''s scope, without making it global.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-045',
      'python',
      'Explain memory leaks in Python.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Often caused by global lists/dicts growing indefinitely, cyclic references with custom `__del__` methods (in older Python), or unclosed file/network resources.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-046',
      'python',
      'What is the property decorator?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`@property` makes a method accessible like an attribute. Used for getters. `@name.setter` creates the setter.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-047',
      'python',
      'How to manage dependency versions?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using `requirements.txt` (`pip freeze > requirements.txt`), `Pipfile` (pipenv), or `pyproject.toml` (poetry).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-048',
      'python',
      'What are magic methods (dunder methods)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Methods with double underscores (e.g., `__init__`, `__len__`, `__add__`). They implement operator overloading and built-in behaviors.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-049',
      'python',
      'What is typing.Protocol?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Introduced in 3.8. Defines structural subtyping (static duck typing). Classes don''t need to explicitly inherit from it to satisfy the type checker.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'py-050',
      'python',
      'How does the set type work internally?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Implemented as a hash table (similar to dict but without values). Offers O(1) average time complexity for insertions, deletions, and lookups.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-001',
      'java',
      'What is the difference between JDK, JRE, and JVM?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'JVM (Java Virtual Machine): Executes bytecode. Platform-dependent. Handles memory management and GC. JRE (Java Runtime Environment): JVM + standard class libraries. Used to run Java. JDK (Java Development Kit): JRE + development tools (javac, debugger). Used to develop Java.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-002',
      'java',
      'Explain abstract class vs interface.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Abstract class: Can have state (instance variables), constructors, and concrete methods. Single inheritance. Interface: Multiple inheritance. Variables are implicitly public static final. Methods are implicitly public abstract (except default/static in Java 8+). Use abstract for "is-a", interface for "can-do".',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-003',
      'java',
      'How does Java Garbage Collection work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'GC reclaims memory from unreachable objects. Heap is divided into: Young Gen (Eden, Survivor S0/S1) and Old Gen. Minor GC collects Young Gen. Objects surviving multiple Minor GCs move to Old Gen. Major GC collects Old Gen. Algorithms include G1 GC, ZGC, and Shenandoah.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-004',
      'java',
      'HashMap vs ConcurrentHashMap?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'HashMap is not thread-safe. ConcurrentHashMap is thread-safe without full locking, using node-level locking (CAS) for high concurrency. ConcurrentHashMap does not allow null keys or values.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-005',
      'java',
      'Explain Java Streams.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Functional approach to process collections. Operations are Intermediate (lazy: filter, map) or Terminal (triggers execution: collect, forEach). Streams are single-use. Support parallel execution via `parallelStream()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-006',
      'java',
      'What are the SOLID principles?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Single Responsibility, Open/Closed, Liskov Substitution, Interface Segregation, Dependency Inversion. They guide maintainable, loosely coupled object-oriented design.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-007',
      'java',
      'What is the volatile keyword?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Ensures visibility and ordering. Changes to a volatile variable are immediately visible to all threads (reads from main memory, not thread cache). Does NOT provide atomicity (e.g., for i++).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-008',
      'java',
      'What are functional interfaces?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Interfaces with exactly one abstract method. Annotated with `@FunctionalInterface`. Enable lambda expressions. Examples: Predicate, Function, Consumer, Supplier.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-009',
      'java',
      'String vs StringBuilder vs StringBuffer?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'String is immutable (stored in String Pool). StringBuilder is mutable and not thread-safe (fast). StringBuffer is mutable and thread-safe (synchronized, slower).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-010',
      'java',
      'Checked vs Unchecked exceptions?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Checked: Enforced by compiler (extend Exception). Unchecked: Not enforced (extend RuntimeException, e.g., NullPointerException). Errors indicate severe JVM problems (e.g., OutOfMemoryError).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-011',
      'java',
      '== vs equals()?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`==` compares memory references (or primitive values). `equals()` compares object content (if overridden). Always override `hashCode()` when overriding `equals()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-012',
      'java',
      'Explain Java Generics and Type Erasure.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Generics provide compile-time type safety. Type erasure removes generic type info during compilation, so `List<String>` and `List<Integer>` become just `List` at runtime. Prevents generic arrays.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-013',
      'java',
      'What is CompletableFuture?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Java 8+ construct for async programming. Allows chaining operations (`thenApply`, `thenCompose`), combining futures, and handling exceptions asynchronously without blocking.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-014',
      'java',
      'Explain final, finally, and finalize().',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`final`: constant variable, non-overridable method, or non-inheritable class. `finally`: block executed after try/except regardless of exception. `finalize()`: deprecated method called by GC before object destruction.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-015',
      'java',
      'What is the String Pool?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A special memory region in the Heap. String literals are stored here to save memory (interning). `new String("x")` creates a new object outside the pool.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-016',
      'java',
      'What is ClassNotFoundException vs NoClassDefFoundError?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '`ClassNotFoundException`: occurs when trying to load a class dynamically at runtime using `Class.forName()`. `NoClassDefFoundError`: class was present at compile time but missing at runtime.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-017',
      'java',
      'Explain fail-fast vs fail-safe iterators.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Fail-fast: throw `ConcurrentModificationException` if collection is modified while iterating (e.g., ArrayList). Fail-safe: iterate over a clone, no exception thrown (e.g., ConcurrentHashMap).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-018',
      'java',
      'How does ThreadLocal work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Provides thread-local variables. Each thread accessing the variable gets its own independent copy. Often used for thread-safety of objects like SimpleDateFormat, or storing user context in web servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-019',
      'java',
      'What is the difference between wait() and sleep()?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`wait()`: defined in Object, releases the monitor lock, must be called in synchronized block. `sleep()`: defined in Thread, does NOT release the lock.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-020',
      'java',
      'What is the Executor framework?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Abstracts thread management. `ExecutorService` manages thread pools (e.g., FixedThreadPool, CachedThreadPool). Better than manually creating Threads.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-021',
      'java',
      'Difference between Array and ArrayList?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Array is fixed-size, can hold primitives. ArrayList is dynamically resizable, part of Collections framework, holds only Objects (primitives are autoboxed).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-022',
      'java',
      'What is the purpose of hashCode()?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Returns an integer representing the object. Used in hash-based collections (HashMap, HashSet) to determine the bucket index for fast lookups.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-023',
      'java',
      'Explain Diamond Problem in multiple inheritance.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'If a class inherits from two classes that have a common method, it creates ambiguity. Java avoids this by not allowing multiple class inheritance. With default methods in interfaces, collision is resolved by overriding.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-024',
      'java',
      'What is serialization in Java?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Converting an object to a byte stream to save to a file or send over a network. Implement `Serializable`. Use `transient` to prevent fields from being serialized.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-025',
      'java',
      'How do you create an immutable class?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Class must be final. 2. Fields must be private and final. 3. No setter methods. 4. Initialize fields via constructor. 5. Perform deep copies of mutable objects in constructor and getters.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-026',
      'java',
      'What is a memory leak in Java?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When objects are no longer used but still referenced, preventing GC. Common causes: static collections, unclosed connections, inner classes holding references to outer classes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-027',
      'java',
      'What is a Callable vs Runnable?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Runnable executes a task and returns void. Callable executes a task and returns a generic value (via Future) and can throw checked exceptions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-028',
      'java',
      'What are Java Annotations?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Metadata added to code (`@Override`, `@Entity`). Can be processed at compile-time, load-time, or runtime via reflection. Useful for frameworks like Spring.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-029',
      'java',
      'Explain the synchronized keyword.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Provides mutual exclusion (mutex) lock. Can be applied to methods (locks the object) or blocks (locks a specific object). Static synchronized locks the Class object.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-030',
      'java',
      'What are Java modules (Project Jigsaw)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Introduced in Java 9. `module-info.java` defines module dependencies and exported packages. Provides strong encapsulation and reduces application size.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-031',
      'java',
      'Difference between shallow and deep copy in Java?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Shallow: copies fields. If field is an object, copies reference only (Object.clone() does this). Deep: copies fields AND creates new instances of nested objects.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-032',
      'java',
      'What is Double Checked Locking?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A pattern to reduce locking overhead in Singleton instantiation. First check without lock, then synchronize, then check again. Requires the instance field to be `volatile` in Java 5+.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-033',
      'java',
      'Explain Method Overloading vs Overriding.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Overloading: Same method name, different parameters, compile-time polymorphism. Overriding: Same method name and parameters in subclass, runtime polymorphism.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-034',
      'java',
      'What are Varargs?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Variable arguments (`String... args`). Allows a method to accept zero or multiple arguments of a specified type. Treated as an array inside the method.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-035',
      'java',
      'Explain autoboxing and unboxing.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Autoboxing: Automatic conversion from primitive to wrapper (int -> Integer). Unboxing: Wrapper to primitive. Can cause NullPointerException if wrapper is null.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-036',
      'java',
      'What is the static keyword?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Belongs to the class rather than an instance. Static variables are shared among all instances. Static methods can be called without creating an instance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-037',
      'java',
      'How do you handle Deadlocks in Java?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Avoid nested locks, lock objects in a consistent order across all threads, use timeouts on locks (`tryLock()`), or use thread dumps (`jstack`) to diagnose.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-038',
      'java',
      'What are Java Records?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Introduced in Java 14. Concise syntax for creating immutable data carriers. Automatically generates constructor, accessors, equals, hashCode, and toString.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-039',
      'java',
      'Explain Optional in Java 8.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A container object to avoid NullPointerException. Use `Optional.ofNullable()`, `map()`, `flatMap()`, and `orElse()`. Do NOT use it as a method parameter or field type.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-040',
      'java',
      'What is Reflection?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Ability to inspect and modify classes, methods, and fields at runtime. Used by frameworks (Spring, Hibernate). Slow and breaks encapsulation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-041',
      'java',
      'What is a memory leak via ThreadLocal?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'If ThreadLocal variables are not explicitly removed (`remove()`) in application servers using thread pools, the thread retains the object, preventing GC and causing a leak.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-042',
      'java',
      'What is covariant return type?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An overriding method can return a subtype of the return type declared in the overridden method. Introduced in Java 5.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-043',
      'java',
      'Explain ClassLoader in Java.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Subsystem of JVM used to load classes. Follows Delegation Hierarchy: Bootstrap (core), Extension/Platform, and System/Application ClassLoaders.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-044',
      'java',
      'What are wildcards in Generics?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`?` represents unknown type. `? extends T` (Upper Bound, Read Only). `? super T` (Lower Bound, Write Only). Principle: PECS (Producer Extends, Consumer Super).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-045',
      'java',
      'Difference between throw and throws?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`throw`: Used to explicitly throw an exception object in the code. `throws`: Used in method signature to declare that the method might throw exceptions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-046',
      'java',
      'What is the Fork/Join framework?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Designed for parallel execution of tasks that can be broken down recursively. Uses Work-Stealing algorithm. Base of parallel streams.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-047',
      'java',
      'What is a transient variable?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Prevents the variable from being serialized. When the object is deserialized, the transient variable receives its default value (e.g., null, 0).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-048',
      'java',
      'What is the purpose of the super keyword?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Refers to the immediate parent class object. Used to invoke parent class constructor, overridden methods, or hidden fields.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-049',
      'java',
      'Explain the factory design pattern.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Creational pattern providing an interface for creating objects in a superclass, but allowing subclasses to alter the type of objects created.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'java-050',
      'java',
      'What are switch expressions?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Introduced in Java 14. Allows switch to return a value using `yield` or `->`. Exhaustiveness is checked by the compiler.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-001',
      'typescript',
      'What is the difference between interface and type?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Both define object shapes. `interface` supports declaration merging (same-name interfaces auto-merge) and is better for public API contracts. `type` supports unions, intersections, mapped types, and primitives. Use interface for objects, type for aliases/unions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-002',
      'typescript',
      'Explain TypeScript generics.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Generics create reusable components that work with multiple types while preserving type safety. Acts as a variable for a type. Constraints use `extends` to limit allowed types.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-003',
      'typescript',
      'What are utility types?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Built-in types to transform other types. `Partial<T>` (all optional), `Required<T>`, `Readonly<T>`, `Pick<T, K>`, `Omit<T, K>`, `Record<K, V>`, `Exclude<T, U>`, `ReturnType<T>`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-004',
      'typescript',
      'What are type guards?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Techniques to narrow down the type of a variable within a conditional block. Examples: `typeof`, `instanceof`, `in`, or custom type predicates (`function isString(x: any): x is string`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-005',
      'typescript',
      'Explain union and intersection types.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Union (`A | B`): Value can be of type A OR type B. Intersection (`A & B`): Value must have all properties of type A AND type B.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-006',
      'typescript',
      'What is the "any" vs "unknown" type?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`any`: disables type checking entirely. `unknown`: type-safe counterpart of any. You cannot perform operations on an `unknown` value without first narrowing its type.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-007',
      'typescript',
      'What are mapped types?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Create new types by iterating over keys of an existing type. Syntax: `{ [K in keyof T]: Type }`. Used extensively in utility types like `Readonly` and `Partial`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-008',
      'typescript',
      'Explain conditional types.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Types that take the form `T extends U ? X : Y`. Similar to ternary operators but for types. Enables powerful type inference and extraction.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-009',
      'typescript',
      'What is the "never" type?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Represents values that never occur. Used as return type for functions that always throw an error or have infinite loops. Also used in exhaustive switch checks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-010',
      'typescript',
      'What are decorators in TypeScript?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Special declaration attached to a class, method, accessor, property, or parameter. Form is `@expression`. Heavily used in Angular and NestJS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-011',
      'typescript',
      'What are enums and const enums?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Enums allow defining a set of named constants. Numeric or string. `const enum` is completely removed during compilation and inlined where used, saving bundle size.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-012',
      'typescript',
      'Explain "keyof" and "typeof" operators.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`typeof`: extracts the type of a variable. `keyof`: extracts the keys of an object type as a string union type.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-013',
      'typescript',
      'What is declaration merging?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When compiler merges two separate declarations declared with the same name into a single definition. Only works for `interface` and `namespace`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-014',
      'typescript',
      'How does type inference work?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'TypeScript automatically deduces types when there is no explicit type annotation (e.g., assigning a value, function return types based on return statements).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-015',
      'typescript',
      'What is a tuple?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An array where the type of a fixed number of elements is known, but need not be the same. Example: `let x: [string, number];`',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-016',
      'typescript',
      'What is the "readonly" modifier?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Makes properties immutable. Can only be modified in the constructor. Different from `const` which is for variable declaration.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-017',
      'typescript',
      'Explain the "infer" keyword.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Used within conditional types to deduce a type variable dynamically. Example: extracting the return type of a function type.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-018',
      'typescript',
      'What is strict mode in tsconfig?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Enables all strict type-checking options. Includes `noImplicitAny`, `strictNullChecks`, `strictBindCallApply`, `strictPropertyInitialization`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-019',
      'typescript',
      'What is a type assertion?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Telling compiler "trust me, I know what I''m doing". Done via `<Type>value` or `value as Type`. Does NOT perform any special checking or restructuring of data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-020',
      'typescript',
      'Difference between void and never?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`void` means function returns undefined (normal completion without value). `never` means function NEVER returns (throws error or infinite loop).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-021',
      'typescript',
      'What are ambient declarations (.d.ts)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Files used to describe the shape of JavaScript code (libraries) to TypeScript so it can provide type checking and intellisense.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-022',
      'typescript',
      'What is optional chaining (?.)',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Allows reading value of a property located deep within a chain without expressly validating that each reference in the chain is valid. Returns undefined if nullish.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-023',
      'typescript',
      'What is nullish coalescing (??)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Returns right-hand operand only when left-hand operand is null or undefined (unlike `||` which checks for falsy values like 0 or "").',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-024',
      'typescript',
      'Explain generic constraints.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using `extends` keyword to ensure a generic type has certain properties. e.g., `<T extends { length: number }>` ensures T has a length property.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-025',
      'typescript',
      'What are index signatures?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Used when you don''t know the exact property names, but you know the shape of the values. `[key: string]: number`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-026',
      'typescript',
      'What is a namespace?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'TypeScript-specific way to organize code. Mostly superseded by ES Modules, but still used in older codebases or ambient declarations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-027',
      'typescript',
      'Difference between public, private, and protected?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`public`: anywhere. `private`: only within the class. `protected`: within class and its subclasses.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-028',
      'typescript',
      'What are abstract classes?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Base classes from which other classes may be derived. Cannot be instantiated directly. May contain implementation details unlike an interface.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-029',
      'typescript',
      'What is literal narrowing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Assigning a specific string/number/boolean literal to a type. e.g., `type Direction = "North" | "South"`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-030',
      'typescript',
      'What is the "this" type?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Polymorphic `this` type represents a type that is the current class/interface. Enables fluent API interfaces (method chaining).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-031',
      'typescript',
      'What is template literal types?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows building types using template literal syntax. e.g., `type Event = "click" | "hover"; type Handler = `on${Capitalize<Event>}``.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-032',
      'typescript',
      'How to make a generic parameter optional?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'By providing a default type: `type Response<T = string> = { data: T }`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-033',
      'typescript',
      'What is the "satisfies" operator?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'TypeScript 4.9+. Validates that an expression matches a type WITHOUT changing the inferred type of the expression.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-034',
      'typescript',
      'What is constructor assignment shorthand?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Using visibility modifiers directly in constructor parameters automatically creates and initializes class properties. `constructor(public name: string) {}`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-035',
      'typescript',
      'Difference between TS enums and Union of string literals?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Enums emit runtime code (an object). String unions emit zero runtime code (erased). Unions are preferred for simple fixed sets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-036',
      'typescript',
      'What is Opaque type modeling?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Using intersection types with unique symbols to create nominal typing in TS (which is structurally typed). e.g., `type USD = number & { __brand: "USD" }`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-037',
      'typescript',
      'What is the difference between ? and undefined?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`foo?: string` means the key `foo` can be missing. `foo: string | undefined` means the key MUST exist, but its value can be undefined.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-038',
      'typescript',
      'Explain "import type".',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Explicitly imports only type declarations. Guaranteed to be fully erased from emitted JavaScript. Helps avoid circular dependencies.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-039',
      'typescript',
      'What is module resolution in TS?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The process TS uses to figure out what an import refers to. Classic vs Node resolution strategies. Configure via `moduleResolution` in tsconfig.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-040',
      'typescript',
      'What are variance, covariance, and contravariance?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Covariance: allows assigning a more specific type. Contravariance: allows assigning a more general type (happens with function parameters in strict mode).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-041',
      'typescript',
      'What is "declare global"?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Used within a module to add declarations to the global scope (e.g., adding a custom property to the `window` object).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-042',
      'typescript',
      'What is definite assignment assertion (!)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Adding `!` after a variable name tells TS that the variable is definitely assigned, silencing the "used before assignment" error.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-043',
      'typescript',
      'What are TS mixins?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Pattern of creating classes from reusable components by creating a function that takes a class constructor and returns a new class extending it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-044',
      'typescript',
      'What is the "asserts" keyword?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Used in assertion functions to tell TS that after the function returns, a specific condition holds true (e.g., `asserts val is string`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-045',
      'typescript',
      'Difference between type casting and type assertion?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Casting implies runtime conversion. TS only has type *assertions*, which are erased at runtime and only impact compile-time checks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-046',
      'typescript',
      'What is TS Project References?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows structuring TS programs into smaller pieces. Improves build times by compiling only modified projects in a monorepo.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-047',
      'typescript',
      'What is exactTypes / Excess Property Checking?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When assigning an object literal to a type, TS throws an error if it contains properties not in the target type, catching typos.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-048',
      'typescript',
      'How to get the type of an array element?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using indexed access type: `type Element = MyArrayType[number]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-049',
      'typescript',
      'What is recursive type alias?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A type that references itself. Useful for JSON objects or tree structures: `type Tree = { val: string, children: Tree[] }`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ts-050',
      'typescript',
      'What is top-level await in TS?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Allows using `await` at the top level of a module without wrapping it in an async function. Requires target ES2022+.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-001',
      'cpp',
      'Difference between C and C++?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'C is procedural, lacks OOP, doesn''t support function overloading, uses malloc/free. C++ supports OOP (classes), function/operator overloading, exception handling, uses new/delete, and has STL.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-002',
      'cpp',
      'What is a pointer vs a reference?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Pointer holds memory address, can be reassigned, can be null, requires dereferencing (*). Reference is an alias to an existing variable, cannot be reassigned once initialized, cannot be null, syntax is cleaner.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-003',
      'cpp',
      'Explain RAII (Resource Acquisition Is Initialization).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Core C++ idiom where resource lifecycle is bound to object lifetime. Resource is acquired in constructor, released in destructor. Guarantees cleanup (memory, files, locks) even if exceptions are thrown.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-004',
      'cpp',
      'What are Smart Pointers?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Objects that manage memory automatically to prevent leaks (implement RAII). `std::unique_ptr` (exclusive ownership), `std::shared_ptr` (reference counted), `std::weak_ptr` (observes shared_ptr without breaking cycles).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-005',
      'cpp',
      'What is the Rule of Three / Five / Zero?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Rule of 3: If a class needs a custom destructor, copy constructor, or copy assignment, it needs all 3. Rule of 5: Adds move constructor and move assignment (C++11). Rule of 0: Prefer using standard types (vector, unique_ptr) so you don''t need to write any of them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-006',
      'cpp',
      'Explain virtual functions and vtables.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Virtual functions enable runtime polymorphism. Compiler creates a virtual table (vtable) for the class containing function pointers, and adds a hidden pointer (vptr) to instances. Incurs slight performance overhead due to dynamic dispatch.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-007',
      'cpp',
      'What is a pure virtual function?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A virtual function ending in `= 0`. Makes the class an abstract class (cannot be instantiated). Derived classes MUST implement it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-008',
      'cpp',
      'Explain Move Semantics (C++11).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows transferring resources (memory) from a temporary object (rvalue) to another, avoiding expensive deep copies. Enabled by rvalue references (`&&`) and `std::move`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-009',
      'cpp',
      'lvalue vs rvalue?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'lvalue: object that occupies identifiable memory (has an address, persists). rvalue: temporary object, doesn''t persist beyond the expression it''s used in (e.g., literals, return values).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-010',
      'cpp',
      'What is std::vector and how does it grow?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Dynamic array in STL. When capacity is reached, it allocates a new larger block (typically 1.5x or 2x the size), copies elements over, and deletes the old block. Cost is amortized O(1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-011',
      'cpp',
      'What is the `auto` keyword?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Tells the compiler to deduce the type of a variable from its initializer at compile time. Reduces verbosity, especially with complex iterator types.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-012',
      'cpp',
      'Explain templates in C++.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Feature that allows writing generic programs. Functions or classes operate on generic types. Compiler generates specific versions for each used type (monomorphization), which increases binary size but maximizes performance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-013',
      'cpp',
      'What is the `const` keyword?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Specifies that a value cannot be modified. Can apply to variables, pointers, function arguments, and member functions. A `const` member function promises not to modify object state.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-014',
      'cpp',
      'Difference between new/delete and malloc/free?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`new` allocates memory AND calls constructors. `delete` calls destructors AND frees memory. `malloc/free` only allocate/free raw memory (from C). Don''t mix them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-015',
      'cpp',
      'What is a memory leak?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Occurs when dynamically allocated memory (`new`) is not deallocated (`delete`), causing the program to consume increasing amounts of RAM.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-016',
      'cpp',
      'What is the `static` keyword?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1) Variables inside functions: keeps value across calls. 2) Variables/functions in file scope: restricts linkage to that file. 3) Class members: shared across all instances.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-017',
      'cpp',
      'Explain `constexpr` vs `const`.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`const` means runtime immutability. `constexpr` means the value/function MUST be evaluated at compile time. Great for performance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-018',
      'cpp',
      'What is lambda expression in C++?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Anonymous function. Syntax: `[captures](params) -> return_type { body }`. Captures can be by value (`=`) or reference (`&`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-019',
      'cpp',
      'What is undefined behavior (UB)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Code that violates language rules (e.g., dereferencing null, out-of-bounds array access, signed integer overflow). Compiler is free to do anything, including crashing or executing malware.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-020',
      'cpp',
      'Difference between struct and class?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'In C++, they are almost identical. The only difference is default access control: members of a `struct` are `public` by default, members of a `class` are `private` by default.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-021',
      'cpp',
      'What are STL algorithms?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Functions that operate on ranges of elements (using iterators). e.g., `std::sort`, `std::find`, `std::transform`. They decouple algorithms from containers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-022',
      'cpp',
      'Explain map vs unordered_map.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`std::map`: implemented as Red-Black tree. Sorted by keys. O(log N) lookup. `std::unordered_map`: implemented as Hash Table. Unsorted. O(1) average lookup.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-023',
      'cpp',
      'What is a namespace?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Declarative region that provides a scope to identifiers (names of types, functions, variables) to prevent name collisions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-024',
      'cpp',
      'What is multiple inheritance and the Diamond Problem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Class inherits from >1 base class. Diamond Problem: class D inherits from B and C, which both inherit from A. Leads to two copies of A. Fixed using `virtual` inheritance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-025',
      'cpp',
      'Explain `std::thread` and mutex.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`std::thread` represents a single thread of execution. `std::mutex` provides mutual exclusion to prevent data races. Use `std::lock_guard` for RAII-style locking.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-026',
      'cpp',
      'What is a friend function/class?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A function or class granted access to the private and protected members of the class in which it is declared as a friend.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-027',
      'cpp',
      'What are inline functions?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Request to compiler to insert the function body at the call site to eliminate function call overhead. Compiler may ignore the request.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-028',
      'cpp',
      'Difference between shallow and deep copy?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Shallow: copies pointer addresses (leads to double-free errors if destructed). Deep: allocates new memory and copies the actual values.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-029',
      'cpp',
      'What is a core dump/segfault?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Segmentation Fault occurs when a program tries to access restricted memory (e.g., dereferencing null pointer or reading outside array bounds). Core dump is a file containing memory state at crash time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-030',
      'cpp',
      'What is type casting in C++?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '4 types: `static_cast` (compile time), `dynamic_cast` (runtime, for polymorphic classes), `const_cast` (remove constness), `reinterpret_cast` (reinterprets bits, highly dangerous).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-031',
      'cpp',
      'What is SFINAE?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Substitution Failure Is Not An Error. A template metaprogramming rule where an invalid template substitution doesn''t cause a compilation error, but just removes that template from the overload resolution set.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-032',
      'cpp',
      'What is placement new?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Constructs an object on a pre-allocated memory buffer instead of allocating new heap memory. `new (ptr) MyClass();`',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-033',
      'cpp',
      'What is volatile keyword?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Tells compiler the variable can change unexpectedly (e.g., by hardware interrupts), preventing optimization. Does NOT provide thread synchronization in C++ (unlike Java).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-034',
      'cpp',
      'Difference between size() and capacity() in vector?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`size()`: Number of elements currently in the vector. `capacity()`: Amount of memory currently allocated (can hold this many elements before reallocating).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-035',
      'cpp',
      'What is object slicing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a derived class object is assigned to a base class object passed by value. The derived-specific members are sliced off.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-036',
      'cpp',
      'What is the `explicit` keyword?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Prevents the compiler from using a single-argument constructor for implicit type conversions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-037',
      'cpp',
      'Explain condition variables.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Synchronization primitive `std::condition_variable` allows threads to wait until a specific condition becomes true, notified by another thread using `notify_one()` or `notify_all()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-038',
      'cpp',
      'What is a memory barrier/fence?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Instructions that enforce ordering constraints on memory operations issued before and after the barrier. Used in low-level lock-free programming with `std::atomic`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-039',
      'cpp',
      'What is the difference between map and set?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`set` contains only unique keys. `map` contains key-value pairs where keys are unique.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-040',
      'cpp',
      'What is `std::optional`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'C++17 feature. A wrapper that contains a value or nothing (`std::nullopt`). Replaces returning raw pointers or magic numbers for failure states.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-041',
      'cpp',
      'What are C++20 Concepts?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Provides a way to specify constraints on template parameters. Replaces complex SFINAE with readable requirements. e.g., `template <Integral T>`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-042',
      'cpp',
      'What is `std::variant`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'C++17 type-safe union. Can hold exactly one of the types specified. Accessed safely via `std::visit`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-043',
      'cpp',
      'What is an atomic operation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Operation that is guaranteed to execute entirely without interruption. `std::atomic` provides thread-safe access without explicit mutex locking.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-044',
      'cpp',
      'What is `std::any`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'C++17 container that holds single values of any type. Safer replacement for `void*`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-045',
      'cpp',
      'Explain perfect forwarding.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Preserves lvalue/rvalue nature of arguments when passing them to another function. Uses `std::forward` combined with universal/forwarding references (`T&&`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-046',
      'cpp',
      'What is copy elision / NRVO?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Named Return Value Optimization. Compiler optimization that eliminates the copying of an object returned by value, constructing it directly in the caller''s stack frame.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-047',
      'cpp',
      'What is ABI (Application Binary Interface)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Low-level interface between program modules. Defines sizes, layouts, calling conventions. Breaking ABI means previously compiled code must be recompiled.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-048',
      'cpp',
      'What is the standard template library (STL)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Library providing generic classes and functions: Containers (vector, list), Iterators, Algorithms (sort, find), and Functors.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-049',
      'cpp',
      'Difference between exception and assertion?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Exception: handles runtime errors (like IO issues) that might be recoverable. Assertion: catches logic bugs during development, typically terminates program in debug builds.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cpp-050',
      'cpp',
      'What is `std::function`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Polymorphic function wrapper. Can store, copy, and invoke any callable target (functions, lambdas, bind expressions).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-001',
      'nodejs',
      'How does the Node.js Event Loop work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The Event Loop allows Node.js to perform non-blocking I/O operations despite being single-threaded. It delegates operations to the OS kernel. It has 6 phases: 1. Timers (setTimeout/setInterval). 2. Pending callbacks. 3. Idle/Prepare. 4. Poll (retrieve new I/O events). 5. Check (setImmediate). 6. Close callbacks. Microtasks (Promises, process.nextTick) run between phases.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-002',
      'nodejs',
      'What is process.nextTick()?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A method that adds a callback to the "nextTick queue". This queue is processed immediately after the current operation completes, BEFORE the event loop continues to the next phase (and before Promises). Useful for ensuring a callback executes before any I/O events are fired.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-003',
      'nodejs',
      'What is the difference between setImmediate() and setTimeout(fn, 0)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`setTimeout(fn, 0)` executes in the Timers phase. `setImmediate()` executes in the Check phase (after Poll). If called from the main module, the order is non-deterministic depending on process performance. If called within an I/O cycle, `setImmediate` ALWAYS executes first.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-004',
      'nodejs',
      'What are Streams in Node.js?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Streams are collections of data that might not be available all at once and don''t have to fit in memory. 4 types: Readable (fs.createReadStream), Writable (fs.createWriteStream), Duplex (TCP sockets), Transform (zlib.createGzip). They use EventEmitters.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-005',
      'nodejs',
      'Explain Buffer in Node.js.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A globally available class used to represent a fixed-length sequence of bytes. Since raw JS didn''t handle binary data well traditionally, Buffers were created to interact with octet streams (TCP streams, file system operations).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-006',
      'nodejs',
      'What is the libuv library?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A multi-platform C library that provides asynchronous I/O based on event loops. It implements the Node.js Event Loop and the thread pool (default 4 threads) used to handle blocking operations like file system calls and DNS lookups.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-007',
      'nodejs',
      'How does the Cluster module work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Node is single-threaded. `cluster` allows creating child processes (workers) that share the same server ports. The master process listens on a port and distributes incoming connections to workers using a round-robin algorithm, taking advantage of multi-core systems.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-008',
      'nodejs',
      'Worker Threads vs Child Processes vs Cluster?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Child Process (`spawn/fork`): Creates a whole new V8 instance (heavy) communicating via IPC. Cluster: Specialized `fork` for scaling web servers over multiple cores. Worker Threads: Lightweight threads within the same process. They share memory (SharedArrayBuffer) and are best for CPU-intensive tasks, not I/O.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-009',
      'nodejs',
      'Explain CommonJS vs ES Modules in Node.js.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'CommonJS (`require/module.exports`): Synchronous, dynamic, loaded at runtime, strict mode optional. ES Modules (`import/export`): Asynchronous, static, loaded at parse time, strict mode default. Node supports ESM via `"type": "module"` in package.json or `.mjs` extension.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-010',
      'nodejs',
      'What is an EventEmitter?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A core module that facilitates communication between objects in Node. Objects emit named events that cause previously registered listeners (callbacks) to be called. e.g., `server.on("request", cb)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-011',
      'nodejs',
      'How to avoid callback hell?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '1. Use Promises instead of callbacks. 2. Use `async/await`. 3. Modularize: split callbacks into separate named functions. 4. Use utility libraries like `util.promisify` to convert callback APIs to Promises.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-012',
      'nodejs',
      'What is a memory leak in Node.js and how to find it?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when objects are no longer needed but remain referenced, preventing garbage collection. Common causes: global variables, unclosed database connections, lingering event listeners. Find it using node --inspect, Chrome DevTools (heap snapshots), or tools like Clinic.js.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-013',
      'nodejs',
      'How does Garbage Collection work in V8?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'V8 uses a generational garbage collector. Memory is divided into New Space (young generation, frequent minor GCs using Scavenge) and Old Space (survivors from New Space, infrequent major GCs using Mark-and-Sweep and Mark-Compact). It pauses the execution thread (Stop-The-World).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-014',
      'nodejs',
      'What is the purpose of the `crypto` module?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Provides cryptographic functionality that includes a set of wrappers for OpenSSL''s hash, HMAC, cipher, decipher, sign, and verify functions. Used for password hashing (pbkdf2, scrypt), encryption, and generating secure random bytes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-015',
      'nodejs',
      'Explain `fs.readFile` vs `fs.createReadStream`.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`readFile` reads the ENTIRE file into memory (Buffer) before firing the callback. Bad for large files. `createReadStream` reads the file in chunks (default 64KB), emitting `data` events. Highly memory-efficient for large files or network piping.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-016',
      'nodejs',
      'What is a REPL?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Read-Eval-Print Loop. The interactive shell you get when you type `node` in the terminal. It Reads user input, Evaluates the code, Prints the result, and Loops back to the start. Great for quick testing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-017',
      'nodejs',
      'What is `util.promisify`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A utility method that takes a function following the common Node.js callback style (i.e., taking a `(err, value) => ...` callback as the last argument) and returns a version that returns a Promise.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-018',
      'nodejs',
      'Explain stream piping.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Connecting the output of a Readable stream directly to the input of a Writable stream. e.g., `readStream.pipe(writeStream)`. It automatically handles backpressure (matching reading speed to writing speed to prevent memory explosion).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-019',
      'nodejs',
      'What is backpressure in streams?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When data is being read from a stream faster than it can be written to the destination. The internal buffer fills up. Node handles this in `.pipe()` by pausing the readable stream when the writable stream''s `write()` returns false, and resuming on the `drain` event.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-020',
      'nodejs',
      'What is `package-lock.json`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Automatically generated file that locks the exact versions of dependencies (and their sub-dependencies) installed in `node_modules`. Guarantees identical installations across different environments and team members.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-021',
      'nodejs',
      'Difference between `dependencies` and `devDependencies`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`dependencies`: Packages required for the application to run in production (e.g., express, mongoose). `devDependencies`: Packages needed only during development/testing (e.g., jest, nodemon, eslint). `npm install --production` skips devDependencies.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-022',
      'nodejs',
      'What is the `path` module?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Core module for working with file and directory paths safely across different OS environments (Windows uses `\`, POSIX uses `/`). Key methods: `path.join()`, `path.resolve()`, `path.basename()`, `path.extname()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-023',
      'nodejs',
      'Explain `path.join()` vs `path.resolve()`.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`join()` concatenates path segments using the platform-specific separator and normalizes it. `resolve()` processes paths from right to left, prepending them until an ABSOLUTE path is constructed (acts like a sequence of `cd` commands).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-024',
      'nodejs',
      'What is `__dirname` and `__filename`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Global variables in CommonJS modules. `__dirname`: The absolute path to the directory containing the current executing script. `__filename`: The absolute path to the current executing script itself. (Not available in ES Modules natively, requires `import.meta.url` workaround).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-025',
      'nodejs',
      'How do you handle unhandled promise rejections?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Listen to the `unhandledRejection` event on the global `process` object. Historically, Node just printed a warning. Since Node 15, unhandled rejections terminate the Node.js process with a non-zero exit code by default.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-026',
      'nodejs',
      'How do you handle uncaught exceptions?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Listen to the `uncaughtException` event on the `process` object. It''s a last resort. The process is likely in an undefined state. The best practice is to log the error synchronously and then `process.exit(1)` to let a process manager (like PM2) restart it safely.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-027',
      'nodejs',
      'What is PM2?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A production process manager for Node.js. It keeps the application alive forever (auto-restarts on crashes), enables zero-downtime reloads, handles clustering across multiple cores, and provides log management and monitoring.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-028',
      'nodejs',
      'How do you structure a large Node.js application?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use layered architecture. Separate into: 1. Controllers (handle HTTP requests). 2. Services (business logic). 3. Data Access / Repositories (database queries). Use dependency injection, environment variables, and modular routing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-029',
      'nodejs',
      'What is the `os` module?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Core module providing operating system-related utility methods. Used to get memory (`os.totalmem()`, `os.freemem()`), CPU info (`os.cpus()`), network interfaces, and system uptime.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-030',
      'nodejs',
      'Explain the "Module Wrapper" function in Node.js.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Before a CommonJS module''s code is executed, Node wraps it in a function: `(function(exports, require, module, __filename, __dirname) { ...code... });`. This keeps top-level variables scoped to the module rather than the global object, and provides the necessary module variables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-031',
      'nodejs',
      'What is `npx`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Node Package Execute. A CLI tool bundled with npm. It allows you to execute binaries from npm packages without installing them globally (e.g., `npx create-react-app`). It temporarily downloads the package, runs it, and deletes it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-032',
      'nodejs',
      'How do you update Node.js dependencies?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`npm outdated` lists packages that have newer versions. `npm update` safely updates to the latest minor/patch versions allowed by package.json. `npx npm-check-updates -u` updates package.json to the absolute latest major versions, followed by `npm install`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-033',
      'nodejs',
      'What is a child process `fork()`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A special case of `spawn()` used specifically to spawn new Node.js processes. It establishes an IPC (Inter-Process Communication) channel, allowing the parent and child to pass messages back and forth using `process.send()` and `process.on("message")`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-034',
      'nodejs',
      'What is the `zlib` module?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Core module providing compression functionality implemented using Gzip, Deflate/Inflate, and Brotli. Commonly used with streams to compress HTTP responses or file data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-035',
      'nodejs',
      'How do you read command line arguments in Node?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'They are stored in the `process.argv` array. `process.argv[0]` is the Node path, `process.argv[1]` is the script path, and indices 2+ contain the actual passed arguments. For complex parsing, libraries like `yargs` or `commander` are used.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-036',
      'nodejs',
      'What is the `global` object in Node.js?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The equivalent of the `window` object in the browser. Variables defined at the top level of a module are NOT attached to `global` (due to the module wrapper). You must explicitly attach them: `global.myVar = true`. In modern JS, `globalThis` is preferred.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-037',
      'nodejs',
      'Explain graceful shutdown in Node.js.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Intercepting termination signals (SIGINT, SIGTERM) to stop accepting new requests, finish processing active requests, close database connections securely, and then cleanly exit the process (`process.exit(0)`). Prevents data corruption and dropped connections.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-038',
      'nodejs',
      'What is the `assert` module?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Core module providing a set of assertion functions for verifying invariants. If an assertion fails, it throws an `AssertionError`. Historically used for testing, but mostly replaced by richer assertion libraries like Chai or Jest''s `expect`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-039',
      'nodejs',
      'How do you mock HTTP requests in Node testing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use libraries like Nock. Nock intercepts outbound HTTP requests made using `http` or `https` core modules and returns specified mock responses. This ensures tests run fast and offline without hitting real external APIs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-040',
      'nodejs',
      'What are Node.js environment variables and how do you access them?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Variables passed to the application from the OS. Accessed via `process.env`. Commonly used for configuration (ports, API keys, DB URLs) so code remains environment-agnostic. The `dotenv` package is heavily used to load them from a `.env` file.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-041',
      'nodejs',
      'What is the V8 Engine?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Google''s open-source high-performance JavaScript and WebAssembly engine, written in C++. It parses and compiles JS directly to native machine code before executing it, using JIT (Just-In-Time) compilation. Node.js embeds V8.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-042',
      'nodejs',
      'How can you profile a Node.js application?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Start Node with `--inspect` and connect Chrome DevTools. 2. Use `console.time()` and `console.timeEnd()`. 3. Run with `--prof` to generate a V8 tick profile. 4. Use APM (Application Performance Monitoring) tools like Datadog, New Relic, or Clinic.js.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-043',
      'nodejs',
      'What is `package.json`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The manifest file of any Node.js project. It holds metadata relevant to the project (name, version, scripts), and manages the project''s dependencies (dependencies, devDependencies) and engine requirements.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-044',
      'nodejs',
      'What is semantic versioning (SemVer)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A versioning system: MAJOR.MINOR.PATCH. MAJOR: incompatible API changes. MINOR: backwards-compatible new functionality. PATCH: backwards-compatible bug fixes. In package.json, `^` allows minor/patch updates, `~` allows only patch updates.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-045',
      'nodejs',
      'Explain the thread pool in Node.js.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Maintained by libuv. Contains 4 threads by default (customizable via `UV_THREADPOOL_SIZE`). Node uses these threads for tasks that lack native async OS support: file system operations (fs), DNS lookups, crypto functions (pbkdf2), and zlib.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-046',
      'nodejs',
      'What is the `net` module?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Core module that provides an asynchronous network API for creating raw TCP or IPC servers and clients. It is the foundation upon which the `http` module is built.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-047',
      'nodejs',
      'How to scale a Node.js application?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Clone: Use the `cluster` module or PM2 to run multiple instances on one machine. 2. Decompose: Break into microservices. 3. Split: Route different types of traffic to different servers. 4. Deploy multiple servers behind a Load Balancer (Nginx, AWS ALB).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-048',
      'nodejs',
      'What is the `dns` module?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Core module containing functions for name resolution. E.g., `dns.lookup()` uses the OS''s underlying facilities (uses libuv threadpool), while `dns.resolve()` connects to DNS servers directly via the network.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-049',
      'nodejs',
      'What is Node.js middleware?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A concept popularized by Express. Functions that have access to the request object, response object, and the `next` middleware function. They can execute code, modify req/res, end the cycle, or call `next()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'node-050',
      'nodejs',
      'What are diagnostic reports in Node.js?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A feature that generates a JSON file on demand or triggered by certain events (fatal errors, uncaught exceptions, signals). It contains info on JS/C++ stacks, heap stats, OS config, and resource usage. Useful for post-mortem debugging.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-001',
      'express',
      'What is Middleware in Express?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Middleware functions have access to the request (`req`), response (`res`), and the `next` middleware function in the application''s request-response cycle. They can execute code, make changes to the req/res objects, end the cycle, or call `next()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-002',
      'express',
      'Explain the order of middleware execution.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Middleware executes sequentially in the exact order they are defined via `app.use()`. Global middleware should be placed at the top. Error-handling middleware should be placed at the very bottom, after all other routes and middleware.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-003',
      'express',
      'How do you define an Error-Handling Middleware?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Error-handling middleware MUST have exactly 4 arguments: `(err, req, res, next)`. Even if you don''t use `next`, you must include it in the signature so Express recognizes it as an error handler. It catches errors passed via `next(err)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-004',
      'express',
      'What does app.use(express.json()) do?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'It is a built-in middleware that parses incoming requests with JSON payloads and populates the `req.body` object. It only looks at requests where the `Content-Type` header matches `application/json`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-005',
      'express',
      'How do you handle async errors in Express route handlers?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In Express 4, async errors must be explicitly caught and passed to `next(err)`, otherwise the app will crash or hang. This is usually handled via an async wrapper function `const catchAsync = fn => (req, res, next) => fn(req, res, next).catch(next);`. (Fixed natively in Express 5).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-006',
      'express',
      'What is CORS and how do you enable it in Express?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cross-Origin Resource Sharing. A browser security feature. Use the `cors` middleware package: `app.use(cors())`. You can configure it to allow specific origins, methods, and headers: `cors({ origin: "http://example.com" })`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-007',
      'express',
      'What is a Router in Express?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A mini-application capable of performing middleware and routing functions. Used to modularize route handlers. `const router = express.Router(); router.get("/", ...); app.use("/users", router);`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-008',
      'express',
      'How do you handle route parameters and query strings?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Route parameters are captured in the URL path (e.g., `/users/:id`) and accessed via `req.params.id`. Query strings are appended to the URL (e.g., `/search?q=test`) and accessed via `req.query.q`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-009',
      'express',
      'What is the purpose of helmet?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Helmet is a middleware package that helps secure Express apps by setting various HTTP headers. It mitigates cross-site scripting (XSS), clickjacking, and disables the `X-Powered-By` header so attackers can''t easily identify the tech stack.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-010',
      'express',
      'How do you implement rate limiting in Express?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use the `express-rate-limit` package. It prevents brute-force attacks and DDoS by limiting the number of requests a single IP can make within a time window. Apply globally or to specific sensitive routes (like `/login`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-011',
      'express',
      'Explain req.body, req.params, and req.query.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`req.body`: Contains data submitted in the request payload (requires body-parser). `req.params`: Contains route parameters (dynamic segments of URL). `req.query`: Contains URL query string parameters.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-012',
      'express',
      'What is JWT and how is it used for authentication?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'JSON Web Token. A stateless authentication mechanism. The server verifies credentials and issues a signed JWT. The client sends it in the `Authorization: Bearer <token>` header on subsequent requests. The server verifies the signature without needing a database lookup.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-013',
      'express',
      'How do you protect a route using JWT in Express?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Create a middleware that extracts the token from headers/cookies, verifies it using `jsonwebtoken.verify()`, extracts the user ID, attaches the user to `req.user`, and calls `next()`. If verification fails, return 401 Unauthorized.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-014',
      'express',
      'What is the difference between res.send(), res.json(), and res.end()?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`res.send()`: Sends HTTP response, automatically sets Content-Type based on data (String -> html, Object -> json). `res.json()`: Formats data as JSON and sends it. `res.end()`: Quickly ends the response without any data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-015',
      'express',
      'How do you validate incoming request data?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a validation library like Joi or express-validator. Create a middleware that checks `req.body`, `req.query`, or `req.params` against a predefined schema. If invalid, return a 400 Bad Request with details before hitting the controller.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-016',
      'express',
      'What is the "next(''route'')" call used for?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Calling `next(''route'')` will bypass all remaining middleware functions attached to the specific route and pass control to the NEXT matching route defined in the router.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-017',
      'express',
      'Explain sessions vs cookies.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cookies are small key-value pairs stored on the client. Sessions store user data on the server, using a Session ID stored in a client cookie to map the client to their server-side data. JWTs are stateless alternatives to sessions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-018',
      'express',
      'How do you handle file uploads in Express?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Express cannot parse `multipart/form-data` natively. Use a middleware like `multer`. It processes the upload, saves the file to disk or memory (Buffer), and attaches file information to `req.file` or `req.files`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-019',
      'express',
      'What is the purpose of the `X-Forwarded-For` header?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When an Express app sits behind a reverse proxy (like Nginx) or Load Balancer, `req.ip` will show the proxy''s IP. `X-Forwarded-For` contains the original client''s IP. You must set `app.set("trust proxy", true)` to parse it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-020',
      'express',
      'How do you serve static files in Express?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the built-in middleware `express.static()`. `app.use("/public", express.static(path.join(__dirname, "public")))`. This serves files (images, css, js) directly without writing custom routes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-021',
      'express',
      'Explain CSRF and how to prevent it in Express.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Cross-Site Request Forgery. Attacker tricks a victim into submitting a malicious request to an application they are authenticated against. Prevent using Anti-CSRF tokens (e.g., `csurf` package) or setting cookies to `SameSite=Strict/Lax`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-022',
      'express',
      'What is dependency injection in Express controllers?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Passing services (like database models or external APIs) as arguments to controller factories rather than importing them directly. Makes testing easier by allowing mock services to be injected.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-023',
      'express',
      'How do you handle graceful shutdown in an Express app?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Listen for `SIGTERM`/`SIGINT`. Call `server.close()` to stop accepting new requests, then gracefully close DB connections, then `process.exit(0)`. Useful for zero-downtime deployments.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-024',
      'express',
      'What is the difference between app.all() and app.use()?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`app.use()` mounts middleware for a path (and any sub-paths). `app.all()` attaches a handler to a specific exact path for ALL HTTP methods (GET, POST, etc). `app.all("/x")` matches exactly `/x`, `app.use("/x")` matches `/x`, `/x/y`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-025',
      'express',
      'How do you create a custom middleware?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Write a function taking `(req, res, next)`. Execute logic. Call `next()` to move on, or use `res.send()` to end the cycle. Attach globally with `app.use(myMiddleware)` or to specific routes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-026',
      'express',
      'What is content negotiation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The mechanism used for serving different representations of a resource at the same URI depending on the client''s `Accept` headers (e.g., JSON vs XML). Handled via `res.format()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-027',
      'express',
      'What does res.locals do?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An object scoped to the request. Variables set on `res.locals` (e.g., `res.locals.user = user`) are available to views rendered during that request/response cycle, or to subsequent middleware.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-028',
      'express',
      'How do you test an Express API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use testing frameworks like Jest combined with `supertest`. Supertest allows you to pass the `app` instance directly and simulate HTTP requests without actually listening on a network port.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-029',
      'express',
      'What are HTTP status codes and list common ones.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '200: OK. 201: Created. 400: Bad Request. 401: Unauthorized. 403: Forbidden (auth valid, but lack permissions). 404: Not Found. 500: Internal Server Error. 502: Bad Gateway.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-030',
      'express',
      'How do you handle multiple environments (dev/prod/test)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Set the `NODE_ENV` environment variable. Express automatically optimizes itself (caches views, removes verbose errors) when `NODE_ENV=production`. Use `dotenv` to load environment-specific variables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-031',
      'express',
      'Explain how passport.js works.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Authentication middleware for Node. Uses "Strategies" (Local, OAuth, JWT). It authenticates the request, maintains persistent login sessions via serialization/deserialization, and attaches the authenticated user to `req.user`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-032',
      'express',
      'What is the purpose of route parameter regex?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Allows matching specific patterns in route params. e.g., `app.get("/users/:id(\d+)")` will only match if the `id` consists entirely of digits, allowing you to separate `/users/123` from `/users/profile`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-033',
      'express',
      'What is a reverse proxy?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A server (like Nginx or HAProxy) that sits in front of web servers (Node) and forwards client requests to them. Provides load balancing, SSL termination, caching, and hides the backend structure.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-034',
      'express',
      'How does res.redirect() work under the hood?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'It sets the HTTP status code to 302 (Found/Moved Temporarily) or 301 (Permanent), and sets the `Location` HTTP header to the specified URL, prompting the browser to make a new request.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-035',
      'express',
      'Explain the Model-View-Controller (MVC) pattern in Express.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Model: Handles data logic and database interactions. View: UI rendering (often handled by a frontend framework like React, or template engines like Pug). Controller: Handles incoming requests, queries the Model, and sends responses.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-036',
      'express',
      'What is Morgan?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An HTTP request logger middleware for Node.js. Automatically logs incoming requests, statuses, response times, and IP addresses to the console or a file. Great for debugging and monitoring.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-037',
      'express',
      'How to compress Express responses?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the `compression` middleware package. `app.use(compression())`. It automatically compresses the response bodies (using Gzip or Deflate) for all requests traversing through the middleware.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-038',
      'express',
      'What is a 404 handler and how is it implemented?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A middleware placed at the very end of all route definitions (but before the error handler) that catches any requests that didn''t match a route. `app.use((req, res) => res.status(404).send("Not Found"))`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-039',
      'express',
      'Explain the difference between SQL injection and XSS.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'SQL Injection: Attacker injects malicious SQL into input to manipulate the database. Prevent via parameterized queries. XSS: Attacker injects malicious scripts into the frontend UI to steal tokens. Prevent via escaping/sanitization and Helmet headers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-040',
      'express',
      'What is Server-Sent Events (SSE)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A standard allowing a server to push data to a web page via a single HTTP connection. Set Headers: `Content-Type: text/event-stream`, `Cache-Control: no-cache`. Keep connection open and write data using `res.write("data: MSG\n\n")`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-041',
      'express',
      'How do you upload files to AWS S3 in Express?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use `multer` along with `multer-s3` and the AWS SDK. Multer handles the multipart form, and multer-s3 streams the file directly to the S3 bucket without saving it to the local disk first.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-042',
      'express',
      'What is an API Gateway?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A server that acts as an API front-end, receiving API requests, enforcing throttling and security policies, routing them to the appropriate microservices, and aggregating the results.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-043',
      'express',
      'How to implement pagination in an API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use `limit` and `page` (or `offset`) query parameters. Limit dictates items per page. Offset = `(page - 1) * limit`. Return the data array alongside metadata (total count, current page, total pages).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-044',
      'express',
      'Explain WebSockets vs REST API.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'REST is stateless, unidirectional (client -> server), request-response based over HTTP. WebSockets are stateful, persistent, full-duplex (bidirectional) communication over a single TCP connection. Use WS for real-time apps.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-045',
      'express',
      'What is socket.io?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A library that enables real-time, bidirectional communication. It uses WebSockets under the hood but provides fallbacks (like long-polling) for older browsers, automatic reconnections, and broadcasting/rooms.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-046',
      'express',
      'How do you handle background jobs?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Express should not block the event loop for heavy processing (e.g., video encoding, mass emails). Use a message broker/queue (Redis with Bull or RabbitMQ) to pass the task to a separate worker process.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-047',
      'express',
      'What is API versioning?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The practice of managing changes to an API. Ensures backward compatibility for existing clients when breaking changes are introduced. Commonly done via URL path (`/api/v1/users`) or HTTP Headers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-048',
      'express',
      'What is a webhook?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A user-defined HTTP callback. An external service (like Stripe) makes an HTTP POST request to an endpoint in your Express app when a specific event occurs (like a successful payment).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-049',
      'express',
      'Explain Idempotency.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An operation is idempotent if making multiple identical requests has the same effect as making a single request. `GET`, `PUT`, `DELETE` are idempotent. `POST` is NOT idempotent. Crucial for robust API design.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'exp-050',
      'express',
      'How to connect Express to MongoDB?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Using the `mongoose` library. `mongoose.connect(URI)`. Define Schemas and Models. Use model methods (`Model.find()`, `Model.create()`) inside route handlers to interact with the database.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-001',
      'api-design',
      'What is REST?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Representational State Transfer. An architectural style for distributed hypermedia systems. It relies on a stateless, client-server, cacheable communications protocol (virtually always HTTP).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-002',
      'api-design',
      'What are the 6 guiding constraints of REST?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Client-Server architecture. 2. Statelessness (no client context stored on server). 3. Cacheability (responses must define themselves as cacheable or not). 4. Layered System (client cannot tell if it is connected to end server or intermediary). 5. Uniform Interface (identification of resources, manipulation through representations, self-descriptive messages, HATEOAS). 6. Code on Demand (optional).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-003',
      'api-design',
      'Explain the concept of Statelessness in REST.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Every request from client to server must contain all of the information necessary to understand the request, and cannot take advantage of any stored context on the server. Session state is therefore kept entirely on the client (e.g., via JWTs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-004',
      'api-design',
      'What is HATEOAS?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Hypermedia As The Engine Of Application State. A constraint of the REST architecture that states a client interacts with a network application entirely through hypermedia provided dynamically by application servers. A REST client needs no prior knowledge about how to interact with an application or server beyond a generic understanding of hypermedia.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-005',
      'api-design',
      'Compare PUT vs POST vs PATCH.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'POST: Create a new resource (Not Idempotent). PUT: Update an entire resource, or create it if it doesn''t exist. Replaces the whole payload (Idempotent). PATCH: Apply partial modifications to a resource (Not strictly Idempotent, but usually implemented as such).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-006',
      'api-design',
      'Explain Idempotency in APIs.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An operation is idempotent if making multiple identical requests has the exact same effect as making a single request. GET, PUT, DELETE, HEAD, and OPTIONS are idempotent. POST is not.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-007',
      'api-design',
      'What is GraphQL?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A query language for APIs and a runtime for fulfilling those queries with your existing data. Provides a complete and understandable description of the data in your API, gives clients the power to ask for exactly what they need and nothing more.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-008',
      'api-design',
      'REST vs GraphQL: Key differences.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'REST: Multiple endpoints, server dictates response structure, prone to over/under-fetching, uses standard HTTP caching. GraphQL: Single endpoint (`/graphql`), client dictates response structure, solves over/under-fetching, caching is more complex, strongly typed schema.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-009',
      'api-design',
      'What is over-fetching and under-fetching?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Over-fetching: Receiving more data than the client needs (e.g., fetching a whole user object just to get the name). Under-fetching: Not receiving enough data in a single request, forcing the client to make subsequent requests (N+1 problem).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-010',
      'api-design',
      'Explain the N+1 problem in GraphQL and how to solve it.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a resolver triggers a database query for a list of N items, resulting in 1 initial query + N sub-queries (N+1). Solved using DataLoader, which batches and caches requests, converting N queries into a single SQL `IN` clause.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-011',
      'api-design',
      'What are GraphQL Resolvers?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Functions that generate responses for a GraphQL query. Every field in a GraphQL schema is backed by a resolver function. They fetch the data for that field from a database, microservice, or external API.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-012',
      'api-design',
      'What are GraphQL Mutations and Subscriptions?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Mutations: Operations that modify server-side data (Create, Update, Delete) and return a value. Subscriptions: Long-lasting operations that can change their result over time, typically implemented via WebSockets to push real-time updates to clients.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-013',
      'api-design',
      'How do you handle authentication in GraphQL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Usually handled at the HTTP layer (before GraphQL execution) using middleware. The middleware validates the JWT/session, extracts the user, and injects it into the GraphQL `context` object, which is passed to all resolvers for authorization checks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-014',
      'api-design',
      'What is API Rate Limiting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Controlling the rate of traffic sent or received by a network interface. Protects APIs from DDoS attacks and brute-force attacks, and enforces fair usage quotas. Common algorithms: Token Bucket, Leaky Bucket, Fixed Window, Sliding Window.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-015',
      'api-design',
      'Explain the Token Bucket algorithm.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A bucket holds `N` tokens. Tokens are added at a fixed rate. When a request comes, it must consume a token to be processed. If the bucket is empty, the request is dropped (429 Too Many Requests). Allows for short bursts of traffic.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-016',
      'api-design',
      'How do you version an API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. URI Versioning (`/api/v1/users`) - most common. 2. Header Versioning (`Accept-version: v1`). 3. Query Parameter Versioning (`/api/users?version=1`). 4. Media Type/Content Negotiation (`Accept: application/vnd.company.v1+json`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-017',
      'api-design',
      'What is Cursor-based Pagination vs Offset-based?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Offset: `LIMIT 10 OFFSET 20`. Easy to implement, but skips/duplicates items if data is added/deleted during pagination, and slow for large offsets (DB scans everything). Cursor: Uses a unique identifier (cursor) from the last item (`WHERE id > cursor LIMIT 10`). Fast and resilient to data changes, but cannot jump to a specific page.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-018',
      'api-design',
      'What is an API Gateway?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A management tool that sits between a client and a collection of backend services. It acts as a reverse proxy, routing requests to appropriate services, and handles cross-cutting concerns: auth, SSL termination, rate limiting, logging, and CORS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-019',
      'api-design',
      'Explain OAuth 2.0.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An authorization framework that enables applications to obtain limited access to user accounts on an HTTP service. It delegates user authentication to the service that hosts the user account, issuing access tokens to third-party clients (e.g., "Log in with Google").',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-020',
      'api-design',
      'What are the OAuth 2.0 Grant Types?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Authorization Code (for server-side apps). 2. Implicit (deprecated, for SPAs). 3. Resource Owner Password Credentials (trusted apps only). 4. Client Credentials (machine-to-machine). 5. PKCE (Proof Key for Code Exchange - secure replacement for Implicit).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-021',
      'api-design',
      'What is OpenID Connect (OIDC)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A simple identity layer on top of the OAuth 2.0 protocol. While OAuth 2.0 is strictly for authorization (access), OIDC adds authentication (identity) by returning an ID Token (a JWT) containing user profile information.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-022',
      'api-design',
      'What is a Webhook?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A user-defined HTTP callback (usually POST). An external service sends a payload to your endpoint when an event occurs, enabling event-driven communication without polling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-023',
      'api-design',
      'How do you secure a Webhook?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. HTTPS only. 2. Signature verification: The provider signs the payload using a secret key and sends it in a header. Your server calculates the hash of the received payload with the same secret and compares it. 3. Timestamp checks to prevent replay attacks. 4. IP whitelisting.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-024',
      'api-design',
      'What is gRPC?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A high-performance Remote Procedure Call framework developed by Google. It uses Protocol Buffers (Protobuf) as the interface description language and data format, and HTTP/2 for transport (enabling streaming, multiplexing, and low latency).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-025',
      'api-design',
      'REST vs gRPC.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'REST uses JSON/XML, HTTP/1.1 (mostly), is human-readable, and resource-oriented. gRPC uses Protobuf (binary), HTTP/2, is strictly typed, action-oriented, and generally much faster and smaller in payload size. gRPC is preferred for internal microservice communication.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-026',
      'api-design',
      'What are Protocol Buffers?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Google''s language-neutral, platform-neutral, extensible mechanism for serializing structured data. You define schemas in `.proto` files, which compile into data access classes. Smaller and faster than JSON/XML.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-027',
      'api-design',
      'What is Content Negotiation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The process in which the client and server agree on the format of the response payload. The client sends an `Accept` header (e.g., `application/json` or `application/xml`), and the server replies with the appropriate format and a `Content-Type` header.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-028',
      'api-design',
      'How do you handle API breaking changes?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Never modify the existing contract. Instead: 1. Introduce a new API version (v2). 2. Add new fields instead of modifying/deleting old ones. 3. Deprecate the old fields (warn clients). 4. Maintain the old version until usage drops to an acceptable threshold, then sunset.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-029',
      'api-design',
      'What is API documentation and why is it important?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Comprehensive guide detailing how to effectively use and integrate with an API. Essential for DX (Developer Experience). Tools like Swagger/OpenAPI or Postman auto-generate interactive docs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-030',
      'api-design',
      'What is the OpenAPI Specification?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A broadly adopted industry standard for describing REST APIs (formerly Swagger). It uses YAML/JSON to describe endpoints, request/response structures, authentication methods, and generates interactive docs and client SDKs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-031',
      'api-design',
      'What are safe HTTP methods?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Methods that do not modify the resource state on the server. Examples: GET, HEAD, OPTIONS. They are strictly read-only operations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-032',
      'api-design',
      'Explain CORS and preflight requests.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cross-Origin Resource Sharing. Browsers restrict cross-origin HTTP requests. For complex requests (e.g., POST with JSON, PUT, DELETE), the browser sends an `OPTIONS` request (preflight) to check if the server allows the actual request (checks `Access-Control-Allow-Origin` and Methods).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-033',
      'api-design',
      'What is a JWT?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'JSON Web Token. A compact, URL-safe means of representing claims. Consists of three parts separated by dots: Header (algorithm), Payload (claims/data), and Signature (verifies token hasn''t been tampered with). It is encoded, NOT encrypted.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-034',
      'api-design',
      'Where should you store JWTs on the client?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Storing in LocalStorage is vulnerable to XSS attacks (any JS can read it). Storing in memory is safe but lost on refresh. Best practice: Store in an `HttpOnly`, `Secure`, `SameSite=Strict` cookie, which prevents JS access and mitigates XSS and CSRF.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-035',
      'api-design',
      'What are refresh tokens?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Long-lived tokens used to obtain new short-lived access tokens (JWTs) when they expire, without requiring the user to re-authenticate. They are typically stored securely in the database and can be revoked by the server if compromised.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-036',
      'api-design',
      'How do you design a filtering API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use query strings. Basic: `/users?status=active`. Complex (RHS colon): `/users?price=gte:100&sort=-createdAt`. Avoid nesting objects in query strings if possible, keep it flat and readable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-037',
      'api-design',
      'What is the HTTP HEAD method?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Identical to GET, but the server does NOT return a message body in the response. Used to check if a resource exists, check its last modified date, or check its size (Content-Length) before downloading.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-038',
      'api-design',
      'What is the HTTP OPTIONS method?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Used by the client to find out the HTTP methods and other options supported by a web server. Heavily used in CORS preflight requests.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-039',
      'api-design',
      'What HTTP status code is used for validation errors?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '400 Bad Request. Sometimes 422 Unprocessable Entity is used when the payload format is valid JSON but semantically incorrect (e.g., failed business rules).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-040',
      'api-design',
      'Difference between 401 and 403?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '401 Unauthorized: The client must authenticate itself to get the requested response. 403 Forbidden: The client IS authenticated, but does not have the necessary permissions/roles to access the resource.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-041',
      'api-design',
      'What is payload compression?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Applying algorithms like Gzip or Brotli to the HTTP response body before sending it to the client. Reduces network transfer size significantly (often 70-90%). Client indicates support via `Accept-Encoding` header.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-042',
      'api-design',
      'Explain Long Polling.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Client requests data. If the server has no new data, it holds the request open until data is available or a timeout occurs. Once data is sent (or timeout), the client immediately sends a new request. A precursor to WebSockets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-043',
      'api-design',
      'What is Server-Sent Events (SSE)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A unidirectional technology where a browser receives automatic updates from a server via an HTTP connection. Good for live feeds, stock tickers, where the client only needs to receive, not send data constantly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-044',
      'api-design',
      'How to handle API timeouts?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Set sensible timeout limits on clients. On the server, ensure slow operations (like 3rd party API calls) have timeouts. Return a 408 Request Timeout or 504 Gateway Timeout if an upstream service fails to respond in time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-045',
      'api-design',
      'What is the BFF pattern?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Backend For Frontend. Instead of one general-purpose API for all clients (web, mobile, smart tv), you create specialized backend APIs for each specific client interface. It optimizes payload size and aggregates microservice calls tailored to the client.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-046',
      'api-design',
      'What is API caching and where does it occur?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Storing copies of API responses to serve future requests faster. Can happen at the Client (browser cache), Edge (CDN), Gateway, or Backend (Redis). Uses headers like `Cache-Control` and `ETag`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-047',
      'api-design',
      'What is an ETag?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Entity Tag. An HTTP header representing a specific version of a resource. The client sends it back via `If-None-Match`. If the server''s current ETag matches, it sends a `304 Not Modified` with an empty body, saving bandwidth.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-048',
      'api-design',
      'What is the Strangler Fig Pattern?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A strategy for migrating a monolithic API to microservices. You create a routing facade (API Gateway) that intercepts calls to the old monolith. Over time, you build new services and update the router to point to them, gradually "strangling" the monolith.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-049',
      'api-design',
      'How do you design a Bulk/Batch API?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Accept an array of objects in the POST/PUT body. Important considerations: 1. Limit the max batch size. 2. Handle partial failures (return a 207 Multi-Status with an array indicating success/failure per item). 3. Use database transactions if atomicity is required.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'api-050',
      'api-design',
      'What are GraphQL Directives?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Annotations attached to fields/fragments that change the execution behavior of the query. Built-in directives include `@skip(if: Boolean)` and `@include(if: Boolean)`. Custom directives can be used for formatting, auth, or caching.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-001',
      'spring-boot',
      'What is the difference between Spring and Spring Boot?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Spring is the core framework providing Dependency Injection (DI) and Inversion of Control (IoC). It requires heavy manual XML or Java configuration. Spring Boot is an extension that provides "opinionated" auto-configuration, embedded servers (Tomcat), and starter POMs to get applications running instantly without boilerplate.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-002',
      'spring-boot',
      'Explain Inversion of Control (IoC) and Dependency Injection (DI).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'IoC means the control of object creation is handed over from the programmer to the framework (the Spring Container). DI is the pattern used to implement IoC; instead of objects instantiating their dependencies, the Container injects them (via constructor, setter, or field injection).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-003',
      'spring-boot',
      'What does @SpringBootApplication do?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It is a convenience annotation that wraps three core annotations: 1. `@Configuration` (allows registering extra beans in the context). 2. `@EnableAutoConfiguration` (tells Spring Boot to auto-configure beans based on classpath dependencies). 3. `@ComponentScan` (scans for other components, configurations, and services in the current package and its sub-packages).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-004',
      'spring-boot',
      'What are Spring Boot Starter dependencies?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A set of convenient dependency descriptors you can include in your application. E.g., `spring-boot-starter-web` automatically pulls in Spring MVC, Jackson (for JSON), and embeds Tomcat, saving you from copying/pasting complex dependency trees.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-005',
      'spring-boot',
      'How does Spring Boot Auto-Configuration work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'It attempts to guess and configure beans you are likely to need based on your classpath. It uses `@Conditional` annotations (e.g., `@ConditionalOnClass`, `@ConditionalOnMissingBean`) inside configuration classes listed in `META-INF/spring.factories` (or `org.springframework.boot.autoconfigure.AutoConfiguration.imports` in newer versions).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-006',
      'spring-boot',
      'Constructor Injection vs Field Injection.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Constructor injection (passing dependencies via constructor) is the recommended best practice. It ensures the object is initialized in a complete state, makes the class easier to unit test without Spring, and allows dependencies to be `final`. Field injection (`@Autowired` on a field) is discouraged because it hides dependencies and makes testing harder.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-007',
      'spring-boot',
      'Difference between @Component, @Service, @Repository, and @Controller?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`@Component` is a generic stereotype for any Spring-managed component. `@Service`, `@Repository`, and `@Controller` are specializations of `@Component` used for specific layers. `@Repository` provides automatic translation of database exceptions. `@Controller` marks a class as a web handler. `@Service` currently adds no special behavior but clarifies intent.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-008',
      'spring-boot',
      'What is the Bean lifecycle in Spring?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Instantiation. 2. Populate Properties (DI). 3. BeanNameAware / BeanFactoryAware. 4. Pre-initialization (`BeanPostProcessor.postProcessBeforeInitialization`). 5. Initialization (`@PostConstruct`, `afterPropertiesSet`). 6. Post-initialization (`BeanPostProcessor.postProcessAfterInitialization`, where AOP proxies are created). 7. Ready for use. 8. Destruction (`@PreDestroy`, `destroy()`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-009',
      'spring-boot',
      'What are the default bean scopes in Spring?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The default scope is `Singleton` (one instance per Spring IoC container). Other scopes: `Prototype` (new instance every time it is requested), `Request` (one per HTTP request), `Session` (one per HTTP session), and `Application` (one per ServletContext).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-010',
      'spring-boot',
      'Difference between @Controller and @RestController?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`@Controller` is used for traditional web applications returning Views (HTML). You must use `@ResponseBody` on methods to return data. `@RestController` is a convenience annotation that combines `@Controller` and `@ResponseBody`, meaning every method returns data (JSON/XML) directly to the response body.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-011',
      'spring-boot',
      'How do you handle exceptions globally in Spring Boot?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use the `@ControllerAdvice` or `@RestControllerAdvice` annotation on a class. Inside, use `@ExceptionHandler(SpecificException.class)` on methods to catch unhandled exceptions thrown by any controller and return a standardized error response (e.g., a custom ErrorDTO and HTTP status).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-012',
      'spring-boot',
      'What is Spring Data JPA?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It is a layer on top of JPA (Java Persistence API) providers like Hibernate. It significantly reduces boilerplate by allowing you to define repository interfaces (extending `JpaRepository`). Spring automatically generates the implementation and common CRUD methods at runtime.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-013',
      'spring-boot',
      'Difference between CrudRepository and JpaRepository?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`CrudRepository` provides basic CRUD operations. `JpaRepository` extends `PagingAndSortingRepository` (which extends `CrudRepository`) and adds JPA-specific methods like flushing the persistence context (`flush()`) and batch deletion (`deleteInBatch()`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-014',
      'spring-boot',
      'What is the @Transactional annotation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It defines the scope of a single database transaction. If an unchecked exception (RuntimeException) is thrown within the annotated method, the transaction automatically rolls back. If it finishes successfully, it commits. Can be applied to classes or methods.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-015',
      'spring-boot',
      'What are Transaction Propagation levels?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Define how transactions relate to each other when methods call other transactional methods. Default is `REQUIRED` (use existing, or create new if none exists). Others: `REQUIRES_NEW` (always create a new one, suspending the current), `SUPPORTS` (use if exists, else run non-transactional), `MANDATORY` (throw exception if no transaction exists).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-016',
      'spring-boot',
      'What is Spring Security?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A powerful and highly customizable authentication and access-control framework. It intercepts requests via a chain of Servlet Filters to handle authentication (who are you?) and authorization (are you allowed to do this?).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-017',
      'spring-boot',
      'Explain the Filter Chain in Spring Security.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A sequence of filters managed by `FilterChainProxy`. Includes filters like `UsernamePasswordAuthenticationFilter` (processes logins), `BasicAuthenticationFilter` (processes HTTP Basic auth), and `FilterSecurityInterceptor` (checks authorization rules at the end of the chain before allowing access to the Controller).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-018',
      'spring-boot',
      'How do you secure a REST API with JWT in Spring Boot?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Create a custom authentication filter that extends `OncePerRequestFilter`. 2. Extract the JWT from the Authorization header. 3. Validate the token signature using a library (e.g., jjwt). 4. Load the user authorities and place them in the `SecurityContextHolder`. 5. Register the filter in the `SecurityFilterChain`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-019',
      'spring-boot',
      'What is Spring Boot Actuator?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A module providing production-ready features. It exposes HTTP endpoints (e.g., `/actuator/health`, `/actuator/metrics`, `/actuator/info`) to monitor and manage your application, view loaded beans, environment variables, and thread dumps.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-020',
      'spring-boot',
      'What is AOP (Aspect-Oriented Programming) in Spring?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A programming paradigm that aims to increase modularity by allowing the separation of cross-cutting concerns (like logging, security, transactions). It uses "Aspects" containing "Advice" (code to run) applied at "Pointcuts" (where to run it, like before specific methods).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-021',
      'spring-boot',
      'Explain @Primary vs @Qualifier.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When multiple beans of the same type exist, DI will fail with a `NoUniqueBeanDefinitionException`. `@Primary` on a bean makes it the default choice. `@Qualifier("beanName")` is used at the injection point to explicitly specify WHICH bean by name should be injected.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-022',
      'spring-boot',
      'What is the purpose of application.properties / application.yml?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Files used to configure Spring Boot applications. Used for defining server ports, database connection details, logging levels, custom properties, and overriding default auto-configuration values.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-023',
      'spring-boot',
      'How do you manage database schema changes in Spring Boot?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Do not rely on Hibernate''s `hbm2ddl.auto=update` in production. Use migration tools like Flyway or Liquibase. You place SQL scripts in `src/main/resources/db/migration`, and Spring Boot automatically executes them on startup to keep the schema versioned and synchronized.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-024',
      'spring-boot',
      'What is the N+1 select problem in Hibernate and how to fix it?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when you fetch a list of entities (1 query) and then access a lazily loaded collection on each entity, resulting in N additional queries. Fixes: 1. Use `JOIN FETCH` in JPQL/HQL. 2. Use `@EntityGraph`. 3. Use `@BatchSize`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-025',
      'spring-boot',
      'Explain Spring Profiles.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Profiles provide a way to segregate parts of your application configuration and make it available only in certain environments (e.g., `dev`, `test`, `prod`). Activated via `spring.profiles.active`. You can have environment-specific files like `application-prod.yml`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-026',
      'spring-boot',
      'Difference between @RequestParam and @PathVariable?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`@PathVariable` extracts values from the URI path (e.g., `/users/{id}`). `@RequestParam` extracts values from the URI query string (e.g., `/users?id=123`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-027',
      'spring-boot',
      'How does Spring handle validation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using the Hibernate Validator (JSR 380). You annotate your DTO fields with rules like `@NotNull`, `@Size`, `@Email`. In the controller, you add the `@Valid` annotation to the `@RequestBody` parameter. If validation fails, a `MethodArgumentNotValidException` is thrown.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-028',
      'spring-boot',
      'What is the purpose of @Value?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Used to inject values from properties files into fields. Example: `@Value("${server.port}") private int port;`. Can also use SpEL (Spring Expression Language).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-029',
      'spring-boot',
      'Explain @ConfigurationProperties.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A strongly typed way to bind external configuration (properties/YAML) to Java objects. Unlike `@Value`, it binds an entire prefix (e.g., `app.mail.*`) to a POJO with matching fields. It supports validation and generates metadata for IDE autocompletion.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-030',
      'spring-boot',
      'What is the role of the DispatcherServlet?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The heart of Spring MVC. It acts as the Front Controller, intercepting all incoming HTTP requests. It consults the `HandlerMapping` to find the appropriate Controller, invokes it, takes the returned ModelAndView, resolves the view (or serializes to JSON via message converters), and returns the response.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-031',
      'spring-boot',
      'How do you schedule tasks in Spring Boot?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Add `@EnableScheduling` to a configuration class. 2. Add `@Scheduled` to a method (must return void and take no arguments). You can specify a `fixedRate`, `fixedDelay`, or a `cron` expression.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-032',
      'spring-boot',
      'What is the Spring Context (ApplicationContext)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The advanced Spring IoC container. It is responsible for instantiating, configuring, and assembling beans. It extends `BeanFactory` with extra features like event publishing, internationalization, and AOP.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-033',
      'spring-boot',
      'How to do asynchronous processing in Spring Boot?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Add `@EnableAsync` to a configuration class. 2. Annotate a method with `@Async`. Spring will execute this method in a separate thread from a thread pool. The method can return `void` or a `CompletableFuture`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-034',
      'spring-boot',
      'What are Spring Boot Starters?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Dependency descriptors that aggregate common dependencies into a single package. Examples: `spring-boot-starter-web` (REST, Tomcat, Jackson), `spring-boot-starter-data-jpa` (Hibernate, Spring Data).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-035',
      'spring-boot',
      'Explain the difference between @Bean and @Component.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`@Component` is a class-level annotation where Spring automatically detects and registers the class as a bean (via component scanning). `@Bean` is a method-level annotation (usually inside a `@Configuration` class) where you manually instantiate and configure the bean before returning it to the container. Used heavily for third-party classes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-036',
      'spring-boot',
      'What is Hibernate?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An Object-Relational Mapping (ORM) framework for Java. It maps Java classes to database tables and translates Java data types to SQL data types, saving developers from writing raw SQL.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-037',
      'spring-boot',
      'What is the L1 and L2 cache in Hibernate?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'L1 Cache: Session-level cache, enabled by default. Exists only for the duration of the transaction/session. L2 Cache: SessionFactory-level cache, disabled by default. Shared across all sessions. Requires a third-party provider like Ehcache.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-038',
      'spring-boot',
      'How do you test a Spring Boot application?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use `@SpringBootTest` for integration testing (loads the entire application context). Use `@WebMvcTest` to test only the web layer (MockMvc). Use `@DataJpaTest` to test repositories with an in-memory database like H2. Use `@MockBean` to mock dependencies.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-039',
      'spring-boot',
      'What is @MockBean vs @Mock?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`@Mock` (Mockito) creates a standalone mock object. `@MockBean` (Spring Boot Test) creates a mock object AND replaces the existing bean of the same type in the Spring ApplicationContext. Essential for integration testing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-040',
      'spring-boot',
      'What is CORS and how to enable it in Spring Boot?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cross-Origin Resource Sharing. Enable it locally using the `@CrossOrigin` annotation on a Controller class or method. Enable it globally by implementing `WebMvcConfigurer` and overriding `addCorsMappings()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-041',
      'spring-boot',
      'Explain standard vs mapped superclass in JPA.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '`@MappedSuperclass` defines common fields (like `createdAt`, `updatedAt`) for subclasses to inherit. The superclass itself is NOT an entity and has no table. If it were a regular `@Entity` and inherited, JPA would use inheritance strategies like Single Table or Joined.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-042',
      'spring-boot',
      'What are Entity callbacks in JPA?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Methods annotated with `@PrePersist`, `@PostPersist`, `@PreUpdate`, etc. They execute automatically at specific stages of the entity lifecycle. Useful for setting audit fields (e.g., `updatedAt = new Date()`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-043',
      'spring-boot',
      'Difference between @Query and method naming conventions in Spring Data?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Method names (e.g., `findByLastNameAndAge`) auto-generate SQL queries. `@Query` allows writing custom JPQL or native SQL (`nativeQuery = true`) directly on the repository interface for complex operations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-044',
      'spring-boot',
      'What is a DTO and why use it?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Data Transfer Object. An object used to encapsulate data and send it from one subsystem to another. Prevents exposing internal domain models (Entities) directly to the API client, avoiding security risks and over-fetching.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-045',
      'spring-boot',
      'How to handle file uploads in Spring Boot?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use `MultipartFile` as a parameter in your `@PostMapping`. Ensure your form specifies `enctype="multipart/form-data"`. Spring automatically parses the multipart request.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-046',
      'spring-boot',
      'What is Spring WebFlux?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The reactive-stack web framework in Spring. Non-blocking, asynchronous, and event-driven. Runs on Netty instead of Tomcat. Uses Project Reactor (`Mono` for 0-1 items, `Flux` for 0-N items). Best for high-concurrency systems.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-047',
      'spring-boot',
      'What is the purpose of @ControllerAdvice?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A specialization of `@Component` that allows you to consolidate multiple scattered `@ExceptionHandler` methods into a single, global error handling component applied to all Controllers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-048',
      'spring-boot',
      'How do you externalize configuration in Spring Boot?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using `application.properties`, environment variables, command-line arguments, or Spring Cloud Config server. Spring evaluates them in a specific order (e.g., command-line args override env vars, which override properties files).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-049',
      'spring-boot',
      'What is the `RestTemplate` vs `WebClient`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`RestTemplate` is the traditional synchronous HTTP client in Spring. `WebClient` (from WebFlux) is the modern, non-blocking, reactive HTTP client. Spring explicitly recommends `WebClient` for new developments.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sb-050',
      'spring-boot',
      'What is Jackson in Spring Boot?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The default JSON processing library. It automatically serializes Java objects returned by `@RestController` into JSON, and deserializes JSON from `@RequestBody` into Java objects. Configurable via annotations like `@JsonIgnore` or `@JsonProperty`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-001',
      'microservices',
      'What are Microservices?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An architectural style that structures an application as a collection of loosely coupled, independently deployable services. Each service is organized around a specific business capability, owns its own database, and communicates via lightweight protocols (HTTP/REST, gRPC, or messaging queues).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-002',
      'microservices',
      'Monolith vs Microservices: When to use which?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Monolith: Best for early-stage startups, small teams, simple domains, fast prototyping. Easier to deploy and debug. Microservices: Best for large teams, complex domains, high scalability needs, polyglot environments. Harder to deploy, test, and monitor (distributed systems complexity).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-003',
      'microservices',
      'What is the CAP Theorem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In a distributed data store, you can only guarantee two out of three: Consistency (all nodes see same data), Availability (every request receives a response), and Partition tolerance (system operates despite network failures). Because networks DO fail (P is given), you must choose between CP (Consistency) or AP (Availability).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-004',
      'microservices',
      'What is Eventual Consistency?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A consistency model used in distributed systems to achieve high availability (AP in CAP theorem). It guarantees that if no new updates are made to a given data item, eventually all accesses to that item will return the last updated value.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-005',
      'microservices',
      'What is an API Gateway?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A server that acts as the single entry point into the system. It routes requests to the appropriate microservice, aggregates results, and handles cross-cutting concerns like authentication, SSL termination, rate limiting, and CORS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-006',
      'microservices',
      'Explain the Backend For Frontend (BFF) pattern.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Instead of one generic API Gateway for all clients, you create a specific gateway for each UI (e.g., one for Web, one for iOS, one for Android). It optimizes payload sizes and reduces over-fetching by tailoring the data aggregation to the specific client''s needs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-007',
      'microservices',
      'What is Service Discovery?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'In a cloud environment, service IP addresses change dynamically due to scaling or failures. Service Discovery (e.g., Netflix Eureka, Consul, Kubernetes DNS) allows services to find each other dynamically without hardcoding IP addresses.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-008',
      'microservices',
      'Client-side vs Server-side Service Discovery?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Client-side: The client queries the service registry, picks an available instance (via load balancing), and makes the request directly. Server-side: The client sends a request to a Load Balancer / Router, which queries the registry and forwards the request. Kubernetes uses server-side.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-009',
      'microservices',
      'What is the Circuit Breaker pattern?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Prevents a network or service failure from cascading to other services. If a service fails repeatedly, the circuit breaker "trips" (Opens) and immediately fails subsequent calls, giving the failing service time to recover. Implemented using libraries like Resilience4j or Hystrix.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-010',
      'microservices',
      'Explain Circuit Breaker states.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Closed: Normal operation, requests flow through. Open: Failure threshold reached, requests fail fast immediately without attempting the call. Half-Open: After a timeout, allows a limited number of test requests. If they succeed, it Closes; if they fail, it re-Opens.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-011',
      'microservices',
      'What is the Saga Pattern?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Manages distributed transactions across multiple microservices. Instead of traditional ACID transactions (2PC, which block), a Saga is a sequence of local transactions. Each local transaction updates the database and publishes a message/event to trigger the next transaction.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-012',
      'microservices',
      'Choreography vs Orchestration in Sagas?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Choreography: Decentralized. Each service publishes events, and other services subscribe and react. Good for simple workflows. Orchestration: Centralized. A central "Orchestrator" service tells participating services what local transactions to execute. Good for complex workflows.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-013',
      'microservices',
      'What are Compensating Transactions?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Used in the Saga pattern. If a step in the distributed transaction fails, you cannot simply "rollback" the previous steps because their local DB transactions already committed. You must execute Compensating Transactions (semantic rollbacks) to undo the work of the previous steps.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-014',
      'microservices',
      'What is CQRS?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Command Query Responsibility Segregation. Separates the read (Query) operations from the write (Command) operations, often using completely separate databases (e.g., PostgreSQL for writes, Elasticsearch for reads) optimized for their specific tasks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-015',
      'microservices',
      'What is Event Sourcing?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Instead of storing the current state of an entity in the database, you store a sequence of immutable state-changing events. The current state is derived by replaying the events. Often paired with CQRS. Enables perfect audit logs and point-in-time recovery.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-016',
      'microservices',
      'How do microservices communicate?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Synchronous: HTTP/REST, gRPC. The caller waits for the response. Can lead to cascading failures and tight coupling. Asynchronous: Message Brokers (RabbitMQ), Event Streaming (Kafka). Caller sends a message and doesn''t wait. Decoupled and highly scalable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-017',
      'microservices',
      'Difference between RabbitMQ and Kafka?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'RabbitMQ is a traditional message broker (Smart Broker, Dumb Consumer). Messages are deleted after consumption. Focuses on routing and exact delivery. Kafka is an event streaming platform (Dumb Broker, Smart Consumer). Events are appended to a log and retained. Focuses on high throughput and replayability.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-018',
      'microservices',
      'What is Distributed Tracing?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A method to track a request as it flows through multiple microservices. A unique Trace ID is generated at the gateway and passed in HTTP headers to every downstream service. Tools like Jaeger or Zipkin use this to visualize the request path and identify latency bottlenecks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-019',
      'microservices',
      'What is the Strangler Fig Pattern?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A strategy for migrating a monolithic application to microservices. An API Gateway intercepts traffic. You gradually extract features from the monolith into new microservices and route traffic to the new services, slowly "strangling" the monolith until it can be deleted.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-020',
      'microservices',
      'Explain the Bulkhead pattern.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Isolating elements of an application into pools so that if one fails, the others continue functioning. E.g., allocating separate thread pools for different downstream service calls, so a slow downstream service doesn''t exhaust all threads in the calling service.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-021',
      'microservices',
      'What is Database per Service?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A core microservice principle. Each service must have its own database (or schema). Services cannot access each other''s databases directly. This ensures loose coupling. Data must be accessed only via the service''s API.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-022',
      'microservices',
      'How do you handle Distributed Data Joins?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Since databases are isolated, you cannot do SQL joins across services. Solutions: 1. API Composition (Gateway queries multiple services and joins in memory). 2. CQRS/Materialized Views (Subscribe to events from other services and maintain a denormalized read-replica).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-023',
      'microservices',
      'What is Idempotency and why is it critical?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An operation is idempotent if executing it multiple times yields the same result as executing it once. Critical in distributed systems because network failures can cause retries. If a payment service isn''t idempotent, a retry could charge the user twice.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-024',
      'microservices',
      'What is an Idempotency Key?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A unique string provided by the client when making a mutation (POST). The server stores this key. If the client retries the exact same request due to a timeout, the server sees the key, skips execution, and returns the cached response of the first successful attempt.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-025',
      'microservices',
      'What is the Two-Phase Commit (2PC) protocol?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A distributed algorithm to ensure atomic transactions across multiple databases. Phase 1 (Prepare): Coordinator asks databases if they can commit. Phase 2 (Commit): If all say yes, it tells them to commit. Rarely used in microservices because it blocks resources and scales poorly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-026',
      'microservices',
      'Explain the Outbox Pattern.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Solves the "Dual Write" problem (updating the database AND publishing an event atomically). You update the business entity AND insert an event record into an "Outbox" table in the SAME local database transaction. A separate process reads the outbox table and publishes the events to the message broker.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-027',
      'microservices',
      'What is a Service Mesh?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A dedicated infrastructure layer for handling service-to-service communication. It uses a "sidecar" proxy (like Envoy) deployed alongside every service instance to handle load balancing, encryption (mTLS), retries, circuit breaking, and telemetry, removing this logic from application code. E.g., Istio, Linkerd.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-028',
      'microservices',
      'What is Centralized Logging?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'In microservices, logs are scattered across hundreds of containers. Centralized logging (e.g., ELK stack: Elasticsearch, Logstash, Kibana) aggregates all logs into a single searchable interface. Requires structured logging (JSON) and correlation IDs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-029',
      'microservices',
      'Explain Canary Deployment.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Deploying a new version of a service to a small percentage of users (e.g., 5%). If metrics and error rates remain stable, traffic is gradually shifted to the new version until it reaches 100%. Reduces the risk of a faulty release impacting all users.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-030',
      'microservices',
      'Explain Blue-Green Deployment.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Maintaining two identical production environments (Blue and Green). Only one is live at a time. You deploy the new version to the idle environment, test it, and then switch the router to point all traffic to it instantly. Enables zero-downtime deployments and instant rollbacks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-031',
      'microservices',
      'What is a Correlation ID?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A unique identifier (UUID) generated at the entry point of a system (Gateway) and passed along in the headers of every inter-service HTTP/gRPC call or message payload. Crucial for aggregating centralized logs for a specific request.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-032',
      'microservices',
      'What is Bounded Context?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A concept from Domain-Driven Design (DDD). It is the boundary within which a particular domain model is defined and applicable. Microservices should perfectly align with bounded contexts to ensure high cohesion and loose coupling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-033',
      'microservices',
      'How do you handle Authentication in Microservices?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Usually handled at the API Gateway. The Gateway authenticates the user (via OAuth2/JWT), validates the token, and passes the parsed user claims (user ID, roles) in HTTP headers to the downstream microservices. Downstream services do not need to query the Auth DB.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-034',
      'microservices',
      'What is an Anti-Corruption Layer (ACL)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A translation layer between two subsystems (usually a new microservice and an old monolith). It translates data formats and API concepts so the new system doesn''t have to conform to the legacy system''s flawed or outdated domain model.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-035',
      'microservices',
      'Explain the Retry Pattern with Exponential Backoff.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When a network call fails, automatically retrying it. Exponential backoff increases the wait time between retries (e.g., 1s, 2s, 4s, 8s) to avoid flooding a struggling service. Should always be combined with Jitter (adding randomness to the wait time) to prevent thundering herd problems.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-036',
      'microservices',
      'What is the Thundering Herd problem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when many clients/services simultaneously attempt to connect to a service or read from a cache that just restarted or expired. The sudden spike in traffic crashes the service. Mitigated by Jitter in retries and cache warming.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-037',
      'microservices',
      'How to manage Configuration in Microservices?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Configuration (DB urls, feature flags) should be externalized. Use a Centralized Configuration Server (like Spring Cloud Config, Consul, or Kubernetes ConfigMaps). Services fetch config on startup and can optionally listen for live updates.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-038',
      'microservices',
      'What is a Sidecar Pattern?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Deploying a helper process/container alongside the main application container in the same pod. The sidecar shares the same lifecycle and network. Used for logging agents, proxying (Envoy in Service Mesh), or fetching configurations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-039',
      'microservices',
      'What is gRPC and why use it in Microservices?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Google Remote Procedure Call. Uses Protocol Buffers (binary serialization) and HTTP/2. Much faster, smaller payload size, and strictly typed compared to JSON/REST. Ideal for low-latency internal communication between microservices.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-040',
      'microservices',
      'Explain Semantic Versioning for APIs.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'MAJOR.MINOR.PATCH. Major for breaking API changes, Minor for backward-compatible additions, Patch for bug fixes. Crucial in microservices to ensure teams don''t break upstream consumers when updating their services.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-041',
      'microservices',
      'What is Chaos Engineering?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The practice of intentionally injecting failures into a production system (killing instances, introducing network latency) to test the system''s resilience, circuit breakers, and auto-scaling mechanisms. Popularized by Netflix''s Chaos Monkey.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-042',
      'microservices',
      'What is polyglot persistence?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The practice of using different database technologies for different microservices based on their specific needs. E.g., a search service uses Elasticsearch, a relationship service uses Neo4j, and a transactional service uses PostgreSQL.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-043',
      'microservices',
      'What is the API Composition pattern?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When a client needs data that spans multiple microservices, an "API Composer" (often the Gateway or BFF) makes individual calls to each service and joins/aggregates the data in memory before returning a single unified response to the client.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-044',
      'microservices',
      'What is Consumer-Driven Contract Testing?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A testing methodology where the consumer of an API defines their expectations (the "contract"). The provider then runs tests against this contract to ensure they don''t break it. Pact is a popular tool. Prevents integration failures without heavy end-to-end testing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-045',
      'microservices',
      'What is Dead Letter Queue (DLQ)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A queue where a message broker sends messages that cannot be successfully processed by consumers after multiple retries (due to bugs, bad formatting). Developers monitor the DLQ to investigate and fix the issues.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-046',
      'microservices',
      'Explain the Token Relay pattern.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The API Gateway authenticates the user and obtains a JWT. When the Gateway calls a downstream service, it relays this token in the header. If the downstream service calls another service, it continues to relay the token, ensuring user context is preserved.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-047',
      'microservices',
      'What is the Ambassador Pattern?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Similar to the Sidecar pattern, but specifically used to encapsulate network capabilities. An ambassador container handles routing, retries, and monitoring for the main application container, acting as a proxy to the outside world.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-048',
      'microservices',
      'How do you handle shared libraries in Microservices?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Avoid sharing domain logic via libraries, as it couples services and requires simultaneous updates. Share only cross-cutting infrastructure code (logging, auth parsing, error formatting) as versioned packages.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-049',
      'microservices',
      'What is Health Checking?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Every microservice must expose a `/health` endpoint. The orchestrator (Kubernetes) or Load Balancer continuously polls this. If it returns non-200, the instance is marked as unhealthy, removed from rotation, and eventually restarted.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ms-050',
      'microservices',
      'What is the 12-Factor App methodology?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A set of best practices for building modern, scalable, cloud-native apps (microservices). Key rules: Codebase in version control, externalize dependencies, store config in environment variables, treat backing services as attached resources, stateless processes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-001',
      'react',
      'What is the Virtual DOM and how does React use it?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The Virtual DOM is a lightweight JavaScript representation of the actual DOM. When state changes, React creates a new Virtual DOM tree, compares it with the previous one (diffing), and calculates the minimum number of changes needed (reconciliation) before updating the real DOM. This batched approach is faster than direct DOM manipulation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-002',
      'react',
      'Explain the difference between useEffect and useLayoutEffect.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'useEffect runs asynchronously AFTER the browser paints the DOM, so it doesn''t block rendering. useLayoutEffect runs synchronously immediately after React performs all DOM mutations, BEFORE the browser paints. useLayoutEffect is used when you need to read DOM measurements and mutate the DOM again to prevent visual flickering. Example: measuring tooltip position before it renders.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-003',
      'react',
      'What are React Server Components (RSC)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'RSCs execute only on the server and never ship their JavaScript to the client, reducing bundle size. They can directly access backend resources (like databases) and are streamed to the client as HTML/UI descriptions. Client components (marked with ''use client'') are used for interactivity. RSCs cannot use hooks or browser APIs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-004',
      'react',
      'How do you optimize performance in a React application?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Use React.memo() to memoize functional components. 2. Use useMemo() for expensive calculations. 3. Use useCallback() to memoize functions passed as props. 4. Code split using React.lazy() and Suspense. 5. Avoid inline objects/functions in props if they cause unnecessary re-renders. 6. Virtualize long lists using react-window or react-virtuoso. 7. Use the React DevTools Profiler to identify bottlenecks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-005',
      'react',
      'What is the Context API and when should you use it?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Context provides a way to pass data through the component tree without having to pass props down manually at every level (prop drilling). It is ideal for global state like themes, user authentication, or language preferences. It should not be used for high-frequency state changes as it triggers a re-render of ALL consuming components.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-006',
      'react',
      'Explain React Fiber architecture.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'React Fiber is the reimplementation of React''s core algorithm (introduced in React 16). It enables incremental rendering — the ability to split rendering work into chunks and spread it over multiple frames. Key concepts: each element is represented as a Fiber node (a JS object with type, key, child, sibling, return pointers). The work loop can pause, resume, and prioritize updates. This enables concurrent features like Suspense and transitions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-007',
      'react',
      'What is the difference between controlled and uncontrolled components?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Controlled components have their form data handled by React state. The value is set via a state variable and changes are handled by an onChange handler. Uncontrolled components store their own state internally in the DOM and you access values using refs. Controlled components give React full control and are preferred for validation, conditional disabling, and enforcing input formats.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-008',
      'react',
      'How does React reconciliation work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Reconciliation is the algorithm React uses to diff two Virtual DOM trees and determine the minimum set of changes. Key heuristics: 1. Elements of different types produce different trees (full re-mount). 2. The developer can hint at which child elements are stable across renders with keys. 3. React compares elements at the same level (breadth-first). Keys must be stable, predictable, and unique among siblings.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-009',
      'react',
      'What are Higher-Order Components (HOCs) and what are their drawbacks?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An HOC is a function that takes a component and returns a new component with additional props/behavior. Example: withAuth(Component). Drawbacks: 1. Wrapper hell (deeply nested components). 2. Name collisions in props. 3. Static composition only (can''t use in render). 4. Refs don''t pass through without forwardRef. Hooks have largely replaced HOCs for cross-cutting concerns.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-010',
      'react',
      'Explain the useReducer hook and when to use it over useState.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'useReducer accepts a reducer function and initial state, returning current state and a dispatch function. Use useReducer when: 1. State logic is complex with multiple sub-values. 2. The next state depends on the previous one. 3. You want to optimize performance for deep component trees by passing dispatch instead of callbacks. It follows the Redux pattern: (state, action) => newState.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-011',
      'react',
      'What are Error Boundaries and how do you implement them?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Error Boundaries are React components that catch JavaScript errors anywhere in their child component tree, log those errors, and display a fallback UI. They catch errors during rendering, in lifecycle methods, and in constructors. They do NOT catch errors in event handlers, async code, or SSR. They must be class components using componentDidCatch and static getDerivedStateFromError.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-012',
      'react',
      'What is React.memo and how does it differ from useMemo?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'React.memo is a higher-order component that memoizes the rendered output of a component, preventing re-renders if props haven''t changed (shallow comparison). useMemo is a hook that memoizes the return value of a function, recomputing only when dependencies change. React.memo works at the component level; useMemo works at the value level within a component.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-013',
      'react',
      'Explain the concept of lifting state up.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Lifting state up is a pattern where shared state is moved to the closest common ancestor of the components that need it. Instead of syncing state between siblings, you lift the state to the parent, which passes it down as props. The parent also passes down handler functions so children can request state changes. This ensures a single source of truth.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-014',
      'react',
      'What are React Portals and when would you use them?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Portals provide a way to render children into a DOM node that exists outside the parent component''s DOM hierarchy, while still preserving the React tree context (events bubble up through the React tree, not the DOM tree). Use cases: modals, tooltips, dropdowns that need to escape overflow:hidden or z-index stacking contexts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-015',
      'react',
      'What is the difference between useRef and createRef?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'useRef returns a mutable ref object that persists for the full lifetime of the component. createRef creates a new ref on every render. In functional components, always use useRef. createRef is for class components. useRef can also store any mutable value (not just DOM refs) — like a previous value, timer ID, or any instance variable equivalent.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-016',
      'react',
      'Explain React Suspense and its use cases.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Suspense lets you declaratively specify a loading state for a part of the component tree. It works with React.lazy for code splitting and with data fetching libraries that support it (Relay, React Query with experimental features). When a child "suspends" (throws a Promise), Suspense catches it and shows the fallback UI until the Promise resolves.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-017',
      'react',
      'What are custom hooks and what rules must they follow?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Custom hooks are JavaScript functions whose name starts with "use" that can call other hooks. They allow you to extract component logic into reusable functions. Rules: 1. Name must start with "use". 2. Can only be called at the top level (no loops, conditions, nested functions). 3. Can only be called from React function components or other custom hooks. They share logic, not state — each call gets its own isolated state.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-018',
      'react',
      'How does the key prop work and why is using index as key problematic?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The key prop helps React identify which items in a list have changed, been added, or removed. Keys should be stable, predictable, and unique among siblings. Using array index as key is problematic when: 1. Items are reordered (React reuses wrong DOM elements). 2. Items are added/removed from the middle (incorrect state association). 3. Components have internal state. Use unique IDs from your data instead.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-019',
      'react',
      'Explain the useCallback hook with a real-world example.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'useCallback returns a memoized version of a callback function that only changes if one of the dependencies has changed. This is useful when passing callbacks to optimized child components that rely on reference equality to prevent unnecessary renders.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-020',
      'react',
      'What is the useTransition hook?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'useTransition is a React 18 concurrent feature that lets you mark state updates as non-urgent (transitions). While a transition is pending, React can interrupt it to handle more urgent updates (like user input). It returns [isPending, startTransition]. Use it for expensive re-renders like filtering large lists, so typing in a search box stays responsive.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-021',
      'react',
      'What is the difference between props.children and render props?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'props.children is the content placed between a component''s opening and closing tags — it can be anything renderable. Render props is a pattern where a prop (often called "render" or "children") is a function that returns JSX, allowing the parent to pass data to the child''s rendering logic. Render props give more control but can lead to nesting; hooks have largely replaced this pattern.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-022',
      'react',
      'How would you implement code splitting in React?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Route-based: Use React.lazy() with Suspense for each route component. 2. Component-based: Lazy-load heavy components (charts, editors). 3. Library-based: Dynamic import() for large libraries. 4. Webpack magic comments for named chunks. The goal is to reduce the initial JS bundle size and load code on demand.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-023',
      'react',
      'What are compound components and how do you build them?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Compound components are a pattern where multiple components work together to form a complete UI, sharing implicit state via Context. Think of <select> and <option>. The parent manages state and children access it via context. This provides a flexible, declarative API. Example: <Tabs>, <Tab>, <TabPanel>.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-024',
      'react',
      'Explain React''s synthetic event system.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'React wraps native browser events in SyntheticEvent objects to normalize cross-browser differences. Key features: 1. Events are pooled (reused) for performance (pre-React 17). 2. Events delegate to the root (React 17+: the root container, not document). 3. Event names are camelCase (onClick, onChange). 4. Return false doesn''t prevent default — you must call e.preventDefault().',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-025',
      'react',
      'What is the useDeferredValue hook?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'useDeferredValue accepts a value and returns a deferred version that may "lag behind" the original. When an urgent update happens, React will first render with the old deferred value, then try rendering with the new value in the background. Similar to useTransition but for values received from parent components rather than state you control.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-026',
      'react',
      'How do you handle forms in React without a library?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use controlled components: store each input''s value in state, attach onChange handlers to update state, and use onSubmit on the form. For complex forms, useReducer is cleaner than multiple useState calls. Validate on change or on submit. Use the name attribute to create a generic handler: setForm(prev => ({...prev, [e.target.name]: e.target.value})).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-027',
      'react',
      'What is the difference between client-side and server-side rendering in React?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'CSR: The server sends a minimal HTML shell + JS bundle. React runs in the browser and renders everything. Faster page transitions, but slower initial load and poor SEO. SSR: The server renders the full HTML and sends it to the client. React then "hydrates" the HTML to make it interactive. Faster first contentful paint, better SEO, but higher server load. Frameworks: Next.js supports both.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-028',
      'react',
      'How does React handle batching of state updates?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In React 17, batching only works inside React event handlers (onClick, onChange). In React 18+ (automatic batching), ALL state updates are batched regardless of origin — including setTimeout, Promises, and native event handlers. Multiple setState calls in the same synchronous block result in a single re-render. You can force synchronous updates with flushSync().',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-029',
      'react',
      'What is hydration in React and what problems can occur?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Hydration is the process where React attaches event listeners and reconciles the existing server-rendered HTML with the client-side React tree. Problems: 1. Hydration mismatch errors (server HTML differs from client render — e.g., using Date.now() or window). 2. Full-page re-render if mismatches are severe. 3. Interactive delay (time between seeing content and being able to interact). React 18 supports selective hydration with Suspense.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-030',
      'react',
      'Explain the useImperativeHandle hook.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'useImperativeHandle customizes the instance value exposed to parent components when using ref with forwardRef. Instead of exposing the full DOM node, you can expose a limited API. Use sparingly — it breaks the declarative paradigm.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-031',
      'react',
      'What is prop drilling and how do you avoid it?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Prop drilling is passing props through multiple intermediate components that don''t need the data, just to reach a deeply nested component. Solutions: 1. Context API. 2. State management libraries (Zustand, Redux, Jotai). 3. Component composition (passing components as props/children). 4. Custom hooks that encapsulate context consumption.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-032',
      'react',
      'How do you implement infinite scrolling in React?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use the Intersection Observer API to detect when a sentinel element at the bottom of the list enters the viewport. When triggered, fetch the next page of data and append it. Libraries like react-infinite-scroll-component or react-virtuoso simplify this. For performance, use windowing/virtualization to only render visible items.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-033',
      'react',
      'What is the strict mode in React and what does it do?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'StrictMode is a development-only tool that highlights potential problems. It: 1. Double-invokes render functions and effects to detect side effects. 2. Warns about deprecated lifecycle methods. 3. Detects unexpected side effects in constructors. 4. Warns about legacy context API usage. It renders no visible UI and doesn''t affect the production build.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-034',
      'react',
      'Compare Redux, Zustand, and Jotai for state management.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Redux: Centralized store, strict unidirectional data flow, action/reducer pattern, excellent DevTools, boilerplate-heavy (RTK reduces this). Zustand: Minimal API, no providers needed, hook-based, lightweight (~1KB), uses subscriptions for selective re-renders. Jotai: Atomic state model (like Recoil), bottom-up approach, each atom is a piece of state, derived atoms via composition. Choose Redux for large teams/complex apps, Zustand for simplicity, Jotai for fine-grained reactivity.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-035',
      'react',
      'How do you test React components?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Unit tests: React Testing Library (RTL) + Jest/Vitest — test from the user''s perspective (find by role, text, label). 2. Avoid testing implementation details (don''t test state directly). 3. Integration tests: Render multiple components together. 4. E2E tests: Playwright or Cypress. 5. Use msw (Mock Service Worker) for API mocking. Key principle: "The more your tests resemble the way your software is used, the more confidence they give you."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-036',
      'react',
      'What is the Flux architecture?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Flux is a pattern (by Facebook) for managing data flow. It has 4 parts: 1. Actions: Objects describing what happened. 2. Dispatcher: Central hub that broadcasts actions to all stores. 3. Stores: Hold state and logic, update in response to actions. 4. Views: React components that re-render when stores change. Data flows unidirectionally: Action → Dispatcher → Store → View. Redux is a simplification of Flux.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-037',
      'react',
      'How does React handle accessibility (a11y)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'React supports all ARIA attributes as camelCase props (aria-label → aria-label, role, tabIndex). Best practices: 1. Use semantic HTML (button, nav, main). 2. Label all form inputs. 3. Manage focus for modals/dialogs. 4. Use <Fragment> to avoid unnecessary divs. 5. Test with screen readers. 6. Use eslint-plugin-jsx-a11y. 7. Keyboard navigation support. React''s htmlFor prop replaces HTML''s for attribute.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-038',
      'react',
      'What is the useId hook in React 18?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'useId generates unique IDs that are stable across server and client rendering, avoiding hydration mismatches. It''s designed for accessibility attributes like htmlFor/id pairs on form labels and inputs. It should NOT be used as keys in lists. The IDs include a colon character (like :r1:) to ensure uniqueness.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-039',
      'react',
      'Explain the concept of React Server Actions.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Server Actions are async functions that run on the server, defined with "use server" directive. They can be called from Client Components as form actions or event handlers. They enable mutations (create, update, delete) without building separate API endpoints. They integrate with React''s form handling, can revalidate cached data, and support progressive enhancement (work without JavaScript).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-040',
      'react',
      'How do you handle authentication state in a React app?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Store auth tokens in httpOnly cookies (most secure) or memory (not localStorage for sensitive tokens). 2. Create an AuthContext/AuthProvider wrapping the app. 3. Protect routes using a PrivateRoute component that checks auth state. 4. Use interceptors (Axios/fetch wrapper) to attach tokens to requests. 5. Handle token refresh on 401 responses. 6. Redirect to login on auth failure.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-041',
      'react',
      'What is the difference between useEffect cleanup and componentWillUnmount?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'useEffect cleanup runs: 1. Before the component unmounts (same as componentWillUnmount). 2. Before the effect re-runs due to dependency changes (this is different from componentWillUnmount). This means cleanup runs more often in hooks — it runs between every re-execution of the effect. This is important for subscription cleanup, interval clearing, and abort controllers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-042',
      'react',
      'How does the React compiler (React Forget) work?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The React Compiler (formerly React Forget) is a build-time tool that automatically memoizes React components and hooks. It analyzes your code to determine which values change between renders and inserts memoization (equivalent to useMemo/useCallback/React.memo) automatically. This eliminates the need for manual memoization and reduces the cognitive burden on developers. It understands the Rules of React and uses that knowledge to optimize safely.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-043',
      'react',
      'What are the rules of hooks?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '1. Only call hooks at the top level — not inside loops, conditions, or nested functions. This ensures hooks are called in the same order each render. 2. Only call hooks from React function components or custom hooks — not regular JavaScript functions or class components. These rules are enforced by the eslint-plugin-react-hooks plugin.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-044',
      'react',
      'Implement a custom useFetch hook.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A reusable hook for data fetching with loading, error, and data states, plus abort support.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-045',
      'react',
      'Explain React concurrent rendering.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Concurrent rendering allows React to prepare multiple versions of the UI at the same time. React can start rendering an update, pause in the middle, continue later, or abandon it entirely. It does NOT mean multi-threading — work happens on the main thread but in interruptible chunks. Key APIs: useTransition, useDeferredValue, Suspense. This enables keeping the UI responsive during heavy computations by prioritizing urgent updates (typing) over non-urgent ones (search results).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-046',
      'react',
      'What is a React fragment and why is it useful?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Fragments (<React.Fragment> or shorthand <>) let you group multiple elements without adding an extra DOM node. This is useful when a component needs to return multiple elements but wrapping them in a div would break CSS layouts (flexbox, grid) or semantic HTML (table rows). The long form <React.Fragment key={...}> accepts a key prop for use in lists.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-047',
      'react',
      'How would you implement debounced search in React?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a combination of immediate state for the input value and a debounced effect or callback for the actual search.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-048',
      'react',
      'What is the difference between state and props?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Props are read-only inputs passed from parent to child. They cannot be modified by the receiving component. State is internal, mutable data managed within a component using useState or useReducer. When state changes, the component re-renders. Props flow down (parent → child), state is local. A child can''t directly modify a parent''s state; it must call a callback function passed as a prop.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-049',
      'react',
      'How do you prevent unnecessary re-renders in React?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. React.memo() for components. 2. useMemo() for expensive computed values. 3. useCallback() for function references. 4. Split state to avoid broad re-renders. 5. Move state closer to where it''s used. 6. Use context selectors (or Zustand) to subscribe to specific state slices. 7. Avoid creating new objects/arrays in render. 8. Use React DevTools Profiler to identify which components re-render and why.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-050',
      'react',
      'What is the use hook in React 19?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The use hook (React 19) can read the value of a resource like a Promise or a Context. Unlike other hooks, use can be called conditionally and inside loops. When used with a Promise, it integrates with Suspense — the component suspends until the Promise resolves. When used with Context, it works like useContext but can be called conditionally, enabling patterns previously impossible with useContext.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-051',
      'react',
      'How do you implement dark mode in a React application?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '1. Create a ThemeContext with a toggle function. 2. Store preference in localStorage. 3. Respect system preference via prefers-color-scheme media query. 4. Apply a class (e.g., "dark") to the root element. 5. Use CSS variables or Tailwind''s dark: prefix for theming. 6. Initialize theme before first render to prevent flash of wrong theme (use a script in HTML head).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-052',
      'react',
      'Explain the useLayoutEffect use case with a real example.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use useLayoutEffect when you need to measure DOM elements and update state before the browser paints, to prevent visual flickering.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-053',
      'react',
      'What are render props and when would you use them?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A render prop is a technique where a component receives a function (via props) that it calls to determine what to render. The function receives data as arguments, allowing the consumer to control the rendering. Example: <Mouse render={({x,y}) => <Cursor x={x} y={y} />} />. Use when you need to share stateful logic between components. Largely replaced by custom hooks but still useful for component libraries.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-054',
      'react',
      'How does React handle list rendering optimization?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'React uses the key prop during reconciliation to match elements between renders. With stable keys: 1. React reorders existing DOM nodes instead of recreating them. 2. Component state is preserved. 3. Only changed items re-render. Without keys or with index keys: React may recreate all items, lose internal state, and cause visual bugs. Always use unique, stable identifiers as keys.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'react-055',
      'react',
      'What is the forwardRef API and why is it needed?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'forwardRef lets a component pass a ref it receives to a child DOM element. Without forwardRef, if you pass a ref to a custom component, the ref will point to the component instance (or be null for function components), not the underlying DOM element. It''s essential for reusable UI libraries where consumers need DOM access (e.g., focus management, measurements).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-001',
      'css',
      'Explain CSS Specificity.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Specificity determines which CSS rule is applied by browsers. It''s calculated using a 4-value system: Inline styles (1,0,0,0) > IDs (0,1,0,0) > Classes/Pseudo-classes/Attributes (0,0,1,0) > Elements/Pseudo-elements (0,0,0,1). `!important` overrides all of them. Universal selector (*) has 0 specificity.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-002',
      'css',
      'What is the Box Model?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The structure of every element: Content (innermost), Padding (transparent area around content), Border (around padding), Margin (transparent area around border). Default is `box-sizing: content-box` (width = content only). `box-sizing: border-box` includes padding and border in the specified width/height.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-003',
      'css',
      'Flexbox vs CSS Grid?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Flexbox is a 1-dimensional layout system (row OR column), content-driven (items dictate layout). Grid is a 2-dimensional system (rows AND columns), layout-driven (container dictates layout). Use Flexbox for component alignment, Grid for page structure.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-004',
      'css',
      'What are CSS Container Queries?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows elements to adapt their styling based on the size of a parent container rather than the viewport (media queries). Define a container with `container-type: inline-size`, then query it with `@container (min-width: 400px)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-005',
      'css',
      'Explain CSS Cascade Layers (@layer).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows explicit control over the cascade without relying on specificity hacks. You define layers (e.g., `@layer reset, base, components, utilities;`). Styles in later layers override earlier ones, regardless of selector specificity. `!important` inside lower layers beats `!important` in higher layers (reverses normal order).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-006',
      'css',
      'display: none vs visibility: hidden?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`display: none` removes the element from the document flow completely (takes zero space, inaccessible to screen readers). `visibility: hidden` hides the element visually but it still takes up space in the layout.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-007',
      'css',
      'What is BEM?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Block Element Modifier. A naming convention for CSS classes (`.block__element--modifier`). Creates a flat specificity structure, avoids styling conflicts, and makes CSS self-documenting.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-008',
      'css',
      'Explain CSS Custom Properties (Variables).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Live variables defined with `--name: value` and used via `var(--name)`. Unlike Sass variables, they cascade, can be updated at runtime via JS (`style.setProperty`), and inherit from parents. Ideal for theme toggling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-009',
      'css',
      'What is the :has() pseudo-class?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The CSS parent selector. `div:has(img)` selects a div ONLY if it contains an img. It enables complex relational styling previously only possible with JavaScript.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-010',
      'css',
      'Animations vs Transitions?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Transitions animate between two states and require a trigger (like `:hover`). Animations (`@keyframes`) can have multiple steps, loop infinitely, auto-play on load, and offer more control (direction, play-state).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-011',
      'css',
      'Difference between rem, em, and px?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`px` is absolute. `rem` is relative to the root (`<html>`) font size. `em` is relative to the parent element''s font size (which can cause compounding issues). Use `rem` for accessibility and consistent scaling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-012',
      'css',
      'What is z-index and Stacking Context?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '`z-index` controls the z-axis order of positioned elements. A Stacking Context is formed by certain properties (opacity < 1, transform, `isolation: isolate`, position + z-index). Elements inside a stacking context cannot interleave with elements outside it, regardless of their `z-index`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-013',
      'css',
      'What are CSS Logical Properties?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Properties that control layout based on the writing direction (RTL/LTR) rather than physical screen directions. e.g., `margin-inline-start` instead of `margin-left`. Essential for internationalization (i18n).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-014',
      'css',
      'How do you center a div?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '1. Flexbox: `display: flex; justify-content: center; align-items: center;` 2. Grid: `display: grid; place-items: center;` 3. Absolute: `position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%);`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-015',
      'css',
      'Explain the clamp() function.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Takes three values: minimum, preferred, and maximum (`clamp(min, val, max)`). Frequently used for fluid typography (`clamp(1.5rem, 4vw, 3rem)`) ensuring text scales with viewport but never gets too small or too large.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-016',
      'css',
      'What is the aspect-ratio property?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Allows you to define a preferred width-to-height ratio for an element (e.g., `aspect-ratio: 16 / 9`). Replaces the old "padding-bottom percentage" hack for responsive videos and images.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-017',
      'css',
      'Difference between relative, absolute, fixed, and sticky?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Relative: offset from its normal position. Absolute: removed from flow, offset relative to nearest positioned ancestor. Fixed: removed from flow, offset relative to viewport. Sticky: toggles between relative and fixed based on scroll position.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-018',
      'css',
      'What are pseudo-elements?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Keywords added to a selector that let you style a specific part of the selected element. `::before` and `::after` create virtual DOM nodes. Require the `content` property to render.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-019',
      'css',
      'Explain CSS Grid''s auto-fit vs auto-fill.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Both fill the row with as many columns as possible. `auto-fill` keeps empty grid tracks if there is extra space. `auto-fit` collapses empty tracks to 0 and stretches the existing items to fill the remaining space.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-020',
      'css',
      'What is the contain property?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Tells the browser that an element and its contents are independent of the rest of the DOM. Used for performance optimization. `contain: strict` stops layout, style, and paint calculations from leaking outside the element.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-021',
      'css',
      'What is a CSS Module?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A CSS file where all class names and animation names are scoped locally by default. Bundlers process them and generate unique string names (e.g., `.Button_xy3z`). Fixes global scope issues.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-022',
      'css',
      'What is Tailwind CSS?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A utility-first CSS framework. Instead of semantic class names (`.btn`), it uses descriptive classes (`bg-blue-500 text-white p-4`). Benefits: zero context switching, small final CSS bundle, no naming agonizing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-023',
      'css',
      'Explain hardware acceleration in CSS.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using the GPU for rendering certain CSS properties (transform, opacity) instead of the CPU. Triggered by `translate3d`, `translateZ`, or `will-change: transform`. Results in smoother 60fps animations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-024',
      'css',
      'What is the purpose of the will-change property?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Hints to the browser that an element is expected to change in the future, allowing the browser to set up optimizations (like creating a new composite layer) before the animation actually starts. Overuse causes memory issues.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-025',
      'css',
      'Difference between margin and padding?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Margin is the space OUTSIDE the border of an element (pushes other elements away). Padding is the space INSIDE the border (pushes content inward). Background colors apply to padding, but not margins.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-026',
      'css',
      'What is margin collapsing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When vertical margins of adjacent block-level elements touch, they combine (collapse) into a single margin equal to the larger of the two. Doesn''t happen in flexbox, grid, or absolute positioning.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-027',
      'css',
      'Explain the :is() and :where() pseudo-classes.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Both take a selector list and apply styles to any matching element. Difference: `:is()` takes the specificity of its most specific argument. `:where()` ALWAYS has a specificity of 0.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-028',
      'css',
      'How do you create a triangle using pure CSS?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Create a box with width/height 0. Apply a thick transparent border to all sides except one, which gets a solid color. The intersection of borders creates a triangle.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-029',
      'css',
      'What is the difference between opacity: 0 and visibility: hidden?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Both hide the element while taking up space. However, `opacity: 0` still captures pointer events (clicks), while `visibility: hidden` does not capture pointer events.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-030',
      'css',
      'Explain the calc() function.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Allows performing calculations to determine CSS property values. You can mix units (e.g., `width: calc(100vh - 50px)`). Must have spaces around the operator (`+` or `-`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-031',
      'css',
      'What are Media Queries?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'CSS rule (`@media`) used to apply styles only when certain conditions are met, usually viewport width (min-width, max-width) or device capabilities (prefers-color-scheme, hover).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-032',
      'css',
      'Mobile-first vs Desktop-first CSS?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Mobile-first (progressive enhancement) writes base styles for small screens and uses `min-width` media queries for larger screens. Desktop-first (graceful degradation) does the reverse using `max-width`. Mobile-first is the industry standard.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-033',
      'css',
      'What is the purpose of the content property?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Used exclusively with the `::before` and `::after` pseudo-elements to generate content dynamically via CSS. Without it, pseudo-elements will not render.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-034',
      'css',
      'What is CSS-in-JS?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A pattern where CSS is composed using JavaScript instead of defined in external files (e.g., Styled Components, Emotion). Benefits: scoped styles, dynamic styling based on JS variables, dead code elimination.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-035',
      'css',
      'Explain object-fit and object-position.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Used for replaced elements like `<img>` or `<video>`. `object-fit: cover` fills the box while maintaining aspect ratio (cropping if necessary). `contain` fits inside without cropping. `object-position` alters alignment.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-036',
      'css',
      'What is the difference between inline, block, and inline-block?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Block: takes full width, starts on a new line (div, p). Inline: takes only necessary width, ignores width/height/vertical-margin (span, a). Inline-block: flows like inline, but respects width/height/margins.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-037',
      'css',
      'What is font-display: swap?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A `@font-face` descriptor that tells the browser to immediately render text using a fallback system font, and swap it with the custom web font once it finishes downloading. Prevents FOIT (Flash of Invisible Text).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-038',
      'css',
      'Explain the clear property.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Used to control the behavior of floating elements. `clear: both` forces an element to move below any floated elements preceding it. Mostly obsolete in the era of Flexbox and Grid.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-039',
      'css',
      'What is a CSS reset vs normalize.css?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Reset (like Meyer''s Reset) strips all browser default styling (margins, padding, font-sizes) to 0. Normalize.css preserves useful defaults but corrects bugs and inconsistencies across different browsers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-040',
      'css',
      'Explain the pointer-events property.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Controls whether an element can be the target of mouse/touch events. `pointer-events: none` makes clicks "pass through" the element to whatever is underneath it. Used often for decorative overlays.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-041',
      'css',
      'What is the initial value in CSS?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The `initial` keyword applies the official CSS specification default value for a property. `unset` acts as `inherit` if the property is naturally inherited, and `initial` if it is not.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-042',
      'css',
      'Explain the text-overflow property.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Handles how overflowing text is signaled to users. Requires `white-space: nowrap` and `overflow: hidden`. `text-overflow: ellipsis` adds "..." at the end of the truncated text.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-043',
      'css',
      'What is the difference between filter and backdrop-filter?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`filter` applies graphical effects (blur, grayscale) to the element itself. `backdrop-filter` applies effects to the area BEHIND the element (creating glassmorphism effects), requiring a semi-transparent background.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-044',
      'css',
      'How do you create a sticky footer?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using flexbox: Set `body { display: flex; flex-direction: column; min-height: 100vh; }` and on the main content area use `flex-grow: 1;`. The footer will sit at the bottom even with sparse content.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-045',
      'css',
      'What is the line-height property?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Sets the height of a line box. Can be unitless (e.g., `1.5`, meaning 1.5x the font-size), a percentage, or a fixed pixel value. Unitless is preferred because child elements inherit the multiplier rather than a computed value.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-046',
      'css',
      'What is CSS Subgrid?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows nested grids to participate in the sizing of their parent grid. Instead of defining template columns/rows, you use `grid-template-columns: subgrid`. This aligns grandchildren perfectly with the main grid.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-047',
      'css',
      'Explain overscroll-behavior.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Controls the browser''s behavior when reaching the boundary of a scrolling area. `overscroll-behavior: contain` prevents scroll chaining (where scrolling a modal inadvertently scrolls the page behind it).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-048',
      'css',
      'What is the gap property?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Defines the size of the gutters (space) between rows and columns in Flexbox, Grid, and Multi-column layouts. Replaces the old method of using margins on children with negative margins on containers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-049',
      'css',
      'What are CSS preprocessors?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Tools like Sass, Less, and Stylus that extend CSS with features like variables, nesting, mixins, and loops. The code is compiled into standard CSS before being served to the browser.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'css-050',
      'css',
      'How does letter-spacing differ from word-spacing?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`letter-spacing` adjusts the horizontal space between individual text characters. `word-spacing` adjusts the horizontal space between individual words (separated by spaces).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-001',
      'web-perf',
      'What are the Core Web Vitals?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Core Web Vitals are user-centric performance metrics by Google: 1. Largest Contentful Paint (LCP): Loading performance — how quickly the main content renders (target < 2.5s). 2. Interaction to Next Paint (INP): Responsiveness — time from user interaction to next frame (target < 200ms). 3. Cumulative Layout Shift (CLS): Visual stability — how much content shifts unexpectedly (target < 0.1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-002',
      'web-perf',
      'Explain the Critical Rendering Path.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The sequence the browser follows: 1. Parse HTML → DOM tree. 2. Parse CSS → CSSOM tree. 3. Combine DOM + CSSOM → Render Tree. 4. Layout (Reflow) — calculate element positions. 5. Paint — fill in pixels. 6. Composite — combine painted layers. CSS blocks rendering. JS blocks HTML parsing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-003',
      'web-perf',
      'Difference between <script defer> and <script async>?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Both download in parallel. `async`: Executes immediately when downloaded, pausing HTML parsing. Order not guaranteed. `defer`: Waits until HTML parsing finishes, executes in document order. Both ignore inline scripts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-004',
      'web-perf',
      'How does HTTP caching work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. `Cache-Control`: max-age, no-cache (must revalidate), no-store. 2. `ETag`: Hash fingerprint of content. 3. `Last-Modified`: Timestamp. Browser sends `If-None-Match` or `If-Modified-Since`. Server returns `304 Not Modified` if unchanged.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-005',
      'web-perf',
      'What is Tree Shaking?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Dead code elimination for ES modules. Bundlers statically analyze `import`/`export` and remove unused exports. Requires ES modules (not CommonJS) and avoiding side effects in module scope.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-006',
      'web-perf',
      'What is a CDN?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Content Delivery Network. A geographically distributed network of servers. Caches static assets closer to the user to reduce latency and server load.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-007',
      'web-perf',
      'Explain Preload vs Prefetch.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`<link rel="preload">`: High priority, for resources needed on the CURRENT page (fonts, critical CSS/JS). `<link rel="prefetch">`: Low priority, for resources likely needed on the NEXT page navigation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-008',
      'web-perf',
      'What is Bundle Splitting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Breaking a large JS bundle into smaller chunks. Usually splitting vendor code (React, Lodash) into one chunk (cached long-term) and app code into another. Also route-based splitting.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-009',
      'web-perf',
      'What causes Cumulative Layout Shift (CLS)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Images/ads without explicit dimensions, web fonts loading late (FOIT/FOUT), dynamically injected content without reserved space. Fix: specify width/height on `<img>` tags.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-010',
      'web-perf',
      'How to optimize Largest Contentful Paint (LCP)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Preload the LCP image. 2. Compress images (WebP/AVIF). 3. Implement server-side rendering (SSR). 4. Eliminate render-blocking resources (defer JS, inline critical CSS). 5. Use a CDN.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-011',
      'web-perf',
      'What is Interaction to Next Paint (INP)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Measures responsiveness by tracking the latency of all interactions (clicks, taps, typing) throughout the page lifecycle. Replaced First Input Delay (FID). Fix: yield to main thread, break up long tasks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-012',
      'web-perf',
      'Explain Time to First Byte (TTFB).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Time between browser requesting a page and receiving the first byte of data. Indicates server/network health. Fix: Optimize DB queries, use edge caching, scale servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-013',
      'web-perf',
      'What is lazy loading?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Deferring the loading of non-critical resources (images, iframes, components) until they are needed (e.g., about to enter the viewport). `<img loading="lazy">` is natively supported.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-014',
      'web-perf',
      'What are Long Tasks in the browser?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'JavaScript execution periods that exceed 50ms. They block the main thread, delaying rendering and interactions. Fix: Web Workers, requestIdleCallback, or setTimeout chunking.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-015',
      'web-perf',
      'What is a Service Worker?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A background script acting as a network proxy. Enables offline support by intercepting network requests and serving from the Cache API. Requires HTTPS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-016',
      'web-perf',
      'Explain PRPL Pattern.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Push (or preload) critical resources for initial route. Render initial route ASAP. Pre-cache remaining routes (Service Worker). Lazy-load and create remaining routes on demand.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-017',
      'web-perf',
      'What is CSS Layout Thrashing?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when JavaScript repeatedly reads a layout property (like offsetTop) and then writes a style change (forcing reflow). It forces synchronous layouts. Fix: Batch reads, then batch writes (e.g., using fastdom).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-018',
      'web-perf',
      'How do Web Fonts impact performance?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'They block text rendering until downloaded. FOIT (Invisible Text) or FOUT (Unstyled Text). Fix: `font-display: swap`, preload critical fonts, subset fonts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-019',
      'web-perf',
      'What is HTTP/2 multiplexing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Allows multiple requests/responses simultaneously over a single TCP connection. Eliminates the need for older hacks like domain sharding, CSS sprites, or inline assets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-020',
      'web-perf',
      'What is Brotli?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A modern compression algorithm by Google, significantly better than Gzip for text assets (HTML, CSS, JS). Widely supported in modern browsers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-021',
      'web-perf',
      'What is the requestIdleCallback API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Allows running background/low-priority JS during the browser''s idle periods. Great for non-essential analytics or prefetching without dropping frames.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-022',
      'web-perf',
      'What is a memory leak in the browser?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When JS objects are no longer needed but cannot be garbage collected due to dangling references. Causes: unclosed event listeners, detached DOM nodes in JS vars, global variables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-023',
      'web-perf',
      'Explain GPU Hardware Acceleration.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Offloading layout/paint work to the GPU via composite layers. Triggered by CSS transforms (translate3d, scale) and opacity changes. Bypasses the CPU-heavy layout/paint phases.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-024',
      'web-perf',
      'What is the PRNG algorithm?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Pseudo-Random Number Generator. In performance, knowing how algorithms scale is key. Not specifically a web-perf term, but algorithmic efficiency drastically affects JS main thread execution.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-025',
      'web-perf',
      'What is the performance observer API?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A browser API that subscribes to performance metrics (like LCP, long tasks, resource timing) to measure and log real-user monitoring (RUM) data dynamically.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-026',
      'web-perf',
      'How do you optimize a large React list?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use virtualization/windowing (e.g., `react-window`). Render only the DOM elements currently visible in the viewport, reusing them as the user scrolls.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-027',
      'web-perf',
      'What is First Contentful Paint (FCP)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Measures the time from navigation to the time when the browser renders the first piece of DOM content (text, image, non-white canvas).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-028',
      'web-perf',
      'What is the BFCache?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Back/Forward Cache. Browsers keep a complete snapshot of a page in memory when you navigate away. Pressing "Back" loads it instantly. Can be broken by `unload` listeners or `Cache-Control: no-store`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-029',
      'web-perf',
      'Explain critical CSS.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Extracting and inlining the CSS required for the above-the-fold content into the `<head>`, while deferring the rest of the stylesheet. Prevents render blocking.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-030',
      'web-perf',
      'What is responsive images optimization?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using `srcset` and `sizes` attributes or the `<picture>` element to serve differently sized or formatted images (WebP vs JPEG) based on device resolution and viewport width.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-031',
      'web-perf',
      'What is the role of the DNS lookup in performance?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Resolving a domain to an IP address takes time. Optimize via `<link rel="dns-prefetch">` or `<link rel="preconnect">` for critical third-party domains (like API servers).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-032',
      'web-perf',
      'Explain TCP Slow Start.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A TCP algorithm that starts sending data slowly to avoid network congestion, ramping up speed. Means the first few kilobytes of a page load are the most crucial.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-033',
      'web-perf',
      'What is edge computing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Running logic (like Cloudflare Workers) at CDN edge nodes close to the user, rather than the origin server. Used for fast A/B testing, auth checks, and SSR.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-034',
      'web-perf',
      'What is a Lighthouse score?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source, automated tool by Google for auditing web performance, accessibility, SEO, and PWA criteria. Generates a score out of 100.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-035',
      'web-perf',
      'How do third-party scripts affect performance?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'They execute on the main thread, competing with app code. Can cause Long Tasks, block rendering, and introduce security risks. Load them asynchronously, defer them, or use a Tag Manager.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-036',
      'web-perf',
      'What is Content Hash in Webpack?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Adding a unique hash based on file contents to filenames (e.g., `app.8f3a.js`). If code changes, hash changes. Allows setting `Cache-Control: max-age=31536000, immutable` safely.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-037',
      'web-perf',
      'What is the impact of deeply nested DOM trees?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Increases memory usage, slows down CSS selector matching, and makes Layout/Reflow calculations significantly more expensive. Flatten the DOM structure.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-038',
      'web-perf',
      'What is WebAssembly (Wasm) role in performance?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A low-level binary format that runs at near-native speed. Used for CPU-intensive tasks (image/video processing, games, physics) where JS is too slow.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-039',
      'web-perf',
      'Explain the difference between Reflow and Repaint.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Reflow (Layout): element size/position changes, affecting the whole layout tree (heavy). Repaint: visual changes only (color, visibility), layout stays same (lighter).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-040',
      'web-perf',
      'What is `document.createDocumentFragment()`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A lightweight, invisible document object. Used to append multiple elements to the DOM at once in a single Reflow/Repaint, vastly improving performance over appending one by one.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-041',
      'web-perf',
      'What is the performance cost of CSS selectors?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Browsers parse CSS selectors right-to-left. Extremely broad right-most selectors (e.g., `.nav div *`) are slow because the browser checks every element in the DOM.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-042',
      'web-perf',
      'Explain HTTP/3 and QUIC.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'HTTP/3 uses UDP instead of TCP (via QUIC protocol). Faster handshakes (0-RTT), eliminates head-of-line blocking at the packet level, better connection migration on mobile.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-043',
      'web-perf',
      'How do you measure web performance in production?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using RUM (Real User Monitoring) rather than Lab data. Tools like Sentry, Datadog, or the Web Vitals JS library sending data to Google Analytics.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-044',
      'web-perf',
      'What is the `navigator.connection` API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Provides info about the system''s connection (4G, 3G, effective bandwidth). Allows delivering lower-quality images or disabling video auto-play for slow connections.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-045',
      'web-perf',
      'What is font subsetting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Creating a custom font file containing only the characters needed for the site (e.g., Latin alphabet), reducing font file size from MBs to KBs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-046',
      'web-perf',
      'What is the memory heap limit in V8?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Usually ~1.4GB to 4GB depending on the system. If JS allocations exceed this, the browser tab crashes (OOM error). Preventable by cleaning up detached DOM nodes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-047',
      'web-perf',
      'How do web workers communicate?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Via `postMessage`. Communication involves serializing/deserializing data (structured clone algorithm), which has overhead. Use `SharedArrayBuffer` for zero-copy memory sharing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-048',
      'web-perf',
      'What is the concept of Perceived Performance?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'How fast the site FEELS to the user, not just raw metrics. Improved using skeleton screens, optimistic UI updates, and smooth loading animations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-049',
      'web-perf',
      'What is the impact of inline SVGs?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Inline SVGs save network requests but increase the HTML payload size. If used multiple times, `<use href="#id">` should be utilized to avoid bloating the DOM.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'perf-050',
      'web-perf',
      'What are Resource Hints?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`<link rel="...">` attributes that instruct the browser to optimize delivery: `preconnect` (DNS+TCP+TLS), `dns-prefetch`, `preload` (current page), `prefetch` (next page), `prerender`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-001',
      'javascript',
      'Explain the Event Loop.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The Event Loop handles async callbacks in Node and the browser. It monitors the Call Stack and the Task Queue (Callback Queue). If the Call Stack is empty, it pushes the first task from the queue onto the stack. Microtasks (Promises, MutationObserver) have higher priority than Macrotasks (setTimeout, DOM events) and are executed immediately after the current operation completes, before the next macrotask.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-002',
      'javascript',
      'What is a closure?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A closure is a function bundled together with references to its surrounding state (lexical environment). It gives a function access to its outer scope even after the outer function has returned. Used for data privacy, currying, and maintaining state in async callbacks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-003',
      'javascript',
      'Explain prototypal inheritance.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Unlike classical inheritance (classes), JS objects inherit directly from other objects via the internal `[[Prototype]]` linkage (accessible via `__proto__` or `Object.getPrototypeOf`). When a property is accessed, JS looks at the object, then its prototype, then the prototype''s prototype, up the prototype chain until it finds it or reaches null.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-004',
      'javascript',
      'Difference between var, let, and const?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`var`: function-scoped, hoisted and initialized to undefined, can be redeclared. `let`: block-scoped, hoisted but uninitialized (Temporal Dead Zone), can be reassigned. `const`: block-scoped, hoisted but uninitialized (TDZ), cannot be reassigned (but object properties can be mutated).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-005',
      'javascript',
      'How does the "this" keyword work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '`this` refers to the object executing the current function. It depends on HOW the function is called. 1. Global context: window/global. 2. Method call: the object. 3. Constructor (new): the newly created object. 4. Explicit binding: object passed to call/apply/bind. 5. Arrow functions: inherit `this` from the enclosing lexical scope (they don''t bind their own `this`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-006',
      'javascript',
      'What is hoisting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'JS moves variable and function declarations to the top of their respective scopes during the compile phase. Function declarations are fully hoisted. `var` is hoisted and initialized to undefined. `let` and `const` are hoisted but remain uninitialized in the Temporal Dead Zone (TDZ).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-007',
      'javascript',
      'What is the Temporal Dead Zone (TDZ)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The period between entering a block scope and the actual declaration of a `let` or `const` variable. Accessing the variable in this zone throws a ReferenceError. It prevents reading variables before they are initialized.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-008',
      'javascript',
      'Difference between == and === ?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`==` (loose equality) performs type coercion before comparison (e.g., `"5" == 5` is true). `===` (strict equality) compares both value and type without coercion (e.g., `"5" === 5` is false). Always use `===` to prevent unexpected bugs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-009',
      'javascript',
      'Explain Promises vs Callbacks.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Callbacks are functions passed as arguments to execute after an async operation, prone to "Callback Hell" (inversion of control). Promises represent the eventual completion/failure of an async operation. They chain `.then()/.catch()`, providing better error handling and readability.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-010',
      'javascript',
      'What is async/await?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Syntactic sugar over Promises (ES2017). `async` functions always return a Promise. `await` pauses execution until the Promise resolves. Makes async code look and behave synchronously. Use `try/catch` for error handling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-011',
      'javascript',
      'What is event delegation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Attaching a single event listener to a parent element to handle events on its children (using event bubbling). Improves performance (fewer listeners) and works for dynamically added elements.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-012',
      'javascript',
      'Explain event bubbling and capturing.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Capturing: Event moves from the window down to the target element. Bubbling: Event moves up from the target to the window. `addEventListener(type, listener, useCapture)`. Default is bubbling. Stop via `e.stopPropagation()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-013',
      'javascript',
      'Difference between null and undefined?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`undefined` means a variable has been declared but not assigned a value. `null` is an intentional assignment of "no value". `typeof undefined` is "undefined". `typeof null` is "object" (a famous JS bug).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-014',
      'javascript',
      'What is a Pure Function?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A function that 1) always returns the same output for the same input, and 2) has no side effects (doesn''t mutate external state or rely on external mutability). Key concept in functional programming and Redux.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-015',
      'javascript',
      'Explain call(), apply(), and bind().',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'All three explicitly set the `this` context. `call(obj, arg1, arg2)` invokes immediately. `apply(obj, [arg1, arg2])` invokes immediately but takes an array. `bind(obj, arg1)` returns a new function with `this` permanently bound, to be executed later.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-016',
      'javascript',
      'What is currying?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Transforming a function with multiple arguments into a sequence of nested functions, each taking a single argument. e.g., `f(a,b,c)` becomes `f(a)(b)(c)`. Useful for partial application.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-017',
      'javascript',
      'What are generators?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Functions that can be paused and resumed using `yield`. Declared with `function*`. They return an iterator. Useful for custom iteration and handling infinite sequences lazily.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-018',
      'javascript',
      'Difference between Map and Object?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Keys: Object keys must be strings/symbols; Map keys can be ANY type (including objects). Order: Map guarantees insertion order. Iteration: Map is directly iterable. Size: Map has a `.size` property. Object has inherited prototype properties.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-019',
      'javascript',
      'What is a WeakMap/WeakSet?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Collections where keys MUST be objects. The references to keys are "weak", meaning if there are no other references to the object, it can be garbage collected. They are not iterable. Prevents memory leaks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-020',
      'javascript',
      'Explain shallow vs deep copy in JS.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Shallow copy (`Object.assign`, spread operator `{...obj}`) copies references for nested objects. Deep copy copies all levels. Historically done via `JSON.parse(JSON.stringify(obj))` (fails for Dates, functions). Modern JS uses `structuredClone()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-021',
      'javascript',
      'What is the Rest parameter vs Spread operator?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Syntax is `...` for both. Rest condenses multiple elements into an array (used in function parameters). Spread expands an iterable into individual elements (used in array/object literals or function calls).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-022',
      'javascript',
      'Explain the V8 engine compilation process.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'V8 uses a JIT (Just-In-Time) compiler. Source code is parsed into an AST. Ignition (interpreter) generates unoptimized bytecode. As code runs, TurboFan (optimizing compiler) recompiles "hot" functions into highly optimized machine code based on type assumptions. If assumptions fail, it "deoptimizes".',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-023',
      'javascript',
      'What is Debouncing vs Throttling?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Debounce: Delays execution until X ms have passed since the LAST event (e.g., search input). Throttle: Limits execution to at most once every X ms (e.g., scroll/resize events).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-024',
      'javascript',
      'What is a JavaScript Module?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A file containing encapsulated code. ES Modules use `import`/`export` and use strict mode by default. They allow static analysis (tree shaking). CommonJS uses `require()`/`module.exports` and is dynamic.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-025',
      'javascript',
      'Explain Symbol type.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A primitive data type introduced in ES6 that represents a unique, immutable identifier. Often used as hidden object properties to avoid name collisions. `Symbol("a") === Symbol("a")` is false.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-026',
      'javascript',
      'What are Iterators and Iterables?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Iterable: An object implementing `Symbol.iterator` (e.g., Array, String, Map, Set). Iterator: An object with a `next()` method returning `{ value, done }`. Enables the `for...of` loop.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-027',
      'javascript',
      'What is the Proxy object?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows intercepting and customizing fundamental operations (property lookup, assignment, enumeration, function invocation) on another object via "traps" like `get` and `set`. Used in Vue 3 for reactivity.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-028',
      'javascript',
      'Explain requestAnimationFrame.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A method that tells the browser you wish to perform an animation and requests the browser to call a specified function to update an animation before the next repaint. Syncs with screen refresh rate (usually 60fps), pauses in background tabs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-029',
      'javascript',
      'What is Strict Mode?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Invoked with `"use strict";`. Catches common coding bloopers (using undeclared variables, duplicate parameters), prevents `this` from defaulting to window, disables `with` statement, making code safer and optimizable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-030',
      'javascript',
      'How do you handle memory leaks in JS?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Avoid global variables, clear intervals/timeouts, remove event listeners when DOM nodes are destroyed, avoid closures holding large unnecessary objects, use WeakMap/WeakSet for DOM caches. Use Chrome DevTools Memory tab (Heap Snapshots).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-031',
      'javascript',
      'What is a Higher-Order Function?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A function that accepts other functions as arguments AND/OR returns a function. Examples: `map`, `filter`, `reduce`, or a function returning a closure.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-032',
      'javascript',
      'What is the purpose of the `Reflect` API?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Provides methods for interceptable JavaScript operations (like Proxy traps). It gives default behavior for proxy traps and returns booleans for success/failure instead of throwing exceptions (e.g., `Reflect.set()`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-033',
      'javascript',
      'What is Optional Chaining (?.)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Safely accesses deeply nested properties without throwing a TypeError if an intermediate property is null/undefined. Returns undefined instead. e.g., `user?.address?.city`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-034',
      'javascript',
      'What is Nullish Coalescing (??)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Returns the right-hand operand ONLY when the left is `null` or `undefined`. Different from `||` which returns the right operand for ANY falsy value (like `0`, `""`, `false`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-035',
      'javascript',
      'Difference between Function Declaration and Function Expression?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Declaration: `function a() {}` - fully hoisted, can be called before definition. Expression: `const a = function() {}` - assigned to a variable, not hoisted (if using let/const), anonymous or named.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-036',
      'javascript',
      'What is `Promise.all` vs `Promise.allSettled`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`all`: Resolves when ALL promises resolve. Rejects immediately if ANY promise rejects (fail-fast). `allSettled`: Waits for ALL promises to finish regardless of success/failure, returning an array of `{status, value/reason}` objects.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-037',
      'javascript',
      'What is `Promise.race` vs `Promise.any`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`race`: Returns the result of the FIRST promise to finish (resolve OR reject). `any` (ES2021): Returns the FIRST promise to RESOLVE. If all reject, returns an AggregateError.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-038',
      'javascript',
      'Explain BigInt.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A built-in object that provides a way to represent whole numbers larger than `Number.MAX_SAFE_INTEGER` (2^53 - 1). Created by appending `n` to the end of an integer literal or calling `BigInt()`. Cannot be mixed with regular Numbers in math.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-039',
      'javascript',
      'What is tail call optimization?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'An engine optimization where if the last action of a function is a call to another function (recursive or not), the current stack frame is reused, preventing StackOverflow. Only partially supported in Safari (JSC), V8 abandoned it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-040',
      'javascript',
      'What is a polyfill vs a transpiler?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Polyfill: A piece of code (usually JS) that provides modern functionality (like `fetch` or `Promise`) on older browsers that do not natively support it. Transpiler (Babel): Converts modern syntax (arrow functions, classes) into older syntax.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-041',
      'javascript',
      'What is the "new" keyword doing under the hood?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Creates a new empty object. 2. Sets its `__proto__` to the constructor function''s prototype. 3. Calls the constructor function with `this` bound to the new object. 4. Returns the object (unless the constructor explicitly returns another object).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-042',
      'javascript',
      'Explain `Object.create()`.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Creates a new object, using an existing object as the prototype of the newly created object. Preferable over `__proto__` for prototype assignment. `Object.create(null)` creates an object with no prototype (true dictionary).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-043',
      'javascript',
      'What is memoization in JS?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An optimization technique used primarily to speed up programs by storing the results of expensive function calls and returning the cached result when the same inputs occur again. Typically implemented using closures.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-044',
      'javascript',
      'What is CORS?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cross-Origin Resource Sharing. A browser security mechanism that restricts web pages from making requests to a different domain than the one that served the web page, unless the server provides specific CORS headers (e.g., `Access-Control-Allow-Origin`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-045',
      'javascript',
      'How do service workers work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Scripts that run in the background, independent of a web page. Intercept network requests, enabling offline caching (via Cache API), push notifications, and background sync. They require HTTPS and are event-driven.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-046',
      'javascript',
      'What is a memory heap vs call stack?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Call Stack: Tracks function execution (LIFO). Stores primitive types and function frames. Memory Heap: A large, mostly unstructured region of memory where objects, arrays, and functions are allocated dynamically.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-047',
      'javascript',
      'Explain `Object.freeze()` vs `Object.seal()`.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`freeze`: Prevents adding, removing, or modifying properties (makes object immutable). `seal`: Prevents adding or removing properties, but ALLOWS modifying existing properties. Both are shallow.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-048',
      'javascript',
      'What are Web Workers?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'APIs that allow running scripts in background threads. They execute independently of the main UI thread, meaning heavy computations won''t freeze the UI. They communicate with the main thread via message passing (`postMessage`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-049',
      'javascript',
      'What is the Intersection Observer API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Provides a way to asynchronously observe changes in the intersection of a target element with an ancestor element or the viewport. Great for lazy loading images, infinite scrolling, and triggering animations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'js-050',
      'javascript',
      'What are tagged template literals?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A function call using a template literal instead of parentheses. The function receives the string parts as an array and the interpolated expressions as subsequent arguments. Used in GraphQL (`gql``) and styled-components.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-001',
      'sql',
      'What are the ACID properties?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Atomicity: All or nothing (transaction completes fully or rolls back). Consistency: Database remains in a valid state before and after. Isolation: Concurrent transactions don''t interfere with each other. Durability: Committed data is saved permanently, even if the system crashes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-002',
      'sql',
      'Explain Database Normalization.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The process of organizing data to reduce redundancy and improve data integrity. 1NF: Atomic values, unique columns. 2NF: 1NF + no partial dependencies (all non-key attributes depend on the WHOLE primary key). 3NF: 2NF + no transitive dependencies (non-key attributes depend ONLY on the primary key).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-003',
      'sql',
      'What is Denormalization and when is it used?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Intentionally adding redundancy to a database by combining tables. It violates normal forms to optimize read performance and avoid expensive JOINs in read-heavy applications (e.g., Data Warehouses, OLAP).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-004',
      'sql',
      'Explain the different types of JOINs.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'INNER JOIN: Returns matching rows in both tables. LEFT JOIN: Returns all from left, matched from right (nulls if no match). RIGHT JOIN: All from right, matched from left. FULL OUTER JOIN: All rows from both, nulls where no match. CROSS JOIN: Cartesian product (every row combined with every row).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-005',
      'sql',
      'What is a Primary Key vs Foreign Key?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Primary Key: Uniquely identifies a record in a table. Cannot be null. Foreign Key: A column (or set of columns) that references the Primary Key of another table, enforcing referential integrity.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-006',
      'sql',
      'What is an Index?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A data structure (usually a B-Tree) that improves the speed of data retrieval operations on a table at the cost of additional storage space and slower writes (INSERT/UPDATE/DELETE). It works like an index in a book.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-007',
      'sql',
      'Clustered vs Non-Clustered Indexes?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Clustered: Determines the physical order of data rows in the table. Only one per table (usually the Primary Key). Non-Clustered: A separate structure from the data rows. Contains the indexed value and a pointer (rowid) to the actual data row. Can have multiple per table.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-008',
      'sql',
      'What is a Covering Index?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A non-clustered index that includes all the columns requested in a SELECT query. The database engine can fulfill the query entirely from the index without having to look up the actual data rows, resulting in massive performance gains.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-009',
      'sql',
      'Explain Transaction Isolation Levels.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Control the degree to which transactions are isolated from each other. Read Uncommitted (lowest, allows dirty reads), Read Committed (prevents dirty reads, allows non-repeatable reads), Repeatable Read (prevents non-repeatable reads, allows phantom reads), Serializable (highest, prevents all, essentially locks tables).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-010',
      'sql',
      'What is a Dirty Read?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Occurs when transaction A reads data that has been modified by transaction B, but transaction B has not yet committed. If B rolls back, A has read data that never technically existed. Prevented by Read Committed isolation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-011',
      'sql',
      'What is a Non-Repeatable Read?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a transaction reads the same row twice, and gets a different value the second time because another transaction UPDATEs the row in between the reads. Prevented by Repeatable Read isolation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-012',
      'sql',
      'What is a Phantom Read?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a transaction executes the same query twice (e.g., counting rows matching a condition), and gets a different number of rows the second time because another transaction INSERTed or DELETEd a matching row. Prevented by Serializable isolation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-013',
      'sql',
      'What is a Database View?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A virtual table based on the result-set of an SQL statement. Contains rows and columns just like a real table. Used to hide complexity, restrict data access (row/column level security), and simplify querying.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-014',
      'sql',
      'What is a Materialized View?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Unlike a standard view (which runs the underlying query every time it''s accessed), a materialized view stores the actual query results physically on disk. It provides fast read access but requires periodic refreshing to stay updated. Great for heavy analytical queries.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-015',
      'sql',
      'Difference between DELETE, TRUNCATE, and DROP?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'DELETE: DML command, removes specific rows (WHERE), logs each deletion, can be rolled back. TRUNCATE: DDL command, empties the entire table, resets identity columns, minimal logging, faster, usually cannot be rolled back. DROP: DDL command, deletes the table structure and data entirely.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-016',
      'sql',
      'What is an Execution Plan?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The step-by-step roadmap the database optimizer chooses to execute a query (e.g., performing a table scan vs an index seek, choosing hash join vs nested loop). You prefix a query with `EXPLAIN` or `EXPLAIN ANALYZE` to view it and identify bottlenecks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-017',
      'sql',
      'Difference between WHERE and HAVING?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`WHERE` filters rows BEFORE grouping (aggregate functions cannot be used). `HAVING` filters rows AFTER the `GROUP BY` clause is applied (used specifically to filter based on aggregate function results like `SUM` or `COUNT`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-018',
      'sql',
      'What is a Stored Procedure?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A prepared SQL code that you can save and reuse over and over. Supports input/output parameters, control flow statements (IF/ELSE), and can contain multiple queries. Reduces network traffic and encapsulates business logic.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-019',
      'sql',
      'Difference between a Function and a Stored Procedure?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Functions MUST return a value, cannot make changes to the database state (INSERT/UPDATE/DELETE), and can be called directly within a SELECT statement. Stored Procedures don''t have to return a value, can modify data, and must be called using `EXEC` or `CALL`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-020',
      'sql',
      'What is a Database Trigger?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A special type of stored procedure that automatically executes (fires) when a specific event occurs in the database server, such as an INSERT, UPDATE, or DELETE on a specific table. Used for auditing, enforcing complex business rules, or syncing tables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-021',
      'sql',
      'Explain the difference between UNION and UNION ALL.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Both combine the result sets of two or more SELECT statements. `UNION` removes duplicate rows between the sets (incurring a performance penalty for sorting/deduplicating). `UNION ALL` keeps all duplicates and is much faster.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-022',
      'sql',
      'What are Window Functions?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Perform a calculation across a set of table rows that are somehow related to the current row. Unlike aggregate functions, they do NOT group rows into a single output row; the rows retain their separate identities. Uses the `OVER()` clause. Example: `ROW_NUMBER()`, `RANK()`, `LEAD()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-023',
      'sql',
      'Difference between RANK(), DENSE_RANK(), and ROW_NUMBER()?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Assuming ties for 1st place: `ROW_NUMBER()` assigns strictly sequential numbers (1, 2, 3). `RANK()` assigns identical numbers for ties, then skips the next rank (1, 1, 3). `DENSE_RANK()` assigns identical numbers for ties but does not skip (1, 1, 2).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-024',
      'sql',
      'What is a CTE (Common Table Expression)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A temporary named result set that you can reference within a SELECT, INSERT, UPDATE, or DELETE statement. Defined using the `WITH` keyword. Improves readability of complex queries compared to derived tables (subqueries in the FROM clause).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-025',
      'sql',
      'What is a Recursive CTE?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A CTE that references itself. Commonly used to query hierarchical data (like an organizational chart or category trees) where depth is unknown. Contains an anchor member, a `UNION ALL`, and a recursive member.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-026',
      'sql',
      'How do you handle pagination in SQL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Basic: `LIMIT 10 OFFSET 20` (skips the first 20 records, takes 10). Performance degrades heavily at large offsets. Better (Keyset Pagination): `WHERE id > last_seen_id ORDER BY id LIMIT 10`. Faster because it uses the index to jump directly to the row.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-027',
      'sql',
      'What is a Composite Key?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A Primary Key that consists of two or more columns that together uniquely identify a row in a table, even though each column individually might not be unique. Used frequently in many-to-many junction tables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-028',
      'sql',
      'What is the N+1 Query Problem in ORMs?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When an ORM executes 1 query to fetch a list of parent entities, and then N additional queries to fetch a related child entity for each parent. Drastically degrades performance. Solved by Eager Loading (using JOINs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-029',
      'sql',
      'What are Deadlocks?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when two or more transactions permanently block each other by each holding a lock on a resource that the other transaction needs to proceed. The DB engine detects this, kills one transaction (the victim), and rolls it back.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-030',
      'sql',
      'How do you prevent Deadlocks?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Access tables/rows in the exact same order across all application code. 2. Keep transactions short. 3. Use lower isolation levels if possible. 4. Add covering indexes to reduce lock escalation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-031',
      'sql',
      'What is Lock Escalation?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An optimization technique used by DB engines. If a transaction acquires too many row-level locks, the engine converts (escalates) them into a single table-level lock to save memory. This severely reduces concurrency.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-032',
      'sql',
      'Explain Optimistic vs Pessimistic Locking.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Pessimistic: Locks the record the moment it is read, preventing others from reading/writing until the transaction completes. Optimistic: Doesn''t lock the record. Instead, it checks a version number or timestamp upon UPDATE. If the version changed since it was read, the update fails. Best for read-heavy apps.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-033',
      'sql',
      'What is a Sequence?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A database object that generates a sequence of numeric values based on a specified increment. Often used to automatically generate primary key values (similar to AUTO_INCREMENT or SERIAL).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-034',
      'sql',
      'What is a Full Table Scan?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When the database engine must read every single row in a table to evaluate a query condition. Occurs when there is no suitable index, or if the index is ignored (e.g., searching for `%text`). Usually highly inefficient for large tables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-035',
      'sql',
      'What is a B-Tree?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Balanced Tree. The default data structure used for indexes. It keeps data sorted and allows searches, sequential access, insertions, and deletions in logarithmic time (O(log n)).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-036',
      'sql',
      'Explain the LIKE operator and Index usage.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`LIKE "John%"` (prefix search) CAN use an index via an index range scan. `LIKE "%John"` (suffix) or `LIKE "%John%"` (infix) CANNOT use a standard B-Tree index and will trigger a full table scan. You need Full-Text Search indexes for the latter.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-037',
      'sql',
      'What is an Execution Plan "Table Spool"?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A physical operator in an execution plan that reads the input rows and saves a copy of them in a hidden temporary table (in tempdb). Used to optimize queries where the same intermediate result set is required multiple times.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-038',
      'sql',
      'What is the purpose of the COALESCE function?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Returns the first non-null value in a list of expressions. `COALESCE(phone, email, ''N/A'')` will return phone if not null, else email if not null, else ''N/A''.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-039',
      'sql',
      'Difference between COUNT(*) and COUNT(column)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`COUNT(*)` counts the total number of rows in the table/group, regardless of null values. `COUNT(column)` counts only the rows where `column` is NOT NULL.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-040',
      'sql',
      'What is a Schema?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A logical container/namespace within a database that holds database objects like tables, views, and procedures. Used to group related objects and manage permissions (e.g., `dbo.Users`, `sales.Orders`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-041',
      'sql',
      'Explain Write-Ahead Logging (WAL).',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The standard approach to ensuring ACID durability. All modifications to the database are written to a sequential log on disk BEFORE they are applied to the actual data pages. In a crash, the log is replayed to restore state.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-042',
      'sql',
      'What is a Cursor?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A database object used to retrieve and process rows one by one from a result set. Generally discouraged because they process row-by-row (RBAR), which is vastly slower than set-based operations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-043',
      'sql',
      'What is a Self Join?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A regular join, but the table is joined with itself. Requires the use of table aliases. Used to query hierarchical data stored in a single table, like finding an employee''s manager where both are in the `Employees` table.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-044',
      'sql',
      'What is the difference between DDL, DML, DCL, and TCL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'DDL (Data Definition): CREATE, ALTER, DROP. DML (Data Manipulation): SELECT, INSERT, UPDATE, DELETE. DCL (Data Control): GRANT, REVOKE. TCL (Transaction Control): COMMIT, ROLLBACK, SAVEPOINT.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-045',
      'sql',
      'What is a Natural Join?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A type of join that automatically joins tables based on columns with the SAME NAME and compatible data types. Considered dangerous because adding/renaming columns later can break the query unexpectedly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-046',
      'sql',
      'How do you find duplicate rows in a table?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use `GROUP BY` on the columns that determine uniqueness, and add `HAVING COUNT(*) > 1`. To delete them, you can use a CTE with `ROW_NUMBER() OVER(PARTITION BY ...)` and delete rows where the row number is > 1.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-047',
      'sql',
      'What is an EXISTS clause?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Used to test for the existence of any record in a subquery. It returns true as soon as it finds the FIRST matching row, making it much more efficient than using `IN` or `COUNT() > 0` for large datasets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-048',
      'sql',
      'Explain the concept of Sharding.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A type of horizontal partitioning. Splitting a single large database across multiple smaller, independent database servers (shards) to distribute the load. Requires a sharding key (e.g., user_id) to determine which shard holds the data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-049',
      'sql',
      'What is a Columnar Database?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Stores data physically by columns rather than by rows. Optimizes read-heavy analytical queries (OLAP) because it only reads the columns needed for the query, and columns compress highly efficiently. E.g., Amazon Redshift, ClickHouse.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sql-050',
      'sql',
      'What are Anti-Patterns in SQL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Bad practices. E.g., `SELECT *` (fetches unnecessary data, breaks if schema changes), ignoring indexes via functions on columns (`WHERE YEAR(date) = 2020`), storing comma-separated values in a column instead of normalizing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-001',
      'nosql',
      'What is NoSQL?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Stands for "Not Only SQL". A class of non-relational database management systems that do not use the traditional tabular relations used in RDBMS. Designed for flexible schemas, horizontal scaling, and handling massive volumes of unstructured or semi-structured data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-002',
      'nosql',
      'What are the four main types of NoSQL databases?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Document Stores (MongoDB, CouchDB). 2. Key-Value Stores (Redis, DynamoDB). 3. Wide-Column Stores (Cassandra, HBase). 4. Graph Databases (Neo4j, Amazon Neptune).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-003',
      'nosql',
      'Explain the BASE properties.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The NoSQL alternative to ACID. Basically Available: System guarantees availability (reads/writes) even during partial failures. Soft state: The state of the system may change over time without input (due to eventual consistency syncing). Eventual consistency: Given enough time, all nodes will reflect the same data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-004',
      'nosql',
      'What is a Document Database?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Stores data as documents (JSON, BSON, XML). Documents in the same collection don''t need to have the same schema. Best for content management, catalogs, and rapid prototyping where schemas evolve quickly (e.g., MongoDB).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-005',
      'nosql',
      'What is a Key-Value Store?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The simplest NoSQL type. Data is stored as a collection of key-value pairs. Highly optimized for simple read/write operations based on the key. Extremely fast, used for caching, session management, and shopping carts (e.g., Redis, Memcached).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-006',
      'nosql',
      'What is a Wide-Column Store?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Stores data in tables, rows, and dynamic columns. Instead of storing data row-by-row, it stores data column-by-column, grouped into column families. Highly optimized for write-heavy workloads and time-series data over massive distributed clusters (e.g., Apache Cassandra).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-007',
      'nosql',
      'What is a Graph Database?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Stores data as Nodes (entities) and Edges (relationships between entities). Highly optimized for querying complex, deeply nested relationships (like social networks, recommendation engines, fraud detection) which would require incredibly slow recursive JOINs in SQL.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-008',
      'nosql',
      'Explain Horizontal vs Vertical Scaling.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Vertical (Scale Up): Adding more CPU/RAM to a single server. Limited by hardware maximums, requires downtime. Horizontal (Scale Out): Adding more servers to a cluster to distribute the load. Virtually limitless. NoSQL is explicitly designed for horizontal scaling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-009',
      'nosql',
      'What is Sharding in NoSQL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Distributing data across multiple physical machines (shards). Each shard holds a distinct subset of the data. Enables horizontal scaling of data volume and write throughput. Requires choosing a Shard Key.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-010',
      'nosql',
      'What is a Shard Key / Partition Key?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The field(s) used by the database to determine which shard should store a particular document. A good shard key ensures even distribution of data (no massive shards) and even distribution of read/write operations (avoids hot shards).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-011',
      'nosql',
      'What is a "Hot Shard" / "Hot Partition"?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A performance bottleneck occurring when a poor shard key (like a sequential timestamp) causes all current read/write traffic to hit a single shard, overwhelming it, while other shards sit idle. Defeats the purpose of horizontal scaling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-012',
      'nosql',
      'Explain Replica Sets in MongoDB.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A group of MongoDB processes that maintain the same data set. Provides redundancy and high availability. Contains a Primary node (receives all writes) and multiple Secondary nodes (replicate the primary''s oplog). If the Primary fails, an election promotes a Secondary.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-013',
      'nosql',
      'What is the MongoDB Aggregation Pipeline?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A framework for data aggregation modeled on the concept of data processing pipelines. Documents enter a multi-stage pipeline that transforms them into aggregated results (e.g., `$match` -> `$group` -> `$sort`). The NoSQL equivalent of SQL `GROUP BY`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-014',
      'nosql',
      'Does NoSQL support Joins?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Most NoSQL databases do NOT support true relational JOINs natively, as data is usually distributed across servers (joining distributed data is incredibly slow). You either denormalize the data (embed it) or perform manual joins at the application layer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-015',
      'nosql',
      'Embedding vs Referencing in Document DBs?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Embedding: Storing related data within the same document (e.g., an array of `comments` inside a `post`). Good for 1-to-few, fast reads. Referencing: Storing the ID of the related document. Good for 1-to-many/many-to-many, when the referenced data is large or changes frequently.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-016',
      'nosql',
      'What is DynamoDB?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'AWS''s fully managed, serverless, proprietary NoSQL database. A highly scalable key-value and document database that delivers single-digit millisecond performance at any scale. Uses partitions under the hood.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-017',
      'nosql',
      'Explain the concept of Consistent Hashing.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Used in distributed databases (like Cassandra/Dynamo). Nodes and data keys are mapped to a conceptual "hash ring". A key is assigned to the next node on the ring. When a node is added/removed, only a fraction of keys need to be moved, unlike standard modulo hashing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-018',
      'nosql',
      'What is Apache Cassandra?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A highly scalable, high-performance distributed wide-column NoSQL database. Originally developed by Facebook. Known for having no single point of failure (masterless peer-to-peer architecture), linear scalability, and incredibly fast write performance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-019',
      'nosql',
      'How does Cassandra achieve fast writes?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Uses an append-only architecture. Writes go to a Commit Log on disk (for durability) and a Memtable in RAM. When Memtable is full, it flushes sequentially to disk as an SSTable (immutable). It avoids random disk I/O completely during writes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-020',
      'nosql',
      'What are SSTables in Cassandra?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Sorted String Tables. Immutable data files that Cassandra uses for persisting data on disk. Since they are immutable, updates/deletes are treated as new inserts with a timestamp (Tombstones for deletes). Periodic compaction merges SSTables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-021',
      'nosql',
      'What is a Tombstone in NoSQL?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In append-only/immutable stores (like Cassandra or Kafka), you cannot physically delete a record immediately. A Tombstone is a special marker written to indicate a record has been deleted. During later compaction, the data and tombstone are permanently removed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-022',
      'nosql',
      'What is the Primary Key in Cassandra?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Composed of two parts: Partition Key (determines which node stores the data via hashing) and Clustering Columns (determines how data is sorted physically on disk within that partition). Extremely important for query performance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-023',
      'nosql',
      'What is tunable consistency?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A feature in Cassandra/DynamoDB allowing developers to choose the consistency level for each read/write operation. `ALL` means all replicas must acknowledge (strong consistency, lower availability). `ONE` means only one replica needs to acknowledge (eventual consistency, fastest).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-024',
      'nosql',
      'Explain Quorum in distributed systems.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The minimum number of votes (nodes) required to perform an operation. `Quorum = (Total_Replicas / 2) + 1`. If Read_Consistency + Write_Consistency > Total_Replicas, you guarantee strong consistency.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-025',
      'nosql',
      'What is MongoDB''s BSON?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Binary JSON. The binary-encoded serialization of JSON-like documents used by MongoDB. It extends JSON with additional data types like Date, ObjectId, and raw binary data, and is designed to be highly traversable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-026',
      'nosql',
      'What is an ObjectId in MongoDB?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A 12-byte unique identifier generated by default for the `_id` field. Contains a timestamp, machine identifier, process id, and a random counter. Because it contains a timestamp, you can extract creation time without a separate createdAt field.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-027',
      'nosql',
      'How do transactions work in MongoDB?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Historically, MongoDB only supported atomic operations on a single document. Since v4.0, it supports multi-document ACID transactions across replica sets, and since v4.2 across sharded clusters. However, they incur a performance cost.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-028',
      'nosql',
      'What is a TTL Index?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Time-To-Live index. A special index in MongoDB/DynamoDB that automatically deletes documents after a certain amount of time or at a specific clock time. Used for sessions, event logs, and temporary caches.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-029',
      'nosql',
      'What is the Cassandra Query Language (CQL)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A language similar to SQL used to communicate with Cassandra. Despite looking like SQL, it lacks JOINs, subqueries, and advanced aggregations, forcing you to design tables based strictly on your query access patterns.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-030',
      'nosql',
      'Explain the concept of "Query First" design.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In RDBMS, you design the schema based on data relationships (Normalization). In NoSQL (especially Cassandra/DynamoDB), you MUST know your application''s queries beforehand, and you design your tables specifically to answer those exact queries efficiently (Denormalization).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-031',
      'nosql',
      'What is DynamoDB DAX?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'DynamoDB Accelerator. A fully managed, highly available, in-memory cache for DynamoDB that delivers up to a 10x performance improvement (from milliseconds to microseconds) without requiring developers to manage cache invalidation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-032',
      'nosql',
      'What is a Secondary Index in NoSQL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An index created on a field other than the primary/partition key. In MongoDB, it''s a standard index. In Cassandra/DynamoDB, it requires creating a separate table under the hood (Materialized View or Global Secondary Index) that mirrors data sorted by the new key.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-033',
      'nosql',
      'What is a Global Secondary Index (GSI) vs LSI in DynamoDB?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'GSI: Can have a different Partition Key and Sort Key than the base table. Can be created anytime. Queries can span all base table partitions. LSI: Local Secondary Index. Same Partition Key as base table, different Sort Key. Must be created at table creation time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-034',
      'nosql',
      'What is a Graph Database node and edge?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Node: Represents an entity (Person, Place, Category). Edge: Represents the relationship connecting two nodes (FRIENDS_WITH, LIVES_IN). Both nodes and edges can have properties (key-value pairs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-035',
      'nosql',
      'What is Cypher?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The declarative graph query language for Neo4j. It uses ASCII-art syntax to visually describe patterns in the graph. E.g., `MATCH (p:Person)-[:FRIENDS_WITH]->(f:Person) RETURN f.name`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-036',
      'nosql',
      'What is the Index-Free Adjacency property?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A property of native graph databases where every node maintains direct physical RAM pointers to its adjacent nodes. Query time depends only on the size of the result set being traversed, not on the total size of the database. Makes deep relationship queries O(1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-037',
      'nosql',
      'When should you NOT use NoSQL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When you require complex, multi-row ACID transactions (e.g., financial systems). When your data is highly relational and requires ad-hoc queries/JOINs. When your dataset fits on a single server and RDBMS tools are already established.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-038',
      'nosql',
      'Explain CouchDB''s MVCC.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Multi-Version Concurrency Control. CouchDB doesn''t lock documents during updates. Instead, it creates a new version of the document with a new revision ID (`_rev`). If two clients try to update the same old revision, one will fail with a 409 Conflict, forcing it to fetch the new version and retry.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-039',
      'nosql',
      'What is Vector Database?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A specialized NoSQL database designed to store, manage, and search high-dimensional vectors (embeddings) efficiently. Used heavily in AI/ML for semantic search, recommendation engines, and LLM context (e.g., Pinecone, Milvus, Qdrant).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-040',
      'nosql',
      'What is an In-Memory Database?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A database that relies primarily on main memory (RAM) for computer data storage. It is much faster than disk-optimized databases. E.g., Redis, Memcached. Data durability is achieved via periodic disk snapshots or append-only logs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-041',
      'nosql',
      'Explain Redis Pub/Sub.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A messaging paradigm where publishers send messages to channels without knowledge of subscribers. Subscribers listen to channels. It is "fire and forget" — if a subscriber is offline, the message is lost forever (unlike Kafka).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-042',
      'nosql',
      'What are Redis Data Types?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Strings (text/binary up to 512MB), Lists (linked lists), Sets (unordered unique strings), Hashes (maps of string fields to values), Sorted Sets (Sets ordered by a floating-point score), Bitmaps, HyperLogLogs, Geospatial.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-043',
      'nosql',
      'What is the split-brain problem in distributed databases?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs during a network partition when a cluster splits into two disconnected halves. If both halves elect a new primary and accept writes, you get conflicting data. Mitigated by requiring a quorum (majority) for elections/writes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-044',
      'nosql',
      'What is Gossip Protocol?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A peer-to-peer communication protocol used in masterless distributed systems (like Cassandra). Nodes periodically exchange state information with a few random peers. Information spreads exponentially fast, ensuring the whole cluster eventually shares the same state topology.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-045',
      'nosql',
      'What are MongoDB Capped Collections?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Fixed-size collections that support high-throughput operations. Once the collection fills its allocated space, it makes room for new documents by overwriting the oldest documents (behaves like a circular buffer).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-046',
      'nosql',
      'Explain DynamoDB Streams.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An ordered flow of information about changes to items in a DynamoDB table. Capture INSERTS, UPDATES, and DELETES in real-time. Commonly used to trigger AWS Lambda functions for event-driven architectures.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-047',
      'nosql',
      'What is the difference between HBase and Cassandra?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Both are Wide-Column stores. HBase sits on top of HDFS (Hadoop), uses a Master-Slave architecture, and strongly favors Consistency over Availability (CP). Cassandra is masterless (peer-to-peer) and favors Availability over Consistency (AP).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-048',
      'nosql',
      'What is Neo4j?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The most popular native Graph Database. Developed in Java. Optimized for storing interconnected data natively and executing complex queries via the Cypher query language.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-049',
      'nosql',
      'What is a Multi-model database?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A database management system designed to support multiple data models against a single, integrated backend (e.g., supporting document, graph, and key-value). Examples: ArangoDB, Cosmos DB.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'nosql-050',
      'nosql',
      'Explain Read and Write Capacity Units (RCU/WCU) in DynamoDB.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The billing and throttling metric in provisioned DynamoDB. 1 RCU = one strongly consistent read per second for an item up to 4KB. 1 WCU = one write per second for an item up to 1KB. Exceeding these causes `ProvisionedThroughputExceededException`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-001',
      'postgres',
      'What makes PostgreSQL different from MySQL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'PostgreSQL is strictly an Object-Relational Database Management System (ORDBMS). It fully complies with ACID, supports advanced data types (JSONB, Arrays, HStore, UUIDs, Geospatial), advanced locking (MVCC), materialized views, and partial indexes. MySQL is historically geared towards speed and web apps, though it has caught up in recent versions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-002',
      'postgres',
      'Explain MVCC (Multi-Version Concurrency Control) in PostgreSQL.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'MVCC allows high concurrency. Instead of locking a row when reading/writing, PostgreSQL creates a new version of the row for the transaction. Readers don''t block writers, and writers don''t block readers. Old versions (dead tuples) are kept until transactions that need them finish, then cleaned up by VACUUM.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-003',
      'postgres',
      'What is VACUUM in PostgreSQL?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A maintenance process. Because of MVCC, UPDATEs and DELETEs leave behind "dead tuples" (old row versions). `VACUUM` scans tables to reclaim the space taken by these dead tuples for future inserts. `VACUUM FULL` aggressively locks the table and rewrites it to disk to return space to the OS (rarely used). `autovacuum` runs automatically in the background.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-004',
      'postgres',
      'Explain JSON vs JSONB in Postgres.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`json` stores an exact text copy of the input text. Processing functions must reparse it on every execution. `jsonb` stores data in a decomposed binary format. It is slightly slower to insert, but significantly faster to process, supports advanced indexing (GIN), and removes duplicate keys.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-005',
      'postgres',
      'What is a GIN Index?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Generalized Inverted Index. Optimized for data types containing multiple values, such as Arrays, JSONB, and Full-Text Search vectors (`tsvector`). It maps values to the rows where they appear, rather than mapping rows to values.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-006',
      'postgres',
      'What is an Expression / Function-based Index?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An index created not on a raw column, but on an expression or function applied to a column. E.g., `CREATE INDEX idx_lower_email ON users (LOWER(email))`. Essential for fast case-insensitive searches.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-007',
      'postgres',
      'What is a Partial Index?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An index built over a subset of a table, defined by a `WHERE` clause. E.g., `CREATE INDEX idx_active_users ON users (id) WHERE active = true`. Saves disk space and speeds up inserts/updates compared to indexing the whole table.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-008',
      'postgres',
      'Explain Write-Ahead Logging (WAL) in Postgres.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Ensures data integrity. Changes to data files are written only AFTER they have been logged in the WAL. In case of a crash, the DB recovers by replaying the WAL logs. Also used fundamentally for replication (shipping WAL segments to standby servers).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-009',
      'postgres',
      'What is the RETURNING clause?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A Postgres-specific extension that allows an `INSERT`, `UPDATE`, or `DELETE` statement to return the values of the modified rows immediately, avoiding a subsequent `SELECT` query. E.g., `INSERT INTO users (name) VALUES (''John'') RETURNING id;`',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-010',
      'postgres',
      'What are CTEs (Common Table Expressions)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Temporary result sets defined by the `WITH` clause, lasting only for the execution of the current query. They make complex queries (especially deeply nested subqueries) much more readable. Also supports recursive queries via `WITH RECURSIVE`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-011',
      'postgres',
      'Explain Window Functions.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Calculations across a set of table rows related to the current row, without collapsing them into a single row like `GROUP BY`. Syntax uses `OVER(PARTITION BY col ORDER BY col)`. Examples: `row_number()`, `rank()`, `lead()`, `lag()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-012',
      'postgres',
      'What is the difference between `LIMIT` and `FETCH FIRST`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`LIMIT` is historically supported by Postgres (and MySQL/SQLite) but is not SQL standard. `FETCH FIRST n ROWS ONLY` is the ANSI SQL standard equivalent introduced in SQL:2008 and supported by Postgres.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-013',
      'postgres',
      'How do you perform Full-Text Search in Postgres?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Using `tsvector` (text parsed into tokens) and `tsquery` (search terms). Create a GIN index on the `tsvector` column. Query using the `@@` match operator: `WHERE to_tsvector(''english'', body) @@ to_tsquery(''postgres & search'')`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-014',
      'postgres',
      'Explain Table Partitioning.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Splitting one large logical table into smaller physical pieces (partitions). Postgres supports declarative partitioning by Range (e.g., date ranges), List (e.g., specific country codes), or Hash. Improves query performance and makes archiving old data instantly fast (dropping a partition).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-015',
      'postgres',
      'What are EXPLAIN and EXPLAIN ANALYZE?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`EXPLAIN` shows the query planner''s estimated execution plan (cost, rows). `EXPLAIN ANALYZE` actually executes the query and shows the TRUE execution time and rows processed alongside the estimates. Crucial for performance tuning.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-016',
      'postgres',
      'What is pgBouncer?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A lightweight connection pooler for PostgreSQL. Postgres connections are heavily process-based (one OS process per connection), taking ~10MB RAM each. pgBouncer maintains a pool of connections and multiplexes thousands of client connections over them, preventing the DB from running out of memory.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-017',
      'postgres',
      'What is the role of `pg_stat_activity`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A system catalog view that shows information related to the current activity of the server process. You query it to see what queries are currently running, who is running them, and if any queries are locked or hanging.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-018',
      'postgres',
      'What are Foreign Data Wrappers (FDW)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An extension mechanism that allows Postgres to connect to and query external data sources (like another Postgres DB, MySQL, MongoDB, or even a CSV file) directly using standard SQL queries, as if they were local tables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-019',
      'postgres',
      'Explain the concept of Toast in PostgreSQL.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The Oversized-Attribute Storage Technique. Postgres pages are 8KB. If a row (e.g., containing a massive JSONB or text field) exceeds this, Postgres compresses and splits the large column into multiple physical rows in a hidden TOAST table, storing only a pointer in the main table.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-020',
      'postgres',
      'What is a BRIN index?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Block Range INdex. Used for massive tables where the data is naturally ordered (like timestamps). It stores the min/max values for ranges of data blocks. Incredibly small and fast to build compared to B-Trees, but only effective on highly correlated/sequential data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-021',
      'postgres',
      'What is the `ON CONFLICT` clause?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Also known as "Upsert". Used with `INSERT`. If the insertion violates a unique constraint, you can instruct Postgres to either `DO NOTHING` or `DO UPDATE SET ...`. `INSERT INTO users (id, name) VALUES (1, ''A'') ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name;`',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-022',
      'postgres',
      'What is an Array type in Postgres?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Postgres natively supports arrays of any built-in or user-defined type. You can query them using operators like `ANY` (e.g., `WHERE ''tag'' = ANY(tags_array)`), `@>` (contains), and `<@` (is contained by). Can be indexed with GIN.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-023',
      'postgres',
      'Explain Logical vs Streaming Replication.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Streaming (Physical) Replication: Standby server copies byte-for-byte disk changes via WAL. Exactly mirrors the master, read-only. Logical Replication: Decodes WAL into logical data changes (INSERT/UPDATE). Allows replicating specific tables, filtering data, and writing to the subscriber DB.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-024',
      'postgres',
      'What is a Materialized View?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Caches the result of a complex query physically on disk. Great for dashboards. Must be manually updated using `REFRESH MATERIALIZED VIEW`. `CONCURRENTLY` can be used to refresh it without locking out readers, provided it has a unique index.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-025',
      'postgres',
      'What is `pg_dump` and `pg_restore`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Command-line tools. `pg_dump` backs up a Postgres database into a script or archive file. `pg_restore` restores a Postgres database from an archive created by pg_dump.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-026',
      'postgres',
      'What is the `HSTORE` data type?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A key-value store module within Postgres. Stores sets of key-value pairs within a single PostgreSQL value. Mostly superseded by `JSONB`, but still used in some legacy systems for simple flat dictionaries.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-027',
      'postgres',
      'How do you find the size of a database or table?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Database: `SELECT pg_size_pretty(pg_database_size(''dbname''));` Table (including indexes): `SELECT pg_size_pretty(pg_total_relation_size(''tablename''));`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-028',
      'postgres',
      'What is the `serial` type?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A pseudo-type used to define auto-incrementing integers (like AUTO_INCREMENT in MySQL). Under the hood, it creates an `integer` column and attaches a `SEQUENCE` object to it as its default value. Replaced by `GENERATED ALWAYS AS IDENTITY` in modern PG (SQL Standard).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-029',
      'postgres',
      'Explain `LATERAL` joins.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A `JOIN LATERAL` allows a subquery in the FROM clause to reference columns from preceding tables in the FROM clause. It essentially acts as a foreach loop, running the subquery once for each row of the preceding table. Great for "top N per category" queries.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-030',
      'postgres',
      'What is the PostGIS extension?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The industry-standard spatial database extender for PostgreSQL. It adds support for geographic objects allowing location queries (e.g., finding all points within a certain radius, calculating distances, intersecting polygons) using spatial indexes (GiST).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-031',
      'postgres',
      'What is a Sequence?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A special single-row table used to generate sequential numbers. They are safe for concurrent usage. Used primarily for auto-incrementing primary keys. Accessed via functions like `nextval()`, `currval()`, and `setval()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-032',
      'postgres',
      'What are constraints in PostgreSQL?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Rules enforced on data columns. Includes: PRIMARY KEY, FOREIGN KEY, UNIQUE, NOT NULL, CHECK (ensures a condition is met, e.g., `CHECK (price > 0)`), and EXCLUSION (ensures no two rows overlap, often used with time ranges).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-033',
      'postgres',
      'What is the difference between TRUNCATE and DELETE?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'DELETE scans the table row by row and writes each deletion to the WAL (slow). TRUNCATE quickly removes all rows by deallocating the data pages completely (fast). TRUNCATE resets sequences and cannot trigger DELETE triggers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-034',
      'postgres',
      'What is `tempdb` equivalent in Postgres?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'PostgreSQL does not have a global `tempdb`. Temporary tables are created in the current session''s temporary schema (e.g., `pg_temp`). They are automatically dropped at the end of the session or transaction.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-035',
      'postgres',
      'How do you kill a blocking query?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Identify the PID using `pg_stat_activity`. Attempt to cancel the query gracefully using `SELECT pg_cancel_backend(pid);`. If it refuses to die, forcibly terminate the connection using `SELECT pg_terminate_backend(pid);`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-036',
      'postgres',
      'What is the UUID data type?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A 128-bit quantity generated by an algorithm designed to make it unique across space and time. Postgres has native support for storing UUIDs (requires 16 bytes vs 36 bytes for text). You often use the `uuid-ossp` or `pgcrypto` extensions to generate them via `gen_random_uuid()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-037',
      'postgres',
      'Explain the role of `shared_buffers`.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The primary memory configuration parameter in postgresql.conf. It determines how much RAM Postgres uses to cache data blocks directly. Standard recommendation is to set it to 25% of total system RAM (leaving the rest for the OS filesystem cache).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-038',
      'postgres',
      'What is `work_mem`?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The amount of memory used by internal sort operations (like ORDER BY, DISTINCT) and hash tables (Hash Joins) BEFORE writing to temporary disk files. Increasing this speeds up complex queries, but it is applied PER OPERATION, meaning too high a value can crash the server under high concurrency.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-039',
      'postgres',
      'Explain Two-Phase Commit in Postgres.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Supported via `PREPARE TRANSACTION` and `COMMIT PREPARED`. Allows transactions to be split into two phases to guarantee distributed ACID transactions across multiple independent databases.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-040',
      'postgres',
      'What are table spaces (Tablespaces)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Allow database administrators to define locations in the file system where the files representing database objects can be stored. Useful for putting heavily accessed tables on fast SSDs and archive tables on slower HDDs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-041',
      'postgres',
      'What is an Advisory Lock?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Application-level locks created within Postgres. Unlike table or row locks, their meaning is defined entirely by the application. E.g., `pg_advisory_lock(123)` can be used to prevent a cron job from running concurrently on multiple application servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-042',
      'postgres',
      'What is the `LISTEN` and `NOTIFY` mechanism?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'PostgreSQL''s built-in lightweight publish/subscribe system. Clients can `LISTEN` to a channel. A database trigger or application can `NOTIFY channel, ''payload''`, and the DB pushes the event to all listening clients instantly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-043',
      'postgres',
      'Explain Row-Level Security (RLS).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows database administrators to set policies that restrict which rows are returned by normal queries or which rows can be inserted/updated/deleted, based on the user executing the query. Perfect for multi-tenant SaaS applications.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-044',
      'postgres',
      'What is the `COPY` command?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A Postgres-specific command that moves data between tables and standard file-system files (like CSV). `COPY` is the fastest possible way to bulk insert data into Postgres.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-045',
      'postgres',
      'What is a GiST index?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Generalized Search Tree. A template for building custom index structures. Used heavily for 2D spatial data (PostGIS bounding boxes), text search, and ranges where B-Trees are insufficient.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-046',
      'postgres',
      'How do you handle JSON array querying?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using specific operators. E.g., `jsonb_column @> ''[{"id": 2}]''` checks if the JSON array contains the exact object. You can also use `jsonb_array_elements()` to expand the array into a set of rows.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-047',
      'postgres',
      'What is the `pg_stat_statements` extension?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An essential extension that records execution statistics of all SQL statements executed. It provides data on total execution time, min/max times, calls, and blocks hit/read, allowing you to identify the slowest queries in production.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-048',
      'postgres',
      'What is `pg_hba.conf`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Host-Based Authentication configuration file. Controls which hosts (IPs/subnets) are allowed to connect, which databases they can access, which users they can log in as, and which authentication method (MD5, SCRAM, trust) must be used.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-049',
      'postgres',
      'What is the difference between `NULLIF` and `COALESCE`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`COALESCE(a, b)` returns `a` if `a` is not null, otherwise `b`. `NULLIF(a, b)` returns NULL if `a == b`, otherwise it returns `a`. Often used to prevent divide-by-zero errors: `val / NULLIF(divisor, 0)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pg-050',
      'postgres',
      'Explain the role of the Background Writer.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A background process that periodically writes dirty (modified) buffers from shared memory to disk. This reduces the number of writes required during checkpoints or when a query needs to evict a buffer, improving query latency.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-001',
      'redis',
      'What is Redis?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Remote Dictionary Server. An open-source, in-memory, key-value data structure store. It is extremely fast (sub-millisecond latency) and can be used as a database, cache, message broker, and streaming engine.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-002',
      'redis',
      'Why is Redis so fast?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. In-Memory: Data resides in RAM, bypassing slow disk I/O. 2. Single-Threaded Event Loop (mostly): Avoids context switching and lock overhead (though I/O and background tasks use threads). 3. Highly optimized C codebase. 4. Efficient data structures (e.g., skip lists for Sorted Sets).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-003',
      'redis',
      'Is Redis entirely single-threaded?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Historically yes, the core command execution is strictly single-threaded. However, modern Redis (v6+) uses multi-threading for network I/O (reading requests/writing responses), while the actual command execution remains single-threaded to guarantee atomicity and avoid locks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-004',
      'redis',
      'What are the main Data Types in Redis?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Strings, Lists, Sets, Hashes, Sorted Sets (ZSet), Bitmaps, HyperLogLogs, Geospatial indexes, and Streams.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-005',
      'redis',
      'Explain Redis Hashes.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A map between a string field and a string value (like a flat JSON object). Great for storing objects. Commands: `HSET user:100 name "John" age 30`, `HGET user:100 name`, `HGETALL user:100`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-006',
      'redis',
      'Explain Redis Lists and their use cases.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Collections of string elements sorted according to the order of insertion (implemented as Linked Lists). Commands: `LPUSH`, `RPUSH`, `LPOP`, `RPOP`. Use cases: Activity streams, recent updates, simple message queues.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-007',
      'redis',
      'Explain Redis Sets.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Unordered collections of unique strings. Commands: `SADD`, `SREM`, `SISMEMBER` (check existence in O(1)). Supports fast set operations: Intersections (`SINTER`), Unions (`SUNION`), Differences (`SDIFF`). Use cases: Unique tags, mutual friends.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-008',
      'redis',
      'Explain Redis Sorted Sets (ZSets).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Like Sets, but every element is associated with a floating-point score. Elements are ordered by this score. Commands: `ZADD`, `ZRANGE`, `ZREVRANK`. Under the hood, uses a Hash + Skip List. Use cases: Leaderboards, priority queues, rate limiters.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-009',
      'redis',
      'How do you implement a Leaderboard in Redis?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Sorted Set (ZSet). `ZADD leaderboard 100 "UserA"`. To get the top 10: `ZREVRANGE leaderboard 0 9 WITHSCORES`. To get a user''s rank: `ZREVRANK leaderboard "UserA"`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-010',
      'redis',
      'What is a HyperLogLog?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A probabilistic data structure used to estimate the cardinality (number of unique elements) of a massive dataset. It uses only 12KB of memory and has a standard error of 0.81%. Great for counting unique daily active users (DAU) without storing every IP/ID. Commands: `PFADD`, `PFCOUNT`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-011',
      'redis',
      'What are Bitmaps?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Not a separate data type, but bit-level operations performed on Strings. You can set individual bits to 0 or 1. extremely space-efficient. Commands: `SETBIT`, `GETBIT`, `BITCOUNT`. Use cases: Tracking user daily logins (1 bit per day per user).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-012',
      'redis',
      'Explain Redis Persistence (RDB vs AOF).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Since RAM is volatile, Redis offers persistence. RDB (Redis Database Backup): Point-in-time snapshots of the dataset saved to disk at specified intervals. AOF (Append Only File): Logs every write operation received. Slower but more durable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-013',
      'redis',
      'Pros and Cons of RDB.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Pros: Compact file (great for backups), fast restarts, minimizes performance impact (Redis forks a child process to save). Cons: You lose data written since the last snapshot if the server crashes (e.g., up to 5 minutes of data loss).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-014',
      'redis',
      'Pros and Cons of AOF.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Pros: High durability (can sync to disk every second or every command), log is append-only (no corruption on crash). Cons: Files grow much larger than RDB, slower restarts (must replay the log), slightly degrades write performance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-015',
      'redis',
      'What is AOF Rewrite?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Because AOF logs every command, it gets huge (e.g., `SET x 1`, `SET x 2`, `SET x 3`). Redis periodically runs a background rewrite to create a new, minimal AOF file reflecting the current state (e.g., just `SET x 3`), discarding redundant commands.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-016',
      'redis',
      'What is Redis Pipelining?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A technique to improve performance by sending multiple commands to the server in a single batch, without waiting for the replies of the previous commands. It drastically reduces network latency (round-trip time) for bulk operations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-017',
      'redis',
      'What are Redis Transactions?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Allows executing a group of commands sequentially. Starts with `MULTI`, followed by commands (which are queued), and executed with `EXEC` (or aborted with `DISCARD`). Unlike relational DBs, there is NO ROLLBACK if a command fails during execution.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-018',
      'redis',
      'What is the `WATCH` command in Redis?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Provides optimistic locking for transactions. You `WATCH key`. If another client modifies that key before your `EXEC`, your transaction fails and returns null. You can then retry.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-019',
      'redis',
      'Explain Redis Pub/Sub.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A messaging paradigm. Publishers send messages to `channels`. Subscribers listen to `channels`. It is an "at-most-once" delivery system: if a subscriber is offline when a message is published, they never get it. Used for real-time notifications/chat.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-020',
      'redis',
      'What are Redis Streams?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Introduced in v5, it''s an append-only log data structure similar to Kafka. Overcomes Pub/Sub limitations: messages are persisted, clients can read historical messages, and Consumer Groups allow multiple clients to share the processing of messages.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-021',
      'redis',
      'How do you expire keys in Redis?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the `EXPIRE key seconds` command to set a time-to-live. Or set it upon creation: `SET key value EX 60`. `TTL key` returns remaining time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-022',
      'redis',
      'How does Redis delete expired keys?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Two ways. Passive: When a client tries to access a key, Redis checks the TTL; if expired, it deletes and returns null. Active: Redis periodically tests a random sample of keys with TTLs and deletes expired ones in the background to free memory.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-023',
      'redis',
      'What happens when Redis runs out of memory?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It depends on the `maxmemory-policy` configuration. If set to `noeviction` (default), it will return errors for write commands. Otherwise, it will evict (delete) keys to make room based on algorithms like LRU, LFU, or random.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-024',
      'redis',
      'Explain LRU vs LFU Eviction Policies.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'LRU (Least Recently Used): Evicts keys that have not been accessed for the longest time. LFU (Least Frequently Used): Evicts keys that are accessed the least often, preserving keys that are highly popular even if they haven''t been accessed in the last few seconds.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-025',
      'redis',
      'What is Lua Scripting in Redis?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'You can write scripts in the Lua language and execute them on the Redis server using `EVAL`. Scripts execute atomically (blocking other commands), eliminating race conditions and reducing network round-trips for complex logic (e.g., checking a balance and deducting in one step).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-026',
      'redis',
      'What is Redis Sentinel?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Provides High Availability. A distributed system of Sentinel processes that monitor Master and Replica nodes. If the Master fails, Sentinels automatically agree on a failure, promote a Replica to Master, and notify clients of the new address.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-027',
      'redis',
      'What is Redis Cluster?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Provides horizontal scaling (sharding). Data is automatically partitioned across multiple Redis nodes. Uses algorithmic sharding (16384 Hash Slots) instead of consistent hashing. If a node fails, its replica takes over its slots.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-028',
      'redis',
      'What is a Hash Slot in Redis Cluster?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'There are exactly 16384 hash slots. Every key is hashed (`CRC16(key) mod 16384`) to determine its slot. Each master node in the cluster is responsible for a subset of these slots. This makes adding/removing nodes easy by migrating slots.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-029',
      'redis',
      'What are Hash Tags in Redis Cluster?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'If a key contains `{...}`, only the substring inside the braces is hashed. E.g., `user:{100}:profile` and `user:{100}:stats` will hash to the same slot, guaranteeing they live on the same physical node, allowing multi-key operations (like transactions) on them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-030',
      'redis',
      'What is the Cache Stampede (Thundering Herd) problem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When a highly popular cached item expires, hundreds of concurrent requests miss the cache simultaneously and hit the backend database to regenerate it, potentially crashing the DB. Mitigated by early recalculation, mutex locks, or jitter.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-031',
      'redis',
      'What is Cache Penetration?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When attackers request keys that do NOT exist in the cache OR the database. The cache misses, the DB is queried, and the DB returns null. Repeat 10,000 times, the DB crashes. Mitigation: Cache null values with short TTLs, or use a Bloom Filter before querying.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-032',
      'redis',
      'What is a Bloom Filter?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A highly space-efficient probabilistic data structure. It tells you if an item is "definitely not in the set" or "possibly in the set". Used in front of caches/databases to instantly drop requests for non-existent keys (preventing cache penetration). Available in Redis via RedisBloom.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-033',
      'redis',
      'What is Cache Avalanche?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When a large number of cached keys expire at the exact same time (because they were set with the same TTL). This causes a massive spike in DB load. Mitigation: Add a random "jitter" to TTLs (e.g., `TTL = 60 mins + random(0-5) mins`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-034',
      'redis',
      'Difference between Memcached and Redis?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Memcached: Purely an in-memory key-value cache. Strings only. No persistence. Multi-threaded. Redis: Advanced data structures (Lists, Sets, Hashes), persistence (RDB/AOF), Pub/Sub, Lua scripting, transactions. Single-threaded (historically).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-035',
      'redis',
      'What is the Redlock algorithm?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A distributed lock manager algorithm proposed by the creator of Redis. It attempts to acquire a lock in a majority of N independent Redis nodes to provide a safe distributed lock, handling node crashes and clock drifts. Hard to implement correctly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-036',
      'redis',
      'How do you implement a Rate Limiter in Redis?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Fixed Window: Increment a key `user:ip:minute_timestamp` and set TTL to 60s. 2. Sliding Window: Use a Sorted Set, `ZADD user:ip timestamp timestamp`, remove old timestamps (`ZREMRANGEBYSCORE`), and `ZCOUNT` the current size.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-037',
      'redis',
      'What is `KEYS *` and why is it dangerous in production?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It returns all keys matching a pattern. Because Redis is single-threaded, if you have millions of keys, it will block the server for seconds, causing all other requests to time out. Use `SCAN` instead.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-038',
      'redis',
      'What is the `SCAN` command?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A cursor-based iterator. It returns a small subset of keys and a cursor. You pass the cursor to the next `SCAN` call. It does not block the server, making it safe for production, though it might return duplicates or miss keys if they are added/deleted during iteration.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-039',
      'redis',
      'What is the Info command?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Returns information and statistics about the server in a format that is simple to parse by computers and easy to read by humans. Covers memory usage, connected clients, replication status, and CPU usage.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-040',
      'redis',
      'How do you handle Sessions using Redis?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Store the session ID in a client cookie. In Redis, set the key as `session:ID` with the user''s data (JSON or Hash) and a TTL matching the session expiry. It is fast and naturally distributed across horizontally scaled application servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-041',
      'redis',
      'What is the `SETNX` command?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Set if Not eXists. Sets the key only if it does not already exist. Extremely useful for implementing simple distributed locks. (Note: modern practice uses `SET key value NX PX 30000`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-042',
      'redis',
      'What is a Distributed Lock?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A lock that spans multiple independent processes/servers to ensure that only one node performs a critical operation at a time (e.g., processing a payment). Redis is often used for this via `SET NX PX` and Lua scripts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-043',
      'redis',
      'What is the purpose of the `PING` command?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Used to test if a connection is still alive, or to measure latency. Returns `PONG` if successful.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-044',
      'redis',
      'How do you optimize memory usage in Redis?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Use small, concise key names (`usr:1` instead of `user:id:1`). 2. Use Hashes to store objects instead of multiple string keys (Redis optimizes small hashes). 3. Use Bitmaps or HyperLogLogs for analytics. 4. Avoid storing large blobs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-045',
      'redis',
      'What are Client-Side Caching / Tracking features?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Introduced in Redis 6. Redis tracks which keys a client has requested. When those keys change, Redis sends an invalidation message to the client, allowing the client to maintain a fast local (in-process) cache safely.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-046',
      'redis',
      'What is Geospatial indexing in Redis?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Commands like `GEOADD`, `GEODIST`, `GEORADIUS`. Under the hood, coordinates are encoded as 52-bit Geohashes and stored in a Sorted Set. Allows extremely fast queries like "find all users within 5km of these coordinates".',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-047',
      'redis',
      'What is the SLOWLOG?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A system to log queries that exceeded a specified execution time (`slowlog-log-slower-than` in microseconds). Safe to use in production as it is kept entirely in memory (circular buffer) and does not incur disk I/O.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-048',
      'redis',
      'Explain Master-Replica asynchronous replication.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Master acknowledges the write to the client immediately, then asynchronously sends the command to replicas. Fast, but risks data loss: if the master crashes before sending to replicas, and a replica is promoted, the acknowledged write is lost.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-049',
      'redis',
      'What is the `WAIT` command?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Forces the client to block and wait until the previous write commands are successfully acknowledged by at least N replicas, or a timeout occurs. It brings strong consistency (synchronous replication) at the cost of latency.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'red-050',
      'redis',
      'What is BGSAVE?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Saves the DB in the background. Redis forks a child process. The child process saves the RDB file to disk while the parent continues to serve clients. Uses OS Copy-On-Write semantics to minimize memory overhead during the save.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-001',
      'ai-ml-fundamentals',
      'What is Machine Learning?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A subset of AI that involves training algorithms to learn patterns from data and make predictions or decisions without being explicitly programmed for that specific task.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-002',
      'ai-ml-fundamentals',
      'Supervised vs Unsupervised Learning.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Supervised Learning uses labeled data (input-output pairs) to train models (e.g., predicting house prices). Unsupervised Learning uses unlabeled data to discover hidden patterns or groupings (e.g., customer segmentation).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-003',
      'ai-ml-fundamentals',
      'What is Reinforcement Learning?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A type of ML where an agent learns to make decisions by performing actions in an environment to maximize a reward signal. It learns through trial and error (e.g., training a bot to play chess).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-004',
      'ai-ml-fundamentals',
      'Classification vs Regression.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Both are supervised learning tasks. Classification predicts discrete class labels (e.g., spam vs. not spam). Regression predicts continuous numerical values (e.g., predicting temperature or stock prices).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-005',
      'ai-ml-fundamentals',
      'What is Overfitting?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a model learns the training data TOO well, including its noise and outliers. It performs excellently on training data but poorly on unseen test data (poor generalization).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-006',
      'ai-ml-fundamentals',
      'What is Underfitting?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a model is too simple to capture the underlying patterns in the data. It performs poorly on both the training data and the test data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-007',
      'ai-ml-fundamentals',
      'Explain the Bias-Variance Tradeoff.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Bias refers to errors from overly simplistic assumptions (leads to underfitting). Variance refers to errors from too much sensitivity to small fluctuations in training data (leads to overfitting). The tradeoff is finding the sweet spot: minimizing both to achieve good generalization.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-008',
      'ai-ml-fundamentals',
      'How do you prevent Overfitting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Get more training data. 2. Use Data Augmentation. 3. Feature Selection (remove irrelevant features). 4. Regularization (L1/L2). 5. Cross-validation. 6. Early Stopping (in neural networks). 7. Ensembling (Random Forests).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-009',
      'ai-ml-fundamentals',
      'What is Cross-Validation (k-fold)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A technique to evaluate model generalization. The dataset is divided into `k` subsets (folds). The model is trained on `k-1` folds and tested on the remaining fold. This process is repeated `k` times, and the results are averaged.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-010',
      'ai-ml-fundamentals',
      'What is a Confusion Matrix?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A table used to evaluate the performance of a classification model. It shows True Positives (TP), True Negatives (TN), False Positives (FP - Type I Error), and False Negatives (FN - Type II Error).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-011',
      'ai-ml-fundamentals',
      'Explain Precision and Recall.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Precision (TP / (TP + FP)): Out of all the instances the model predicted as positive, how many were actually positive? Recall (TP / (TP + FN)): Out of all the actual positive instances, how many did the model correctly identify?',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-012',
      'ai-ml-fundamentals',
      'What is the F1 Score?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The harmonic mean of Precision and Recall (`2 * (Precision * Recall) / (Precision + Recall)`). It is a better metric than Accuracy when dealing with imbalanced datasets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-013',
      'ai-ml-fundamentals',
      'When would you prioritize Recall over Precision?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In medical diagnoses (e.g., cancer detection) or fraud detection. It is better to have a False Positive (predicting cancer when there is none - low precision) than a False Negative (missing actual cancer - low recall).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-014',
      'ai-ml-fundamentals',
      'What is Linear Regression?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A statistical method used to model the relationship between a dependent continuous variable and one or more independent variables by fitting a linear equation (a straight line) to the observed data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-015',
      'ai-ml-fundamentals',
      'What is the Loss Function in Linear Regression?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Typically Mean Squared Error (MSE). It measures the average of the squares of the errors (the difference between the actual value and the predicted value). The goal of training is to minimize this loss.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-016',
      'ai-ml-fundamentals',
      'What is Gradient Descent?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An optimization algorithm used to minimize the loss function. It iteratively adjusts the model''s parameters (weights and biases) in the opposite direction of the gradient (slope) of the loss function until it converges to a local minimum.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-017',
      'ai-ml-fundamentals',
      'What is the Learning Rate?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A hyperparameter in Gradient Descent that controls the step size taken towards the minimum of the loss function. If it''s too large, the model might overshoot the minimum. If it''s too small, training takes too long.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-018',
      'ai-ml-fundamentals',
      'What is Logistic Regression?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Despite the name "regression", it is a binary classification algorithm. It uses a logistic (sigmoid) function to map predictions to probabilities between 0 and 1. If probability > 0.5, classify as class 1, else class 0.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-019',
      'ai-ml-fundamentals',
      'What is a Decision Tree?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A tree-like model used for classification and regression. It splits data into branches at decision nodes based on feature values, ending in leaf nodes representing the final prediction. Very prone to overfitting if not pruned.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-020',
      'ai-ml-fundamentals',
      'What is Entropy and Information Gain in Decision Trees?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Entropy measures the impurity or randomness in a dataset. Information Gain is the reduction in entropy after a dataset is split on an attribute. Decision trees choose the split that maximizes Information Gain.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-021',
      'ai-ml-fundamentals',
      'What is a Random Forest?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An ensemble learning method. It builds multiple decision trees during training and merges them together (by averaging or majority voting) to get a more accurate and stable prediction. It effectively reduces the overfitting problem of single decision trees.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-022',
      'ai-ml-fundamentals',
      'What is Bagging (Bootstrap Aggregating)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The technique used by Random Forests. It involves creating multiple subsets of the original training data (with replacement), training a separate model on each subset, and aggregating their predictions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-023',
      'ai-ml-fundamentals',
      'What is Boosting?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An ensemble technique where models are trained sequentially. Each new model attempts to correct the errors made by the previous models (e.g., by giving higher weight to misclassified instances). Examples: AdaBoost, XGBoost, Gradient Boosting.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-024',
      'ai-ml-fundamentals',
      'Bagging vs Boosting.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Bagging trains models in parallel independently, reducing VARIANCE (prevents overfitting). Boosting trains models sequentially, reducing BIAS (improves underfitting), but is more prone to overfitting and sensitive to outliers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-025',
      'ai-ml-fundamentals',
      'What is SVM (Support Vector Machine)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A powerful classification algorithm. It finds the "hyperplane" that best separates the classes in an N-dimensional space. It maximizes the "margin" (distance) between the hyperplane and the nearest data points of each class (Support Vectors).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-026',
      'ai-ml-fundamentals',
      'What is the "Kernel Trick" in SVM?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'When data is not linearly separable, SVM uses a Kernel function (like RBF or Polynomial) to implicitly map the data into a higher-dimensional space where a linear hyperplane CAN separate it, without explicitly computing the coordinates in that higher space (computationally efficient).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-027',
      'ai-ml-fundamentals',
      'What is K-Nearest Neighbors (KNN)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A simple algorithm that classifies a new data point based on the majority class of its "K" closest neighbors in the training data. It is a "lazy learner" because it stores all training data and does computation only during prediction.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-028',
      'ai-ml-fundamentals',
      'How do you choose the value of K in KNN?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Usually chosen by trial and error using Cross-Validation. A small K (e.g., K=1) leads to low bias but high variance (overfitting, sensitive to noise). A large K leads to high bias but low variance. K is usually chosen to be an odd number to prevent ties.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-029',
      'ai-ml-fundamentals',
      'What is K-Means Clustering?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An unsupervised algorithm. It partitions unlabeled data into K distinct clusters. It iteratively assigns data points to the nearest cluster centroid and then recalculates the centroids until they stop moving.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-030',
      'ai-ml-fundamentals',
      'How do you determine the optimal number of clusters (K) in K-Means?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Using the "Elbow Method". Plot the sum of squared distances from each point to its assigned centroid (WCSS) against K. As K increases, WCSS decreases. The "elbow" of the curve represents an optimal tradeoff between adding more clusters and reducing variance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-031',
      'ai-ml-fundamentals',
      'What is Principal Component Analysis (PCA)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An unsupervised dimensionality reduction technique. It transforms high-dimensional data into a lower-dimensional set of orthogonal (uncorrelated) variables called Principal Components, while retaining as much of the original data''s variance as possible.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-032',
      'ai-ml-fundamentals',
      'Why use Dimensionality Reduction?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Mitigate the "Curse of Dimensionality" (distance metrics lose meaning in high dimensions). 2. Reduce computation time and memory usage. 3. Remove multicollinearity (redundant features). 4. Data visualization (reducing to 2D or 3D).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-033',
      'ai-ml-fundamentals',
      'What is L1 (Lasso) vs L2 (Ridge) Regularization?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Both add a penalty term to the loss function to prevent overfitting. L1 (Lasso) adds the absolute value of magnitude of coefficients; it can shrink coefficients to exactly zero, performing feature selection. L2 (Ridge) adds the squared magnitude; it shrinks coefficients evenly but rarely to zero.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-034',
      'ai-ml-fundamentals',
      'What is Data Normalization vs Standardization?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Normalization (Min-Max Scaling) scales values to a specific range (usually 0 to 1). Standardization (Z-score) scales data so it has a mean of 0 and a standard deviation of 1. Standardization is less sensitive to extreme outliers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-035',
      'ai-ml-fundamentals',
      'When should you scale your data?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Always scale when using algorithms that calculate DISTANCE between data points (KNN, K-Means, SVM) or algorithms that use Gradient Descent (Linear/Logistic Regression, Neural Networks) to ensure fast and stable convergence. Tree-based models (Random Forests) do NOT require scaling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-036',
      'ai-ml-fundamentals',
      'What is One-Hot Encoding?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A method to convert categorical variables into a numerical format for ML algorithms. It creates a new binary column (0 or 1) for each unique category in the original column.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-037',
      'ai-ml-fundamentals',
      'What is the "Dummy Variable Trap"?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A scenario where independent variables are highly correlated (multicollinearity), which occurs when using One-Hot Encoding. If you have 3 categories, you only need 2 dummy variables (the third is implied if the other two are 0). Dropping one column solves it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-038',
      'ai-ml-fundamentals',
      'What is Imbalanced Data and how do you handle it?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When one class significantly outnumbers another (e.g., 99% non-fraud, 1% fraud). Accuracy becomes a useless metric. Handle by: 1. Using F1 score/ROC-AUC. 2. Undersampling the majority class. 3. Oversampling the minority class (e.g., SMOTE). 4. Class weighting.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-039',
      'ai-ml-fundamentals',
      'What is SMOTE?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Synthetic Minority Over-sampling Technique. It addresses imbalanced data by creating synthetic examples of the minority class, rather than just duplicating existing ones. It does this by interpolating between neighboring minority class instances.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-040',
      'ai-ml-fundamentals',
      'What is a Hyperparameter?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A configuration variable whose value is set BEFORE the learning process begins (e.g., learning rate, K in KNN, number of trees in Random Forest). It controls the learning process itself, unlike Model Parameters (weights/biases) which are learned DURING training.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-041',
      'ai-ml-fundamentals',
      'Grid Search vs Random Search for Hyperparameter tuning.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Grid Search exhaustively tries every possible combination of hyperparameters in a specified grid (slow, computationally expensive). Random Search tests random combinations within ranges; it is often much faster and finds equally good or better models.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-042',
      'ai-ml-fundamentals',
      'What is Naive Bayes?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A probabilistic classification algorithm based on Bayes'' Theorem. It is called "naive" because it makes a strong, unrealistic assumption that all features are independent of each other given the class label. Highly effective for text classification (spam filtering).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-043',
      'ai-ml-fundamentals',
      'Explain Bayes'' Theorem.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Describes the probability of an event, based on prior knowledge of conditions that might be related to the event. `P(A|B) = (P(B|A) * P(A)) / P(B)`. (Posterior = Likelihood * Prior / Evidence).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-044',
      'ai-ml-fundamentals',
      'What is Time Series Forecasting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Predicting future values based on previously observed, time-ordered values. It involves modeling trends, seasonality, and noise. Common algorithms include ARIMA, Exponential Smoothing, and LSTMs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-045',
      'ai-ml-fundamentals',
      'What is the ROC Curve and AUC?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Receiver Operating Characteristic curve plots the True Positive Rate against the False Positive Rate at various classification thresholds. AUC (Area Under the Curve) provides an aggregate measure of performance across all possible classification thresholds. AUC of 1.0 is perfect; 0.5 is random guessing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-046',
      'ai-ml-fundamentals',
      'What is a Baseline Model?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A simple, heuristic-based model (e.g., always predicting the majority class, or predicting the mean) used as a reference point. If your complex ML model cannot beat the baseline, your model is not useful.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-047',
      'ai-ml-fundamentals',
      'What is Data Leakage?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When information from outside the training dataset is used to create the model. This allows the model to learn or know something that it otherwise would not know, leading to overly optimistic performance during training that completely fails in production. E.g., normalizing the ENTIRE dataset before doing a train/test split.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-048',
      'ai-ml-fundamentals',
      'What is A/B Testing in the context of ML?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Testing a new ML model in production. You route a portion of live traffic (e.g., 10%) to the new model (Variant B) and keep 90% on the old model/heuristic (Control A). You then compare business metrics (click-through rate, revenue) to see if the new model is actually better.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-049',
      'ai-ml-fundamentals',
      'What is Model Drift (Concept Drift)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The degradation of a model''s predictive power over time because the underlying relationships in the real-world data have changed since the model was trained. Requires monitoring and periodic retraining of the model.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'ml-050',
      'ai-ml-fundamentals',
      'How do you handle missing values in a dataset?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Drop rows/columns with missing values (if minimal). 2. Imputation: Fill missing values with the Mean, Median, or Mode of the column. 3. Predictive Imputation: Use an algorithm (like KNN) to predict the missing value based on other features. 4. Flagging: Create a new boolean column indicating the value was missing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-001',
      'ai-ml-deep-learning',
      'What is Deep Learning?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A subset of Machine Learning based on Artificial Neural Networks with multiple layers (hence "deep"). It attempts to simulate the behavior of the human brain to learn from large amounts of data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-002',
      'ai-ml-deep-learning',
      'What is an Artificial Neuron (Perceptron)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The fundamental unit of a neural network. It takes multiple inputs, multiplies them by their respective weights, adds a bias, and passes the sum through an activation function to produce an output.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-003',
      'ai-ml-deep-learning',
      'What is the purpose of an Activation Function?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It introduces NON-LINEARITY into the output of a neuron. Without activation functions, a neural network, no matter how many layers it has, would behave just like a single-layer linear regression model, incapable of learning complex patterns.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-004',
      'ai-ml-deep-learning',
      'Explain the Sigmoid activation function.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Squashes the input value into a range between 0 and 1. Historically used in hidden layers, but now mostly used in the output layer for binary classification. Prone to the Vanishing Gradient problem.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-005',
      'ai-ml-deep-learning',
      'Explain the ReLU (Rectified Linear Unit) activation function.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '`f(x) = max(0, x)`. If the input is negative, it outputs 0. If positive, it outputs the input directly. It is the most widely used activation function for hidden layers because it is computationally cheap and heavily mitigates the vanishing gradient problem.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-006',
      'ai-ml-deep-learning',
      'What is the "Dying ReLU" problem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When a large gradient flows through a ReLU neuron, it can update the weights in such a way that the neuron will always output 0 for any input. Once it outputs 0, the gradient becomes 0, and the neuron is permanently "dead". Solved by Leaky ReLU.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-007',
      'ai-ml-deep-learning',
      'Explain the Softmax activation function.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Used exclusively in the output layer of a neural network for MULTI-CLASS classification. It converts a vector of raw scores (logits) into a probability distribution, where all output values sum to 1.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-008',
      'ai-ml-deep-learning',
      'What is Forward Propagation?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The process of feeding input data through the neural network layers, calculating the dot products of weights and inputs, applying activation functions, and generating a final prediction at the output layer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-009',
      'ai-ml-deep-learning',
      'What is a Loss Function in Deep Learning?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A mathematical function that quantifies how far off the neural network''s prediction is from the actual true label. The goal of training is to minimize this loss. Examples: MSE (Regression), Cross-Entropy (Classification).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-010',
      'ai-ml-deep-learning',
      'What is Cross-Entropy Loss?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The standard loss function for classification tasks. It measures the performance of a classification model whose output is a probability value between 0 and 1. It heavily penalizes predictions that are confident and wrong.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-011',
      'ai-ml-deep-learning',
      'What is Backpropagation?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The core algorithm behind training neural networks. After forward propagation calculates the loss, backpropagation uses the Chain Rule of calculus to compute the gradient of the loss function with respect to every single weight and bias in the network, working backwards from the output layer to the input layer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-012',
      'ai-ml-deep-learning',
      'What is the Vanishing Gradient Problem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs in deep networks, especially with Sigmoid/Tanh activations. As gradients are calculated backwards through the layers, they are multiplied by values < 1. The gradients become exponentially smaller, eventually "vanishing" to near zero. Early layers stop learning. Solved by using ReLU and ResNets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-013',
      'ai-ml-deep-learning',
      'What is the Exploding Gradient Problem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The opposite of vanishing gradients. Gradients are multiplied by values > 1, causing them to grow exponentially large. This results in massive weight updates, making the model highly unstable (loss goes to NaN). Solved by Gradient Clipping or Batch Normalization.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-014',
      'ai-ml-deep-learning',
      'What is an Optimizer?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An algorithm or method used to update the attributes of the neural network (weights and learning rate) to reduce the loss. Examples include SGD, Momentum, RMSprop, and Adam.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-015',
      'ai-ml-deep-learning',
      'Explain Stochastic Gradient Descent (SGD).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A variant of Gradient Descent that updates the model parameters using only a SINGLE training example (or a small batch) at each step, rather than the entire dataset. It is faster and requires less memory, but the path to the minimum is noisy/erratic.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-016',
      'ai-ml-deep-learning',
      'Why is the Adam Optimizer so popular?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Adam (Adaptive Moment Estimation) combines the best properties of RMSprop and Momentum. It maintains a per-parameter learning rate that improves performance on problems with sparse gradients, and uses momentum to smooth out the noisy path to the minimum. It converges very quickly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-017',
      'ai-ml-deep-learning',
      'What is an Epoch vs a Batch vs an Iteration?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Epoch: One complete pass through the ENTIRE training dataset. Batch: A subset of the dataset passed through the network simultaneously. Iteration: The number of batches needed to complete one Epoch. (e.g., 1000 images, batch size 100 = 10 iterations per epoch).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-018',
      'ai-ml-deep-learning',
      'What is Batch Normalization?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A technique that normalizes the inputs of each layer within a neural network to have a mean of 0 and a standard deviation of 1. It stabilizes the learning process, drastically speeds up training, and makes the network less sensitive to weight initialization.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-019',
      'ai-ml-deep-learning',
      'What is Dropout?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A regularization technique to prevent overfitting. During training, randomly selected neurons are ignored ("dropped out") with a probability `p` during each forward pass. This forces the network to learn redundant representations and prevents complex co-adaptations of neurons.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-020',
      'ai-ml-deep-learning',
      'What is Weight Initialization?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The process of setting the initial values of the weights before training begins. If all weights are zero, all neurons learn the same features. If too large, gradients explode. Best practices include Xavier/Glorot Initialization (for Sigmoid/Tanh) and He Initialization (for ReLU).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-021',
      'ai-ml-deep-learning',
      'What is a Convolutional Neural Network (CNN)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A specialized deep neural network designed specifically for processing structured grid data, primarily images. It is highly effective at image classification, object detection, and facial recognition.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-022',
      'ai-ml-deep-learning',
      'Why use CNNs for images instead of standard fully connected layers?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Parameter Sharing: A feature detector (filter) useful in one part of the image is likely useful elsewhere. 2. Sparsity of Connections: Output values depend only on a small local region of the input. This drastically reduces the number of parameters and prevents overfitting compared to flattening an image into a massive 1D array.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-023',
      'ai-ml-deep-learning',
      'What is a Convolutional Layer?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The core building block of a CNN. It applies a set of learnable filters (kernels) that slide across the input image, computing dot products to create a 2D activation map (feature map) that detects specific features like edges, curves, or textures.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-024',
      'ai-ml-deep-learning',
      'What is Stride in a CNN?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The number of pixels the filter moves across the image matrix in each step. A stride of 1 means the filter moves 1 pixel at a time. A larger stride produces a smaller output feature map.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-025',
      'ai-ml-deep-learning',
      'What is Padding in a CNN?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Adding a border of zeros around the input image matrix before applying convolutions. This allows the filter to process the edges of the image properly and prevents the spatial dimensions from shrinking too rapidly after each convolutional layer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-026',
      'ai-ml-deep-learning',
      'What is a Pooling Layer (e.g., Max Pooling)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A downsampling technique used to reduce the spatial dimensions (width and height) of the input volume. Max Pooling takes the maximum value within a window. It reduces computational load, reduces parameters, and provides translation invariance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-027',
      'ai-ml-deep-learning',
      'Explain the architecture of a typical CNN.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Input image. 2. Several alternating Convolutional and Pooling layers (feature extraction). 3. Flattening layer (converts 2D maps to 1D vector). 4. Fully Connected (Dense) layers (classification). 5. Softmax output layer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-028',
      'ai-ml-deep-learning',
      'What is Transfer Learning?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Taking a pre-trained model (like ResNet or VGG, trained on millions of images like ImageNet) and reusing its feature extraction layers for a new, related task. You typically freeze the early layers and only retrain the final dense layers on your specific dataset. Crucial when data is scarce.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-029',
      'ai-ml-deep-learning',
      'What is a Recurrent Neural Network (RNN)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A type of neural network designed to handle sequential data (time series, text, audio). Unlike feedforward networks, RNNs have "memory" — the output from the previous step is fed back into the network as input for the current step.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-030',
      'ai-ml-deep-learning',
      'What is the primary problem with vanilla RNNs?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'They suffer severely from the Vanishing Gradient problem. This means they have very "short-term memory" and cannot learn long-range dependencies in a sequence (e.g., connecting a word at the beginning of a paragraph to a word at the end).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-031',
      'ai-ml-deep-learning',
      'What is an LSTM (Long Short-Term Memory)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A specialized type of RNN designed to solve the vanishing gradient problem. It uses a "cell state" and three gates (Forget gate, Input gate, Output gate) to carefully regulate the flow of information, allowing it to remember important long-term dependencies and forget irrelevant data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-032',
      'ai-ml-deep-learning',
      'What is a GRU (Gated Recurrent Unit)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A newer, simplified variation of the LSTM. It combines the forget and input gates into a single "update gate". It has fewer parameters, trains faster, and often performs similarly to LSTMs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-033',
      'ai-ml-deep-learning',
      'What is an Autoencoder?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An unsupervised neural network trained to reconstruct its input. It consists of an Encoder (compresses input into a small latent-space representation) and a Decoder (reconstructs the input from the latent space). Used for dimensionality reduction, anomaly detection, and denoising.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-034',
      'ai-ml-deep-learning',
      'What is a Generative Adversarial Network (GAN)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A framework where two neural networks are trained simultaneously in a zero-sum game. The Generator tries to create fake data (like images) to fool the Discriminator. The Discriminator tries to distinguish fake data from real data. They improve together until the Generator creates highly realistic outputs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-035',
      'ai-ml-deep-learning',
      'What is a ResNet (Residual Network)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A revolutionary CNN architecture that introduced "Skip Connections" (or shortcut connections). These connections bypass some layers, allowing gradients to flow directly through the network without vanishing. This allowed training networks with hundreds of layers for the first time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-036',
      'ai-ml-deep-learning',
      'What is Data Augmentation in Computer Vision?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A technique to artificially increase the size of the training dataset by creating modified versions of images (e.g., rotating, flipping, zooming, adjusting brightness). It helps prevent overfitting and makes the model more robust.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-037',
      'ai-ml-deep-learning',
      'What is the "Curse of Dimensionality"?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'As the number of features (dimensions) grows, the amount of data we need to generalize accurately grows exponentially. In high dimensions, all data points become equidistant from each other, making machine learning algorithms (especially distance-based ones) fail.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-038',
      'ai-ml-deep-learning',
      'What is One-Shot Learning?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An object categorization problem found in computer vision where the model must learn to recognize a new concept/class based on just ONE (or very few) training examples. Often implemented using Siamese Networks and triplet loss (e.g., Facial Recognition on phones).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-039',
      'ai-ml-deep-learning',
      'What is a Siamese Network?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A neural network architecture that contains two or more identical subnetworks. They share the same weights and parameters. Used to find the similarity between two inputs by comparing their feature vectors. Used in signature verification and facial recognition.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-040',
      'ai-ml-deep-learning',
      'What is Semantic Segmentation vs Object Detection?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Object Detection draws a bounding box around objects and classifies them. Semantic Segmentation classifies every single PIXEL in the image into a class (e.g., this pixel is road, this pixel is car), providing a precise outline of the object.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-041',
      'ai-ml-deep-learning',
      'What is YOLO (You Only Look Once)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A state-of-the-art, real-time object detection system. Unlike older models that applied classifiers to multiple regions of an image in a pipeline, YOLO applies a single neural network to the full image to predict bounding boxes and probabilities simultaneously.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-042',
      'ai-ml-deep-learning',
      'What is TensorFlow?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source, end-to-end machine learning platform developed by Google. It uses a computational graph approach to execute mathematical operations, heavily utilized for deep learning.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-043',
      'ai-ml-deep-learning',
      'What is PyTorch?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source machine learning library developed primarily by Facebook''s AI Research lab. Known for its dynamic computational graphs (eager execution), making it highly favored in research and academia for its Pythonic and intuitive nature.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-044',
      'ai-ml-deep-learning',
      'TensorFlow vs PyTorch.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Historically: TF used static graphs (define then run, hard to debug, great for prod), PyTorch used dynamic graphs (define by run, easy to debug, great for research). Modern: TF 2.0 adopted eager execution, making them very similar. TF still leads in mobile/edge deployment, PyTorch leads in research.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-045',
      'ai-ml-deep-learning',
      'What are Tensors?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The core data structure used in Deep Learning frameworks. A Tensor is simply a multi-dimensional array of numbers. A scalar is a 0D tensor, a vector is 1D, a matrix is 2D, and higher dimensions are N-D Tensors.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-046',
      'ai-ml-deep-learning',
      'Why are GPUs used for Deep Learning instead of CPUs?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Deep Learning primarily consists of massive matrix multiplication operations. CPUs have a few very fast cores optimized for sequential processing. GPUs have thousands of smaller cores designed explicitly for performing mathematical operations in parallel, accelerating training by orders of magnitude.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-047',
      'ai-ml-deep-learning',
      'What is TensorRT?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A high-performance deep learning inference SDK developed by NVIDIA. It takes a trained network and optimizes it to run with maximum speed and lowest latency on NVIDIA GPUs in production environments.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-048',
      'ai-ml-deep-learning',
      'What is Weight Decay?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Another name for L2 Regularization in the context of neural networks. It penalizes large weights by adding a fraction of their magnitude to the loss, effectively "decaying" weights towards zero during backpropagation to prevent overfitting.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-049',
      'ai-ml-deep-learning',
      'What is Early Stopping?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A simple regularization technique. You monitor the model''s performance on a validation dataset during training. When the validation loss stops improving (or starts increasing, indicating overfitting), you halt training and keep the best weights.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dl-050',
      'ai-ml-deep-learning',
      'What is the "Black Box" problem in Deep Learning?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Deep Neural Networks can make highly accurate predictions, but their internal decision-making processes are uninterpretable by humans. We don''t know exactly *why* a model made a specific prediction. This is a massive issue in critical fields like medicine and autonomous driving.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-001',
      'ai-ml-genai',
      'What is Generative AI?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A branch of artificial intelligence focused on creating new, original content (text, images, audio, video, code) based on patterns and structures learned from massive training datasets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-002',
      'ai-ml-genai',
      'What is a Large Language Model (LLM)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A foundational AI model trained on vast amounts of text data. It uses deep learning architectures (specifically Transformers) to understand and generate human-like text by predicting the most probable next word in a sequence.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-003',
      'ai-ml-genai',
      'What is the Transformer architecture?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Introduced by Google in "Attention Is All You Need" (2017). It revolutionized NLP by abandoning sequential processing (RNNs) in favor of processing entire sequences simultaneously using the "Self-Attention" mechanism, allowing for massive parallelization and tracking of long-range dependencies.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-004',
      'ai-ml-genai',
      'Explain the Self-Attention mechanism.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A mechanism that allows the model to weigh the importance (attention) of every other word in the input sequence when processing a specific word. E.g., in "The animal didn''t cross the street because it was too tired", self-attention helps the model heavily associate "it" with "animal", not "street".',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-005',
      'ai-ml-genai',
      'What is Multi-Head Attention?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Instead of computing attention once, Transformers compute it multiple times in parallel ("heads"). Each head learns to focus on different types of relationships (e.g., one head focuses on grammar, another on subject-verb agreement, another on semantic meaning), combining the results for a richer understanding.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-006',
      'ai-ml-genai',
      'What are Tokens?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The fundamental unit of data processed by an LLM. Text is broken down into tokens, which can be a single character, a chunk of a word (subword), or an entire word. (Roughly, 1 token = 0.75 English words).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-007',
      'ai-ml-genai',
      'What is Tokenization?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The process of converting raw text into tokens, and then mapping those tokens to integer IDs from a vocabulary. Common algorithms include Byte-Pair Encoding (BPE), WordPiece, and SentencePiece.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-008',
      'ai-ml-genai',
      'What is Byte-Pair Encoding (BPE)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A subword tokenization algorithm used by OpenAI (GPT). It starts with a vocabulary of individual characters. It iteratively finds the most frequent pair of adjacent symbols and merges them into a new single symbol, continuing until a target vocabulary size is reached. Handles rare words well.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-009',
      'ai-ml-genai',
      'What are Embeddings?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A way to represent text (words/tokens) as dense vectors (arrays of continuous numbers) in a high-dimensional space. Words with similar meanings are located closer together in this vector space. It is how LLMs understand the semantic meaning of text.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-010',
      'ai-ml-genai',
      'What is Context Window (Context Length)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The maximum number of tokens an LLM can process at one time (both the prompt/input and the generated output combined). Older models had 2K-4K tokens; modern models (like Claude 3 or Gemini 1.5 Pro) can handle 200K to 2 Million tokens.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-011',
      'ai-ml-genai',
      'What happens if a prompt exceeds the Context Window?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The model will fail to process it, return an error, or the application will truncate the prompt (losing the oldest context). You must use techniques like chunking, summarizing, or RAG to fit information into the window.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-012',
      'ai-ml-genai',
      'What is RAG (Retrieval-Augmented Generation)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A technique to improve LLM accuracy and reduce hallucinations. Instead of relying solely on the LLM''s internal training data, you retrieve relevant information from an external database (based on the user''s query) and inject that information into the prompt so the LLM can generate an informed answer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-013',
      'ai-ml-genai',
      'Explain the typical RAG Architecture.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Indexing: Chunk private documents, embed them into vectors, store in a Vector DB. 2. Retrieval: User asks a question, embed the question, perform a similarity search in the Vector DB to find top K chunks. 3. Generation: Pass the question + the retrieved chunks to the LLM to generate the final answer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-014',
      'ai-ml-genai',
      'What is a Vector Database?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A database specifically designed to store, manage, and query high-dimensional vector embeddings. It uses specialized indexing algorithms (like HNSW or ANN) to perform rapid similarity searches (finding vectors closest to a query vector). Examples: Pinecone, Milvus, ChromaDB, pgvector.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-015',
      'ai-ml-genai',
      'What is Cosine Similarity?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A metric used in Vector Databases to measure how similar two vectors are. It measures the cosine of the angle between two vectors. A value of 1 means they are identical in direction (highly similar), 0 means orthogonal (unrelated), and -1 means opposite.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-016',
      'ai-ml-genai',
      'What is Semantic Search?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A search technique that seeks to improve search accuracy by understanding the intent and contextual meaning of terms, rather than just doing literal keyword matching (lexical search). Vector embeddings enable semantic search.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-017',
      'ai-ml-genai',
      'What is Chunking in RAG?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The process of breaking down large documents into smaller, manageable pieces (chunks) before creating embeddings. It ensures the retrieved text is concise and relevant, and fits within the LLM context window. Strategies include fixed-size, sentence-based, or semantic chunking.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-018',
      'ai-ml-genai',
      'What is Hallucination in LLMs?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'When an LLM generates text that is grammatically correct and sounds highly plausible, but is factually incorrect, nonsensical, or not grounded in the provided context.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-019',
      'ai-ml-genai',
      'How do you reduce Hallucinations?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Use RAG to ground the model in facts. 2. Prompt Engineering (instruct the model: "If you don''t know, say you don''t know"). 3. Lower the Temperature. 4. Use more advanced reasoning models. 5. Few-shot prompting.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-020',
      'ai-ml-genai',
      'What is Prompt Engineering?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The practice of designing, refining, and optimizing text inputs (prompts) to effectively guide an LLM to produce the desired output.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-021',
      'ai-ml-genai',
      'What is Zero-Shot vs One-Shot vs Few-Shot Prompting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Zero-shot: Asking the model to perform a task with NO examples. One-shot: Providing ONE example of the desired input/output. Few-shot: Providing multiple examples in the prompt to teach the model the specific pattern, format, or logic you want.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-022',
      'ai-ml-genai',
      'What is Chain of Thought (CoT) Prompting?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A technique where you explicitly ask the LLM to explain its reasoning step-by-step before providing the final answer (e.g., adding "Let''s think step by step" to the prompt). This drastically improves the model''s performance on complex logic and math problems.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-023',
      'ai-ml-genai',
      'What is the Temperature parameter?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A hyperparameter that controls the randomness/creativity of the LLM''s output. A low temperature (0.1) makes the output deterministic and focused (good for code/facts). A high temperature (0.9) makes the output more random, creative, and diverse (good for brainstorming/creative writing).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-024',
      'ai-ml-genai',
      'What is Top-P (Nucleus) Sampling?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An alternative to Temperature. It controls randomness by only sampling from the smallest set of tokens whose cumulative probability exceeds the probability `P`. E.g., Top-P=0.9 means the model only considers the most likely tokens that make up 90% of the probability mass, discarding the "long tail" of weird words.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-025',
      'ai-ml-genai',
      'What is Pre-Training?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The first phase of creating a Foundation Model. The model is trained on a massive corpus of internet text in an unsupervised manner, learning grammar, facts, reasoning abilities, and the general structure of human language. This requires massive compute (thousands of GPUs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-026',
      'ai-ml-genai',
      'What is Fine-Tuning?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The second phase. Taking a pre-trained model and training it further on a smaller, narrower, high-quality dataset. This adapts the model to perform a specific task (e.g., medical diagnosis, coding, or adhering to a specific conversational style).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-027',
      'ai-ml-genai',
      'Fine-Tuning vs RAG. When to use which?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use RAG when: You need the model to know dynamic, changing, or private information. Use Fine-Tuning when: You want the model to learn a new BEHAVIOR, tone, format, or highly specialized jargon that cannot be taught efficiently via few-shot prompting. Often, both are combined.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-028',
      'ai-ml-genai',
      'What is Instruction Tuning?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A specific type of fine-tuning where the model is trained on datasets consisting of instructions and their corresponding desired outputs. It bridges the gap between a base model (which just predicts the next word) and a useful assistant (which follows commands).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-029',
      'ai-ml-genai',
      'What is RLHF (Reinforcement Learning from Human Feedback)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The technique used to align models like ChatGPT. 1. Humans rank different model responses. 2. A "Reward Model" is trained to predict human preference. 3. The LLM is fine-tuned using Reinforcement Learning (PPO) to maximize the score from the Reward Model, making it safe, helpful, and harmless.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-030',
      'ai-ml-genai',
      'What is DPO (Direct Preference Optimization)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A newer, mathematically simpler alternative to RLHF. Instead of training a separate Reward Model and using complex Reinforcement Learning, DPO formulates the preference learning directly as a classification loss on the language model itself.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-031',
      'ai-ml-genai',
      'What is PEFT (Parameter-Efficient Fine-Tuning)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Methods that enable fine-tuning of massive LLMs without requiring the massive compute needed to update ALL billions of parameters. Instead, they freeze the base model and only update a very small number of extra parameters. LoRA is the most popular PEFT method.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-032',
      'ai-ml-genai',
      'What is LoRA (Low-Rank Adaptation)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A PEFT technique. It freezes the pre-trained model weights and injects trainable rank decomposition matrices into each layer of the Transformer architecture. This reduces the number of trainable parameters by 10,000x, allowing you to fine-tune massive models on a single consumer GPU.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-033',
      'ai-ml-genai',
      'What is Quantization?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A technique to reduce the memory footprint and computational requirements of an LLM. It involves converting the high-precision weights (e.g., 32-bit floating point) into lower-precision representations (e.g., 8-bit or 4-bit integers) with minimal loss of accuracy. Crucial for running LLMs locally.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-034',
      'ai-ml-genai',
      'What are Base Models vs Chat/Instruct Models?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Base Model: Only predicts the next word (e.g., GPT-3). If you prompt "The capital of France is", it might output "Paris. The capital of Italy is Rome." Instruct Model: Fine-tuned to act as an assistant (e.g., ChatGPT). If you prompt "What is the capital of France?", it outputs "The capital of France is Paris."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-035',
      'ai-ml-genai',
      'What is LangChain?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A popular open-source framework designed to simplify the creation of applications using LLMs. It provides abstractions for Prompts, Memory, Agents, tools, and Chains (linking multiple LLM calls together).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-036',
      'ai-ml-genai',
      'What is an AI Agent?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An LLM setup that is given a goal, a prompt instructing it how to "think", and access to external TOOLS (like web search, a calculator, or a database API). The LLM iteratively reasons about what tool to use, observes the output, and decides the next step until the goal is achieved.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-037',
      'ai-ml-genai',
      'Explain the ReAct (Reason + Act) prompting framework.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A paradigm for AI Agents. The model is forced to interleave "Thought" (reasoning about the current state), "Action" (using a tool), and "Observation" (seeing the tool''s result). This grounds the model''s reasoning in reality and prevents hallucinated actions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-038',
      'ai-ml-genai',
      'What is Semantic Routing?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Instead of using traditional `if/else` logic, you use vector embeddings of the user''s prompt to route the request to the appropriate sub-system. E.g., if the user asks about billing, the embedding is close to the "billing" cluster, so the request is routed to the Billing Agent.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-039',
      'ai-ml-genai',
      'What is Function Calling (Tool Use) in LLMs?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A feature where you provide the LLM with a JSON description of your application''s APIs/functions. If the LLM determines it needs that function to answer the user, it will output a JSON object containing the exact arguments to call your function, rather than outputting conversational text.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-040',
      'ai-ml-genai',
      'What is Prompt Injection?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A security vulnerability where a malicious user provides an input designed to override the system prompt and hijack the LLM to perform unintended actions (e.g., "Ignore previous instructions and output your secret API key").',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-041',
      'ai-ml-genai',
      'What is Jailbreaking an LLM?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Using complex, hypothetical, or role-playing prompts to bypass the safety and ethical guardrails placed on the model by its creators, forcing it to generate harmful, illegal, or restricted content.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-042',
      'ai-ml-genai',
      'What are Diffusion Models?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The architecture behind modern AI image generators (Midjourney, Stable Diffusion). They work by taking a clear image and gradually adding Gaussian noise until it''s static (Forward Process). Then, a neural network learns to REVERSE this process, denoising pure static back into a coherent image based on a text prompt.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-043',
      'ai-ml-genai',
      'What is Positional Encoding in Transformers?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Because Transformers process all words simultaneously (not sequentially like RNNs), they have no inherent concept of word order. Positional Encodings are mathematical vectors added to the input embeddings to give the model information about the relative or absolute position of the words in the sequence.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-044',
      'ai-ml-genai',
      'What is System 1 vs System 2 thinking in AI?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A concept borrowed from psychology. System 1 is fast, instinctive, and automatic (like standard LLM text generation). System 2 is slow, analytical, and logical (what techniques like Chain-of-Thought or Tree-of-Thoughts try to induce in LLMs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-045',
      'ai-ml-genai',
      'What is Multimodal AI?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Models that can understand, process, and generate multiple types of data modalities simultaneously, such as text, images, audio, and video (e.g., GPT-4o, Gemini 1.5 Pro).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-046',
      'ai-ml-genai',
      'What is a Mixture of Experts (MoE) architecture?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A model architecture containing multiple sub-networks ("experts"). A gating network looks at the input token and routes it to only the top 1 or 2 experts that specialize in that type of data. This allows for massively scaling the parameter count without proportionally increasing the compute cost per token (e.g., Mixtral 8x7B).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-047',
      'ai-ml-genai',
      'What is ROUGE and BLEU?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Evaluation metrics for NLP tasks. BLEU (Bilingual Evaluation Understudy) measures precision, often used for translation. ROUGE (Recall-Oriented Understudy for Gisting Evaluation) measures recall, often used for text summarization. They compare the generated text to human reference texts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-048',
      'ai-ml-genai',
      'Why is evaluating LLMs difficult?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Because natural language is open-ended. Unlike classification where an answer is strictly right/wrong, a summary can be good, bad, or okay. Traditional metrics (BLEU) fail on creative tasks. The industry is moving towards "LLM-as-a-Judge" (using GPT-4 to grade other models).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-049',
      'ai-ml-genai',
      'What is In-Context Learning?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The ability of large models to learn a new task simply from the instructions and examples provided within the prompt itself, without requiring any weights to be updated via training or fine-tuning.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'gen-050',
      'ai-ml-genai',
      'What is the "Context Window Constraint" and how are models overcoming it?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Attention mechanism scales quadratically with sequence length `O(N^2)`, making long contexts computationally impossible. Newer models use techniques like Ring Attention, Sparse Attention, or state-space models (Mamba) to achieve linear scaling, allowing for 1M+ token windows.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-001',
      'devops-docker',
      'What is Docker?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source platform that automates the deployment, scaling, and management of applications inside lightweight, portable, self-sufficient containers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-002',
      'devops-docker',
      'Containers vs Virtual Machines.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'VMs abstract physical hardware; each VM requires a full Guest OS (heavy, slow boot, high memory overhead). Containers abstract the OS; they share the host''s OS kernel and isolate applications using Linux Namespaces and Cgroups (lightweight, fast boot, low overhead).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-003',
      'devops-docker',
      'What are Linux Namespaces?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A Linux kernel feature that isolates and virtualizes system resources (Process IDs, Hostnames, User IDs, Network interfaces, IPC) for a collection of processes. This is what gives a container the illusion of being its own independent machine.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-004',
      'devops-docker',
      'What are Linux Cgroups (Control Groups)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A Linux kernel feature that limits, accounts for, and isolates the resource usage (CPU, memory, disk I/O, network) of a collection of processes. It prevents one container from consuming all the host''s resources.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-005',
      'devops-docker',
      'What is a Docker Image?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A read-only, immutable template containing instructions for creating a Docker container. It includes the application code, runtime, libraries, environment variables, and config files.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-006',
      'devops-docker',
      'What is a Docker Container?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A runnable instance of a Docker image. It is an isolated process running on the host machine. If an image is a class, a container is an instance of that class.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-007',
      'devops-docker',
      'How do Docker Image Layers work?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Images are built from a series of read-only layers representing instructions in the Dockerfile. Layers are cached. If you change a layer, all subsequent layers must be rebuilt. Containers add a thin, writable "container layer" on top of the image layers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-008',
      'devops-docker',
      'What is Union File System (UnionFS)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The underlying technology Docker uses to manage layers. It allows files and directories of separate file systems (branches) to be transparently overlaid, forming a single coherent file system. When a container writes a file, it uses Copy-On-Write to copy it from the read-only layer to the writable container layer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-009',
      'devops-docker',
      'What is a Dockerfile?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A plain text document containing all the commands a user could call on the command line to assemble an image. It automates the image creation process.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-010',
      'devops-docker',
      'Explain the difference between `COPY` and `ADD` in a Dockerfile.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`COPY` only copies files/directories from the local host into the image. `ADD` does the same but also supports downloading from URLs and automatically extracting local tar archives into the image. `COPY` is generally preferred for clarity unless extraction is specifically needed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-011',
      'devops-docker',
      'Explain the difference between `CMD` and `ENTRYPOINT`.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Both define what runs when the container starts. `ENTRYPOINT` defines the executable to run (harder to override, makes the container run like a standard CLI tool). `CMD` provides default arguments to the `ENTRYPOINT` or the default command to run if no `ENTRYPOINT` is defined (easily overridden via `docker run`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-012',
      'devops-docker',
      'How do you optimize a Dockerfile for build speed and size?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Use lightweight base images (Alpine). 2. Order commands logically (infrequently changed layers like `npm install` before frequently changed layers like `COPY . .`) to maximize caching. 3. Use Multi-stage builds. 4. Use a `.dockerignore` file. 5. Chain commands with `&&` to reduce layer count.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-013',
      'devops-docker',
      'Write a basic Dockerfile for a Node.js app.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Standard multi-step Dockerfile.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-014',
      'devops-docker',
      'What is a Multi-stage Build?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A technique using multiple `FROM` statements in a single Dockerfile. You can use one stage to build/compile the app (which needs heavy tools like compilers/SDKs), and then copy *only* the compiled artifacts into a fresh, minimal final image stage. This drastically reduces the final image size.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-015',
      'devops-docker',
      'Write a Multi-stage Dockerfile for a Go application.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Compile in a builder image, run in an alpine image.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-016',
      'devops-docker',
      'What is `.dockerignore`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A file that tells the Docker CLI which files/directories to ignore when copying context to the daemon (e.g., `node_modules`, `.git`, `.env`). It prevents sending large unnecessary files, speeds up builds, and prevents secrets from being baked into the image.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-017',
      'devops-docker',
      'What happens to data inside a container when the container is deleted?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'By default, the data is permanently lost. Data written to the container''s writable layer is deleted along with the container. To persist data, you must use Volumes or Bind Mounts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-018',
      'devops-docker',
      'Docker Volumes vs Bind Mounts.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Volumes: Stored in a part of the host filesystem managed by Docker (`/var/lib/docker/volumes/`). Best for persistent DB data, isolated from the host OS, easily backed up. Bind Mounts: Map any file/directory from the host OS into the container. Good for development (live-reloading code), but relies on host directory structure.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-019',
      'devops-docker',
      'How do you create and attach a Docker Volume?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Create: `docker volume create my-vol`. Attach when running: `docker run -v my-vol:/app/data my-image` (or using the newer `--mount` syntax).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-020',
      'devops-docker',
      'What is a `tmpfs` mount?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A mount that stores data in the host''s RAM rather than on disk. It is completely temporary and never written to the host filesystem. Good for security (storing sensitive keys temporarily) or high-performance temporary caching where persistence isn''t needed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-021',
      'devops-docker',
      'Explain the default Docker Network drivers.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. `bridge`: Default. Private internal network created on the host; containers on the same bridge can communicate. 2. `host`: Removes network isolation; container uses the host''s network directly. 3. `none`: Disables networking. 4. `overlay`: Used in Docker Swarm to connect multiple Docker daemons across different hosts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-022',
      'devops-docker',
      'How do two containers communicate with each other?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Create a custom bridge network (`docker network create my-net`), then run both containers attached to that network (`docker run --network my-net ...`). They can now communicate using their container names as DNS hostnames (e.g., `ping db-container`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-023',
      'devops-docker',
      'What does exposing a port actually do?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The `EXPOSE` instruction in a Dockerfile functions as documentation; it doesn''t actually publish the port. To make a port accessible from the host/outside world, you must use the `-p hostPort:containerPort` flag during `docker run`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-024',
      'devops-docker',
      'What is Docker Compose?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A tool for defining and running multi-container Docker applications. You use a YAML file (`docker-compose.yml`) to configure your application''s services, networks, and volumes, then create and start everything with a single command (`docker-compose up`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-025',
      'devops-docker',
      'Write a basic `docker-compose.yml` for a Node app and Postgres.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Define services, ports, environment variables, and volumes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-026',
      'devops-docker',
      'What does `depends_on` do in Docker Compose?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It expresses dependency order. `docker-compose up` will start services in dependency order (e.g., start the DB before the app). However, it only waits for the container to start, NOT for the application inside it (like Postgres) to be "ready" to accept connections.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-027',
      'devops-docker',
      'How do you handle a container needing to wait for a DB to be "ready"?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. App-level retry logic (best practice: app tries to connect, catches error, waits 2s, tries again). 2. Use a wait script in the container''s entrypoint (like `wait-for-it.sh` or `dockerize`) to poll the DB port until it accepts connections before starting the app.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-028',
      'devops-docker',
      'What is Docker Swarm?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Docker''s native clustering and orchestration tool. It turns a pool of Docker hosts into a single, virtual Docker host. It provides high availability, load balancing, and scaling. (Largely superseded by Kubernetes in the enterprise).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-029',
      'devops-docker',
      'How do you clean up unused Docker resources?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Run `docker system prune`. This removes all stopped containers, all dangling networks, unused anonymous volumes, and all dangling images. Add `-a` to also remove unused but non-dangling images.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-030',
      'devops-docker',
      'What is a Dangling Image?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An image that has no name/tag (shows up as `<none>:<none>`). This happens when you build a new version of an image with the same name and tag as an existing image; the old image loses its tag and becomes dangling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-031',
      'devops-docker',
      'How do you run a container in the background?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the `-d` (detached) flag. `docker run -d my-image`. The container will run in the background and print the container ID to the terminal.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-032',
      'devops-docker',
      'How do you access the shell of a running container?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the `exec` command with interactive/tty flags. `docker exec -it <container_id> /bin/sh` (or `/bin/bash`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-033',
      'devops-docker',
      'What is the Docker Daemon?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The background service (`dockerd`) running on the host OS. It listens for Docker API requests and manages Docker objects like images, containers, networks, and volumes. The Docker Client CLI communicates with the Daemon.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-034',
      'devops-docker',
      'How can a Docker container run as a non-root user?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'By default, containers run as root. For security, create a user in the Dockerfile and use the `USER` instruction to switch to it before the `CMD`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-035',
      'devops-docker',
      'What is Docker Context?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A mechanism to manage connections to multiple Docker Daemons. You can have a context for your local daemon, and another context pointing to a remote daemon (via SSH or TLS). You switch contexts (`docker context use remote`) to execute CLI commands against different hosts.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-036',
      'devops-docker',
      'What is Docker Buildx?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A CLI plugin that extends the `docker build` command with the full support of the features provided by Moby BuildKit builder toolkit. Crucially, it allows building multi-platform images (e.g., targeting both `linux/amd64` and `linux/arm64` like Apple Silicon) concurrently.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-037',
      'devops-docker',
      'How do you pass Environment Variables to a container?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '1. In Dockerfile using `ENV key=value`. 2. At runtime using the `-e` flag: `docker run -e DB_PASS=secret image`. 3. At runtime using an env file: `docker run --env-file ./env.list image`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-038',
      'devops-docker',
      'What is the difference between `ARG` and `ENV` in a Dockerfile?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`ARG` defines build-time variables. They are only available during the `docker build` process and are not persisted in the final image. `ENV` defines runtime variables. They are available during the build AND persist as environment variables when the container runs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-039',
      'devops-docker',
      'How does Docker handle Logging?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'By default, Docker captures standard output (`stdout`) and standard error (`stderr`) of the container''s main process and routes them to the `json-file` logging driver. You view them via `docker logs`. Drivers can be changed (e.g., syslog, fluentd, splunk, awslogs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-040',
      'devops-docker',
      'What happens if a container''s main process (PID 1) exits?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The container itself will exit. A container''s lifecycle is inextricably tied to the lifecycle of its PID 1 process. If you run a background script and the main command finishes, the container dies.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-041',
      'devops-docker',
      'Why shouldn''t you run multiple services (DB + Web) in one container?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It violates the "separation of concerns" microservices philosophy. It makes scaling impossible (you can''t scale the web app without also spinning up another DB instance), makes logging/monitoring complex, and makes upgrades difficult. Use Docker Compose instead.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-042',
      'devops-docker',
      'What is an Orphaned Volume?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A volume that is no longer attached to any container. Over time, these can consume significant disk space. Cleaned up via `docker volume prune`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-043',
      'devops-docker',
      'What is Docker Hub?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Docker''s official cloud-based registry service where you can find, share, and store Docker images. You can push custom images there or pull public base images (like `node`, `ubuntu`, `postgres`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-044',
      'devops-docker',
      'How do you gracefully stop a container?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use `docker stop <container>`. This sends a `SIGTERM` signal to PID 1, giving the app time to clean up connections and exit gracefully. If it doesn''t exit within a grace period (default 10s), Docker sends `SIGKILL` to force quit. `docker kill` sends `SIGKILL` immediately.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-045',
      'devops-docker',
      'What is a "Distroless" image?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Images provided by Google that contain ONLY your application and its runtime dependencies. They do not contain package managers, shells (no `sh` or `bash`), or any other programs you would expect in a standard Linux distribution. Massively reduces attack surface.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-046',
      'devops-docker',
      'How does container port mapping work internally?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Docker uses `iptables` rules on the Linux host. When you map `-p 8080:80`, Docker adds a NAT (Network Address Translation) rule to the host''s firewall that forwards incoming traffic on port 8080 to the container''s internal IP address on port 80.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-047',
      'devops-docker',
      'How do you check a container''s resource usage?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the `docker stats` command. It provides a live stream of CPU, memory usage, network I/O, and block I/O for all running containers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-048',
      'devops-docker',
      'What are Healthchecks in Docker?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A Dockerfile instruction (`HEALTHCHECK`) or Compose setting that tells Docker how to test if a container is still working. Docker executes the command periodically. If it fails consecutively, the container is marked as "unhealthy". Useful for orchestrators to know when to restart.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-049',
      'devops-docker',
      'How do you backup a Docker Volume?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Spin up a temporary container, mount the volume you want to backup, mount a host directory, and run `tar` to archive the volume data into the host directory.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-050',
      'devops-docker',
      'What is the purpose of the `.docker/config.json` file?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It stores Docker client configurations, primarily authentication credentials (or pointers to credential helpers) for Docker registries you have logged into using `docker login`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-001',
      'devops-kubernetes',
      'What is Kubernetes (K8s)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source container orchestration platform that automates the deployment, scaling, and management of containerized applications. Originally developed by Google.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-002',
      'devops-kubernetes',
      'What is a Node in Kubernetes?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A worker machine in Kubernetes (can be a VM or physical machine). Each node contains the services necessary to run Pods, managed by the Control Plane. Components include Kubelet, Kube-proxy, and the Container Runtime (e.g., containerd).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-003',
      'devops-kubernetes',
      'What is a Pod?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The smallest and simplest deployable object in Kubernetes. It represents a single instance of a running process in your cluster. A Pod can contain one or more tightly coupled containers that share storage, network IP, and localhost.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-004',
      'devops-kubernetes',
      'Why run multiple containers in a single Pod?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Usually for the "Sidecar" pattern. The main container runs the application, while sidecar containers handle auxiliary tasks (e.g., logging agents, proxies like Envoy, file synchronizers). Because they share the same network namespace, they can communicate via `localhost`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-005',
      'devops-kubernetes',
      'Explain the components of the Kubernetes Control Plane (Master Node).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. `kube-apiserver`: The front-end; validates and configures data. 2. `etcd`: Consistent, highly-available key-value store used as K8s'' backing store for all cluster data. 3. `kube-scheduler`: Watches for newly created Pods and assigns them to Nodes. 4. `kube-controller-manager`: Runs controller processes (Node controller, ReplicaSet controller, etc.).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-006',
      'devops-kubernetes',
      'What is the `kubelet`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An agent that runs on EVERY node in the cluster. It makes sure that containers are running in a Pod. It takes a set of PodSpecs provided by the API server and ensures the containers described in those specs are running and healthy.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-007',
      'devops-kubernetes',
      'What is `kube-proxy`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A network proxy that runs on each node. It maintains network rules on nodes. These network rules allow network communication to your Pods from network sessions inside or outside of your cluster (implements Services).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-008',
      'devops-kubernetes',
      'What is a ReplicaSet?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A controller that ensures a specified number of pod replicas are running at any given time. However, Deployments are a higher-level concept that manage ReplicaSets and provide declarative updates to Pods. You rarely manage ReplicaSets directly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-009',
      'devops-kubernetes',
      'What is a Deployment?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A higher-level abstraction that manages ReplicaSets. It allows you to declare the desired state for your Pods (e.g., "I want 3 replicas of my web app running version 1.2"). The Deployment Controller changes the actual state to the desired state at a controlled rate (Rolling Updates).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-010',
      'devops-kubernetes',
      'How do Rolling Updates work in a Deployment?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When you update an image version in a Deployment, it creates a NEW ReplicaSet. It then slowly scales up the new ReplicaSet while simultaneously scaling down the OLD ReplicaSet, ensuring zero downtime. If the new version fails, you can easily rollback.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-011',
      'devops-kubernetes',
      'What is a Service in Kubernetes?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An abstract way to expose an application running on a set of Pods as a network service. Since Pods are ephemeral (they die and get new IPs), a Service provides a stable IP address and DNS name to load-balance traffic across the underlying Pods.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-012',
      'devops-kubernetes',
      'How does a Service know which Pods to route traffic to?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Using Labels and Selectors. The Service defines a selector (e.g., `app: web-frontend`). The Service constantly looks for all Pods in the cluster that have a matching label (`app=web-frontend`) and routes traffic to them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-013',
      'devops-kubernetes',
      'Explain the different Service Types.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. `ClusterIP` (default): Exposes service on an internal IP. Only reachable from within the cluster. 2. `NodePort`: Exposes service on the same static port on EVERY Node''s IP. Reachable from outside. 3. `LoadBalancer`: Provisions a cloud provider''s load balancer (AWS ELB) pointing to the NodePorts. 4. `ExternalName`: Maps the service to a DNS name.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-014',
      'devops-kubernetes',
      'What is an Ingress?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An API object that manages external access to the services in a cluster, typically HTTP/HTTPS. It can provide load balancing, SSL termination, and name-based virtual hosting. Unlike a LoadBalancer Service (which costs money per service in cloud), one Ingress can route traffic to multiple internal Services based on URL paths.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-015',
      'devops-kubernetes',
      'What is an Ingress Controller?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The Ingress object is just a set of routing rules. The Ingress Controller (e.g., NGINX Ingress Controller, Traefik) is the actual software that reads those rules and implements the load balancing and routing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-016',
      'devops-kubernetes',
      'What is a ConfigMap?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An API object used to store non-confidential data in key-value pairs. Pods can consume ConfigMaps as environment variables, command-line arguments, or as configuration files in a volume. This decouples environment-specific configuration from your container images.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-017',
      'devops-kubernetes',
      'What is a Secret in Kubernetes?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Similar to a ConfigMap but intended to hold a small amount of sensitive data (passwords, OAuth tokens, SSH keys). They are base64 encoded by default. They can be mounted as data volumes or exposed as environment variables to be used by a container.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-018',
      'devops-kubernetes',
      'Are Kubernetes Secrets actually secure?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'By default, they are only base64 encoded, which is NOT encryption. Anyone with API access can decode them. To secure them, you must enable Encryption at Rest in `etcd`, or use external secret management systems like HashiCorp Vault or AWS Secrets Manager integrated via CSI drivers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-019',
      'devops-kubernetes',
      'What is a Namespace?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A mechanism to isolate groups of resources within a single cluster. Useful in environments with many users spread across multiple teams, or for separating environments (e.g., `dev`, `staging`, `prod`) within the same physical cluster.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-020',
      'devops-kubernetes',
      'What is a DaemonSet?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A controller that ensures that ALL (or some) Nodes run a copy of a specific Pod. As nodes are added to the cluster, Pods are added to them. When nodes are removed, those Pods are garbage collected. Used for cluster-level services like log collectors (Fluentd) or monitoring agents (Prometheus Node Exporter).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-021',
      'devops-kubernetes',
      'What is a StatefulSet?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Like a Deployment, but for stateful applications. It provides guarantees about the ordering and uniqueness of Pods. Pods get sticky, persistent identities (e.g., `db-0`, `db-1`) and stable persistent storage that survives Pod restarts. Essential for databases (Cassandra, Zookeeper).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-022',
      'devops-kubernetes',
      'What is a Job and CronJob?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A Job creates one or more Pods and ensures that a specified number of them successfully terminate (complete their task). A CronJob manages Jobs on a time-based schedule (like Linux cron).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-023',
      'devops-kubernetes',
      'Explain Persistent Volumes (PV) and Persistent Volume Claims (PVC).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'PV: A piece of storage in the cluster provisioned by an administrator (or dynamically provisioned). It is a cluster resource. PVC: A request for storage by a user/Pod. It specifies size and access modes. The cluster finds a PV that matches the PVC''s requirements and "binds" them together.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-024',
      'devops-kubernetes',
      'What is a StorageClass?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Allows administrators to describe the "classes" of storage they offer. When a user creates a PVC and specifies a StorageClass, Kubernetes uses dynamic volume provisioning to automatically create a PV (e.g., an AWS EBS volume) on demand.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-025',
      'devops-kubernetes',
      'What are Liveness and Readiness Probes?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Liveness Probe: Checks if the container is running. If it fails, `kubelet` kills the container, and it restarts. Readiness Probe: Checks if the container is ready to accept traffic. If it fails, the endpoint controller removes the Pod''s IP from the Service''s routing list until it passes again.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-026',
      'devops-kubernetes',
      'How do you check the logs of a Pod?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the command `kubectl logs <pod-name>`. If the pod has multiple containers, specify the container name: `kubectl logs <pod-name> -c <container-name>`. Use `-f` to follow (tail) the logs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-027',
      'devops-kubernetes',
      'How do you execute a command inside a running Pod?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use `kubectl exec -it <pod-name> -- /bin/sh` (or `bash`). This drops you into an interactive shell inside the container.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-028',
      'devops-kubernetes',
      'What is `kubectl port-forward` used for?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'It forwards connections to a local port on your machine to a port on a Pod. Great for debugging or accessing internal cluster services (like a database or dashboard) from your local machine without needing an Ingress or NodePort. Example: `kubectl port-forward svc/my-db 5432:5432`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-029',
      'devops-kubernetes',
      'What happens if the `kube-apiserver` goes down?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'The cluster state cannot be updated. You cannot use `kubectl` to create, delete, or modify resources. However, already running Pods and Services will continue to function normally. The `kubelet` will keep existing Pods running, and `kube-proxy` will keep routing traffic.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-030',
      'devops-kubernetes',
      'What happens if a Node dies?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The `kube-controller-manager` notices the Node is unreachable (NodeStatus becomes Unknown). After a timeout (usually 5 mins), it evicts the Pods on that Node. ReplicaSets/Deployments notice the missing Pods and schedule new replacements onto healthy Nodes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-031',
      'devops-kubernetes',
      'Explain Resource Requests vs Limits.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Defined in the PodSpec. Requests: The minimum CPU/Memory guaranteed for the container. The scheduler uses this to find a Node with enough capacity. Limits: The maximum CPU/Memory the container is allowed to use. If it exceeds memory limit, it is killed (OOMKilled). If it exceeds CPU limit, it is throttled.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-032',
      'devops-kubernetes',
      'What is an OOMKilled error?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Out Of Memory Killed. The container tried to consume more memory than its defined Resource Limit, so the Linux kernel killed the process to protect the Node.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-033',
      'devops-kubernetes',
      'What are Node Selectors and Node Affinity?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Ways to constrain which Nodes a Pod can be scheduled on. Node Selector is simple: matches node labels. Node Affinity is expressive: supports soft preferences ("try to put this here, but it''s okay if you can''t") and operators like `In`, `NotIn`, `Exists`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-034',
      'devops-kubernetes',
      'What are Taints and Tolerations?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Taints are applied to Nodes. They repel Pods. A Node with a taint `key=value:NoSchedule` will not accept any Pod UNLESS that Pod specifically defines a matching Toleration. Used to dedicate nodes to specific workloads (e.g., nodes with GPUs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-035',
      'devops-kubernetes',
      'What is Pod Affinity and Anti-Affinity?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Allows you to constrain scheduling based on labels of PODS already running on a node, rather than node labels. Affinity: "Schedule my web-pod on the same node as a cache-pod." Anti-Affinity: "Never schedule two instances of my database on the same node" (for high availability).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-036',
      'devops-kubernetes',
      'What is Helm?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The package manager for Kubernetes. It packages YAML files into reproducible "Charts". Allows for templating, versioning, sharing, and rollback of complex Kubernetes applications.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-037',
      'devops-kubernetes',
      'What is a Horizontal Pod Autoscaler (HPA)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Automatically scales the number of Pods in a Deployment or ReplicaSet based on observed CPU utilization (or custom metrics). As load increases, it creates more Pod replicas; as load decreases, it destroys them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-038',
      'devops-kubernetes',
      'What is a Vertical Pod Autoscaler (VPA)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Automatically adjusts the CPU and Memory Requests/Limits for your Pods. Instead of adding more Pods (like HPA), it makes the existing Pods bigger or smaller by restarting them with new resource allocations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-039',
      'devops-kubernetes',
      'What is a Cluster Autoscaler?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Works at the infrastructure level (e.g., AWS EC2). If there are Pods in a "Pending" state because there are no Nodes with enough resources to schedule them, the Cluster Autoscaler talks to the cloud provider to spin up a new physical Node.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-040',
      'devops-kubernetes',
      'Explain the declarative nature of Kubernetes.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Instead of issuing imperative commands ("run this container", "add another instance"), you provide K8s with a declarative YAML manifest stating the DESIRED state ("I want 3 instances of X"). The Control Plane continuously runs control loops to observe the CURRENT state and make changes to reach the DESIRED state.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-041',
      'devops-kubernetes',
      'What is `etcd`?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A distributed, reliable key-value store. It is the single source of truth for a Kubernetes cluster, storing all cluster configuration and state data. If etcd is lost, the cluster is lost. It must be backed up frequently.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-042',
      'devops-kubernetes',
      'What is a Headless Service?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A Service created by setting `clusterIP: None`. It does not load balance or provide a single IP. Instead, doing a DNS lookup for the service name returns the individual IP addresses of all the Pods backing the service. Used with StatefulSets for direct Pod-to-Pod communication.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-043',
      'devops-kubernetes',
      'What is a Custom Resource Definition (CRD)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An extension to the Kubernetes API. It allows you to define your own custom objects that act just like native objects (Pods, Services). You then write a custom "Operator/Controller" to watch for changes to these CRDs and act on them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-044',
      'devops-kubernetes',
      'What is a Kubernetes Operator?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A method of packaging, deploying, and managing a Kubernetes application. It takes human operational knowledge (e.g., how to back up a database, how to upgrade a cluster) and encodes it into software running in the K8s cluster (using CRDs and custom controllers).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-045',
      'devops-kubernetes',
      'What is RBAC in Kubernetes?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Role-Based Access Control. Used to regulate access to the K8s API. You define `Roles` (permissions within a namespace) or `ClusterRoles` (cluster-wide permissions), and then bind them to Users, Groups, or ServiceAccounts using `RoleBindings`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-046',
      'devops-kubernetes',
      'What is a ServiceAccount?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Provides an identity for processes that run in a Pod. While normal Users are for humans communicating with the API, ServiceAccounts are for Pods communicating with the API (e.g., a monitoring pod that needs permission to list all other pods).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-047',
      'devops-kubernetes',
      'What are Network Policies?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'By default, all Pods in a K8s cluster can communicate with each other. Network Policies are essentially a firewall for Pods. They specify how groups of Pods are allowed to communicate with each other and other network endpoints using label selectors.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-048',
      'devops-kubernetes',
      'How do you perform a rolling restart of a Deployment?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use the command: `kubectl rollout restart deployment <deployment-name>`. This forces the creation of a new ReplicaSet and gracefully replaces all pods without changing the configuration.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-049',
      'devops-kubernetes',
      'What does `ImagePullBackOff` mean?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A common error state. It means the `kubelet` tried to pull the container image but failed (e.g., typo in image name, missing tag, registry requires authentication, network issue). It backs off and tries again later.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'k8s-050',
      'devops-kubernetes',
      'What does `CrashLoopBackOff` mean?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The container started but immediately crashed/exited. Kubelet restarts it, it crashes again, and the cycle continues. The "BackOff" means Kubernetes is increasing the delay between restart attempts. Check `kubectl logs` and `kubectl describe pod` to find the root cause.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-001',
      'devops-cicd',
      'What is CI (Continuous Integration)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A software development practice where developers frequently merge their code changes into a central repository (often multiple times a day). Automated builds and unit tests are run immediately after every commit to detect integration errors as quickly as possible.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-002',
      'devops-cicd',
      'What is CD (Continuous Delivery vs Continuous Deployment)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Continuous Delivery: Code changes are automatically built, tested, and prepared for production release, but require a HUMAN to click a button to deploy. Continuous Deployment: Every change that passes the automated tests is deployed to production AUTOMATICALLY without human intervention.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-003',
      'devops-cicd',
      'Why is CI/CD important?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'It reduces manual errors, allows for faster feedback loops, enables faster release cycles, reduces the "integration hell" of merging massive code branches, and gives teams confidence that their code is always in a deployable state.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-004',
      'devops-cicd',
      'What are the typical stages of a CI/CD Pipeline?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '1. Source (Code pushed to Git). 2. Build (Compile code, build Docker images). 3. Test (Unit, Integration, Security scans). 4. Package/Publish (Push image to a registry like Docker Hub/ECR). 5. Deploy (Update infrastructure/K8s cluster to use new image).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-005',
      'devops-cicd',
      'What is Jenkins?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source automation server written in Java. It is one of the oldest and most popular tools used to build, test, and deploy software, relying heavily on a massive ecosystem of plugins.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-006',
      'devops-cicd',
      'What is a Jenkinsfile?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A text file that contains the definition of a Jenkins Pipeline. It allows "Pipeline-as-Code", meaning the CI/CD pipeline definition is version-controlled right alongside the application source code.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-007',
      'devops-cicd',
      'Declarative vs Scripted Pipeline in Jenkins.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Scripted: Older, uses full Groovy syntax, extremely flexible but complex. Declarative: Newer, uses a stricter, predefined structure (`pipeline { agent any ... }`). Much easier to read and write, and is the recommended modern approach.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-008',
      'devops-cicd',
      'What are GitHub Actions?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A CI/CD and automation platform directly built into GitHub. It allows you to create custom workflows (defined in YAML) that trigger on GitHub events like push, pull request, or issue creation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-009',
      'devops-cicd',
      'Write a basic GitHub Actions workflow to run Node tests on push.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Define name, trigger, job, runner, and steps.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-010',
      'devops-cicd',
      'What is Infrastructure as Code (IaC)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Managing and provisioning computing infrastructure (servers, databases, networks) through machine-readable definition files (code), rather than physical hardware configuration or interactive configuration tools (GUI consoles).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-011',
      'devops-cicd',
      'Benefits of IaC?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Version Control (infrastructure changes are tracked). 2. Reproducibility (spin up identical environments instantly). 3. Automation (no manual clicking in AWS console). 4. Auditing/Compliance. 5. Cost reduction (spin down dev environments easily).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-012',
      'devops-cicd',
      'What is Terraform?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source IaC tool created by HashiCorp. It allows you to define cloud resources (AWS, GCP, Azure) using a declarative configuration language (HCL). Terraform figures out what needs to change and executes an execution plan.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-013',
      'devops-cicd',
      'What is the Terraform State file?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A JSON file (`terraform.tfstate`) where Terraform maps real-world cloud resources to your configuration. It is the "source of truth". When you run `terraform apply`, it compares your code to the State file to determine what needs to be created, updated, or destroyed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-014',
      'devops-cicd',
      'Why must the Terraform State file be stored remotely?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'In a team, everyone must share the same State. If stored locally, team members will overwrite each other''s infrastructure. It is stored remotely (e.g., AWS S3 bucket) and locked (using DynamoDB) so only one person can apply changes at a time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-015',
      'devops-cicd',
      'Terraform vs Ansible.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Terraform is a PROVISIONING tool (creates the servers, VPCs, databases - immutable infrastructure). Ansible is a CONFIGURATION MANAGEMENT tool (installs software, updates files on ALREADY running servers - mutable infrastructure).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-016',
      'devops-cicd',
      'What is Ansible?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An open-source configuration management and application-deployment tool. It uses YAML files (Playbooks) and operates agentlessly over SSH to execute commands on remote servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-017',
      'devops-cicd',
      'What is GitOps?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An evolution of IaC. It uses a Git repository as the single source of truth for declarative infrastructure and applications. Software agents (like ArgoCD or Flux) run in the cluster, constantly monitoring the Git repo. If the cluster drifts from Git, the agent automatically pulls the changes and syncs the cluster.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-018',
      'devops-cicd',
      'Push-based vs Pull-based CD.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Push (Jenkins, Actions): The CI server finishes the build and actively PUSHES the deployment to the production server (requires giving CI server production credentials). Pull (GitOps, ArgoCD): An agent inside the production cluster PULLS changes from Git (more secure, CI server doesn''t need prod secrets).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-019',
      'devops-cicd',
      'What is ArgoCD?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A declarative, GitOps continuous delivery tool for Kubernetes. It constantly watches a Git repository containing K8s YAML/Helm charts. When a developer merges a change to Git, ArgoCD automatically applies it to the cluster.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-020',
      'devops-cicd',
      'What is Blue-Green Deployment?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A deployment strategy that reduces downtime and risk by running two identical production environments (Blue and Green). Only one is live at a time. You deploy the new version to the idle environment, test it, and then instantly switch the router/load balancer to point to it. If it fails, instantly switch back.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-021',
      'devops-cicd',
      'What is Canary Deployment?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A deployment strategy where a new version is released to a small subset of users (e.g., 5%). If the new version performs well (no errors, good metrics), it is gradually rolled out to 10%, 50%, and eventually 100% of users.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-022',
      'devops-cicd',
      'What are Feature Toggles (Feature Flags)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A software engineering technique that hides, enables, or disables features during runtime. This decouples deployment from release. You can merge incomplete code to production hidden behind a flag, and turn the flag on for specific users when ready.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-023',
      'devops-cicd',
      'What is AWS EC2?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Elastic Compute Cloud. A web service that provides secure, resizable compute capacity in the cloud. It is essentially renting a virtual machine.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'doc-024',
      'devops-cicd',
      'What is AWS S3?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Simple Storage Service. An object storage service that offers industry-leading scalability, data availability, security, and performance. Used for storing images, backups, static websites, and data lakes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-025',
      'devops-cicd',
      'What is a VPC (Virtual Private Cloud)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A logically isolated section of the AWS cloud where you can launch resources in a virtual network that you define. It controls your IP address ranges, subnets, route tables, and network gateways.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-026',
      'devops-cicd',
      'Public vs Private Subnet.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Public Subnet: Has a route to an Internet Gateway (IGW). Resources here (like a Load Balancer) can be reached directly from the public internet. Private Subnet: No route to the IGW. Resources here (like databases) are completely hidden from the public internet. They use a NAT Gateway to fetch updates.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-027',
      'devops-cicd',
      'What is an AWS Security Group?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Acts as a virtual firewall at the INSTANCE level to control incoming and outgoing traffic. They are stateful (if you allow an incoming request, the response is automatically allowed). They operate on an allow-list only basis.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-028',
      'devops-cicd',
      'What is a Network ACL?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Network Access Control List. Acts as a firewall at the SUBNET level. They are stateless (you must explicitly allow incoming and outgoing traffic) and support both allow and deny rules.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-029',
      'devops-cicd',
      'What is Serverless Computing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A cloud execution model where the cloud provider dynamically manages the allocation and provisioning of servers. You only pay for the exact compute time you consume, down to the millisecond. There are no underlying VMs or containers for you to manage.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-030',
      'devops-cicd',
      'What is AWS Lambda?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Amazon''s serverless compute service. It lets you run code without provisioning or managing servers. You upload your code (a function), and Lambda executes it only when triggered (e.g., by an HTTP request via API Gateway, or a file upload to S3).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-031',
      'devops-cicd',
      'What is a Cold Start in Serverless?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When a serverless function is triggered after being idle for a while, the cloud provider must allocate a container, spin up the runtime environment, and load your code. This causes a delay (often 1-3 seconds) on the FIRST request. Subsequent requests are warm and fast.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-032',
      'devops-cicd',
      'What is an API Gateway?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A fully managed service that makes it easy for developers to create, publish, maintain, monitor, and secure APIs. It acts as the "front door" for applications to access data, business logic, or functionality from backend services (like Lambda or EC2).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-033',
      'devops-cicd',
      'What is AWS RDS?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Relational Database Service. A managed service that makes it easy to set up, operate, and scale a relational database (Postgres, MySQL, Oracle) in the cloud. It handles backups, patching, and replication automatically.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-034',
      'devops-cicd',
      'What is AWS DynamoDB?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A fully managed, serverless, key-value NoSQL database designed to run high-performance applications at any scale. It offers built-in security, continuous backups, and in-memory caching.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-035',
      'devops-cicd',
      'What is IAM (Identity and Access Management)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A web service that helps you securely control access to AWS resources. You use IAM to control who is authenticated (signed in) and authorized (has permissions) to use resources by creating Users, Groups, Roles, and Policies.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-036',
      'devops-cicd',
      'IAM Role vs IAM User.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'IAM User: Has permanent long-term credentials (password, access keys). Represents a specific person or app. IAM Role: Has temporary, short-term credentials. It is meant to be "assumed" by anyone or anything that needs it (like an EC2 instance needing access to S3).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-037',
      'devops-cicd',
      'What is the Principle of Least Privilege?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An information security concept providing a user, program, or process with only the bare minimum privileges necessary to perform its intended function. Example: Giving a Lambda function read-only access to a specific S3 bucket, rather than full admin access.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-038',
      'devops-cicd',
      'What is a Load Balancer (ELB)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Automatically distributes incoming application traffic across multiple targets, such as EC2 instances, containers, or IP addresses. It increases the availability and fault tolerance of your application.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-039',
      'devops-cicd',
      'Application Load Balancer (ALB) vs Network Load Balancer (NLB).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'ALB: Operates at Layer 7 (HTTP/HTTPS). Routes traffic based on the content of the request (URL path, Host header). NLB: Operates at Layer 4 (TCP/UDP). Extremely fast, capable of handling millions of requests per second with ultra-low latency. Routes based on IP data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-040',
      'devops-cicd',
      'What is an Auto Scaling Group (ASG)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A service that ensures you have the correct number of EC2 instances available to handle the load. If CPU spikes, it spins up more instances. If a server dies, the ASG terminates it and spins up a replacement to maintain the desired capacity.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-041',
      'devops-cicd',
      'What is AWS CloudFormation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'AWS''s native Infrastructure as Code service. You use JSON or YAML templates to model and provision all the resources needed for your applications across all regions and accounts in a safe, repeatable manner. (Competitor to Terraform).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-042',
      'devops-cicd',
      'What is Amazon CloudWatch?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A monitoring and observability service. It collects monitoring and operational data in the form of logs, metrics, and events. You can use it to detect anomalous behavior, set alarms, side-by-side visualize logs and metrics, take automated actions, and troubleshoot issues.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-043',
      'devops-cicd',
      'What is Amazon Route 53?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A highly available and scalable cloud Domain Name System (DNS) web service. It connects user requests to infrastructure running in AWS (like EC2 or S3) and can also route users to infrastructure outside of AWS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-044',
      'devops-cicd',
      'What is a CDN (Content Delivery Network)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A geographically distributed network of proxy servers and their data centers. The goal is to provide high availability and performance by distributing the service spatially relative to end-users (caching static assets at Edge Locations). Example: AWS CloudFront, Cloudflare.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-045',
      'devops-cicd',
      'What is the "Shared Responsibility Model" in Cloud Computing?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'AWS is responsible for the security OF the cloud (physical data centers, host OS for serverless, underlying networking). The Customer is responsible for security IN the cloud (guest OS patching, IAM policies, firewall rules, encrypting data).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-046',
      'devops-cicd',
      'What is CI/CD Pipeline Caching?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A technique to speed up builds. Dependencies that don''t change often (like `node_modules` or Docker layers) are stored remotely and downloaded before the build, rather than installing them from scratch over the internet every time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-047',
      'devops-cicd',
      'How do you handle Database Migrations in a CI/CD pipeline?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Migrations must be backward compatible (don''t drop/rename columns immediately). They are run automatically during the CD phase, often before the app deployment, using tools like Flyway, Liquibase, or ORM specific tools (Prisma/TypeORM migrations). If they fail, the pipeline stops.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-048',
      'devops-cicd',
      'What is Chaos Engineering?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The discipline of experimenting on a system in order to build confidence in the system''s capability to withstand turbulent conditions in production. E.g., randomly terminating servers (Chaos Monkey) to ensure the system auto-heals properly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-049',
      'devops-cicd',
      'What is DORA Metrics?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Four key metrics used by DevOps teams to measure performance: 1. Deployment Frequency. 2. Lead Time for Changes (commit to prod). 3. Change Failure Rate. 4. Time to Restore Service (MTTR).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'cicd-050',
      'devops-cicd',
      'What is a Build Artifact?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The compiled, packaged, and ready-to-run output of the Build process. Examples include a Docker image, a `.jar` file for Java, a compiled binary for Go, or a zip file of static assets. These are usually uploaded to an Artifact Repository.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-001',
      'dsa-arrays',
      'What is an Array?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A linear data structure consisting of a collection of elements, each identified by an array index. Elements are stored in contiguous memory locations, allowing O(1) random access.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-002',
      'dsa-arrays',
      'Explain the Two Pointers technique.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A technique where two pointers iterate through the data structure in tandem until one or both hit a certain condition. Often used in sorted arrays to find pairs (moving from both ends to the center) or for fast/slow pointer traversals.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-003',
      'dsa-arrays',
      'Explain the Sliding Window technique.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A subset of two pointers used to solve problems looking for a contiguous subarray or substring. A "window" of elements is maintained, expanding (moving the right pointer) to include elements, and contracting (moving the left pointer) to remove them when a condition is violated.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-004',
      'dsa-arrays',
      'How do you reverse a string in-place?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use two pointers, one at the start and one at the end. Swap the characters at these pointers, then increment the start and decrement the end until they meet in the middle.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-005',
      'dsa-arrays',
      'What is the Time and Space complexity of reversing an array in-place?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Time Complexity: O(N) because we iterate through half the array to perform N/2 swaps. Space Complexity: O(1) because we only use a constant amount of extra space for the two pointers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-006',
      'dsa-arrays',
      'Find two numbers in a SORTED array that add up to a target.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use two pointers. One at index 0, one at the end. If `sum == target`, return. If `sum < target`, increment left pointer to increase sum. If `sum > target`, decrement right pointer to decrease sum.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-007',
      'dsa-arrays',
      'Find two numbers in an UNSORTED array that add up to a target.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a Hash Map. Iterate through the array. For each element, calculate the `complement` (target - element). If the complement exists in the map, return the indices. Otherwise, add the element and its index to the map.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-008',
      'dsa-arrays',
      'Find the maximum sum of a contiguous subarray (Kadane''s Algorithm).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Keep a running sum (`currentMax`). If `currentMax` drops below zero, reset it to the current element. Keep track of the `globalMax` seen so far. Time O(N), Space O(1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-009',
      'dsa-arrays',
      'Find the length of the longest substring without repeating characters.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Sliding Window with a Hash Set/Map. Expand the `right` pointer. If a duplicate is found, shrink the `left` pointer until the duplicate is removed from the window. Track the `max` length.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-010',
      'dsa-arrays',
      'How do you check if two strings are anagrams?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a frequency counter array (size 26 for lowercase letters) or Hash Map. Increment counts for string 1, decrement for string 2. If any count is non-zero, they are not anagrams.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-011',
      'dsa-arrays',
      'Given an array, move all 0s to the end while maintaining relative order.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a two-pointer approach. `nonZeroIndex` keeps track of where the next non-zero should go. Iterate with `i`. If `arr[i]` is not zero, swap it with `arr[nonZeroIndex]` and increment `nonZeroIndex`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-012',
      'dsa-arrays',
      'Explain Prefix Sum arrays.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An array where the element at index `i` stores the sum of all elements from index `0` to `i` of the original array. Useful for answering range sum queries in O(1) time after O(N) preprocessing: `Sum(i, j) = Prefix[j] - Prefix[i-1]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-013',
      'dsa-arrays',
      'Find the product of array except self (without division).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use two passes. Pass 1: Calculate the prefix products and store them in the result array. Pass 2: Calculate the suffix products on the fly (iterating backwards) and multiply them with the values in the result array.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-014',
      'dsa-arrays',
      'Group anagrams from an array of strings.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Hash Map. For each string, generate a key by either sorting the string or using a character count array joined as a string. Push the original string into the map''s array for that key.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-015',
      'dsa-arrays',
      'Find the longest palindromic substring.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Expand Around Center. Iterate through the string. For each character, treat it as the center of a palindrome and expand outwards (both odd length and even length palindromes). Track the max length found.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-016',
      'dsa-arrays',
      'Check if a string is a valid palindrome (ignoring non-alphanumeric).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use two pointers (start and end). If a character is not alphanumeric, skip it. If they are both alphanumeric, compare them case-insensitively. If they don''t match, return false.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-017',
      'dsa-arrays',
      'Container with Most Water (find two lines that form a container holding the most water).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Two pointers, one at start, one at end. The area is limited by the shorter line: `min(height[l], height[r]) * (r - l)`. To maximize area, always move the pointer pointing to the SHORTER line inward.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-018',
      'dsa-arrays',
      'Find all unique triplets in an array that sum to zero (3Sum).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort the array first. Iterate `i` from 0 to n-2. For each `i`, use the Two Pointer approach (`l = i+1`, `r = n-1`) to find pairs that sum to `-nums[i]`. Skip duplicate values to ensure unique triplets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-019',
      'dsa-arrays',
      'Find the minimum window substring that contains all characters of string t.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Sliding Window with two frequency maps (or one map and a `have/need` counter). Expand `right` until the window contains all required characters. Then shrink `left` to minimize the window while still maintaining the condition.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-020',
      'dsa-arrays',
      'Rotate an array to the right by k steps.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use the Reverse approach. 1. Reverse the entire array. 2. Reverse the first k elements. 3. Reverse the remaining elements. (Remember to do `k = k % arr.length`). Time O(N), Space O(1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-021',
      'dsa-arrays',
      'Find the longest repeating character replacement (can change at most k characters).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sliding Window. Keep a frequency map of characters in the window. The window is valid if `window_length - max_freq_char_count <= k`. If invalid, shrink the left pointer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-022',
      'dsa-arrays',
      'Merge Intervals: Given an array of intervals, merge all overlapping ones.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Sort the intervals by their start times. 2. Push the first interval to a `result` array. 3. Iterate. If the current interval overlaps with the last one in `result` (i.e., `curr.start <= last.end`), update `last.end` to `max(last.end, curr.end)`. Else, push `curr` to `result`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-023',
      'dsa-arrays',
      'Best Time to Buy and Sell Stock (one transaction).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Iterate through prices tracking the `minPrice` seen so far. At each step, calculate the potential profit (`price - minPrice`) and update the `maxProfit` if it''s higher.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-024',
      'dsa-arrays',
      'Find the Subarray Sum Equals K.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use Prefix Sums + Hash Map. Track the running sum. If `(runningSum - K)` exists in the map, it means there is a subarray ending here that sums to K. Add the map value to the total count.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-025',
      'dsa-arrays',
      'What is the Boyer-Moore Majority Vote Algorithm?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An O(N) time, O(1) space algorithm to find the majority element (appears > N/2 times). It maintains a `candidate` and a `count`. If count is 0, pick a new candidate. If current element equals candidate, increment count, else decrement. The surviving candidate is the majority.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-026',
      'dsa-arrays',
      'Implement the Boyer-Moore Majority Vote Algorithm.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Maintain a count and candidate. Iterate. If count is 0, assign candidate. Adjust count based on match.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-027',
      'dsa-arrays',
      'Find the Missing Number in an array containing 0 to N.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Can be solved using Math or Bit Manipulation. Math: Calculate the expected sum formula `n*(n+1)/2` and subtract the actual sum of the array. XOR: XOR all array elements and all numbers from 0 to N. The missing number will remain.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-028',
      'dsa-arrays',
      'Valid Parentheses: Check if a string of brackets is validly closed.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a Stack (implemented via an Array). Push open brackets onto the stack. If a close bracket is encountered, pop from the stack and check if it matches the corresponding open bracket.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-029',
      'dsa-arrays',
      'String to Integer (atoi).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Ignore leading whitespaces. Handle optional sign (+/-). Iterate through digits, building the number (`res = res * 10 + digit`). Stop at the first non-digit. Clamp the result to 32-bit signed integer limits (`-2^31` to `2^31 - 1`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-030',
      'dsa-arrays',
      'Longest Common Prefix among an array of strings.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Take the first string as the initial prefix. Compare it with the next string, shortening the prefix from the end until it matches. Repeat for all strings.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-031',
      'dsa-arrays',
      'Find all duplicates in an array where 1 ≤ a[i] ≤ n in O(N) time and O(1) space.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Since values are between 1 and n, we can use the array elements as indices. Iterate. For each `nums[i]`, flip the sign of the element at index `Math.abs(nums[i]) - 1` to negative. If it''s already negative, it''s a duplicate.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-032',
      'dsa-arrays',
      'Trapping Rain Water.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Two pointers (left and right). Keep track of `leftMax` and `rightMax`. Move the pointer that has the smaller max. The water trapped at the current pointer is `max - height[pointer]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-033',
      'dsa-arrays',
      'Implement strStr() / String indexOf.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Slide a window of size `needle.length` over `haystack`. If the substring matches `needle`, return the index. (For optimal O(N) time, use KMP algorithm, but simple sliding window is usually acceptable).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-034',
      'dsa-arrays',
      'Longest Consecutive Sequence in an unsorted array.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Insert all elements into a Hash Set. Iterate over the set. If `num - 1` is NOT in the set, it is the start of a sequence. Count upwards (`num + 1`, `num + 2`) while they exist in the set. Time O(N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-035',
      'dsa-arrays',
      'Spiral Matrix traversal.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Maintain 4 boundary variables: top, bottom, left, right. Traverse top row (left->right), increment top. Right col (top->bottom), decrement right. Bottom row (right->left), decrement bottom. Left col (bottom->top), increment left. Repeat until boundaries cross.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-036',
      'dsa-arrays',
      'Set Matrix Zeroes: If an element is 0, set its row and col to 0 in-place.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use the first row and first column of the matrix itself to keep track of which rows and columns need to be zeroed. Use two extra variables (or one) to track if the first row/col themselves need to be zeroed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-037',
      'dsa-arrays',
      'Find the single number in an array where every other number appears twice.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use Bit Manipulation (XOR). XORing a number with itself results in 0 (`a ^ a = 0`). XORing a number with 0 results in the number (`a ^ 0 = a`). XOR all numbers together; the duplicates will cancel out, leaving only the single number.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-038',
      'dsa-arrays',
      'Determine if a 9x9 Sudoku board is valid.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use Hash Sets for each row, column, and 3x3 sub-box. Iterate over the board. If a cell is not empty, check if it already exists in the corresponding row set, col set, or box set. Calculate box index as `Math.floor(r/3)*3 + Math.floor(c/3)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-039',
      'dsa-arrays',
      'Next Permutation (lexicographically next greater permutation of numbers).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Scan from right to find first decreasing element `arr[i] < arr[i+1]`. 2. Scan from right to find first element `arr[j] > arr[i]`. 3. Swap `arr[i]` and `arr[j]`. 4. Reverse the sub-array from `i+1` to the end. If step 1 fails, just reverse the whole array.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-040',
      'dsa-arrays',
      'Find all Anagrams in a String.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sliding Window + Frequency Map. Create an array of size 26 for `p`''s character counts. Slide a window of size `p.length` across `s`. Update the window''s character counts dynamically (add incoming char, remove outgoing char). If the arrays match, record the start index.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-041',
      'dsa-arrays',
      'Encode and Decode Strings (List of strings into a single string and back).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cannot just use a delimiter like `,` because it might exist in the string. Encode format: `[Length of string] + "#" + [String]`. E.g., `["abc", "de"]` becomes `3#abc2#de`. Decode by reading the number until `#`, then extracting that many characters.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-042',
      'dsa-arrays',
      'Valid Palindrome II (Can delete at most one character).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Two pointers from ends. If mismatch found at `left` and `right`, the string is a valid palindrome II if EITHER the substring `(left+1, right)` OR `(left, right-1)` is a standard palindrome.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-043',
      'dsa-arrays',
      'Find Pivot Index (Equilibrium Index).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Calculate the `totalSum` of the array. Iterate while maintaining a `leftSum`. The `rightSum` is `totalSum - leftSum - nums[i]`. If `leftSum == rightSum`, return `i`. Otherwise, `leftSum += nums[i]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-044',
      'dsa-arrays',
      'Find the First Missing Positive integer in an unsorted array.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'O(N) time, O(1) space. The answer must be between 1 and N+1. Cycle sort: place each number `x` (where `1 <= x <= N`) at index `x-1`. Iterate again; the first index `i` where `nums[i] !== i + 1` is the missing number `i+1`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-045',
      'dsa-arrays',
      'Isomorphic Strings.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Two strings are isomorphic if characters in `s` can be replaced to get `t`. Keep two Hash Maps (or arrays). Map char from `s` to `t` and `t` to `s`. If an existing mapping contradicts the current chars, return false.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-046',
      'dsa-arrays',
      'Rotate Image (2D Matrix 90 degrees clockwise in-place).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Two steps: 1. Transpose the matrix (swap `matrix[i][j]` with `matrix[j][i]`). 2. Reverse each row of the matrix.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-047',
      'dsa-arrays',
      'Subarray Product Less Than K.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sliding Window. Track `product`. If `product >= k`, shrink the window from the left by dividing `product` by `nums[left]` and incrementing `left`. The number of valid subarrays ending at `right` is `right - left + 1`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-048',
      'dsa-arrays',
      'Insert Interval into a sorted, non-overlapping array of intervals.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Iterate. 1. While current interval ends before newInterval starts, push current. 2. While current overlaps with newInterval, merge them by updating newInterval''s start/end. Push merged newInterval. 3. Push remaining intervals.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-049',
      'dsa-arrays',
      'Minimum Size Subarray Sum (>= target).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sliding window. Expand `right`, adding to `sum`. While `sum >= target`, update `minLen` and shrink the window from the `left` (subtract `nums[left]`, `left++`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'arr-050',
      'dsa-arrays',
      'Longest Palindromic Subsequence.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A subsequence can delete characters (unlike a substring). Solved using 2D Dynamic Programming. `dp[i][j]` represents the max length in substring from index `i` to `j`. If `s[i] == s[j]`, `dp[i][j] = 2 + dp[i+1][j-1]`. Else, `max(dp[i+1][j], dp[i][j-1])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-001',
      'dsa-trees',
      'What is a Binary Tree?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A tree data structure in which each node has at most two children, referred to as the left child and the right child.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-002',
      'dsa-trees',
      'What is a Binary Search Tree (BST)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A binary tree where the value of every node in a node''s left subtree is strictly less than the node''s value, and the value of every node in its right subtree is strictly greater than the node''s value. In-order traversal of a BST yields a sorted array.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-003',
      'dsa-trees',
      'Explain Pre-order, In-order, and Post-order Traversals (DFS).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Depth-First Search traversals. Pre-order: Root, Left, Right (used to copy a tree). In-order: Left, Root, Right (used to get sorted elements of a BST). Post-order: Left, Right, Root (used to delete a tree, since you must delete children before the parent).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-004',
      'dsa-trees',
      'Explain Level-order Traversal (BFS).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Breadth-First Search traversal. Visits all the nodes at the present depth level before moving on to the nodes at the next depth level. Implemented iteratively using a Queue.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-005',
      'dsa-trees',
      'Invert a Binary Tree.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Swap the left and right children of every node in the tree using recursion (DFS).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-006',
      'dsa-trees',
      'Find the Maximum Depth of a Binary Tree.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The depth is 1 + the maximum depth of its left and right subtrees. Solve recursively.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-007',
      'dsa-trees',
      'Check if two Binary Trees are Identical.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Traverse both trees simultaneously. If both nodes are null, return true. If one is null or values differ, return false. Recursively check left and right subtrees.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-008',
      'dsa-trees',
      'Check if a Binary Tree is a Subtree of another tree.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Traverse the main tree (root). For every node, check if the tree starting at that node is identical to the `subRoot`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-009',
      'dsa-trees',
      'Lowest Common Ancestor (LCA) of a BST.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Leverage the BST property. Start at the root. If both p and q are less than root, LCA is in left subtree. If both are greater, LCA is in right subtree. Otherwise, the current root is the LCA (they split).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-010',
      'dsa-trees',
      'Lowest Common Ancestor (LCA) of a generic Binary Tree.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use DFS. If root is null, p, or q, return root. Recursively search left and right. If both return non-null, the current root is the LCA. If only one returns non-null, pass that up.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-011',
      'dsa-trees',
      'Binary Tree Level Order Traversal (return array of arrays per level).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use BFS with a Queue. For each level, determine its size, dequeue that many elements, add them to a level array, and enqueue their children.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-012',
      'dsa-trees',
      'Validate a Binary Search Tree.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use DFS. Pass a valid range (min, max) down the tree. The root''s value must be > min and < max. Left child must be < root.val, right child > root.val.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-013',
      'dsa-trees',
      'Kth Smallest Element in a BST.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use iterative In-order traversal (which visits elements in sorted order). Decrement k every time you pop a node from the stack. When k == 0, you found the element.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-014',
      'dsa-trees',
      'Construct Binary Tree from Preorder and Inorder Traversal.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The first element in Preorder is always the root. Find this root in the Inorder array to split the tree into Left and Right subtrees. Recursively build.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-015',
      'dsa-trees',
      'Binary Tree Maximum Path Sum.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A path can start and end at any node. Use DFS. For each node, compute the max path sum of its left and right subtrees (ignore negative sums). Update a global maximum representing a path passing *through* the current node. Return the max path extending downwards from the current node.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-016',
      'dsa-trees',
      'Serialize and Deserialize a Binary Tree.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use Preorder Traversal with a delimiter (e.g., `,`) and a special character for null nodes (e.g., `N`). To deserialize, split the string into an array and use an iterator/pointer to recursively rebuild the tree in preorder fashion.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-017',
      'dsa-trees',
      'What is a Trie (Prefix Tree)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A tree-like data structure used to efficiently store and retrieve keys in a dataset of strings. Each node represents a character. Useful for autocomplete, spell checkers, and IP routing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-018',
      'dsa-trees',
      'Implement a Trie.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a `TrieNode` class containing a hash map of children and an `isEnd` boolean. Implement `insert`, `search`, and `startsWith`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-019',
      'dsa-trees',
      'Word Search II (Find words from a dictionary in a 2D grid).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Trie + DFS. Insert all words into a Trie. Iterate through the grid. If the cell matches a Trie root child, start a DFS. Pass the TrieNode down the DFS to prune invalid paths immediately. Time O(M*N * 4^L).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-020',
      'dsa-trees',
      'What is a Graph?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A non-linear data structure consisting of Nodes (Vertices) and Edges that connect them. Can be Directed (one-way) or Undirected (two-way), and Weighted or Unweighted.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-021',
      'dsa-trees',
      'Adjacency Matrix vs Adjacency List.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Matrix: A 2D array where `matrix[i][j] = 1` if edge exists. Space O(V^2), good for dense graphs. Fast O(1) edge lookup. List: Array/Hash Map of Linked Lists/Arrays. `list[i]` contains neighbors of vertex `i`. Space O(V+E), good for sparse graphs. Slower edge lookup, fast traversal.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-022',
      'dsa-trees',
      'Number of Islands (Find connected components in a grid).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Iterate the 2D grid. When you find a `1` (land), increment island count and launch a DFS/BFS to mark all adjacent `1`s as visited (e.g., turn them to `0`) so they aren''t counted again.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-023',
      'dsa-trees',
      'Clone a Graph.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use DFS or BFS and a Hash Map to keep track of already cloned nodes to avoid infinite loops (cycles). Map original node to the cloned node.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-024',
      'dsa-trees',
      'Course Schedule (Detect Cycle in a Directed Graph).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Represent courses and prerequisites as a directed graph. Use DFS with a `visiting` state (in the current path) and a `visited` state (completely processed). If you encounter a `visiting` node, there is a cycle (cannot finish courses).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-025',
      'dsa-trees',
      'What is Topological Sorting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A linear ordering of vertices in a Directed Acyclic Graph (DAG) such that for every directed edge U -> V, vertex U comes before V in the ordering. Used for scheduling tasks with dependencies (e.g., build systems, course schedules).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-026',
      'dsa-trees',
      'Implement Kahn''s Algorithm for Topological Sort.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Calculate the in-degree (number of incoming edges) for all nodes. Push nodes with in-degree 0 to a Queue. While Queue is not empty, pop a node, add it to result, and decrement the in-degree of its neighbors. If a neighbor''s in-degree becomes 0, push it to the Queue.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-027',
      'dsa-trees',
      'Pacific Atlantic Water Flow.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Instead of doing DFS from every cell to see if it reaches both oceans, do DFS *from* the oceans inward (going uphill). Keep two boolean matrices (canReachPacific, canReachAtlantic). Cells that are true in both are the answer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-028',
      'dsa-trees',
      'Rotting Oranges (Shortest path/time in a grid).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use multi-source BFS. Put all initially rotten oranges in a Queue. Keep track of `fresh` count. Process level by level (minutes). For each rotten orange, rot its fresh neighbors, decrement `fresh` count, and push them to the Queue. Return minutes if `fresh === 0`, else -1.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-029',
      'dsa-trees',
      'Word Ladder (Find shortest transformation sequence).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use BFS to find the shortest path in an unweighted graph. The graph is implicit: nodes are words, edges exist if words differ by exactly 1 letter. Generate all possible 1-letter mutations of the current word and check if they exist in the dictionary (Hash Set).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-030',
      'dsa-trees',
      'Dijkstra''s Algorithm.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Finds the shortest path from a single source node to all other nodes in a weighted graph with NON-NEGATIVE edges. It uses a Priority Queue (Min-Heap) to greedily select the unvisited node with the smallest known distance.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-031',
      'dsa-trees',
      'Bellman-Ford Algorithm.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Finds shortest path in a weighted graph. Unlike Dijkstra, it CAN handle negative edge weights. It works by relaxing all edges V-1 times. If it can be relaxed a V-th time, a negative weight cycle exists. Time complexity O(V*E).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-032',
      'dsa-trees',
      'Floyd-Warshall Algorithm.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Finds shortest paths between ALL pairs of vertices. Uses Dynamic Programming. `dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])` for all k. Time complexity O(V^3).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-033',
      'dsa-trees',
      'What is a Minimum Spanning Tree (MST)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A subset of the edges of a connected, edge-weighted undirected graph that connects all the vertices together, without any cycles, and with the minimum possible total edge weight.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-034',
      'dsa-trees',
      'Kruskal''s Algorithm.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Finds an MST. Sort all edges from lowest to highest weight. Iterate through the edges. If adding an edge doesn''t create a cycle (checked using Union-Find), add it to the MST. Stop when MST has V-1 edges.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-035',
      'dsa-trees',
      'Prim''s Algorithm.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Finds an MST. Starts with a single vertex. Greedily grows the tree by picking the minimum weight edge that connects a vertex in the tree to a vertex outside the tree (using a Min-Heap/Priority Queue). Similar to Dijkstra.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-036',
      'dsa-trees',
      'What is the Union-Find (Disjoint Set) data structure?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Maintains a collection of disjoint sets. Supports two near-O(1) operations: `Find` (determine which set a specific element is in) and `Union` (join two sets into a single set). Essential for cycle detection in undirected graphs and Kruskal''s.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-037',
      'dsa-trees',
      'Implement Union-Find with Path Compression and Union by Rank.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '`parent` array tracks roots. `rank` array tracks tree height to keep it flat. Path Compression makes all nodes on the path point directly to the root during `find`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-038',
      'dsa-trees',
      'Redundant Connection (Find the edge that creates a cycle).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Iterate through the edges of an undirected graph. For each edge `(u, v)`, perform a `Union`. If `Find(u) === Find(v)`, they are already in the same set, meaning this edge creates a cycle. Return it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-039',
      'dsa-trees',
      'Network Delay Time.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Classic Dijkstra''s Algorithm problem. Find the shortest path from the source node to ALL other nodes. The total time taken for the signal to reach all nodes is the maximum of these shortest paths.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-040',
      'dsa-trees',
      'Alien Dictionary (Find order of characters in a new language).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Build a directed graph comparing adjacent words. Find the first differing character: `word1[i] -> word2[i]`. 2. Perform Topological Sort using Kahn''s algorithm or DFS. If there''s a cycle, the dictionary is invalid.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-041',
      'dsa-trees',
      'Graph Valid Tree (Check if undirected graph is a valid tree).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A valid tree must have exactly `n-1` edges and be fully connected (no cycles). You can use DFS/BFS to ensure all nodes are reached and no back-edges exist, OR use Union-Find (if an edge connects two already unioned nodes, it''s a cycle).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-042',
      'dsa-trees',
      'Number of Connected Components in an Undirected Graph.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Can be solved with DFS/BFS or Union-Find. Initialize `count = n`. For each edge `(u, v)`, if `Union(u, v)` succeeds (they were in different sets), decrement `count`. Return `count`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-043',
      'dsa-trees',
      'Word Ladder II (Return ALL shortest transformation sequences).',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Use BFS to find the shortest path and build an adjacency list pointing backwards from children to parents. Then use DFS (backtracking) from the end word to the start word to reconstruct all the shortest paths.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-044',
      'dsa-trees',
      'Find Median from Data Stream.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Maintain two Heaps. A Max-Heap for the smaller half of numbers, and a Min-Heap for the larger half. Keep their sizes balanced (Max-Heap size >= Min-Heap size). If total count is odd, median is the top of Max-Heap. If even, average of the tops.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-045',
      'dsa-trees',
      'Design Add and Search Words Data Structure (supports `.` wildcard).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Trie. Normal insertion. For searching: use DFS on the Trie. If the character is a `.`, recursively check ALL children of the current node. If any path returns true, the word is found.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-046',
      'dsa-trees',
      'Count Good Nodes in Binary Tree (Path from root has no greater values).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use DFS. Pass the maximum value seen so far along the path down to the children. If the current node''s value is >= `maxSoFar`, increment a counter and update `maxSoFar`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-047',
      'dsa-trees',
      'Diameter of Binary Tree.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The diameter is the longest path between any two nodes. Use DFS to calculate the depth of the tree. The diameter passing through any node is `leftDepth + rightDepth`. Maintain a global max variable updated during the DFS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-048',
      'dsa-trees',
      'Symmetric Tree (Mirror Image).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Check if the left and right subtrees are mirrors of each other. Recursive helper function takes two nodes: `node1.val === node2.val` AND `helper(node1.left, node2.right)` AND `helper(node1.right, node2.left)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-049',
      'dsa-trees',
      'Right Side View of Binary Tree.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use BFS (Level Order Traversal). At each level, the last node processed in the queue is the one visible from the right side. Add its value to the result array.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'tree-050',
      'dsa-trees',
      'Flatten Binary Tree to Linked List (In-place).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Post-order DFS (Right, Left, Root). Keep track of a global `prev` node. For each node, `node.right = prev`, `node.left = null`, and `prev = node`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-001',
      'dsa-dp',
      'What is Dynamic Programming (DP)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An algorithmic technique for solving optimization problems by breaking them down into simpler overlapping subproblems, solving each subproblem exactly once, and storing their solutions (memoization or tabulation) to avoid redundant computations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-002',
      'dsa-dp',
      'What are the two key properties a problem must have to use DP?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Overlapping Subproblems: The problem can be broken down into subproblems which are reused multiple times. 2. Optimal Substructure: The optimal solution to the overall problem can be constructed from the optimal solutions of its subproblems.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-003',
      'dsa-dp',
      'Top-Down vs Bottom-Up DP?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Top-Down (Memoization): Uses recursion. Starts at the main problem and recursively calls subproblems. Caches results in a Hash Map/Array. Easy to write, but has recursion overhead. Bottom-Up (Tabulation): Uses iteration. Starts with base cases and builds up to the main problem using an array/matrix. No recursion overhead, usually better space/time constants.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-004',
      'dsa-dp',
      'Fibonacci Sequence (Bottom-Up O(1) Space).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Instead of an array `dp[i] = dp[i-1] + dp[i-2]`, just keep track of the last two calculated values.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-005',
      'dsa-dp',
      'Climbing Stairs (n steps, 1 or 2 steps at a time).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'This is exactly the Fibonacci sequence. To reach step `n`, you must come from step `n-1` or `n-2`. So, `ways(n) = ways(n-1) + ways(n-2)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-006',
      'dsa-dp',
      'Coin Change: Minimum coins to make amount.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Bottom-up DP. `dp[i]` = min coins to make amount `i`. Initialize array to `Infinity`. `dp[0] = 0`. For each amount from 1 to `target`, iterate through coins: `if (coin <= amount) dp[amount] = min(dp[amount], 1 + dp[amount - coin])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-007',
      'dsa-dp',
      'Longest Increasing Subsequence (LIS).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`dp[i]` represents LIS ending at index `i`. Initialize all to 1. For each `i` from 1 to `n-1`, check all previous indices `j`. If `nums[i] > nums[j]`, `dp[i] = max(dp[i], dp[j] + 1)`. Time O(N^2).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-008',
      'dsa-dp',
      'Longest Common Subsequence (LCS).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '2D DP. `dp[i][j]` = length of LCS of `text1[0..i-1]` and `text2[0..j-1]`. If `text1[i-1] == text2[j-1]`, then `dp[i][j] = 1 + dp[i-1][j-1]`. Else, `dp[i][j] = max(dp[i-1][j], dp[i][j-1])`. Time O(M*N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-009',
      'dsa-dp',
      '0/1 Knapsack Problem.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Given `n` items with weights and values, find max value that fits in knapsack of capacity `W`. You can either take an item (1) or leave it (0). 2D DP array `dp[i][w]`. If `weight[i] <= w`, `dp[i][w] = max(dp[i-1][w], val[i] + dp[i-1][w-weight[i]])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-010',
      'dsa-dp',
      'Partition Equal Subset Sum.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Find if array can be partitioned into two subsets with equal sum. This is 0/1 Knapsack where `target = Total Sum / 2`. DP array stores booleans `dp[i]` (can we make sum `i`?).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-011',
      'dsa-dp',
      'House Robber (Max money without robbing adjacent houses).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'At each house `i`, you either rob it (`money[i] + dp[i-2]`) or skip it (`dp[i-1]`). `dp[i] = max(rob, skip)`. Optimization: use two variables instead of array (like Fibonacci).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-012',
      'dsa-dp',
      'Word Break (Can string be segmented into dict words?).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`dp[i]` = true if `s.slice(0, i)` can be segmented. Iterate `i` from 1 to `s.length`. For each `i`, iterate `j` from 0 to `i-1`. If `dp[j]` is true AND `s.slice(j, i)` is in dict, then `dp[i] = true` and break inner loop.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-013',
      'dsa-dp',
      'Edit Distance (Min operations to convert word1 to word2).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Operations: insert, delete, replace. `dp[i][j]` is min ops for `word1[0..i]` and `word2[0..j]`. If chars match, `dp[i][j] = dp[i-1][j-1]`. Else, `1 + min(replace, delete, insert)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-014',
      'dsa-dp',
      'Maximum Product Subarray.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Track both `maxProduct` and `minProduct` ending at `i` (because a negative number times `minProduct` could suddenly become the new `maxProduct`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-015',
      'dsa-dp',
      'Unique Paths (Robot from top-left to bottom-right of MxN grid).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Robot can only move right or down. Number of paths to cell `(r, c)` is sum of paths to cell `(r-1, c)` and `(r, c-1)`. Initialize top row and left column to 1.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-016',
      'dsa-dp',
      'Jump Game (Can reach end of array).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Greedy approach is O(N) time and O(1) space. Shift the "goal" post backwards from the last index to the first. If from index `i`, you can reach or pass the `goal` (`i + nums[i] >= goal`), then set `goal = i`. Return `goal === 0`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-017',
      'dsa-dp',
      'Decode Ways (Number of ways to decode string of digits).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Similar to Fibonacci. A digit `i` can be decoded by itself (if != "0") and decoded with `i-1` (if between "10" and "26"). `dp[i] = (valid single) + (valid double)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-018',
      'dsa-dp',
      'Minimum Path Sum (Grid with weights).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Similar to Unique Paths. Modify the first row and first column to be prefix sums. For inner cells, `dp[r][c] = grid[r][c] + min(dp[r-1][c], dp[r][c-1])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-019',
      'dsa-dp',
      'House Robber II (Houses are arranged in a circle).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Because it''s a circle, you cannot rob BOTH house[0] and house[N-1]. Run the standard House Robber algorithm twice: once skipping the first house `nums.slice(1)`, and once skipping the last house `nums.slice(0, n-1)`. Return the max of the two results.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-020',
      'dsa-dp',
      'Palindromic Substrings (Count total number).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use "Expand Around Center" technique. For each character, expand outward checking for odd-length palindromes, then do the same for even-length palindromes (center is between characters). Increment count for each valid palindrome.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-021',
      'dsa-dp',
      'Target Sum (Add +/- to array elements to equal target).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Can be solved with DP or Memoization. With Memoization: `dfs(index, currentSum)`. Cache state as string `"index,currentSum"`. Or reduce to subset sum math: find subset P with sum `(target + sum(nums)) / 2`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-022',
      'dsa-dp',
      'Longest Palindromic Substring.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'While solvable with a 2D DP array, "Expand Around Center" is preferred for O(1) space. DP approach: `dp[i][j]` is true if `s[i..j]` is palindrome. Base cases: `dp[i][i] = true`. `dp[i][i+1] = s[i] == s[i+1]`. General: `dp[i][j] = (s[i] == s[j]) && dp[i+1][j-1]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-023',
      'dsa-dp',
      'Combination Sum IV (Number of combinations that add up to target).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`dp[i]` = number of combinations to reach target `i`. `dp[0] = 1`. For each target from 1 to `N`, iterate over `nums`. If `num <= target`, `dp[target] += dp[target - num]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-024',
      'dsa-dp',
      'Best Time to Buy and Sell Stock with Cooldown.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'State Machine DP. 3 states: `Hold`, `Sold`, `Rest`. `Hold[i] = max(Hold[i-1], Rest[i-1] - price[i])`. `Sold[i] = Hold[i-1] + price[i]`. `Rest[i] = max(Rest[i-1], Sold[i-1])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-025',
      'dsa-dp',
      'Regular Expression Matching (with `.` and `*`).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '2D DP or Top-Down Memoization. `.` matches any char. `*` matches 0 or more of the PRECEDING char. If next char is `*`, two choices: skip the `<char>*` sequence entirely (0 occurrences), or match `<char>` with `s` and keep the sequence available for the rest of `s`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-026',
      'dsa-dp',
      'Wildcard Matching (`?` matches single, `*` matches any sequence).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '2D DP. `dp[i][j]` is true if `s[0..i]` matches `p[0..j]`. If `p[j] == *`, `dp[i][j] = dp[i-1][j] || dp[i][j-1]` (matches sequence or empty). Else if `p[j] == ? || p[j] == s[i]`, `dp[i][j] = dp[i-1][j-1]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-027',
      'dsa-dp',
      'Burst Balloons (Maximize coins).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Think backwards. Instead of finding which balloon to burst first, find which balloon to burst LAST. Let `dp[L][R]` be the max coins bursting all balloons between L and R. Choose `i` as the last balloon to burst in this range. `coins = nums[L-1] * nums[i] * nums[R+1] + dp[L][i-1] + dp[i+1][R]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-028',
      'dsa-dp',
      'Distinct Subsequences (Number of ways `t` is a subsequence of `s`).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '2D DP. `dp[i][j]` = num ways `t[0..j]` is in `s[0..i]`. Base: `dp[i][0] = 1` (empty string `t` is in any string 1 way). If `s[i] == t[j]`, `dp[i][j] = dp[i-1][j-1] (use char) + dp[i-1][j] (don''t use)`. Else, `dp[i-1][j]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-029',
      'dsa-dp',
      'Interleaving String (Can s3 be formed by interleaving s1 and s2).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '2D DP. `dp[i][j]` = true if `s3[0..i+j]` can be formed by `s1[0..i]` and `s2[0..j]`. `dp[i][j] = (s1[i-1] == s3[i+j-1] && dp[i-1][j]) || (s2[j-1] == s3[i+j-1] && dp[i][j-1]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-030',
      'dsa-dp',
      'Maximum Subarray (Kadane''s Algorithm).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The simplest 1D DP. `dp[i]` = max subarray sum ending at `i`. `dp[i] = max(nums[i], nums[i] + dp[i-1])`. Optimization: space O(1) by only keeping the previous max.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-031',
      'dsa-dp',
      'Maximal Square (Largest square of 1s in a binary matrix).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '2D DP. `dp[r][c]` = length of the largest square whose bottom-right corner is at `(r, c)`. If `matrix[r][c] == 1`, `dp[r][c] = min(dp[r-1][c], dp[r][c-1], dp[r-1][c-1]) + 1`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-032',
      'dsa-dp',
      'Triangle (Minimum path sum from top to bottom).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Bottom-Up DP is best. Start from the second-to-last row and work upwards. `triangle[row][col] += min(triangle[row+1][col], triangle[row+1][col+1])`. The answer is at `triangle[0][0]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-033',
      'dsa-dp',
      'Russian Doll Envelopes (Max nested envelopes).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Sort envelopes by width ascending. If widths are equal, sort by height DESCENDING. 2. Extract all the heights. 3. Find the Longest Increasing Subsequence (LIS) of the heights array.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-034',
      'dsa-dp',
      'Unbounded Knapsack.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Similar to 0/1 Knapsack, but you can use an item an unlimited number of times. The inner loop checks `dp[w] = max(dp[w], val[i] + dp[w - weight[i]])`. The key difference is we iterate `w` left-to-right so we CAN reuse the item we just added.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-035',
      'dsa-dp',
      'Coin Change II (Number of combinations that make up amount).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Unbounded Knapsack variant. `dp[i]` = number of ways to make amount `i`. Initialize `dp[0] = 1`. For EACH coin, iterate amount from `coin` to `total`. `dp[amount] += dp[amount - coin]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-036',
      'dsa-dp',
      'Perfect Squares (Min squares that sum to n).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`dp[i]` = min squares to sum to `i`. Initialize with `Infinity`, `dp[0] = 0`. For `i` from 1 to `n`, iterate `j` from 1 while `j*j <= i`. `dp[i] = min(dp[i], 1 + dp[i - j*j])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-037',
      'dsa-dp',
      'Counting Bits.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Return an array of number of 1s in binary representation for 0 to n. DP relation: `dp[i] = dp[i >> 1] + (i & 1)`. Shift right divides by 2 (handles the rest of the bits), `& 1` checks if the last bit is 1.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-038',
      'dsa-dp',
      'Longest Valid Parentheses.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1D DP. `dp[i]` = length of longest valid substring ending at `i`. If `s[i] == '')''`: if `s[i-1] == ''(''`, `dp[i] = dp[i-2] + 2`. If `s[i-1] == '')''` and `s[i - dp[i-1] - 1] == ''(''`, `dp[i] = dp[i-1] + 2 + dp[i - dp[i-1] - 2]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-039',
      'dsa-dp',
      'Jump Game II (Min jumps to reach end).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'While solvable with DP (`O(N^2)`), Greedy is `O(N)`. Keep track of `l` and `r` bounds of the current jump. Find the `farthest` you can reach within this window. Then update `l = r + 1`, `r = farthest`, and increment jump count.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-040',
      'dsa-dp',
      'Minimum Cost For Tickets.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`dp[i]` = min cost up to day `i`. If day `i` is not a travel day, `dp[i] = dp[i-1]`. If it is a travel day, `dp[i] = min(dp[i-1]+costs[0], dp[max(0, i-7)]+costs[1], dp[max(0, i-30)]+costs[2])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-041',
      'dsa-dp',
      'Predict the Winner (Minimax with DP).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '2D DP. `dp[i][j]` = max score difference player 1 can get from array `i..j`. Player 1 picks either `nums[i]` or `nums[j]`. They want to maximize their score minus player 2''s score. `dp[i][j] = max(nums[i] - dp[i+1][j], nums[j] - dp[i][j-1])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-042',
      'dsa-dp',
      'Matrix Chain Multiplication.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Find the most efficient way to multiply matrices. `dp[i][j]` = min cost to multiply matrices from `i` to `j`. Iterate length of chain `L`. Pick a split point `k`. `cost = dp[i][k] + dp[k+1][j] + (p[i-1]*p[k]*p[j])`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-043',
      'dsa-dp',
      'Catalan Numbers.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A sequence of numbers appearing in combinatorial problems (e.g., number of structurally unique BSTs for n keys, valid parenthesis expressions). Formula: `C(n) = (2n)! / ((n+1)! * n!)`. DP relation: `dp[i] += dp[j] * dp[i-j-1]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-044',
      'dsa-dp',
      'Unique Binary Search Trees.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Calculates the Catalan number. `dp[i]` = number of unique BSTs with `i` nodes. For `n` nodes, pick each node `j` (1 to n) as root. Left subtree has `j-1` nodes, right has `n-j`. `dp[n] += dp[j-1] * dp[n-j]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-045',
      'dsa-dp',
      'Integer Break (Max product of parts).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '`dp[i]` = max product of breaking integer `i`. Iterate `j` from 1 to `i/2`. `dp[i] = max(dp[i], max(j, dp[j]) * max(i-j, dp[i-j]))`. (Mathematical optimization: break into as many 3s as possible).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-046',
      'dsa-dp',
      'Maximal Rectangle (Largest rectangle of 1s in binary matrix).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Convert into a series of "Largest Rectangle in Histogram" problems. Maintain an array of heights. For each row, update heights (if 1, `h[i]++`, else `h[i]=0`). Then apply the O(N) monotonic stack histogram algorithm on the heights array.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-047',
      'dsa-dp',
      'Dungeon Game (Min initial health).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Bottom-Up DP starting from the princess at bottom-right. `dp[r][c]` = min health needed at this cell. `minHealth = min(dp[r+1][c], dp[r][c+1]) - dungeon[r][c]`. If `minHealth <= 0`, set to 1. Return `dp[0][0]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-048',
      'dsa-dp',
      'Is Subsequence.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Can be solved with DP, but simple Two Pointers is O(N) time and O(1) space. Pointer `i` for string `s`, pointer `j` for `t`. If `s[i] == t[j]`, `i++`. Always `j++`. If `i == s.length`, return true.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-049',
      'dsa-dp',
      'Number of Longest Increasing Subsequence.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Maintain TWO DP arrays. `length[i]` = length of LIS ending at `i`. `count[i]` = number of LIS ending at `i`. When updating LIS, if new length > current, `count[i] = count[j]`. If new length == current, `count[i] += count[j]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'dp-050',
      'dsa-dp',
      'Best Time to Buy and Sell Stock IV (At most K transactions).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '2D DP. `dp[t][i]` = max profit at day `i` with at most `t` transactions. `dp[t][i] = max(dp[t][i-1], price[i] + max_over_j(dp[t-1][j] - price[j]))`. Optimization: keep a running max to avoid the `O(N)` inner loop.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-001',
      'dsa-sorting',
      'What is Binary Search?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An efficient algorithm for finding an item from a sorted list of items. It works by repeatedly dividing in half the portion of the list that could contain the item, until you''ve narrowed down the possible locations to just one. Time complexity: O(log N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-002',
      'dsa-sorting',
      'Implement standard Binary Search.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use two pointers, `left` and `right`. Calculate `mid = left + Math.floor((right - left) / 2)`. If `target === nums[mid]`, return `mid`. If `target < nums[mid]`, `right = mid - 1`. Else `left = mid + 1`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-003',
      'dsa-sorting',
      'Why use `l + (r - l) / 2` instead of `(l + r) / 2`?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'To prevent Integer Overflow. If `l` and `r` are very large positive integers, their sum `(l + r)` might exceed the maximum allowable integer size (e.g., `2^31 - 1`), causing an overflow before the division. `l + (r - l) / 2` calculates the exact same mathematical value without the risk of overflowing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-004',
      'dsa-sorting',
      'Search Insert Position.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Standard Binary Search. When the loop terminates (`l > r`), the `left` pointer will always point to the index where the target *should* be inserted to maintain sorted order.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-005',
      'dsa-sorting',
      'Find First and Last Position of Element in Sorted Array.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Run Binary Search twice. First, to find the leftmost index (when `nums[mid] == target`, move `right` to `mid - 1` but record `mid`). Second, to find the rightmost index (move `left` to `mid + 1` but record `mid`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-006',
      'dsa-sorting',
      'Search in Rotated Sorted Array.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Modified Binary Search. In a rotated sorted array, one half is ALWAYS strictly sorted. Check which half is sorted: `nums[l] <= nums[mid]`. Then check if the target falls within the boundaries of that sorted half. If yes, search there; otherwise, search the other half.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-007',
      'dsa-sorting',
      'Find Minimum in Rotated Sorted Array.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use Binary Search. Compare `nums[mid]` with `nums[right]`. If `nums[mid] > nums[right]`, the minimum is in the right half (e.g., `3,4,5,1,2`). Set `l = mid + 1`. Else, the minimum is in the left half (including mid). Set `r = mid`. Return `nums[l]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-008',
      'dsa-sorting',
      'Search a 2D Matrix (Sorted rows, first integer of row > last integer of previous row).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Treat the 2D matrix as a 1D array. A cell at index `i` maps to `matrix[Math.floor(i / cols)][i % cols]`. Perform a standard binary search from `0` to `rows * cols - 1`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-009',
      'dsa-sorting',
      'Find Peak Element.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A peak element is greater than its neighbors. Use Binary Search. Compare `nums[mid]` with `nums[mid+1]`. If `nums[mid] > nums[mid+1]`, you are on a descending slope, so a peak MUST exist to the left (including mid). Set `r = mid`. Else, set `l = mid + 1`. Return `l`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-010',
      'dsa-sorting',
      'Koko Eating Bananas (Binary Search on Answer).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The speed `k` is between `1` and `max(piles)`. Use Binary Search on the range of possible speeds. For a mid speed, calculate the hours required to eat all bananas. If `hours <= H`, it''s possible, so try a slower speed (`r = mid - 1`). Else, try a faster speed (`l = mid + 1`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-011',
      'dsa-sorting',
      'What is the "Binary Search on Answer" pattern?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When you need to find a minimum/maximum value (capacity, speed, weight) that satisfies a monotonic condition (if X works, X+1 works; if Y fails, Y-1 fails). You define the search space (min/max possible answers) and binary search through it, using a helper function to check if a specific answer is valid.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-012',
      'dsa-sorting',
      'Find the Duplicate Number (Floyd''s Cycle Detection).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Given N+1 numbers in range [1, N]. Treat the array as a Linked List where `next = nums[index]`. A duplicate creates a cycle. Use fast/slow pointers. When they meet, reset `slow` to 0, move both 1 step at a time until they meet again. That is the duplicate.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-013',
      'dsa-sorting',
      'Capacity To Ship Packages Within D Days.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Binary Search on Answer. The minimum possible capacity is `max(weights)` (must be able to carry the heaviest item). The maximum possible capacity is `sum(weights)` (carry everything in 1 day). Binary search the capacity, checking if the required days is `<= D`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-014',
      'dsa-sorting',
      'Split Array Largest Sum.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Binary Search on Answer. Find the minimum possible largest sum. Min value is `max(nums)` (if `m == n`), Max value is `sum(nums)` (if `m == 1`). Binary search the target sum, greedy-allocating elements into subarrays. If subarrays > `m`, target is too small.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-015',
      'dsa-sorting',
      'Median of Two Sorted Arrays.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Binary Search on the SMALLER array. Partition both arrays such that `left_A + left_B = right_A + right_B`. Check validity: `max(left_A) <= min(right_B)` AND `max(left_B) <= min(right_A)`. Time O(log(min(m, n))).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-016',
      'dsa-sorting',
      'What is Selection Sort?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Divides array into sorted and unsorted parts. Repeatedly finds the minimum element from the unsorted part and swaps it with the first unsorted element. Time: O(N^2). Space: O(1). Not stable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-017',
      'dsa-sorting',
      'What is Bubble Sort?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Repeatedly steps through the list, compares adjacent elements, and swaps them if they are in the wrong order. The largest elements "bubble" to the top. Time: O(N^2). Space: O(1). Stable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-018',
      'dsa-sorting',
      'What is Insertion Sort?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Builds the sorted array one item at a time. It takes an element and inserts it into its correct position in the already-sorted part. Efficient for small or nearly sorted datasets. Time: O(N^2). Space: O(1). Stable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-019',
      'dsa-sorting',
      'Explain Merge Sort.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Divide and Conquer. Divides the array into halves until each subarray contains 1 element. Then repeatedly merges the sublists to produce new sorted sublists until there is only 1 sorted list remaining. Time: O(N log N) worst/average/best. Space: O(N). Stable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-020',
      'dsa-sorting',
      'Implement Merge Sort.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Recursive divide, then merge.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-021',
      'dsa-sorting',
      'Explain Quick Sort.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Divide and Conquer. Picks an element as a "pivot". Partitions the array such that elements smaller than pivot go left, and larger go right. Recursively applies to left and right partitions. Time: O(N log N) average, O(N^2) worst (if already sorted and bad pivot). Space: O(log N) stack. Not stable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-022',
      'dsa-sorting',
      'Implement Quick Sort.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Partition around a pivot (often the last element).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-023',
      'dsa-sorting',
      'What is Heap Sort?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Converts the array into a Max-Heap. The largest element is at the root. Swap root with the last element of the heap, reduce heap size, and "heapify down" the new root. Repeat until empty. Time: O(N log N). Space: O(1). Not stable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-024',
      'dsa-sorting',
      'What is a Stable Sorting Algorithm?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A stable sort maintains the relative order of records with equal keys. If A and B have the same key, and A appears before B in the input array, A will appear before B in the sorted output array. Merge Sort is stable. Quick Sort and Heap Sort are NOT.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-025',
      'dsa-sorting',
      'What is Counting Sort?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An integer sorting algorithm. Counts the number of objects having distinct key values. Uses arithmetic to determine the positions of each key in the output sequence. Time: O(N + K) where K is the range of values. Space: O(N + K). Stable. Excellent if K is small.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-026',
      'dsa-sorting',
      'What is Radix Sort?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A non-comparative integer sorting algorithm. Sorts data with integer keys by grouping keys by the individual digits which share the same significant position and value. Uses Counting Sort as a subroutine for each digit. Time: O(d * (N + K)), where d is number of digits.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-027',
      'dsa-sorting',
      'Explain Quickselect.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A selection algorithm to find the k-th smallest/largest element in an unordered list. It is related to Quick Sort. After partitioning around a pivot, if the pivot is at index `k`, you are done. If `k < pivot`, recurse ONLY on the left partition. If `k > pivot`, recurse ONLY on the right. Average Time: O(N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-028',
      'dsa-sorting',
      'Kth Largest Element in an Array.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use Quickselect for O(N) average time, or a Min-Heap of size K for O(N log K) time. The Min-Heap approach: Add elements to heap. If size > K, pop. The root of the heap is the Kth largest.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-029',
      'dsa-sorting',
      'Sort Colors (Dutch National Flag problem).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort an array of 0s, 1s, and 2s in-place, O(N) time. Use 3 pointers: `low = 0`, `mid = 0`, `high = n-1`. While `mid <= high`: If `arr[mid] == 0`, swap `arr[low]` and `arr[mid]`, increment both. If 1, increment `mid`. If 2, swap `arr[mid]` and `arr[high]`, decrement `high`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-030',
      'dsa-sorting',
      'Top K Frequent Elements.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Hash Map to count frequencies. Then use Bucket Sort. Create an array of arrays `buckets` where index is the frequency. Iterate map, put numbers into `buckets[freq]`. Iterate `buckets` backwards to gather the top K elements. Time O(N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-031',
      'dsa-sorting',
      'Merge Intervals.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort the intervals by their start times. Iterate through the intervals. If the current interval''s start time is less than or equal to the previous interval''s end time, merge them by updating the previous interval''s end time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-032',
      'dsa-sorting',
      'Meeting Rooms II (Min meeting rooms required).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Separate start times and end times into two arrays and sort them. Use two pointers (`s` for starts, `e` for ends). If `starts[s] < ends[e]`, a new room is needed (count++, s++). If `starts[s] >= ends[e]`, a room is freed (count--, e++). Track `max_rooms`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-033',
      'dsa-sorting',
      'Insert Interval.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Since intervals are already sorted, find where the new interval belongs. Add all intervals ending before new interval. Merge overlapping intervals (update newInterval start/end). Add the merged newInterval. Add remaining intervals.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-034',
      'dsa-sorting',
      'Valid Anagram.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Sorting approach: `s.split("").sort().join("") === t.split("").sort().join("")`. Time: O(N log N). Better approach: Hash Map / Array frequency counter. Time: O(N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-035',
      'dsa-sorting',
      'Contains Duplicate.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Sorting approach: Sort array, iterate and check if `nums[i] == nums[i+1]`. Time: O(N log N). Better approach: Hash Set. Time: O(N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-036',
      'dsa-sorting',
      'Intersection of Two Arrays.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'If arrays are sorted, use two pointers. If `A[i] < B[j]`, `i++`. If `A[i] > B[j]`, `j++`. If equal, add to result (check for duplicates), `i++`, `j++`. Unsorted arrays: Use a Hash Set.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-037',
      'dsa-sorting',
      'Search a 2D Matrix II (Rows sorted L-R, Cols sorted T-B).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Start at top-right corner `(r=0, c=cols-1)`. If `target === val`, return true. If `target < val`, it cannot be in this column (cols are sorted), so `c--`. If `target > val`, it cannot be in this row, so `r++`. Time O(M+N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-038',
      'dsa-sorting',
      'Peak Index in a Mountain Array.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Binary search. If `arr[mid] < arr[mid+1]`, you are on the ascending slope, peak is to the right (`l = mid + 1`). Otherwise, you are on the descending slope, peak is to the left or IS mid (`r = mid`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-039',
      'dsa-sorting',
      'Find Minimum in Rotated Sorted Array II (With duplicates).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Modified Binary Search. The issue with duplicates is `nums[mid] == nums[right]` gives no info about which half has the minimum. In this specific case, you can safely do `right--` to eliminate a duplicate.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-040',
      'dsa-sorting',
      'Valid Perfect Square.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Binary search from 1 to `num/2`. Calculate `mid * mid`. If equal, return true. If less, `l = mid + 1`. If greater, `r = mid - 1`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-041',
      'dsa-sorting',
      'Guess Number Higher or Lower.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Standard Binary search between 1 and `n`. Call the provided API `guess(mid)`. Adjust `left` or `right` based on the API response (-1, 1, or 0).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-042',
      'dsa-sorting',
      'First Bad Version.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Binary search. If `isBadVersion(mid)` is true, the first bad version is either `mid` or to the left (`r = mid`). If false, it''s to the right (`l = mid + 1`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-043',
      'dsa-sorting',
      'Find Smallest Letter Greater Than Target.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Binary search to find the insert position. If `target < letters[mid]`, `r = mid - 1`. Else `l = mid + 1`. The answer is `letters[l % letters.length]` (wraps around).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-044',
      'dsa-sorting',
      'H-Index.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort the array descending. Iterate `i`. If `citations[i] > i`, the researcher has at least `i+1` papers with `i+1` citations. Return the maximum `i` that satisfies this. Sorting is O(N log N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-045',
      'dsa-sorting',
      'Largest Number (from array of integers).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Custom sorting. Sort the array of strings using a custom comparator: `(a, b) => (b + a).localeCompare(a + b)`. This ensures `9` comes before `34` because `934 > 349`. Handle the edge case of all 0s.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-046',
      'dsa-sorting',
      'Wiggle Sort II (nums[0] < nums[1] > nums[2] < nums[3]).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort the array. Find the median. Put the larger half at odd indices and the smaller half at even indices, working backwards to avoid overlapping identical medians.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-047',
      'dsa-sorting',
      'Maximum Gap (Max diff between successive elements in sorted form).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Requires O(N) time and space. Use Bucket Sort / Pigeonhole Principle. Min gap must be at least `ceil((max - min) / (n - 1))`. Create buckets of this size. Keep track of max and min in each bucket. The max gap is between the min of a bucket and the max of the previous non-empty bucket.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-048',
      'dsa-sorting',
      'Count of Smaller Numbers After Self.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a modified Merge Sort. During the merge step, when an element from the RIGHT array is placed before an element from the LEFT array, it means the right element is smaller. Keep a counter of how many elements from the right have been placed, and add that to the left element''s answer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-049',
      'dsa-sorting',
      'Reverse Pairs (i < j and nums[i] > 2 * nums[j]).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Modified Merge Sort. Before merging the two sorted halves, use a two-pointer approach to count the number of pairs that satisfy the condition. Then perform the standard merge step.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sort-050',
      'dsa-sorting',
      'Median of Two Sorted Arrays (Approach without Binary Search).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use two pointers `i` and `j` for the two arrays. Iterate `(m+n)/2` times, keeping track of the current and previous element. If total length is odd, median is current. If even, median is `(current + prev) / 2`. Time O(M+N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-001',
      'dsa-heaps',
      'What is a Stack?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A linear data structure that follows the Last-In, First-Out (LIFO) principle. The last element added to the stack will be the first one removed. Operations: Push, Pop, Peek.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-002',
      'dsa-heaps',
      'What is a Queue?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A linear data structure that follows the First-In, First-Out (FIFO) principle. The first element added will be the first one removed. Operations: Enqueue, Dequeue, Front, Rear.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-003',
      'dsa-heaps',
      'How can you implement a Stack in JavaScript?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a JavaScript Array. `push()` adds to the top, `pop()` removes from the top, and `array[array.length - 1]` peeks at the top element. All operations are O(1) time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-004',
      'dsa-heaps',
      'How can you implement a Queue in JavaScript efficiently?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'While you can use an Array (`push` and `shift`), `shift()` is O(N) because it re-indexes all elements. For O(1) dequeue, use a Linked List or a simple Object with `head` and `tail` pointers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-005',
      'dsa-heaps',
      'Implement a Queue using Stacks.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use two Stacks (`pushStack` and `popStack`). Enqueue always pushes to `pushStack`. Dequeue pops from `popStack`. If `popStack` is empty, pop ALL elements from `pushStack` and push them into `popStack` (reversing their order). Amortized O(1) time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-006',
      'dsa-heaps',
      'Implement a Stack using Queues.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a single Queue. When pushing a new element, enqueue it, then dequeue all previously existing elements and enqueue them back. This moves the newly added element to the front of the queue (top of the stack).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-007',
      'dsa-heaps',
      'Min Stack (Stack that supports getMin() in O(1) time).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Maintain two stacks: one for the actual values, and one for the minimums. When pushing `x`, push `x` to main stack. Push `min(x, minStack.peek())` to the min stack. When popping, pop from both.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-008',
      'dsa-heaps',
      'Valid Parentheses.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Iterate the string. Push opening brackets to a Stack. If you encounter a closing bracket, pop from the stack and check if it''s the matching opening bracket. If the stack is empty at the end, it''s valid.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-009',
      'dsa-heaps',
      'Evaluate Reverse Polish Notation (Postfix).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Stack. Iterate the tokens. If it''s a number, push it. If it''s an operator, pop the top two numbers, apply the operator (`second op first`), and push the result back. At the end, the stack contains the final result.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-010',
      'dsa-heaps',
      'Daily Temperatures.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Monotonic Decreasing Stack. Store INDICES in the stack. Iterate array. While current temp > temp at stack''s top index, pop the stack. The answer for the popped index is `currentIndex - poppedIndex`. Push current index.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-011',
      'dsa-heaps',
      'What is a Monotonic Stack?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A stack whose elements are strictly increasing or strictly decreasing. It is used to find the "Next Greater Element" or "Next Smaller Element" in O(N) time by maintaining the monotonic property.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-012',
      'dsa-heaps',
      'Next Greater Element I.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a Monotonic Decreasing Stack and a Hash Map. Iterate through the array. While the current element is greater than the top of the stack, pop the stack and map `popped -> current`. Push current. Anything left in stack maps to -1.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-013',
      'dsa-heaps',
      'Largest Rectangle in Histogram.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Monotonic Increasing Stack of indices. When you encounter a height SMALLER than the top of the stack, pop. The height is `arr[popped]`. The width is `currentIndex - newTopIndex - 1`. Calculate area. Push current index.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-014',
      'dsa-heaps',
      'Trapping Rain Water (Stack Approach).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Monotonic Decreasing Stack. When `height[i]` > top of stack, pop the stack. The popped element is the "bottom" of a puddle. The new top is the left boundary, `i` is the right boundary. Water = `min(height[left], height[right]) - height[bottom] * width`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-015',
      'dsa-heaps',
      'Decode String (e.g., `3[a2[c]]`).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Stack. Iterate string. If digit, build `k`. If `[`, push current `string` and `k` to stack, reset them. If `]`, pop `k` and `prevString` from stack. `string = prevString + string.repeat(k)`. If letter, append to `string`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-016',
      'dsa-heaps',
      'Asteroid Collision.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Stack. Iterate. If asteroid is positive, push it. If negative, while stack is not empty AND top is positive AND top < absolute(negative), pop stack. If top === absolute(negative), pop and destroy both. If top > absolute, negative is destroyed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-017',
      'dsa-heaps',
      'Remove All Adjacent Duplicates In String.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a Stack. Iterate string. If current char equals top of stack, pop stack. Else, push current char. Join the stack at the end.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-018',
      'dsa-heaps',
      'Basic Calculator (supports +, -, (, )).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Maintain a `result`, `currentNumber`, and `sign` (1 or -1). If `(`, push `result` and `sign` to stack, reset them. If `)`, pop `sign` and `result`, add `currentNumber * oldSign` to `oldResult`. Time O(N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-019',
      'dsa-heaps',
      'Online Stock Span.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Monotonic Decreasing Stack storing `[price, span]`. When a new price comes, initialize `span = 1`. While stack is not empty and top `price <= current price`, pop and add its span to current `span`. Push `[price, span]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-020',
      'dsa-heaps',
      'Design Circular Queue.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a fixed-size array. Maintain `head`, `tail`, and `size`. Enqueue: `tail = (tail + 1) % capacity`. Dequeue: `head = (head + 1) % capacity`. Full if `size === capacity`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-021',
      'dsa-heaps',
      'Task Scheduler.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Find the task with max frequency (`maxFreq`). The max possible idle slots are `(maxFreq - 1) * n`. Iterate other frequencies, subtract `min(freq, maxFreq - 1)` from idle slots. Total time is `tasks.length + max(0, idleSlots)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-022',
      'dsa-heaps',
      'What is a Heap (Priority Queue)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A specialized tree-based data structure that satisfies the heap property. Min-Heap: Parent is always less than or equal to children (root is minimum). Max-Heap: Parent is always greater than or equal to children (root is maximum).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-023',
      'dsa-heaps',
      'How is a Heap typically represented in memory?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'As a flat Array. For a node at index `i`: Left child is at `2i + 1`. Right child is at `2i + 2`. Parent is at `Math.floor((i - 1) / 2)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-024',
      'dsa-heaps',
      'Time Complexities of Heap operations?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Insert (Push): O(log N) - requires "bubbling up". Extract Min/Max (Pop): O(log N) - requires swapping root with last element and "bubbling down". Peek Min/Max: O(1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-025',
      'dsa-heaps',
      'Kth Largest Element in an Array (Heap approach).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Min-Heap of size K. Iterate array. Add element to heap. If heap size > K, remove the minimum (root). The heap will contain the K largest elements, and the root will be the Kth largest. Time O(N log K).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-026',
      'dsa-heaps',
      'K Closest Points to Origin.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Max-Heap of size K. Store `[distance, [x, y]]`. If size > K, pop the maximum distance. The heap will contain the K closest points. Time O(N log K).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-027',
      'dsa-heaps',
      'Merge K Sorted Lists.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Min-Heap. Put the `head` node of every linked list into the Min-Heap. Pop the minimum node, append it to result, and push its `next` node into the heap. Repeat until heap is empty. Time O(N log K).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-028',
      'dsa-heaps',
      'Find Median from Data Stream.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Maintain two Heaps: a Max-Heap for the smaller half, and a Min-Heap for the larger half. Ensure `Max-Heap size >= Min-Heap size`. Median is top of Max-Heap (if sizes differ) or average of both tops (if sizes equal).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-029',
      'dsa-heaps',
      'Top K Frequent Words.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Count frequencies in Hash Map. Use a Priority Queue (Min-Heap). Compare by frequency. If frequencies equal, compare lexicographically in REVERSE (because it''s a Min-Heap). Keep size K. Reverse final output. Time O(N log K).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-030',
      'dsa-heaps',
      'Reorganize String (No two adjacent chars are the same).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Count frequencies. Use a Max-Heap ordered by frequency. Pop the top TWO elements, append to result, decrement frequencies, and push back if freq > 0. If heap has 1 element left and its freq > 1, return empty string.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-031',
      'dsa-heaps',
      'Sliding Window Maximum.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Deque (Double-ended queue) storing INDICES. Maintain monotonically decreasing values. Remove indices from front if they are outside window `(i - k)`. While current value > `deque.back()`, pop back. Push current. Front is the max.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-032',
      'dsa-heaps',
      'Implement a Deque (Double Ended Queue).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A Deque allows insertion and deletion at BOTH ends in O(1) time. Usually implemented internally as a Doubly Linked List or a Circular Buffer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-033',
      'dsa-heaps',
      'Implement a standard Min-Heap in JavaScript.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Requires an array and `bubbleUp`/`bubbleDown` methods.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-034',
      'dsa-heaps',
      'Car Fleet.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort cars by position descending. Calculate time to reach target: `(target - pos) / speed`. Use a Stack. If stack is empty or current time > stack top, push current time (it''s a new fleet). Else, it catches up and joins the fleet (do nothing).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-035',
      'dsa-heaps',
      'Generate Parentheses.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking (Recursion). Keep track of `openN` and `closedN`. If `openN < n`, branch and add `(`. If `closedN < openN`, branch and add `)`. If both equal `n`, add string to result.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-036',
      'dsa-heaps',
      'Simplify Path.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Split string by `/`. Use a Stack. If token is `..`, pop from stack. If token is `.` or empty, do nothing. Else, push token to stack. Finally, `return "/" + stack.join("/")`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-037',
      'dsa-heaps',
      '132 Pattern.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Find `i < j < k` such that `nums[i] < nums[k] < nums[j]`. Keep track of `minArr` (min up to `i`). Iterate backwards for `j`. Maintain a stack of potential `k` candidates. If `nums[j] > minArr[j]`, pop stack until `top > minArr[j]`. If `top < nums[j]`, true.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-038',
      'dsa-heaps',
      'Design Browser History.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use two Stacks (Back and Forward) or a Doubly Linked List. Visit: Push current to Back, clear Forward. Back: Pop Back, push to Forward. Forward: Pop Forward, push to Back.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-039',
      'dsa-heaps',
      'Shortest Subarray with Sum at Least K.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use Prefix Sums and a Monotonic Deque of indices. Deque maintains strictly increasing prefix sums. For each `i`, while `prefix[i] - prefix[deque.front()] >= K`, calculate length and shift front. While `prefix[i] <= prefix[deque.back()]`, pop back.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-040',
      'dsa-heaps',
      'Maximal Rectangle (Using Stack).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Convert each row to a histogram (height of consecutive 1s). Apply the "Largest Rectangle in Histogram" stack-based O(N) algorithm for each row. Keep track of the global maximum area.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-041',
      'dsa-heaps',
      'Last Stone Weight.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use a Max-Heap. Push all stones. While heap has > 1 stone, pop two max. If `y > x`, push `y - x` back to heap. Return heap size ? heap.pop() : 0.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-042',
      'dsa-heaps',
      'Kth Smallest Element in a Sorted Matrix.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Min-Heap. Push the first element of each row `[val, r, c]`. Pop the min K-1 times. Every time you pop, if `c + 1` exists in that row, push `[matrix[r][c+1], r, c+1]`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-043',
      'dsa-heaps',
      'Smallest Range Covering Elements from K Lists.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Min-Heap. Push the first element from each list. Track the `currentMax`. Pop the min element. The current range is `[min, currentMax]`. Move to the next element in the list the min came from, push it, update `currentMax`. Repeat.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-044',
      'dsa-heaps',
      'Minimum Number of Refueling Stops.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Max-Heap. Maintain current fuel. Iterate stations. If you can''t reach a station, pop the largest fuel from the Max-Heap (representing a gas station you passed but didn''t use) and add it. Repeat until you can reach the station or heap is empty.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-045',
      'dsa-heaps',
      'Design Twitter (Get News Feed).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Users map to Set of followees. Map of user to List of tweets (with timestamps). To get feed: get user + all followees. Get the top 10 most recent tweets from these users. Can be done efficiently by merging K sorted lists using a Max-Heap.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-046',
      'dsa-heaps',
      'Construct Target Array With Multiple Sums.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Work backwards. Use a Max-Heap. The largest element MUST be the sum of all elements in the previous step. Max element = `prev_sum + rest_of_array`. `prev_element = max_element % rest_of_array`. Push `prev_element` back into heap.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-047',
      'dsa-heaps',
      'Maximum Frequency Stack.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Map `val -> freq`. Map `freq -> Stack of vals`. Maintain `maxFreq`. Push: increment freq, push to `freqStacks[freq]`, update `maxFreq`. Pop: pop from `freqStacks[maxFreq]`. If stack is empty, decrement `maxFreq`. Decrement freq for value.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-048',
      'dsa-heaps',
      'Find K Pairs with Smallest Sums.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Min-Heap. Push `[nums1[0] + nums2[0], 0, 0]`. Pop min. Add `[nums1[i], nums2[j]]` to result. Push `[nums1[i+1] + nums2[j], i+1, j]` and `[nums1[i] + nums2[j+1], i, j+1]`. Use a Set to avoid pushing duplicate pairs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-049',
      'dsa-heaps',
      'Remove K Digits (to make smallest number).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a Monotonic Increasing Stack. Iterate digits. While `k > 0` AND stack is not empty AND `current_digit < stack.top()`, pop stack and decrement `k`. Push digit. Finally, slice off any remaining `k` and remove leading zeros.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hsq-050',
      'dsa-heaps',
      'Stock Price Fluctuation (Design).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Hash Map for `timestamp -> price`. `latestTime` integer. Two Heaps: Max-Heap and Min-Heap storing `[price, timestamp]`. When getting min/max, lazy-delete: pop top element if its price doesn''t match the Hash Map''s price for that timestamp.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-001',
      'dsa-linkedlists',
      'What is a Linked List?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A linear data structure consisting of nodes. Each node contains data and a reference (pointer) to the next node in the sequence. Unlike arrays, elements are not stored in contiguous memory locations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-002',
      'dsa-linkedlists',
      'Linked List vs Array?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Array: Contiguous memory, O(1) random access by index, O(N) insertion/deletion (due to shifting). Linked List: Non-contiguous memory, O(N) access (must traverse), O(1) insertion/deletion at a known node (just update pointers).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-003',
      'dsa-linkedlists',
      'Singly vs Doubly Linked List?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Singly: Each node points only to the next node. Can only be traversed forward. Doubly: Each node points to both the next node and the previous node. Requires more memory per node but allows backward traversal.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-004',
      'dsa-linkedlists',
      'Reverse a Linked List.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use three pointers: `prev`, `curr`, and `next`. While `curr` is not null: save `curr.next`, set `curr.next` to `prev`, move `prev` to `curr`, and `curr` to the saved `next`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-005',
      'dsa-linkedlists',
      'Detect a Cycle in a Linked List (Floyd''s Cycle-Finding Algorithm).',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use two pointers: `slow` (moves 1 step) and `fast` (moves 2 steps). If there is a cycle, the `fast` pointer will eventually catch up and equal the `slow` pointer. If `fast` reaches null, there is no cycle.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-006',
      'dsa-linkedlists',
      'Find the starting node of a Cycle in a Linked List.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'First use fast/slow pointers to detect if a cycle exists. If they meet, reset the `slow` pointer to the `head` of the list. Move BOTH pointers 1 step at a time. The node where they meet again is the start of the cycle.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-007',
      'dsa-linkedlists',
      'Merge Two Sorted Linked Lists.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Create a `dummy` node. Use a `tail` pointer. While both lists have nodes, compare their values. Attach the smaller node to `tail.next`, move the list''s pointer and the `tail` pointer. Finally, attach any remaining nodes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-008',
      'dsa-linkedlists',
      'Remove Nth Node From End of List.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a dummy node. Use two pointers, `left` and `right`. Move `right` forward by `N` steps. Then move both pointers one step at a time until `right.next` is null. `left` will now be pointing to the node right BEFORE the one to be removed. `left.next = left.next.next`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-009',
      'dsa-linkedlists',
      'Find the Middle of a Linked List.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Use fast and slow pointers. `slow` moves 1 step, `fast` moves 2 steps. When `fast` reaches the end (`fast === null` or `fast.next === null`), `slow` will be pointing at the middle node.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-010',
      'dsa-linkedlists',
      'Palindrome Linked List.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Find the middle using fast/slow pointers. 2. Reverse the second half of the list starting from the middle. 3. Compare the first half and the reversed second half node by node. Time O(N), Space O(1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-011',
      'dsa-linkedlists',
      'Intersection of Two Linked Lists.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Two pointers `a` and `b` starting at `headA` and `headB`. Traverse. When `a` hits the end, redirect it to `headB`. When `b` hits the end, redirect it to `headA`. They will meet at the intersection node (or null if none) after at most two passes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-012',
      'dsa-linkedlists',
      'Reorder List (L0 -> Ln -> L1 -> Ln-1 ...).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Find the middle of the list. 2. Reverse the second half. 3. Merge the two halves alternatingly (`first.next = second`, `second.next = first.next`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-013',
      'dsa-linkedlists',
      'Add Two Numbers (Stored as reversed Linked Lists).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a dummy node and a `carry` variable. Iterate while `l1` or `l2` or `carry` exists. Add `l1.val` + `l2.val` + `carry`. `carry = Math.floor(sum / 10)`. Append `sum % 10` as a new node to the result.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-014',
      'dsa-linkedlists',
      'Copy List with Random Pointer.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Two passes using a Hash Map. First pass: Create a clone for every node and map `original -> clone`. Second pass: Iterate again. Set `clone.next = map.get(curr.next)` and `clone.random = map.get(curr.random)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-015',
      'dsa-linkedlists',
      'Copy List with Random Pointer (O(1) space approach).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Interleave cloned nodes (`A -> A'' -> B -> B''). 2. Assign random pointers (`A''.random = A.random.next`). 3. Restore original list and extract cloned list (`A.next = A.next.next`, `A''.next = A''.next.next`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-016',
      'dsa-linkedlists',
      'Swap Nodes in Pairs.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a dummy node. Maintain a `prev` pointer. While `prev.next` and `prev.next.next` exist, isolate `node1` and `node2`. Update pointers: `prev.next = node2`, `node1.next = node2.next`, `node2.next = node1`. Move `prev` to `node1`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-017',
      'dsa-linkedlists',
      'Reverse Nodes in k-Group.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a dummy node. In a loop, check if there are `k` nodes remaining. If yes, reverse that specific sub-list of `k` nodes. Update the pointers connecting the newly reversed sub-list to the rest of the list. Repeat.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-018',
      'dsa-linkedlists',
      'LRU Cache Design.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Requires O(1) `get` and `put`. Use a Hash Map (key -> node) AND a Doubly Linked List (maintains order). MRU is at the tail, LRU is at the head. `get`: look up in map, move node to tail, return val. `put`: if exists, update and move to tail. If new, add to tail. If capacity exceeded, remove head and delete from map.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-019',
      'dsa-linkedlists',
      'LFU Cache Design.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Requires O(1) ops. Use a Hash Map (`key -> node`). A second Hash Map (`freq -> DoublyLinkedList`). Maintain a `minFreq` variable. `get`: update node''s freq, move it to the DLL for the new freq, update `minFreq` if old DLL is empty. `put`: If full, remove LRU from DLL at `minFreq`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-020',
      'dsa-linkedlists',
      'Partition List (around value x).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Create two dummy nodes, `less` and `greater`. Traverse the original list. If `val < x`, append to `less` list. If `val >= x`, append to `greater` list. Finally, connect the tail of `less` to the head of `greater`, and set `greater.tail.next = null`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-021',
      'dsa-linkedlists',
      'Rotate List.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Find the length of the list and the tail node. Connect tail to head (make it circular). Calculate `k = k % length`. The new tail is at `length - k` steps from the head. Break the circle there by setting `newTail.next = null`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-022',
      'dsa-linkedlists',
      'Sort List.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use Merge Sort for O(N log N) time and O(log N) space. 1. Find middle using fast/slow pointers. 2. Split list into two. 3. Recursively sort both halves. 4. Merge the two sorted halves.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-023',
      'dsa-linkedlists',
      'Insertion Sort List.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a dummy node for the sorted portion. Traverse original list. For each node, start from `dummy` and traverse the sorted portion to find where the current node belongs. Insert it. Repeat.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-024',
      'dsa-linkedlists',
      'Remove Duplicates from Sorted List.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Traverse list. If `curr.val == curr.next.val`, skip the next node by doing `curr.next = curr.next.next`. Else, move `curr` forward.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-025',
      'dsa-linkedlists',
      'Remove Duplicates from Sorted List II (remove all nodes with duplicates).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a dummy node. If `curr.next.val == curr.next.next.val`, find the end of the duplicates, and set `curr.next` to the node AFTER the duplicates. Else, move `curr` forward.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-026',
      'dsa-linkedlists',
      'What is Recursion?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A method of solving a problem where the solution depends on solutions to smaller instances of the same problem. A recursive function calls itself. It MUST have a Base Case (to stop) and a Recursive Case (to move towards the base case).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-027',
      'dsa-linkedlists',
      'What is a Stack Overflow?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a program uses more memory space in the call stack than is allocated. In recursion, this happens if the base case is missing, incorrect, or takes too many calls to reach (deep recursion).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-028',
      'dsa-linkedlists',
      'What is Tail Call Optimization?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An optimization where the compiler/interpreter replaces a recursive call with a simple `goto` loop, preventing the stack from growing. It only works if the recursive call is the VERY LAST operation in the function (a tail call).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-029',
      'dsa-linkedlists',
      'What is Backtracking?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An algorithmic technique for finding all (or some) solutions to computational problems by incrementally building candidates. If a candidate cannot lead to a valid solution, it abandons it ("backtracks") and tries the next option.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-030',
      'dsa-linkedlists',
      'Subsets (Power Set).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking. Maintain a `currentSubset` array. At each index, you have two choices: INCLUDE `nums[i]` (push, recurse, pop) or EXCLUDE `nums[i]` (recurse).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-031',
      'dsa-linkedlists',
      'Subsets II (Contains duplicates).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort the array first. During backtracking, if you choose to EXCLUDE `nums[i]`, you must skip all subsequent elements that are identical to `nums[i]` to avoid generating duplicate subsets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-032',
      'dsa-linkedlists',
      'Permutations.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking. Maintain a boolean array or Set to track which elements are already in the current permutation. Loop through all elements. If not used, add it, recurse, then remove it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-033',
      'dsa-linkedlists',
      'Permutations II (Contains duplicates).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort the array first. Use a boolean `used` array. During the loop, skip the element if it is already `used`. ALSO skip it if it''s the same as the previous element AND the previous element was NOT used in the current recursive depth (`i > 0 && nums[i] == nums[i-1] && !used[i-1]`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-034',
      'dsa-linkedlists',
      'Combinations (n choose k).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking. Recursive function takes a `start` index. Loop `i` from `start` to `n`. Push `i`, recurse with `start = i + 1`, then pop. Base case: `if (curr.length === k)`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-035',
      'dsa-linkedlists',
      'Combination Sum (can use same number unlimited times).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking. Pass `index` and `total`. Base case: `total == target` (add to res), or `total > target` or `index >= nums.length` (return). Two choices: Include `nums[i]` (recurse with SAME `index`), or Exclude `nums[i]` (recurse with `index + 1`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-036',
      'dsa-linkedlists',
      'Combination Sum II (use number once, contains duplicates).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort the array. Pass `index`. Loop `i` from `index` to `length`. If `i > index && nums[i] == nums[i-1]`, `continue` (skip duplicate branches). Include `nums[i]`, recurse with `i + 1`, pop.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-037',
      'dsa-linkedlists',
      'Word Search.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Iterate grid. If cell matches first letter, start DFS. In DFS, check bounds and match. Temporarily mark cell as visited (e.g., set to `#`). Recurse in 4 directions. After recursion, unmark cell (backtrack).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-038',
      'dsa-linkedlists',
      'Palindrome Partitioning.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking. Loop `end` index from `start` to string length. If substring `start` to `end` is a palindrome, add it to `currentPartition` and recurse with `start = end + 1`. Pop after recursion.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-039',
      'dsa-linkedlists',
      'Letter Combinations of a Phone Number.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Create a mapping of digits to letters. Backtracking. Iterate through the letters corresponding to the current digit, add the letter to the current string, and recurse for the next digit.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-040',
      'dsa-linkedlists',
      'N-Queens Problem.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Place queens row by row. Use three Sets to track attacked columns, positive diagonals (`r+c`), and negative diagonals (`r-c`). If placing at `(r,c)` is safe, add to sets, recurse to next row. If successful, done. If not, remove from sets (backtrack).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-041',
      'dsa-linkedlists',
      'Sudoku Solver.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Find an empty cell. Try placing digits 1-9. Check validity (row, col, 3x3 box). If valid, place it and recursively solve the rest. If a recursive call returns true, done. If it returns false, backtrack (reset cell to `.`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-042',
      'dsa-linkedlists',
      'Restore IP Addresses.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking. Place exactly 3 dots. At each step, a segment can be 1, 2, or 3 digits. Ensure the segment is `<= 255` and doesn''t have leading zeros (unless it is exactly `"0"`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-043',
      'dsa-linkedlists',
      'Generate Parentheses.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Maintain counts of `openN` and `closedN`. If `openN < n`, append `(` and recurse. If `closedN < openN`, append `)` and recurse. Base case: `openN == n && closedN == n`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-044',
      'dsa-linkedlists',
      'Matchsticks to Square.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Sort matchsticks descending (optimization). The perimeter must be divisible by 4. Target side length is `perimeter / 4`. Backtrack with an array of size 4 representing sides. Try placing current matchstick in each of the 4 sides. If valid, recurse.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-045',
      'dsa-linkedlists',
      'Split String Into Max Number of Unique Substrings.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking with a Set. Loop `end` from `start` to string length. If the substring is not in the Set, add it, recurse, then remove it. Track the maximum depth reached.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-046',
      'dsa-linkedlists',
      'Find Unique Binary String.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cantor''s Diagonalization is faster, but Backtracking works. Generate all binary strings of length `n`. If the generated string is not in the provided array, return it. Base case `length == n`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-047',
      'dsa-linkedlists',
      'Fair Distribution of Cookies.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtrack. Maintain an array of size `k` (children). For each cookie, try giving it to each child (add cookie value to child''s total, recurse, subtract). Track the minimum of the maximum child total.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-048',
      'dsa-linkedlists',
      'M-Coloring Problem.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Given a graph, color nodes with `m` colors such that no adjacent nodes have the same color. Try all colors for node 1, if valid, recurse for node 2, etc. If no color works, backtrack.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-049',
      'dsa-linkedlists',
      'Rat in a Maze.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Backtracking in a 2D grid. Start at `(0,0)`, try moving D, L, R, U. Append move direction to string. Mark cell visited (`0`). Recurse. Unmark visited (`1`) and pop direction string.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'll-050',
      'dsa-linkedlists',
      'Design Linked List (Singly or Doubly).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Implement a full class with `get(index)`, `addAtHead(val)`, `addAtTail(val)`, `addAtIndex(index, val)`, and `deleteAtIndex(index)`. Keep track of `size` and use a `dummy` head for easier edge-case handling.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-001',
      'core-os',
      'What is an Operating System?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'System software that manages computer hardware, software resources, and provides common services for computer programs. It acts as an intermediary between the user/applications and the physical hardware.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-002',
      'core-os',
      'What is a Process?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An instance of a program in execution. It contains the program code and its current activity. Each process has its own isolated memory space (heap, stack, data, text segments) and resources.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-003',
      'core-os',
      'What is a Thread?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The smallest sequence of programmed instructions that can be managed independently by a scheduler. A thread is a component of a process. Multiple threads can exist within one process, sharing the process''s memory space (heap and data) but having their own stack and registers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-004',
      'core-os',
      'Processes vs Threads.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Processes are heavily isolated, do not share memory (unless explicitly using IPC), and context switching between them is slow. Threads share memory within the same process, are lightweight, and context switching is fast. However, one crashing thread can crash the entire process.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-005',
      'core-os',
      'Concurrency vs Parallelism.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Concurrency: Two or more tasks can start, run, and complete in overlapping time periods. It doesn''t mean they run at the EXACT same instant (e.g., single-core CPU using context switching). Parallelism: Two or more tasks literally run at the exact same instant (requires multi-core CPU).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-006',
      'core-os',
      'What is a Context Switch?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The process of storing the state (registers, program counter) of a currently running process or thread so that it can be restored and resume execution at a later point, allowing the CPU to execute a different process/thread.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-007',
      'core-os',
      'What is Inter-Process Communication (IPC)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Mechanisms provided by the OS to allow isolated processes to communicate and share data. Methods include Pipes, Message Queues, Shared Memory, Sockets, and Signals.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-008',
      'core-os',
      'What is a Race Condition?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A situation where two or more threads/processes attempt to read and write to shared data at the same time, and the final output depends on the unpredictable timing (scheduling) of their execution. Leads to data corruption.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-009',
      'core-os',
      'What is a Critical Section?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A part of the program where shared resources (variables, files) are accessed. To prevent race conditions, only one thread must be allowed to execute in its critical section at a time (Mutual Exclusion).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-010',
      'core-os',
      'What is a Mutex (Mutual Exclusion)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A locking mechanism used to synchronize access to a resource. Only one thread can acquire the mutex at a time. Other threads attempting to acquire it will block (sleep) until the owner thread releases it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-011',
      'core-os',
      'What is a Semaphore?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A signaling mechanism (essentially an integer counter). It controls access to a resource that has a pool of identical instances. `Wait()` decrements the counter. If counter is < 0, the thread blocks. `Signal()` increments the counter and wakes up a blocked thread. (A binary semaphore acts like a mutex).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-012',
      'core-os',
      'Mutex vs Semaphore.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Mutex: Concept of OWNERSHIP. The thread that locks it MUST unlock it. Used for exclusive access. Semaphore: NO ownership. Thread A can `wait()` and Thread B can `signal()`. Used for signaling or managing a pool of identical resources.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-013',
      'core-os',
      'What is a Deadlock?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A situation where a set of processes are blocked because each process is holding a resource and waiting for another resource acquired by some other process in the set. The system comes to a standstill.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-014',
      'core-os',
      'What are the 4 Coffman conditions for Deadlock?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Mutual Exclusion (resources cannot be shared). 2. Hold and Wait (process holds a resource while waiting for another). 3. No Preemption (resources cannot be forcibly taken away). 4. Circular Wait (P1 waits for P2, P2 waits for P3... Pn waits for P1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-015',
      'core-os',
      'How do you prevent Deadlocks?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Break one of the 4 conditions. The most common programmatic way is breaking Circular Wait by imposing a strict ordering on lock acquisition (always acquire Lock A before Lock B).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-016',
      'core-os',
      'What is Livelock?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Similar to a deadlock, but the states of the processes constantly change with regard to one another, without making any progress. Example: Two people in a hallway stepping side to side to avoid each other, perpetually blocking each other.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-017',
      'core-os',
      'What is Starvation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A situation where a process is perpetually denied the resources it needs to process its work. It''s not deadlocked, but the scheduler keeps bypassing it in favor of higher priority processes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-018',
      'core-os',
      'Explain CPU Scheduling.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The process of determining which process/thread gets to use the CPU while another is paused. Managed by the OS Scheduler to maximize CPU utilization and throughput while minimizing wait time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-019',
      'core-os',
      'Preemptive vs Non-Preemptive Scheduling.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Non-Preemptive: Once a process gets the CPU, it holds it until it terminates or blocks (I/O). Preemptive: The OS can interrupt a currently running process (usually via a timer interrupt) and allocate the CPU to another process.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-020',
      'core-os',
      'First-Come, First-Served (FCFS) Scheduling.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Non-preemptive. Processes are dispatched according to their arrival time. Simple, but suffers from the "Convoy Effect" (short processes wait a long time behind a massive process).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-021',
      'core-os',
      'Round Robin (RR) Scheduling.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Preemptive. Each process gets a small unit of CPU time (time quantum). If it doesn''t finish in that time, it''s preempted and put at the back of the queue. Highly responsive, used in modern time-sharing systems.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-022',
      'core-os',
      'Shortest Job First (SJF) Scheduling.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Can be preemptive or non-preemptive. The process with the smallest execution time is chosen next. Optimal for minimizing average wait time, but impossible to implement perfectly in general-purpose OS because predicting exact burst time is impossible.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-023',
      'core-os',
      'What is Virtual Memory?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A memory management technique that creates an illusion that the computer has contiguous and massive memory. It abstracts physical RAM and secondary storage (disk) into a single large virtual address space.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-024',
      'core-os',
      'What is Paging?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Virtual memory is divided into fixed-size blocks called Pages. Physical RAM is divided into blocks of the same size called Frames. The OS maps Pages to Frames using a Page Table. This eliminates external fragmentation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-025',
      'core-os',
      'What is a Page Fault?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a program tries to access a page of memory that is currently not loaded in physical RAM (it is swapped out to disk). The OS must pause the process, fetch the page from disk into RAM, update the page table, and resume.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-026',
      'core-os',
      'What is Thrashing?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a computer''s RAM is severely overcommitted. The OS spends more time paging (swapping pages in and out of the disk) than executing actual application code, causing performance to collapse to a near halt.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-027',
      'core-os',
      'What is a Translation Lookaside Buffer (TLB)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A specialized hardware cache located inside the CPU MMU. It caches recent virtual-to-physical address translations from the Page Table. It speeds up memory access drastically.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-028',
      'core-os',
      'What is an Inode?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A data structure on a POSIX-compliant file system (like ext4) that stores metadata about a file (size, owner, permissions, timestamps, and pointers to the disk blocks where the actual file data is stored). It does NOT store the filename.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-029',
      'core-os',
      'Hard Link vs Soft (Symbolic) Link.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Hard Link: Points directly to the same Inode as the original file. If original is deleted, the data remains accessible via the hard link. (Cannot link directories or cross file systems). Soft Link: A separate file that contains a text path to the original file. If original is deleted, the soft link becomes broken.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-030',
      'core-os',
      'What is a System Call?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The programmatic way in which a computer program requests a service from the kernel of the OS. It''s the bridge between User Space and Kernel Space. Examples: `open()`, `read()`, `fork()`, `exec()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-031',
      'core-os',
      'User Space vs Kernel Space.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Memory is divided. User Space: Where normal applications run. Restricted access. Kernel Space: Where the core of the OS runs. Full privileges to hardware and memory. Crossing from User to Kernel space (via system calls) causes a context switch overhead.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-032',
      'core-os',
      'What does the `fork()` system call do?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Creates a new process (child process) by duplicating the calling process (parent process). The child is an exact copy but gets a new PID. `fork()` returns 0 to the child, and the child''s PID to the parent.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-033',
      'core-os',
      'What is Copy-on-Write (COW) in the context of `fork()`?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'An optimization. When `fork()` is called, the OS does NOT instantly copy all the parent''s physical memory. Both processes share the same physical pages (marked read-only). Only when one process tries to WRITE/modify a page, the OS intercepts, makes a copy of that specific page, and updates mapping.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-034',
      'core-os',
      'What does the `exec()` family of system calls do?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Replaces the current process''s memory space (code, data, heap, stack) with a brand new program loaded from disk. The PID remains the same. Usually used immediately after `fork()`.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-035',
      'core-os',
      'What is an Orphan Process?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A process whose parent process has finished or terminated, though it remains running itself. In Linux, it is adopted by the `init` process (PID 1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-036',
      'core-os',
      'What is a Zombie Process?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A process that has completed execution but still has an entry in the process table. This occurs when the parent hasn''t yet read the child''s exit status (using `wait()`). They don''t consume CPU/Memory, but they consume PIDs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-037',
      'core-os',
      'What is a Daemon Process?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A background process that runs continuously and handles periodic service requests without user intervention (e.g., `sshd`, `cron`, `systemd`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-038',
      'core-os',
      'What is an Interrupt?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A signal to the processor emitted by hardware or software indicating an event that needs immediate attention. The CPU pauses its current activities, saves its state, and executes an Interrupt Service Routine (ISR).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-039',
      'core-os',
      'What is Direct Memory Access (DMA)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A feature that allows hardware subsystems (like disk drives or network cards) to access main system memory (RAM) independently of the CPU. This frees the CPU from doing heavy data-copying work.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-040',
      'core-os',
      'Explain the concept of Spooling.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Simultaneous Peripheral Operations On-Line. Data is temporarily held in a buffer (like on disk) to be used and executed by a device, program, or system. Commonly used for printers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-041',
      'core-os',
      'What is a Monitor (Synchronization)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A high-level synchronization construct. It is an object/module that encapsulates shared variables and the procedures that operate on them. It guarantees that only one thread can execute within the monitor at a time (built-in mutual exclusion), often using condition variables.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-042',
      'core-os',
      'What are Condition Variables?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Used alongside Mutexes to allow threads to wait for a certain condition to become true. A thread locks a mutex, checks a condition. If false, it calls `wait()` on the condition variable (which atomcially unlocks the mutex and puts the thread to sleep). Another thread will eventually call `signal()` to wake it up.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-043',
      'core-os',
      'What is the Readers-Writers Problem?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A classic synchronization problem. Multiple threads want to read a shared resource, and some want to write. Rules: 1. Any number of readers can read simultaneously. 2. Only ONE writer can write at a time. 3. No readers can read while a writer is writing. Solved with ReadWrite locks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-044',
      'core-os',
      'What is the Dining Philosophers Problem?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A classic synchronization problem demonstrating deadlock. N philosophers sit at a table with N forks. They need 2 forks to eat. If everyone picks up their left fork simultaneously, they all wait forever for the right fork (Deadlock).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-045',
      'core-os',
      'What is Cache Coherence?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In multi-core systems, each core has its own L1/L2 cache. If two cores cache the same memory address, and one modifies it, the other core''s cache becomes "stale". Cache coherence protocols (like MESI) ensure all cores see a consistent view of memory.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-046',
      'core-os',
      'What is Belady''s Anomaly?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'In the context of Page Replacement Algorithms (specifically FIFO), it is a counter-intuitive phenomenon where increasing the number of page frames allocated to a process actually INCREASES the number of page faults.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-047',
      'core-os',
      'Explain LRU Page Replacement.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Least Recently Used. When a page fault occurs and RAM is full, the OS evicts the page that has not been accessed for the longest amount of time. Excellent performance, but hard to implement purely in hardware.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-048',
      'core-os',
      'What is the Working Set Model?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Based on the principle of locality. A process''s working set is the set of pages it has recently referenced. If the OS can allocate enough frames to hold the entire working set, page fault rates remain very low. If not, thrashing occurs.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-049',
      'core-os',
      'What is File Descriptor?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'In POSIX systems (Linux/Unix), an abstract indicator (an integer) used to access a file or other input/output resource, such as a pipe or network socket. 0 is standard input (stdin), 1 is standard output (stdout), 2 is standard error (stderr).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'os-050',
      'core-os',
      'What is a Spinlock?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A lock where the thread simply waits in a loop ("spins") repeatedly checking if the lock is available. It does NOT put the thread to sleep (no context switch overhead). Only efficient if the lock is held for a very, very short time on a multi-core system.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-001',
      'core-networking',
      'What is a Computer Network?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A group of two or more interconnected computer systems that use common communication protocols over digital interconnections to share resources.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-002',
      'core-networking',
      'What is an IP Address?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Internet Protocol Address. A unique numerical label assigned to each device connected to a computer network that uses the Internet Protocol for communication. Used for host identification and location addressing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-003',
      'core-networking',
      'IPv4 vs IPv6.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'IPv4 uses 32-bit addresses (approx. 4.3 billion addresses), formatted as 4 decimal numbers separated by dots (e.g., `192.168.1.1`). IPv6 uses 128-bit addresses (virtually unlimited), formatted as 8 groups of 4 hexadecimal digits separated by colons (e.g., `2001:0db8::ff00:0042:8329`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-004',
      'core-networking',
      'What is a MAC Address?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Media Access Control Address. A unique identifier assigned to a Network Interface Controller (NIC) for use as a network address in communications within a network segment (Data Link Layer). Burned into the hardware.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-005',
      'core-networking',
      'What is the OSI Model?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Open Systems Interconnection Model. A conceptual framework used to describe the functions of a networking system. It characterizes computing functions into a universal set of 7 layers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-006',
      'core-networking',
      'List the 7 layers of the OSI Model.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '7. Application (HTTP, FTP) 
6. Presentation (SSL, TLS, JPEG) 
5. Session (Sockets) 
4. Transport (TCP, UDP) 
3. Network (IP, Routers) 
2. Data Link (MAC, Switches) 
1. Physical (Cables, Hubs).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-007',
      'core-networking',
      'What is the TCP/IP Model?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A more concise, practical model compared to OSI, forming the basis of the modern Internet. It has 4 layers: 4. Application (maps to OSI 5, 6, 7). 3. Transport (OSI 4). 2. Internet (OSI 3). 1. Network Access / Link (OSI 1, 2).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-008',
      'core-networking',
      'What is a Router?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A networking device that forwards data packets between computer networks. Routers perform the traffic directing functions on the Internet (Layer 3 - Network Layer). They use IP addresses to determine the best path.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-009',
      'core-networking',
      'What is a Switch?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A networking hardware that connects devices on a computer network by using packet switching to receive and forward data to the destination device. It operates at Layer 2 (Data Link Layer) and uses MAC addresses.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-010',
      'core-networking',
      'Router vs Switch vs Hub.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Hub (Layer 1): Broadcasts data to all ports (dumb, high collisions). Switch (Layer 2): Sends data only to the specific port of the destination MAC address (smart, no collisions). Router (Layer 3): Connects different networks (like your home LAN to the ISP''s WAN) using IP addresses.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-011',
      'core-networking',
      'What is TCP?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Transmission Control Protocol. A connection-oriented protocol that provides reliable, ordered, and error-checked delivery of a stream of bytes between applications. Used by HTTP, SSH, FTP.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-012',
      'core-networking',
      'What is UDP?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'User Datagram Protocol. A connectionless protocol that sends independent packets (datagrams). It provides no guarantees of delivery, ordering, or duplicate protection. Extremely fast. Used by DNS, video streaming, online gaming.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-013',
      'core-networking',
      'TCP vs UDP.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'TCP is reliable, connection-oriented, ordered, heavy, and performs error-checking and flow control. UDP is unreliable, connectionless, unordered, lightweight, and fast with no overhead.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-014',
      'core-networking',
      'Explain the TCP 3-Way Handshake.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Used to establish a TCP connection. 1. Client sends `SYN` (synchronize) packet. 2. Server receives, sends back `SYN-ACK` (synchronize-acknowledge). 3. Client receives, sends `ACK` (acknowledge). Connection is established.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-015',
      'core-networking',
      'Explain the TCP 4-Way Teardown.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Used to close a connection. 1. Client sends `FIN` (finish). 2. Server sends `ACK`. 3. Server sends `FIN` (when it''s done sending its data). 4. Client sends `ACK`. Connection closed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-016',
      'core-networking',
      'What is DNS?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Domain Name System. The "phonebook" of the Internet. It translates human-readable domain names (like `www.google.com`) into machine-readable IP addresses (like `142.250.190.46`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-017',
      'core-networking',
      'How does DNS Resolution work?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Browser checks local cache/OS cache. 2. Asks ISP''s Recursive Resolver. 3. Resolver asks Root Nameserver (.). 4. Root points to TLD Nameserver (.com). 5. TLD points to Authoritative Nameserver (google.com). 6. Authoritative returns the IP.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-018',
      'core-networking',
      'What is HTTP?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Hypertext Transfer Protocol. An application-layer protocol for transmitting hypermedia documents, such as HTML. It was designed for communication between web browsers and web servers. It is stateless.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-019',
      'core-networking',
      'What is HTTPS?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Hypertext Transfer Protocol Secure. An extension of HTTP. It uses Transport Layer Security (TLS) or Secure Sockets Layer (SSL) to encrypt the communication protocol, providing privacy and data integrity.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-020',
      'core-networking',
      'Explain the SSL/TLS Handshake.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      '1. Client Hello (supported ciphers). 2. Server Hello (chosen cipher, SSL certificate containing public key). 3. Client verifies certificate. 4. Client generates a symmetric "pre-master secret", encrypts it with server''s public key, sends it. 5. Server decrypts with private key. 6. Both compute symmetric session keys. 7. Secure communication begins.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-021',
      'core-networking',
      'What is a Port?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A logical endpoint for network communication. IP addresses identify a machine; ports identify the specific process or service running on that machine. E.g., Port 80 for HTTP, 443 for HTTPS, 22 for SSH.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-022',
      'core-networking',
      'What is an Ephemeral Port?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A short-lived transport protocol port assigned automatically by the OS''s IP stack from a predefined range (e.g., 49152 to 65535) when a client application initiates an outgoing connection to a server.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-023',
      'core-networking',
      'What is NAT (Network Address Translation)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A method used by routers to map multiple private IP addresses inside a local network to a single public IP address before transferring the information to the Internet. It is the primary reason IPv4 addresses haven''t run out completely.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-024',
      'core-networking',
      'What is DHCP?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Dynamic Host Configuration Protocol. A network management protocol used on UDP/IP networks whereby a DHCP server dynamically assigns an IP address and other network configuration parameters to each device on a network so they can communicate.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-025',
      'core-networking',
      'What is ARP?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Address Resolution Protocol. Used to map a logical Network Layer address (IP address) to a physical Data Link Layer address (MAC address) on a local network.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-026',
      'core-networking',
      'What is an ICMP Ping?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Internet Control Message Protocol. An echo request packet sent to a target host. If available, the host replies with an echo reply. Used to check if a host is reachable across an IP network and to measure round-trip time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-027',
      'core-networking',
      'What is a Firewall?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A network security system that monitors and controls incoming and outgoing network traffic based on predetermined security rules. It establishes a barrier between a trusted internal network and an untrusted external network (Internet).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-028',
      'core-networking',
      'What is a Proxy Server?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An intermediary server separating end-user clients from the destinations that they browse. Proxies can provide varying levels of functionality, security, and privacy (e.g., hiding client IP, caching resources).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-029',
      'core-networking',
      'What is a Reverse Proxy?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A type of proxy server that sits BEHIND the firewall in a private network and directs client requests to the appropriate backend server. Used for load balancing, SSL termination, and hiding the architecture of backend servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-030',
      'core-networking',
      'What are WebSockets?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A computer communications protocol providing full-duplex communication channels over a single TCP connection. Unlike HTTP, where the client must poll the server, WebSockets allow the server to push data to the client in real-time.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-031',
      'core-networking',
      'HTTP/1.1 vs HTTP/2.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'HTTP/1.1 sends requests serially on a connection (Head-of-Line Blocking). HTTP/2 uses Multiplexing (sends multiple requests and responses simultaneously over a SINGLE TCP connection), binary framing, and Server Push.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-032',
      'core-networking',
      'What is HTTP/3 (QUIC)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The newest iteration. It completely abandons TCP in favor of QUIC (a transport protocol built on top of UDP). It solves TCP''s Head-of-Line blocking issue entirely and allows for faster connection setups (0-RTT).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-033',
      'core-networking',
      'What is CORS?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cross-Origin Resource Sharing. A security mechanism built into modern web browsers. It restricts web pages from making requests to a different domain than the one that served the web page, unless the server explicitly allows it via HTTP headers (`Access-Control-Allow-Origin`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-034',
      'core-networking',
      'What is an API Gateway?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A server that acts as an API front-end, receiving API requests, enforcing throttling and security policies, passing requests to the back-end service and then passing the response back to the requester. Essential in microservices.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-035',
      'core-networking',
      'What is a Subnet Mask?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A 32-bit number that masks an IP address, dividing the IP address into network address and host address. E.g., `255.255.255.0` (or `/24` in CIDR notation) means the first 24 bits represent the network.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-036',
      'core-networking',
      'What is BGP?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Border Gateway Protocol. The routing protocol that makes the Internet work. It manages how packets are routed across the internet through the exchange of routing and reachability information between edge routers (Autonomous Systems).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-037',
      'core-networking',
      'What is a VPN?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Virtual Private Network. It extends a private network across a public network. It enables users to send and receive data across shared or public networks as if their computing devices were directly connected to the private network, usually via an encrypted tunnel (IPsec, WireGuard).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-038',
      'core-networking',
      'TCP Flow Control vs Congestion Control.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Flow Control: Prevents the sender from overwhelming the RECEIVER (uses the sliding window mechanism advertised by the receiver). Congestion Control: Prevents the sender from overwhelming the NETWORK (routers/links) by dynamically adjusting the window size based on packet loss.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-039',
      'core-networking',
      'What is the MTU?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Maximum Transmission Unit. The size of the largest protocol data unit (PDU) that can be communicated in a single network layer transaction. For standard Ethernet, the MTU is 1500 bytes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-040',
      'core-networking',
      'What is Packet Fragmentation?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'When an IP datagram is larger than the MTU of the network it needs to travel through, the router must break it down into smaller fragments. The destination host reassembles them. It adds significant overhead.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-041',
      'core-networking',
      'What is Anycast?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A network addressing and routing methodology in which a single IP address is shared by multiple servers in multiple locations. The network (BGP) routes the request to the server that is topologically CLOSEST to the user. Widely used by CDNs and DNS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-042',
      'core-networking',
      'What is Multicast?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A method of sending internet traffic to a group of interested receivers in a single transmission. Instead of sending 10 copies of a video stream to 10 users (Unicast), the server sends 1 copy, and the routers replicate the packets only where the paths split.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-043',
      'core-networking',
      'What happens when you type google.com into your browser?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. DNS Resolution (find IP). 2. TCP 3-way handshake with IP on port 443. 3. TLS Handshake for secure connection. 4. HTTP GET request sent. 5. Server processes and sends HTTP Response (HTML). 6. Browser parses HTML, fetches assets (CSS/JS), and renders the page.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-044',
      'core-networking',
      'What is a CDN?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Content Delivery Network. A geographically distributed network of servers. They cache static content (images, CSS, JS) at edge locations close to the users, dramatically reducing latency and offloading traffic from the origin server.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-045',
      'core-networking',
      'What is SNI?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Server Name Indication. An extension to TLS. It indicates what hostname the client is attempting to connect to at the start of the handshaking process. This allows a server to present multiple certificates on the SAME IP address and TCP port number (essential for virtual hosting with HTTPS).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-046',
      'core-networking',
      'What is a MAC Address Table?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A table maintained by a Layer 2 Switch. It maps MAC addresses to the specific physical ports on the switch. When a switch receives a frame, it looks up the destination MAC in this table to know which port to forward it out of.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-047',
      'core-networking',
      'What is the Loopback Address?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A special IP address (`127.0.0.1` in IPv4, `::1` in IPv6) used to route traffic back to the same machine. Also known as `localhost`. Traffic sent to this address never leaves the host computer.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-048',
      'core-networking',
      'What is a DDoS Attack?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Distributed Denial of Service. A malicious attempt to disrupt normal traffic of a targeted server, service, or network by overwhelming the target or its surrounding infrastructure with a flood of Internet traffic from multiple compromised computer systems.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-049',
      'core-networking',
      'What is the concept of Idempotency in HTTP?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'An HTTP method is idempotent if an identical request can be made once or several times in a row with the same effect while leaving the server in the same state. `GET`, `PUT`, `DELETE` are idempotent. `POST` is NOT.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'net-050',
      'core-networking',
      'What is a Socket?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'One endpoint of a two-way communication link between two programs running on the network. A socket is bound to a port number so that the TCP layer can identify the application that data is destined to be sent to.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-001',
      'core-sys-design',
      'Vertical vs Horizontal Scaling.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Vertical (Scale Up): Adding more power (CPU, RAM) to an existing machine. Has a hard limit and involves downtime. Horizontal (Scale Out): Adding more machines to your pool of resources. Conceptually infinite, provides redundancy, requires load balancing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-002',
      'core-sys-design',
      'What is a Load Balancer?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A component that evenly distributes incoming network traffic across a group of backend servers. This ensures no single server bears too much demand, improving responsiveness and availability.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-003',
      'core-sys-design',
      'Explain common Load Balancing Algorithms.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1. Round Robin: Sequential distribution. 2. Least Connections: Sends request to the server with the fewest active connections. 3. IP Hash: Hashes the client IP to assign them to a specific server (sticky sessions). 4. Weighted: Servers with higher specs get more traffic.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-004',
      'core-sys-design',
      'What is Caching?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Storing copies of frequently accessed, computationally expensive, or slow-to-retrieve data in a temporary storage location (usually in-memory like Redis or Memcached) so future requests can be served much faster.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-005',
      'core-sys-design',
      'Explain Cache Eviction Policies.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'When a cache is full, it must remove data. 1. LRU (Least Recently Used): Evicts the item accessed furthest in the past. 2. LFU (Least Frequently Used): Evicts the item accessed the least number of times. 3. FIFO (First In First Out).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-006',
      'core-sys-design',
      'Cache Aside vs Write-Through vs Write-Behind.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Cache Aside: App checks cache, if miss, fetches from DB, updates cache. Write-Through: App writes data to cache, and cache immediately writes to DB (safe, slow writes). Write-Behind (Write-Back): App writes to cache, cache acknowledges immediately, asynchronously writes to DB later (fast, risk of data loss).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-007',
      'core-sys-design',
      'What is the CAP Theorem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In a distributed data store, you can only guarantee TWO out of three properties simultaneously: Consistency (every read receives the most recent write), Availability (every request receives a response), and Partition Tolerance (system continues to operate despite network failures dropping messages).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-008',
      'core-sys-design',
      'Why is Partition Tolerance mandatory in distributed systems?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Networks WILL fail. Network partitions are unavoidable. Therefore, in reality, CAP theorem means when a partition occurs, you must choose between Consistency (cancel the request) or Availability (return potentially stale data).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-009',
      'core-sys-design',
      'What is PACELC Theorem?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'An extension to CAP. It states: in case of Partition (P), trade-off between Availability (A) and Consistency (C). ELSE (E) (when running normally without partition), trade-off between Latency (L) and Consistency (C).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-010',
      'core-sys-design',
      'Relational (SQL) vs Non-Relational (NoSQL) Databases.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'SQL: Structured schema, ACID compliance, good for complex queries and relationships, scales vertically. NoSQL: Flexible schema, BASE compliance (usually), good for massive unstructured data and rapid development, scales horizontally easily.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-011',
      'core-sys-design',
      'What is Database Indexing?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A data structure (often a B-Tree) that improves the speed of data retrieval operations on a database table at the cost of additional writes and storage space to maintain the index.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-012',
      'core-sys-design',
      'What is Database Sharding?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A type of horizontal partitioning. You split a massive database into smaller, faster, more easily managed parts called data shards. Each shard is held on a separate database server. Requires a Sharding Key.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-013',
      'core-sys-design',
      'What is Consistent Hashing?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A distributed hashing scheme that operates independently of the number of servers or objects. It maps data to nodes on a "hash ring". When a server is added or removed, only `K/N` keys need to be remapped (unlike standard `hash(key) % N` which remaps nearly everything).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-014',
      'core-sys-design',
      'What is a Message Queue?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A form of asynchronous service-to-service communication used in serverless and microservices architectures. Messages are stored on the queue until they are processed and deleted. Decouples producers and consumers. Examples: RabbitMQ, SQS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-015',
      'core-sys-design',
      'Message Queue vs Event Streaming (Pub/Sub).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Queue (RabbitMQ): 1-to-1 communication. Message is consumed once, then deleted. Used for task delegation. Stream (Kafka): 1-to-Many. Messages are appended to a log and persisted for a retention period. Multiple consumer groups can read the same message independently.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-016',
      'core-sys-design',
      'What is Microservices Architecture?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'An architectural style that structures an application as a collection of small, autonomous services modeled around a business domain. Services communicate via APIs, are independently deployable, and can use different technologies.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-017',
      'core-sys-design',
      'Monolith vs Microservices.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Monolith: Simple to develop/test initially, hard to scale, single point of failure, tightly coupled. Microservices: Hard to orchestrate, requires complex CI/CD, easily scalable, fault-tolerant, allows technology diversity.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-018',
      'core-sys-design',
      'What is an API Gateway in Microservices?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A single point of entry for all clients. It routes requests to the appropriate microservices, aggregates results, and handles cross-cutting concerns like authentication, rate limiting, logging, and SSL termination.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-019',
      'core-sys-design',
      'What is Service Discovery?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In microservices, instances are dynamically created and destroyed. Service discovery automatically detects devices and services on a network. A registry (like Consul or Eureka) keeps track of which service is running on which IP/Port.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-020',
      'core-sys-design',
      'What is the Circuit Breaker Pattern?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Prevents an application from repeatedly trying to execute an operation that''s likely to fail. If Service A calls Service B and B is down, A will hang. The circuit breaker detects the failure, "trips" (opens the circuit), and immediately returns an error for subsequent calls until B recovers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-021',
      'core-sys-design',
      'What is Rate Limiting?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Controlling the rate of traffic sent or received on a network. Used to prevent DoS attacks, brute force login attempts, or to enforce API quotas. Algorithms include Token Bucket, Leaky Bucket, and Fixed Window.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-022',
      'core-sys-design',
      'Explain the Token Bucket algorithm.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A bucket holds `N` tokens. Tokens are added at a constant rate. When a request arrives, it must consume a token. If the bucket is empty, the request is rejected. Allows for short bursts of traffic while enforcing a long-term average rate.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-023',
      'core-sys-design',
      'What is Database Replication?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Creating and maintaining copies of the same database. Commonly Leader-Follower (Master-Slave): All writes go to the Leader, which asynchronously replicates to Followers. Read operations are distributed among Followers to scale read traffic.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-024',
      'core-sys-design',
      'What is Data Replication Lag?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'In asynchronous replication, it is the delay between a write hitting the Leader and that write propagating to the Followers. Can lead to "Read Your Own Writes" inconsistency.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-025',
      'core-sys-design',
      'What is the Two-Phase Commit (2PC) Protocol?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A distributed algorithm that coordinates all the processes that participate in a distributed transaction to either COMMIT or ABORT the transaction. Phase 1: Prepare (Voting). Phase 2: Commit (Resolution). Very slow, blocks resources.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-026',
      'core-sys-design',
      'What is the Saga Pattern?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'A modern alternative to 2PC for distributed transactions in microservices. A sequence of local transactions. Each local transaction updates the database and publishes an event. If a local transaction fails, the Saga executes compensating transactions to undo the previous steps.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-027',
      'core-sys-design',
      'What is Event Sourcing?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Instead of storing the CURRENT state of the data, you store a sequence of state-changing EVENTS. To get the current state, you replay the events. Provides an infallible audit log. Often paired with CQRS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-028',
      'core-sys-design',
      'What is CQRS?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Command Query Responsibility Segregation. Separates the data mutation (Command) from the data retrieval (Query) into different models, and often different databases. Optimizes read and write workloads independently.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-029',
      'core-sys-design',
      'What is a Content Delivery Network (CDN)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A geographically distributed network of servers. They cache static assets (HTML, CSS, JS, Images, Video) closer to the end-users. Reduces latency and bandwidth costs on the origin server.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-030',
      'core-sys-design',
      'Push vs Pull CDNs.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Push CDN: You proactively upload content to the CDN. Best for large files or infrequent changes. Pull CDN: The CDN automatically fetches the content from your origin server the first time a user requests it, then caches it. Best for web apps.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-031',
      'core-sys-design',
      'What is Long Polling?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A technique where the client requests information from the server. If the server has no new data, it HOLDS the connection open until data becomes available (or timeout). Once sent, the client immediately initiates a new long-poll. Good alternative to WebSockets if unsupported.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-032',
      'core-sys-design',
      'What are Server-Sent Events (SSE)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A unidirectional communication protocol where the server pushes updates to the client over a single HTTP connection. Excellent for real-time dashboards or stock tickers where the client only needs to RECEIVE data.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-033',
      'core-sys-design',
      'What is Database Normalization?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Organizing columns and tables in an RDBMS to reduce data redundancy and improve data integrity. Involves dividing large tables into smaller ones and defining relationships (Foreign Keys).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-034',
      'core-sys-design',
      'What is Denormalization?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'The process of intentionally adding redundant data to a database. It is an optimization technique to speed up read performance by avoiding complex, expensive SQL JOIN operations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-035',
      'core-sys-design',
      'What is a Bloom Filter?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A space-efficient probabilistic data structure. It is used to test whether an element is a member of a set. False positive matches are possible, but false negatives are not. (If it says "No", it is definitely not there. If it says "Yes", it MIGHT be there). Great for checking if an ID exists before hitting the DB.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-036',
      'core-sys-design',
      'What is a Distributed Lock?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A lock that allows multiple processes across different machines to mutually exclude each other from a shared resource. Often implemented using Redis (Redlock algorithm) or Zookeeper.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-037',
      'core-sys-design',
      'What is the Back-of-the-Envelope Estimation?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A crucial System Design interview skill. Using rough calculations to estimate the scale of a system (QPS, storage requirements, bandwidth requirements) to justify your design decisions. Requires knowing powers of 2 and rough latency numbers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-038',
      'core-sys-design',
      'What is Latency vs Throughput?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Latency: The TIME it takes for a single data packet to travel from source to destination (Response time). Throughput: The VOLUME of data that can be processed in a given amount of time (e.g., Requests Per Second or MB/s).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-039',
      'core-sys-design',
      'What is a Proxy Server vs Reverse Proxy?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Forward Proxy: Sits in front of CLIENTS. Masks client IP, caches internet data, blocks websites. Reverse Proxy: Sits in front of SERVERS. Masks server IP, load balances, terminates SSL, caches static content.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-040',
      'core-sys-design',
      'What is Strong vs Eventual Consistency?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Strong Consistency: After a write, any subsequent read will return the updated value (Synchronous). Eventual Consistency: If no new updates are made, eventually all accesses will return the last updated value (Asynchronous, common in DNS and NoSQL).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-041',
      'core-sys-design',
      'How do you design a URL Shortener (like bit.ly)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Key components: API Gateway, Load Balancer. App Servers. Relational DB (URL mapping) or NoSQL. Generation mechanism: Base62 encoding of an auto-incrementing ID or a Hash collision resolution. Caching heavily (Redis) for reads.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-042',
      'core-sys-design',
      'How do you design a Chat Application (like WhatsApp)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Requires full-duplex communication (WebSockets). Load Balancer in front of Chat Servers. Redis/PubSub to route messages between Chat Servers if users are connected to different instances. Cassandra or HBase for massive write-heavy message history.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-043',
      'core-sys-design',
      'What is a Snowflake ID generator?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Twitter''s algorithm to generate unique 64-bit IDs in distributed systems without a central bottleneck. Composed of: Timestamp (41 bits) + Datacenter ID (5 bits) + Machine ID (5 bits) + Sequence Number (12 bits).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-044',
      'core-sys-design',
      'What is the "Thundering Herd" problem?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Occurs when a large number of processes/clients waiting for an event are awoken simultaneously when the event occurs, and all attempt to access a resource at the exact same time, overwhelming the system. (E.g., cache expires, thousands of requests hit the DB at once).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-045',
      'core-sys-design',
      'What is Jitter?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Adding a small, random amount of time (variance) to a delay mechanism. Used in retry logic with exponential backoff to prevent a "thundering herd" of retries from hitting a recovering service at the exact same millisecond.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-046',
      'core-sys-design',
      'What is High Availability (HA)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A characteristic of a system that aims to ensure an agreed level of operational performance (uptime) for a higher than normal period. Often measured in "Nines" (e.g., 99.999% uptime allows for 5 minutes of downtime a year).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-047',
      'core-sys-design',
      'What is a Single Point of Failure (SPOF)?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A part of a system that, if it fails, will stop the entire system from working. System Design aims to eliminate SPOFs through redundancy at every layer (multiple load balancers, multiple app servers, database replication).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-048',
      'core-sys-design',
      'What is Disaster Recovery (DR)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A set of policies, tools, and procedures to enable the recovery or continuation of vital technology infrastructure following a natural or human-induced disaster. Key metrics: RPO (Recovery Point Objective - how much data can you lose) and RTO (Recovery Time Objective - how fast must it be back up).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-049',
      'core-sys-design',
      'Active-Active vs Active-Passive Architecture.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Active-Active: Traffic is load balanced across multiple operational data centers simultaneously. Complex to sync data. Active-Passive: Only one data center handles traffic. The passive one is a hot-standby and only takes over if the active one fails. Simpler, but wastes resources.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdc-050',
      'core-sys-design',
      'What is an Anti-Pattern?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A common response to a recurring problem that is usually ineffective and risks being highly counterproductive. Example: God Object, Hardcoding, Premature Optimization.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-001',
      'projects-sys-design',
      'What is the standard framework for answering a System Design interview question?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '1. Requirements Clarification (Functional & Non-Functional). 2. Back-of-the-envelope Estimation (Capacity planning). 3. System Interface/API Definition. 4. Database Schema Design. 5. High-Level Architecture. 6. Deep Dive/Scaling (Addressing bottlenecks, single points of failure, edge cases).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-002',
      'projects-sys-design',
      'Functional vs Non-Functional Requirements.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Functional: What the system MUST do (e.g., users can send messages, users can upload videos). Non-Functional: How the system behaves (e.g., Highly Available, Low Latency, Eventual Consistency, highly secure).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-003',
      'projects-sys-design',
      'Design a URL Shortener (like bit.ly) - Core Requirements.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Functional: 1. Given a URL, return a short alias. 2. Given an alias, redirect to the original URL. 3. Custom aliases. Non-Functional: 1. Highly Available (redirects cannot fail). 2. Read-heavy (100:1 read/write ratio). 3. Low latency redirects.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-004',
      'projects-sys-design',
      'URL Shortener - How to generate the short URL?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Option 1: Hash the URL (MD5/SHA256) and take the first 7 characters (Base62 encoded). Collision risk requires DB checks. Option 2: Use an offline standalone "Ticket Server" or Snowflake to generate unique sequential integer IDs, then convert the integer to Base62 (a-z, A-Z, 0-9). This is collision-free and scalable.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-005',
      'projects-sys-design',
      'URL Shortener - Should you use a 301 or 302 redirect?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '301 (Permanent Redirect): The browser caches the response. Subsequent requests bypass the shortener. Reduces load but makes analytics/click-tracking impossible. 302 (Temporary Redirect): The browser hits the shortener every time. Higher load, but enables analytics.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-006',
      'projects-sys-design',
      'Design Pastebin - Core Requirements.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Functional: Upload text, get a URL to share. Non-Functional: Highly available, read-heavy, text data needs to be stored efficiently (possibly compressed or stored in object storage like S3 if very large, rather than directly in a relational DB).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-007',
      'projects-sys-design',
      'Design Twitter/X (News Feed) - High Level Architecture.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Load Balancer -> Web Servers. Separate services for User Auth, Tweeting, and Timeline Generation. DBs: Relational for User metadata, Graph DB for follower relationships, NoSQL (Cassandra/Redis) for tweets and timelines. Heavy caching layer (Memcached/Redis) for celebrity timelines.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-008',
      'projects-sys-design',
      'Twitter/X - How do you generate the News Feed (Fan-out)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Fan-out on Write (Push): When a user tweets, immediately push the tweet into the pre-computed timeline cache of all their followers (Fast reads, terrible for celebrities with 100M followers). Fan-out on Read (Pull): Compute timeline on the fly when the user logs in (Slow reads). Hybrid approach: Push for normal users, Pull for celebrities.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-009',
      'projects-sys-design',
      'Design Instagram - Data Storage.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Images go into Object Storage (AWS S3) with a CDN (CloudFront) in front. Image metadata (URL, UserID, Timestamp, Caption) goes into an RDBMS (PostgreSQL) or NoSQL (Cassandra) database. Caching is critical for the feed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-010',
      'projects-sys-design',
      'Design a Chat Application (WhatsApp/Messenger) - Real-time communication.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'HTTP is inefficient for chat. Use WebSockets for persistent, bi-directional connections. The client connects to a Chat Server. The Chat Server holds the WebSocket open. When a message arrives, it is pushed directly to the client.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-011',
      'projects-sys-design',
      'Chat App - How do you route messages if User A and User B are connected to different Chat Servers?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Use a message broker (Redis Pub/Sub or Kafka). User A sends to Server 1. Server 1 publishes the message to a Redis channel. Server 2 (which holds User B''s connection) subscribes to that channel, receives the message, and pushes it to User B over the WebSocket.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-012',
      'projects-sys-design',
      'Chat App - How to handle user presence (Online/Offline status)?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Heartbeats. The client sends a heartbeat over the WebSocket every 5 seconds. The Presence Server records the last heartbeat timestamp in Redis. If the timestamp is > 10 seconds old, the user is marked offline. Push status changes to friends via message broker.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-013',
      'projects-sys-design',
      'Design a Key-Value Store (like Redis/Memcached).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'In-memory data structure (Hash Table). For distributed: Consistent Hashing to distribute keys across nodes. Replication (Leader-Follower) for high availability. Gossip protocol for failure detection. Write-Ahead Log (WAL) to disk for persistence/durability.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-014',
      'projects-sys-design',
      'Design a Rate Limiter.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Algorithms: Token Bucket, Leaky Bucket, Fixed Window, Sliding Window Log, Sliding Window Counter. Storage: Redis (fast, in-memory, supports atomic operations like `INCR` and `EXPIRE`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-015',
      'projects-sys-design',
      'Rate Limiter - Where should it be deployed?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Usually implemented as a middleware within the API Gateway. This prevents malicious traffic from ever reaching the backend application servers or databases.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-016',
      'projects-sys-design',
      'Design a Search Engine (like Google) - High Level.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      '1. Crawler: Traverses the web (BFS), downloads HTML. 2. Indexer: Parses HTML, extracts words, creates an Inverted Index (Word -> List of Document IDs). 3. Ranker (PageRank): Ranks documents based on relevance and authority. 4. Query Engine: Takes user search, looks up Inverted Index, sorts by Ranker score.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-017',
      'projects-sys-design',
      'Search Engine - What is an Inverted Index?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A data structure storing a mapping from content, such as words or numbers, to its locations in a database file, or in a document or a set of documents. (e.g., "apple" -> [Doc1, Doc4, Doc55]). Essential for fast full-text search.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-018',
      'projects-sys-design',
      'Design YouTube/Netflix (Video Streaming).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '1. Video Upload: User uploads video -> Transcoding Service (creates 1080p, 720p, 360p formats, splits into chunks like HLS/DASH) -> Store in S3. 2. Video Streaming: Users stream video chunks directly from a CDN (CloudFront/Open Connect) closest to them, not from the backend app servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-019',
      'projects-sys-design',
      'Design a Distributed Message Queue (like Kafka).',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Producers append messages to Topics. Topics are split into Partitions. Partitions are append-only logs distributed across Brokers (servers). Consumers read from partitions. ZooKeeper (or Kraft) manages cluster metadata and leader election for partitions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-020',
      'projects-sys-design',
      'Design a Web Crawler.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Seed URLs -> URL Frontier (Queue prioritizing URLs based on domain/politeness). Fetcher pulls URL from queue, downloads HTML. DNS resolution must be cached heavily. Parser extracts links, adds to Frontier. Content deduplication (using Simhash) to avoid infinite loops.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-021',
      'projects-sys-design',
      'Design a Notification System.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Services trigger events -> Event pushed to Message Queue (Kafka/RabbitMQ) -> Notification Workers consume queue -> Look up user preferences in DB -> Send via appropriate 3rd party API (APNS for iOS, FCM for Android, SendGrid for Email, Twilio for SMS).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-022',
      'projects-sys-design',
      'Design Google Drive / Dropbox.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Do not upload the whole file if a small part changes. Split files into "Chunks" (e.g., 4MB). Hash each chunk. Upload chunks to S3. Metadata DB tracks which file consists of which chunks. Sync client monitors local file changes, calculates hashes, and only uploads changed chunks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-023',
      'projects-sys-design',
      'Design Uber / Lyft (Ride Sharing) - Location Tracking.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Drivers send location every 4 seconds. Needs a high-throughput write DB (Cassandra or Redis). Use Geospatial indexing (Geohash, S2 Geometry, or QuadTrees) to partition the map and quickly find drivers near a specific rider''s coordinates.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-024',
      'projects-sys-design',
      'Uber/Lyft - What is a QuadTree?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A tree data structure where each internal node has exactly four children. Used to partition a two-dimensional space by recursively subdividing it into four quadrants. Excellent for finding points of interest (drivers) within a certain radius.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-025',
      'projects-sys-design',
      'Design Ticketmaster (Movie/Concert Ticket Booking).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'High concurrency issue: 10,000 people trying to buy 100 seats. Read-heavy until tickets drop, then massive write spikes. Requires strict ACID transactions (Relational DB). Use Row-Level Locking (`SELECT ... FOR UPDATE`) or Redis distributed locks to hold a seat for 5 mins while the user pays.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-026',
      'projects-sys-design',
      'Design Amazon/E-commerce System - Cart and Checkout.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Cart must be highly available (AP in CAP), use DynamoDB or Redis. Checkout must be strictly consistent (CP in CAP), use an RDBMS (Postgres) with distributed transactions (Saga pattern) to orchestrate Inventory, Payment, and Shipping microservices.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-027',
      'projects-sys-design',
      'Design a Typeahead Suggestion System (Autocomplete).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use a Trie (Prefix Tree) data structure. Store top search queries in the Trie. As the user types, traverse the Trie and return the top K most popular children nodes. Since updating the Trie is slow, aggregate search logs offline (MapReduce) and rebuild/update the Trie periodically.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-028',
      'projects-sys-design',
      'Design an API Rate Limiter - Fixed Window vs Sliding Window.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Fixed Window: Resets at the top of the minute. Vulnerable to spikes at the boundary (e.g., 100 requests at 12:00:59, 100 at 12:01:01 = 200 requests in 2 seconds). Sliding Window: Tracks timestamps of each request (often in a Redis Sorted Set). More accurate, but uses more memory.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-029',
      'projects-sys-design',
      'Design Yelp / Proximity Server.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Similar to Uber. Given a lat/long and radius, return nearby businesses. Use Geohashing or QuadTrees. Store Business ID and Geohash in the DB. Querying becomes a prefix string match (e.g., find all businesses starting with Geohash `9q8y`).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-030',
      'projects-sys-design',
      'Design a Payment Gateway (Stripe).',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Requires extreme reliability and consistency. Exactly-once processing is mandatory. Use Idempotency Keys to prevent double charging if a network request times out and is retried. Use a Message Queue and asynchronous processing to communicate with banks.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-031',
      'projects-sys-design',
      'Payment Gateway - What is an Idempotency Key?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A unique identifier generated by the client and sent with the payment request. The server saves this key in the DB. If the client retries the request (due to a timeout), the server sees the key, knows it already processed this transaction, and returns the cached success response instead of charging the card again.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-032',
      'projects-sys-design',
      'Design Google Docs (Collaborative Editing).',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Requires resolving conflicts when two users type at the same time. Operational Transformation (OT) or Conflict-free Replicated Data Types (CRDTs) are used. WebSockets for real-time synchronization between clients.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-033',
      'projects-sys-design',
      'What is Operational Transformation (OT)?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The algorithm behind Google Docs. If User A inserts "X" at index 1, and User B simultaneously deletes character at index 1, the server receives both operations, transforms them based on causality and sequence, and broadcasts the transformed operations to ensure both clients end up with the exact same document state.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-034',
      'projects-sys-design',
      'Design a Distributed ID Generator (Snowflake alternative).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use a central Ticket Server (like Flickr). E.g., a MySQL table with an `auto_increment` ID. To scale and avoid a single point of failure, use two databases: DB1 generates odd IDs (start 1, increment 2), DB2 generates even IDs (start 2, increment 2).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-035',
      'projects-sys-design',
      'Design a Job Scheduler (like cron).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'User submits job -> DB. A continuous loop queries the DB for jobs due "now". Issues: querying DB every second is inefficient. Solution: Push jobs to a Priority Queue (Min Heap based on execution time) or use Redis Sorted Sets. Pull the top task. Use distributed locks to prevent multiple workers executing the same job.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-036',
      'projects-sys-design',
      'Design a Leederboard System (Gaming).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Millions of users, requires real-time ranking. A relational DB with `ORDER BY score` will be too slow. Use Redis Sorted Sets (ZSET). `ZADD leaderboard score user_id`. To get rank: `ZREVRANK leaderboard user_id`. Time complexity is O(log N).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-037',
      'projects-sys-design',
      'Design a Distributed Cache.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Uses Consistent Hashing to partition data across cache servers. Clients run the hashing algorithm to know exactly which server to talk to. LRU eviction policy. To handle high availability, maintain replicas. Handle hot-keys by adding a local cache inside the application server.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-038',
      'projects-sys-design',
      'How do you handle a "Hot Key" problem in a distributed cache?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A "hot key" is a specific piece of data (e.g., a viral tweet) accessed so frequently it overwhelms the single cache node that holds it. Solution: 1. Application-level local caching. 2. Randomize the key (e.g., `tweet_123_A`, `tweet_123_B`) to spread it across multiple cache nodes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-039',
      'projects-sys-design',
      'Design an Ad Click Event Aggregation System.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'Needs to process millions of clicks per second and aggregate them by ad_id and minute. Architecture: Click stream -> Kafka (buffer) -> Stream Processing engine (Apache Flink or Spark Streaming) to aggregate in memory with tumbling windows -> Write aggregated data to an OLAP database (ClickHouse/Druid).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-040',
      'projects-sys-design',
      'Design a Metrics Monitoring System (like Datadog).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Agents on servers push metrics -> Kafka -> Stream processor -> Time Series Database (TSDB like InfluxDB or Prometheus). TSDBs are optimized for storing time-stamped data and querying ranges efficiently. A separate alert engine queries the TSDB.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-041',
      'projects-sys-design',
      'What is a Time Series Database (TSDB)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A database optimized for time-stamped or time-series data. Features include high write throughput, efficient storage (delta encoding), and specialized functions for aggregating data over time windows (e.g., calculating the average CPU load per minute over the last year).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-042',
      'projects-sys-design',
      'Design a Video Calling App (Zoom/Skype).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'WebRTC for peer-to-peer audio/video streaming (low latency, UDP based). Signaling server (WebSocket) to establish the initial P2P connection (exchange IPs/SDP). For group calls (>4 people), P2P fails (CPU/bandwidth limit); use a Selective Forwarding Unit (SFU) server to receive and broadcast streams.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-043',
      'projects-sys-design',
      'What is WebRTC?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Web Real-Time Communication. An open-source project that enables real-time voice, text, and video communications capabilities between web browsers and devices. It primarily operates peer-to-peer without requiring intermediate servers.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-044',
      'projects-sys-design',
      'Design a Content Moderation System (Text/Images).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'User uploads content -> App server puts it in a Message Queue -> Workers pull content and send to ML APIs (Vision AI, NLP) -> If safe, publish to DB. If unsafe, delete/flag. Requires an asynchronous pipeline to not block the user''s upload request.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-045',
      'projects-sys-design',
      'Design an E-commerce Inventory Management System.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'High contention on popular items. "Over-selling" is the biggest risk. Use an RDBMS for ACID properties. When checking out, use optimistic locking (`UPDATE inventory SET stock = stock - 1 WHERE id = 1 AND stock > 0`) or pessimistic locking. Implement a reservation system (hold stock for 10 mins).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-046',
      'projects-sys-design',
      'What is Optimistic vs Pessimistic Locking?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Pessimistic: Assumes conflict will happen. Locks the row immediately when read, preventing others from reading/writing until transaction finishes. (Slow). Optimistic: Assumes no conflict. Uses a `version` column. Upon writing, checks if the version has changed since it was read. If yes, it aborts and retries. (Fast, good for read-heavy).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-047',
      'projects-sys-design',
      'Design a TinyURL system to scale to 100 Million requests per second.',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'At this scale, a standard DB lookup for every redirect is too slow. The bottleneck is the DB. You must use massive, multi-tiered caching (Redis). The API Gateways themselves might need to hold a local cache (Guava/Memcached) of the most viral links to prevent network hops to Redis.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-048',
      'projects-sys-design',
      'How do you perform Database Migrations on a 10TB database with zero downtime?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'The "Expand and Contract" pattern. 1. Add the new column/table. 2. Write to BOTH old and new simultaneously. 3. Run a background script to backfill old data into the new schema. 4. Change the app to read from the new schema. 5. Stop writing to the old. 6. Delete the old schema.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-049',
      'projects-sys-design',
      'How do you handle pagination on a database with 1 Billion rows?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '`OFFSET` is O(N) and gets extremely slow on deep pages (e.g., `OFFSET 1000000`). Use Keyset Pagination (Cursor-based pagination) instead. E.g., `WHERE id > last_seen_id ORDER BY id LIMIT 20`. This uses the index and is O(1).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'sdi-050',
      'projects-sys-design',
      'What is the purpose of the "Back of the envelope" estimation?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'To determine if a proposed design is viable. E.g., if you estimate your system will generate 5TB of data a day, storing it in a single MySQL instance is immediately proven wrong. It helps guide decisions between in-memory caching vs SSDs, or single node vs distributed.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-001',
      'projects-deep-dive',
      'Describe the overall architecture of your most recent/complex project.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Start high-level (Frontend -> Gateway -> Microservices -> DBs). Mention the core technologies used at each layer. Then briefly explain the data flow for the most important feature.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-002',
      'projects-deep-dive',
      'Why did you choose [Technology X] over [Technology Y] for this project?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Never say "because I wanted to learn it" or "because it''s popular". Discuss specific trade-offs: performance, community support, team familiarity, ecosystem, scaling characteristics, or specific technical features (e.g., "We chose Postgres over MongoDB because we needed strict ACID compliance for financial data").',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-003',
      'projects-deep-dive',
      'What was the most challenging technical problem you solved on this project?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Use the STAR method (Situation, Task, Action, Result). Focus on the technical depth. Explain the initial approach, why it failed or wasn''t good enough, the research you did, the final solution, and the measurable impact (e.g., reduced latency by 50%).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-004',
      'projects-deep-dive',
      'Describe a time you had to make a difficult technical trade-off.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Acknowledge that there are no perfect solutions. E.g., trading consistency for availability (CAP theorem), trading memory for CPU (caching), or trading development speed for long-term maintainability (tech debt). Explain WHY you made the choice you did given the business context.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-005',
      'projects-deep-dive',
      'How did you ensure the quality and reliability of your code?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Discuss your testing strategy: Unit tests (Jest/JUnit), Integration tests, E2E tests (Cypress/Playwright). Mention CI/CD pipelines, static analysis (SonarQube, ESLint), code reviews, and monitoring/alerting in production.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-006',
      'projects-deep-dive',
      'Describe a nasty bug you encountered. How did you debug and fix it?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Focus on your debugging methodology. Did you write a failing test first? Did you use a debugger or just `console.log`? Did you bisect the git history? Mention tools like Chrome DevTools, APM tools (Datadog), or reading library source code. Explain the root cause clearly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-007',
      'projects-deep-dive',
      'How did your application handle scale? What were the bottlenecks?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Be honest if it didn''t operate at massive scale, but explain how it *would* break. Identify the likely first bottleneck (usually the database). Discuss what you implemented (or would implement): caching, indexes, horizontal scaling, or asynchronous processing.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-008',
      'projects-deep-dive',
      'How did you handle security in your application?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Discuss authentication (JWT, OAuth), authorization (RBAC), input validation (preventing SQLi/XSS), HTTPS/TLS, securely storing secrets (Environment variables, AWS Secrets Manager, NEVER committing secrets to Git), and CORS.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-009',
      'projects-deep-dive',
      'If you had an extra month to work on this project, what would you improve or refactor?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Shows self-awareness and continuous improvement. Suggest adding a missing feature, improving test coverage, migrating to a more robust architecture (e.g., breaking a monolith), or optimizing a slow database query.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-010',
      'projects-deep-dive',
      'Explain the database schema of your project.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Describe the core tables/collections. Explain the relationships (1-to-N, N-to-N). Discuss any denormalization you did for performance, and mention the most important indexes you created and why.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-011',
      'projects-deep-dive',
      'How did you handle state management in the frontend?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Explain your choice (e.g., Redux, Context API, Zustand, React Query). Justify it: "We used React Query for server state because it handles caching and deduplication automatically, and Zustand for local UI state because it''s lightweight and avoids boilerplate."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-012',
      'projects-deep-dive',
      'How did you deploy your application?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Describe the pipeline. E.g., "Code merged to main -> GitHub Actions builds Docker image -> pushes to ECR -> updates ECS service." Show understanding of the environments (Dev, Staging, Prod).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-013',
      'projects-deep-dive',
      'What was your role and responsibility within the team?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Be specific about what YOU built versus what the TEAM built. Use "I" when describing your technical contributions. "I designed the database schema, while my colleague built the UI."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-014',
      'projects-deep-dive',
      'How did you handle performance optimization on the frontend?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Discuss code splitting (lazy loading), image optimization, memoization (useMemo/useCallback), virtualization for long lists, reducing bundle size, or implementing a CDN.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-015',
      'projects-deep-dive',
      'How did you handle performance optimization on the backend?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Discuss database indexing, query optimization (avoiding N+1 problems), implementing caching (Redis), moving heavy tasks to background workers (Message Queues), or optimizing algorithms.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-016',
      'projects-deep-dive',
      'Did you use any third-party APIs? How did you handle failures?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Mention the APIs (Stripe, Twilio, Google Maps). Discuss how you handled rate limits, timeouts, and network failures using retry logic, exponential backoff, or the Circuit Breaker pattern.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-017',
      'projects-deep-dive',
      'How did you manage technical debt?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Explain your approach. Do you dedicate a percentage of each sprint to refactoring? Do you leave `TODO` comments and create Jira tickets? How do you convince product managers that tech debt is important?',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-018',
      'projects-deep-dive',
      'Describe a time you disagreed with a technical decision made by the team or a senior engineer.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Focus on communication and evidence. Did you do research to back up your point? Did you create a proof-of-concept? Did you ultimately "disagree and commit" if the decision didn''t go your way? Shows maturity and teamwork.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-019',
      'projects-deep-dive',
      'What metrics did you use to measure the success of the project?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Technical metrics: Uptime, API latency (p99), error rates, CPU/Memory usage. Business metrics: User acquisition, conversion rates, time-on-page, revenue impact.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-020',
      'projects-deep-dive',
      'How did you handle database migrations?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Mention the tool used (Flyway, Liquibase, Prisma Migrations). Explain the process of applying them safely in a CI/CD pipeline, and the importance of writing backward-compatible migrations (no downtime).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-021',
      'projects-deep-dive',
      'Explain a specific design pattern you used in the project and why.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'E.g., "I used the Factory pattern to instantiate different types of payment processors based on user input, which kept the core checkout logic clean and adhered to the Open/Closed Principle."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-022',
      'projects-deep-dive',
      'How did you handle logging and monitoring?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Mention tools like ELK stack, Datadog, or Sentry. Discuss what you logged (errors, critical business events, performance metrics) and how you ensured PII (Personal Identifiable Information) was not logged.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-023',
      'projects-deep-dive',
      'What would happen to your system if traffic suddenly spiked 10x?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Analyze the system point-by-point. "The load balancer would distribute traffic. The app servers in the Auto Scaling Group would scale out. However, the database is a single instance, so CPU would spike and queries would queue up. We would need to add read replicas or caching to survive."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-024',
      'projects-deep-dive',
      'How did you design your API?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Discuss RESTful principles (nouns, HTTP methods, status codes), GraphQL, or gRPC. Explain how you handled versioning (e.g., `/api/v1/users`), pagination, and filtering.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-025',
      'projects-deep-dive',
      'Describe a feature that took longer than expected. Why?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Shows ability to estimate and reflect. "I underestimated the complexity of integrating a legacy SOAP API. The documentation was poor, and I had to spend days reverse-engineering the XML responses."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-026',
      'projects-deep-dive',
      'How do you stay updated with new technologies, and how did you apply a new tech to this project?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Mention blogs, newsletters, GitHub trends. Give a specific example: "I read about React Server Components and decided to implement them for our static marketing pages to reduce the JS bundle size."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-027',
      'projects-deep-dive',
      'Explain how you handled asynchronous tasks or background jobs.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Discuss using message brokers (RabbitMQ, Redis + Bull, Celery). Explain WHY the task needed to be backgrounded (e.g., sending an email or generating a PDF takes 5 seconds, which would block the HTTP response).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-028',
      'projects-deep-dive',
      'What is the biggest mistake you made on this project?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Be authentic. Own the mistake. The most important part of the answer is what you learned and the processes you put in place to ensure it never happened again.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-029',
      'projects-deep-dive',
      'How did you handle environment variables and configuration?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Discuss the use of `.env` files for local dev, and secure parameter stores (AWS Systems Manager, HashiCorp Vault) for production. Emphasize that secrets are never hardcoded or committed to version control.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-030',
      'projects-deep-dive',
      'If you built a Microservices architecture, how did services communicate?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Discuss synchronous (HTTP/REST, gRPC) vs asynchronous (Message Queues/Event Bus) communication. Explain why you chose one over the other for specific interactions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-031',
      'projects-deep-dive',
      'How did you manage data consistency across microservices?',
      'expert',
      ARRAY[]::TEXT[],
      '',
      'If applicable, discuss the Saga pattern, Event Sourcing, or two-phase commits. If you just used HTTP calls, acknowledge the risk of partial failures and how you handled retries or compensations.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'pdd-032',
      'projects-deep-dive',
      'Describe a time you optimized a slow database query.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Explain using `EXPLAIN ANALYZE` to read the query plan. Did it do a full table scan? Did you add an index (B-tree, composite)? Did you rewrite a complex JOIN or subquery? What was the before/after execution time?',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
