      'What is the STAR method?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A structured manner of responding to a behavioral interview question. Situation (set the scene), Task (describe your responsibility), Action (explain exactly what YOU did), Result (share the positive outcome, ideally with metrics).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
