      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-031',
      'hr-behavioral',
      'Describe a time you had to work with an unfamiliar codebase.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: Inherited a legacy PHP app with no tests. A: Instead of rewriting it, I wrote characterization tests (Snapshot testing) for the existing behavior, mapped out the core flow, and only refactored the specific modules I needed to touch. R: Safely added features without breaking legacy logic."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-032',
      'hr-behavioral',
      'Tell me about a time you had to make a presentation to an executive team.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Focus on knowing your audience. "A: I stripped out all the deep technical jargon. I focused the presentation on business value, costs, and timelines, using high-level architecture diagrams. R: Secured the budget for the new infrastructure."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-033',
      'hr-behavioral',
      'Describe a time you discovered a security vulnerability.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"S: While reviewing code, I found an endpoint vulnerable to IDOR. A: I didn''t just fix it; I audited the rest of the app for similar flaws, fixed them all, and added a linting rule to catch it in the future. R: Secured the app before any data was compromised."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-034',
      'hr-behavioral',
      'Tell me about a time you had to decline a request from a stakeholder.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Focus on "No, but...". "S: Marketing wanted a massive new feature 2 days before launch. A: I explained the risk to system stability so close to launch. I said ''No, but we can fast-track it for the first patch next week''. R: They understood the risk and agreed to the delay."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-035',
      'hr-behavioral',
      'Describe a time your idea was rejected.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: I proposed migrating to GraphQL, but the lead architect rejected it due to the learning curve for the team. A: I accepted the decision gracefully, recognized the business logic behind it, and focused my energy on optimizing our existing REST APIs. R: Maintained a great relationship with the lead."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-036',
      'hr-behavioral',
      'Tell me about a time you had to deliver bad news to a client or manager.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"S: A key database migration failed, delaying launch. A: I called the client immediately, explained exactly what went wrong without using confusing jargon, outlined my immediate plan to fix it, and provided a new ETA. R: The client appreciated the prompt honesty."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-037',
      'hr-behavioral',
      'Describe a time you found a creative solution to a problem.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: An external API we relied on was rate-limiting us severely. A: Instead of paying for a massive enterprise tier, I implemented a Redis-based queuing system that batched our requests and executed them right at the rate limit threshold. R: Saved the company $10k/month."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-038',
      'hr-behavioral',
      'Tell me about a time you had to enforce a standard or policy.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: Developers were bypassing CI/CD and pushing directly to main. A: I didn''t just yell at them; I realized the CI pipeline was too slow (taking 30 mins). I optimized the pipeline down to 5 mins, THEN protected the main branch via GitHub settings. R: Compliance reached 100% naturally."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-039',
      'hr-behavioral',
      'Describe a time you were overwhelmed with your workload.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"A: I compiled a list of everything on my plate, estimated the hours, and took it to my manager. I asked them to help me ruthlessly prioritize. R: We dropped two low-value tasks, allowing me to deliver the high-value tasks perfectly on time."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-040',
      'hr-behavioral',
      'Tell me about a time you used data to make a decision.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: Team was debating whether to support older versions of Safari. A: I pulled the Google Analytics data, which showed only 0.2% of our users used that browser. R: We confidently dropped support, saving weeks of QA testing time."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-041',
      'hr-behavioral',
      'Describe a time you contributed to open source or the broader tech community.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Mention PRs to libraries you use, writing technical blog posts, speaking at meetups, or answering questions on StackOverflow.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-042',
      'hr-behavioral',
      'Tell me about a time you had to troubleshoot a problem with minimal documentation.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"A: The library had no docs. I cloned the source code, read the unit tests to understand the intended behavior, and used a debugger to step through the execution flow. R: Fixed the issue and submitted a PR to the maintainers to update their Readme."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-043',
      'hr-behavioral',
      'Describe a time you fostered an inclusive environment.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: I noticed our remote team members rarely spoke up during hybrid meetings. A: I implemented a ''remote-first'' meeting policy where everyone dialed in from their laptops, even if in the office, leveling the playing field. R: Participation from remote workers skyrocketed."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-044',
      'hr-behavioral',
      'Tell me about a time you had to quickly pivot your technical approach.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: A week before launch, a new privacy regulation was announced that invalidated our data storage architecture. A: I pivoted the team to use a hashing technique that anonymized the data at rest. R: We met the compliance deadline."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-045',
      'hr-behavioral',
      'Describe a time you mentored someone who was underperforming.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"S: A junior dev was missing deadlines. A: I had a private, empathetic conversation and discovered they were overwhelmed by Git. I spent an hour teaching them Git workflows and set up a daily 15-min check-in. R: Their velocity improved drastically within a month."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-046',
      'hr-behavioral',
      'Tell me about a time you took ownership of a project that wasn''t yours.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: A critical internal tool broke while its creator was on vacation. A: I dove into the codebase, debugged the issue, pushed a hotfix, and documented the process so others could do it in the future. R: Unblocked the sales team for the week."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-047',
      'hr-behavioral',
      'Describe a time you identified a bottleneck in your team''s workflow.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: QA was taking too long because they had to manually set up test environments. A: I wrote a Docker Compose file that spun up the app and a seeded database with one command. R: QA testing time was cut in half."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-048',
      'hr-behavioral',
      'Tell me about a time you balanced technical excellence with business value.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"S: I wanted to rewrite the entire billing module using a new framework (technical excellence). However, the business needed a new payment gateway integrated immediately (business value). A: I integrated the gateway into the legacy code first to secure revenue, then scheduled the rewrite for the next quarter. R: Revenue increased immediately."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-049',
      'hr-behavioral',
      'Describe a time you disagreed with a product requirement.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"S: Product wanted an auto-playing video with sound on the landing page. A: I pushed back, citing UX best practices and mobile data concerns. I suggested a muted video that plays on hover. R: Product agreed, and bounce rates stayed low."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrb-050',
      'hr-behavioral',
      'Tell me about a time you automated a repetitive task.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"S: I noticed I spent 20 mins every morning pulling reports from 3 different systems. A: I wrote a Python script using their APIs to fetch, format, and Slack me the report at 8 AM automatically. R: Saved myself over 80 hours a year."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-001',
      'hr-leadership',
      'How do you define Leadership?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Leadership is not a title; it is action. It is about taking ownership, empowering others, clearing roadblocks, setting a vision, and taking responsibility when things go wrong while sharing credit when things go right.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-002',
      'hr-leadership',
      'Describe your leadership style.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Examples: Servant Leadership (focus on unblocking the team), Transformational (inspiring innovation), or Democratic (building consensus). "I lean towards Servant Leadership. My primary job is to ensure my team has the tools, knowledge, and psychological safety to do their best work."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-003',
      'hr-leadership',
      'How do you handle an underperforming team member?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Start with empathy, not reprimand. 1. Have a private 1-on-1 to understand the root cause (burnout, lack of skills, personal issues). 2. Set clear, measurable goals together (PIP if necessary, but ideally informal first). 3. Provide the necessary resources or mentorship. 4. Follow up regularly.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-004',
      'hr-leadership',
      'How do you build trust within a new team?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Through consistency, transparency, and vulnerability. Listen more than you speak initially. Deliver on your promises. Admit when you don''t know something. Celebrate team wins.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-005',
      'hr-leadership',
      'Tell me about a time you had to manage a remote or distributed team.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Focus on over-communication and asynchronous workflows. Mention using tools effectively (Slack, Jira, Loom), respecting time zones, and enforcing a culture of writing things down (RFCs, design docs) rather than relying on synchronous meetings.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-006',
      'hr-leadership',
      'How do you foster a culture of continuous learning?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Lead by example. Share articles, host "lunch and learns", encourage pair programming, and advocate for the company to provide an education budget. Make it safe to fail, as failure is a prerequisite for learning.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-007',
      'hr-leadership',
      'Describe your approach to code reviews.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Code reviews should be empathetic, objective, and timely. Automate style checks (linters) so humans can focus on architecture and logic. Review the code, not the person. Suggest improvements rather than just pointing out flaws.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-008',
      'hr-leadership',
      'How do you balance technical debt with delivering new features?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Communicate the cost of tech debt in BUSINESS terms (e.g., "This old API takes 3 days to modify, costing us $X in developer time"). Advocate for dedicating a percentage (e.g., 20%) of every sprint to refactoring, or adopt the "Boy Scout Rule" (leave the code cleaner than you found it).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-009',
      'hr-leadership',
      'Tell me about a time you had to align cross-functional teams (e.g., Engineering, Product, Design).',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Focus on finding common ground. "Product wanted speed, Design wanted perfection, Engineering wanted stability. I organized a kickoff meeting, aligned everyone on the core MVP user journey, and negotiated scope cuts that satisfied all three pillars."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-010',
      'hr-leadership',
      'How do you ensure psychological safety in your team?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Psychological safety is the belief that you won''t be punished for making a mistake. Foster it by running blameless post-mortems, encouraging junior devs to speak first in meetings, and openly sharing your own mistakes.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-011',
      'hr-leadership',
      'What is a Blameless Post-Mortem?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A meeting held after a severe incident (outage) where the focus is entirely on identifying system vulnerabilities and process failures, NOT on blaming the individual who triggered the incident. The assumption is everyone had good intentions.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-012',
      'hr-leadership',
      'How do you handle "brilliant jerks" on a team?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Toxicity destroys team velocity more than brilliance adds to it. Address the behavior immediately in private. Focus on the impact their behavior has on the team. If coaching fails, they must be removed, regardless of their technical output.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-013',
      'hr-leadership',
      'Tell me about a time you had to scale a team.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Discuss interviewing strategies, standardizing the onboarding process, writing extensive documentation, and delegating responsibilities to prevent yourself from becoming a bottleneck.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-014',
      'hr-leadership',
      'How do you deliver constructive criticism?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Use the SBI (Situation-Behavior-Impact) model. Be specific, private, and timely. "During yesterday''s meeting (Situation), you interrupted the junior dev twice (Behavior). This caused them to stop contributing to the brainstorm (Impact)."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-015',
      'hr-leadership',
      'How do you handle receiving critical feedback?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Do not get defensive. Say "thank you", ask clarifying questions if needed, reflect on the feedback, and outline the actionable steps you will take to improve.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-016',
      'hr-leadership',
      'What are the Amazon Leadership Principles? (If interviewing at AWS)',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Customer Obsession, Ownership, Invent and Simplify, Are Right A Lot, Learn and Be Curious, Hire and Develop the Best, Insist on Highest Standards, Think Big, Bias for Action, Frugality, Earn Trust, Dive Deep, Have Backbone (Disagree and Commit), Deliver Results.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-017',
      'hr-leadership',
      'Explain "Bias for Action".',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Speed matters in business. Many decisions and actions are reversible and do not need extensive study. It means preferring to take action and iterate, rather than suffering from analysis paralysis.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-018',
      'hr-leadership',
      'Explain "Disagree and Commit".',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'A leadership principle. You are obligated to respectfully challenge decisions when you disagree, even if it''s uncomfortable. However, once a decision is finalized by the team/leader, you must commit to it wholly and support its success as if it were your own idea.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-019',
      'hr-leadership',
      'Explain "Customer Obsession".',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Starting with the customer and working backwards. Competitors are important to watch, but true innovation comes from focusing obsessively on solving customer pain points, even before the customer realizes they have them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-020',
      'hr-leadership',
      'How do you mentor a junior developer?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Don''t just give them the answers. Ask guiding questions (Socratic method). Pair program with them. Help them break down large tasks. Celebrate their small wins to build confidence. Encourage them to present their work.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-021',
      'hr-leadership',
      'How do you manage a high performer who is bored?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Give them autonomy and harder problems. Ask them to lead a spike on a new technology, mentor a junior developer, or present at a company all-hands. Find out what their long-term career goals are and align their tasks with them.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-022',
      'hr-leadership',
      'Describe a time you failed as a leader.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Acknowledge a genuine mistake. "I micromanaged a project because the deadline was tight. I ended up burning myself out and demoralizing the team. I learned that I must trust the team and focus on clearing roadblocks, not writing their code for them."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-023',
      'hr-leadership',
      'How do you resolve architectural disputes between senior engineers?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Move the conversation from opinions to data. Ask both to write a short RFC (Request for Comments) outlining the pros/cons of their approach. Create a POC if necessary. Evaluate against business goals (e.g., time to market vs long-term scalability). If a consensus isn''t reached, make the call and ask for "Disagree and Commit".',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-024',
      'hr-leadership',
      'How do you ensure diversity and inclusion in your team?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Ensure diverse interview panels. Actively challenge unconscious bias during hiring. Ensure everyone''s voice is heard in meetings (round-robin speaking). Use inclusive language in documentation and code (e.g., replacing master/slave with primary/replica).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-025',
      'hr-leadership',
      'What is your strategy for delegating tasks?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Delegate tasks, not just execution. Give the person the full context and the desired outcome, but let them figure out the "how". Match tasks to people''s growth areas, not just their current strengths.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-026',
      'hr-leadership',
      'How do you keep a team motivated during a "death march" or crunch time?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Acknowledge the pain; don''t sugarcoat it. Ensure the goal is crystal clear. Shield the team from non-essential meetings and external distractions. Provide food/coffee. Most importantly, ensure comp time or significant rest is guaranteed immediately after the crunch.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-027',
      'hr-leadership',
      'How do you handle scope creep?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Protect the team. When a stakeholder asks for a new feature mid-sprint, respond with trade-offs: "We can add X, but that means Y will be delayed to the next sprint. Is X more important than Y right now?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-028',
      'hr-leadership',
      'What is the difference between a Manager and a Leader?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A manager organizes resources, tracks timelines, and ensures processes are followed. A leader sets the vision, inspires the team, challenges the status quo, and empowers individuals to achieve the goals.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-029',
      'hr-leadership',
      'How do you evaluate the success of your team?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Beyond standard metrics (velocity, bug rates, uptime), I evaluate success by team retention, eNPS (employee net promoter score), and how often team members are promoted or take on new responsibilities.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-030',
      'hr-leadership',
      'Tell me about a time you had to fire someone.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'If applicable, emphasize that it was a last resort. Describe the extensive PIP (Performance Improvement Plan) process leading up to it, the clear feedback given, and the respectful, compliant way the termination was handled.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-031',
      'hr-leadership',
      'How do you onboard a new engineer?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Provide a structured 30/60/90 day plan. Assign them a "buddy" (not their manager). Ensure their laptop is provisioned and they can push a tiny, safe commit to production on Day 1 to build confidence.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-032',
      'hr-leadership',
      'How do you handle a situation where a key engineer threatens to quit?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Listen first. Understand their grievances (compensation, boredom, bad manager, burnout). Address what you can immediately (e.g., moving them to a new project). However, never accept being held hostage; start planning for knowledge transfer immediately.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-033',
      'hr-leadership',
      'What is your approach to 1-on-1 meetings?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '1-on-1s are for the employee, not status updates. Focus on their career growth, roadblocks, team dynamics, and personal well-being. Ask: "What is the hardest part of your job right now, and how can I help?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-034',
      'hr-leadership',
      'How do you advocate for your team to upper management?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Translate engineering wins into business value. Don''t say "We migrated to Kubernetes." Say, "The team''s infrastructure changes reduced AWS costs by $50k/year and improved uptime to 99.99%, directly protecting our revenue." Highlight individual contributors by name.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-035',
      'hr-leadership',
      'Describe a time you took a stance that was unpopular.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"S: The entire engineering org wanted to rewrite a legacy system in Go. A: I was the lone voice arguing that the rewrite would take 2 years and halt all feature development. I proposed an unpopular strangler-fig migration instead. R: It was accepted, saving the company from a disastrous rewrite."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-036',
      'hr-leadership',
      'How do you handle team members who are resistant to change?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Understand their fear (often fear of obsolescence or more workload). Involve them in the decision-making process early. Provide training for the new tools. Highlight "what''s in it for them" (e.g., this CI tool means you don''t have to work weekends).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-037',
      'hr-leadership',
      'What role does culture play in an engineering team?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Culture is everything. It dictates how people behave when no one is watching. A good culture (high trust, blamelessness, continuous learning) attracts top talent and creates resilient software. A bad culture (blame, silos) creates technical debt and high turnover.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-038',
      'hr-leadership',
      'How do you measure individual developer productivity?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Be very careful. Avoid measuring lines of code or number of commits (these are easily gamified and toxic). Measure outcomes: features delivered, bugs resolved, code review participation, and peer feedback.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-039',
      'hr-leadership',
      'Tell me about a time you had to step in and write code as a manager.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Ideally, a manager shouldn''t be in the critical path. "A critical Sev-1 incident occurred while the lead was out. I stepped in, wrote the hotfix, and pushed it. The next day, I stepped back out of the codebase and resumed my managerial duties."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-040',
      'hr-leadership',
      'How do you prevent burnout on your team?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Monitor hours, enforce PTO usage (lead by example by taking your own vacations completely unplugged), distribute "pager duty" fairly, and regularly check in on their mental load during 1-on-1s.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-041',
      'hr-leadership',
      'What is the "Peter Principle"?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The concept that people in a hierarchy tend to rise to their "level of incompetence." (E.g., promoting a brilliant individual contributor to an engineering manager, a job they are terrible at). Good companies offer dual-tracks (Staff Engineer track vs Management track).',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-042',
      'hr-leadership',
      'How do you transition an IC (Individual Contributor) to a Management role?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Ensure they ACTUALLY want to manage people, not just get a pay bump. Provide leadership training. Start them as a tech lead with a small team. Emphasize that their success is no longer measured by the code they write, but by the output of their team.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-043',
      'hr-leadership',
      'Describe a time you navigated corporate politics.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Keep it professional. "Two departments were fighting over ownership of a shared API. I set up a meeting with both VP''s, mapped out the boundaries using Domain-Driven Design, and agreed on a federated approach. Maintained neutrality and focused on the company''s goal."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-044',
      'hr-leadership',
      'How do you communicate technical risks to non-technical stakeholders?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Translate risk into business impact. Don''t say "We have a single point of failure in our Redis cluster." Say, "If this specific server goes down, the checkout page will crash, costing us roughly $10k per hour in lost sales. We need 2 weeks to fix this."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-045',
      'hr-leadership',
      'What is your approach to interviewing candidates?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Standardized rubrics to avoid bias. Focus on problem-solving and communication over trivia. Use pair-programming or take-home assignments instead of whiteboard hazing. Ensure the candidate has a positive experience regardless of the outcome.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-046',
      'hr-leadership',
      'How do you manage a team member who is technically brilliant but a poor communicator?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Pair them with strong communicators. Ask them to write Design Docs (RFCs) instead of presenting in meetings if they are uncomfortable. Provide specific, actionable feedback on their communication in PRs and Jira tickets.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-047',
      'hr-leadership',
      'What is the "Bus Factor"?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'A measurement of risk resulting from information and capabilities not being shared. It''s the minimum number of team members that have to suddenly disappear (e.g., hit by a bus) before the project stalls. Increase it through pair programming and documentation.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-048',
      'hr-leadership',
      'How do you handle a project that is vastly behind schedule?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'First, stop digging. Do not add more engineers (Brooks''s Law). Inform stakeholders immediately. Re-evaluate the critical path, brutally cut scope to the absolute MVP, and protect the team from external pressure so they can focus.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-049',
      'hr-leadership',
      'What do you look for in a company culture?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Align your answer with the company you are interviewing for. Common good answers: Autonomy, transparency, blamelessness, a focus on engineering excellence, and opportunities for mentorship.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrl-050',
      'hr-leadership',
      'Tell me about a time you led a project that failed. What did you learn?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Own the failure as the leader. "We built a feature for 6 months that no one used. I learned that we failed to validate the idea with users early on. I implemented a strict ''MVP first, user testing second'' policy for all future projects."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-001',
      'hr-common',
      'Tell me about yourself.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'The Elevator Pitch. Keep it to 2 minutes. Present -> Past -> Future. "Currently, I am a [Title] at [Company] building [Current Project]. Before that, I worked on [Past Highlight]. I am looking for a role where I can [Future Goal aligning with the company]."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-002',
      'hr-common',
      'Why do you want to work here?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Show you did your research. Don''t just say "it''s a great company". Mention a specific product they build, a recent blog post they wrote, their tech stack, or their engineering culture. Align it with your career goals.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-003',
      'hr-common',
      'Why are you leaving your current role?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Never badmouth your current employer. Focus on the pull (what you are moving TOWARDS), not the push (what you are running FROM). "I''ve learned a lot at my current role, but I''m looking for more challenges in [scaling/leadership/new tech] which this role offers."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-004',
      'hr-common',
      'What is your greatest strength?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Pick a strength highly relevant to the job description (e.g., debugging complex systems, cross-functional communication, or mastering a specific framework). Provide a brief, concrete example proving it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-005',
      'hr-common',
      'What is your greatest weakness?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Don''t use a fake weakness ("I work too hard"). State a real, professional weakness that is NOT critical to the core job function, and immediately explain the steps you are actively taking to improve it. (e.g., "I struggle with public speaking, so I joined Toastmasters").',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-006',
      'hr-common',
      'Where do you see yourself in 5 years?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Show ambition but realism. You don''t need to say "CEO". "I want to be a Staff Engineer driving architectural decisions," or "I want to transition into an Engineering Manager role to focus on team growth."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-007',
      'hr-common',
      'What are your salary expectations?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Try to deflect initially: "I''m more focused on finding the right fit, what is the budgeted range for this role?" If pressed, provide a RANGE based on market research (Levels.fyi), not a specific number.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-008',
      'hr-common',
      'Are you interviewing anywhere else?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Be honest but vague. "Yes, I am exploring a few other opportunities in the [Industry] space, but this role is currently my top choice because [Reason]." Creates a sense of urgency without being arrogant.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-009',
      'hr-common',
      'What is your preferred work environment?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Be honest. If you hate open-plan offices, say you prefer a quiet environment for deep work. If you are interviewing for a remote role, emphasize your ability to work autonomously and communicate asynchronously.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-010',
      'hr-common',
      'How do you handle stress and pressure?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Give a concrete method. "I step back, break the overwhelming problem into small, actionable Jira tickets, prioritize them, and communicate the realistic timeline to my manager. Outside of work, I make sure to exercise."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-011',
      'hr-common',
      'What are you most proud of in your career?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Pick an achievement with measurable impact. "I built a caching layer that reduced our AWS bill by $10,000 a month," or "I mentored an intern who just got hired as a full-time engineer."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-012',
      'hr-common',
      'What is your favorite technology and why?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Be passionate. "I love React because of its massive ecosystem and the declarative nature of the UI," or "I love Go because of its simplicity and incredible concurrency model via Goroutines."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-013',
      'hr-common',
      'What is a technology you dislike and why?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Be professional. Don''t just bash a language. "I find loosely typed languages like raw JavaScript frustrating for large codebases because refactoring is risky; that''s why I strongly advocate for TypeScript."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-014',
      'hr-common',
      'How do you stay organized?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Mention your tools. "I use a personal Trello board, aggressively block out ''deep work'' time on my calendar, and keep a daily written to-do list."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-015',
      'hr-common',
      'Describe your ideal manager.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"I work best under a manager who provides clear goals and context, but gives me the autonomy to figure out the technical implementation. I also value managers who give regular, direct feedback."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-016',
      'hr-common',
      'What is a book or blog that has influenced your career?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Have a few ready. "Clean Code by Uncle Bob," "Designing Data-Intensive Applications by Martin Kleppmann," or "The Pragmatic Programmer."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-017',
      'hr-common',
      'Tell me about a side project you worked on.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Pick something that shows initiative. It doesn''t have to be a massive success. Explain the tech stack, what you learned, and why you built it.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-018',
      'hr-common',
      'What would your current manager say about you?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"They would say I am highly reliable, always deliver on time, and am the go-to person on the team for debugging complex database issues."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-019',
      'hr-common',
      'What do you consider to be your biggest professional failure?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      'Choose a real failure, but one from the past that you have clearly learned from. Explain the context, the mistake you made, the fallout, and exactly what you changed about your process afterward.',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-020',
      'hr-common',
      'How do you handle shifting priorities?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"I don''t get frustrated. I pause my current work, ask my manager to clarify the new priority against the existing deadlines, document where I left off on the old task, and pivot immediately."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-021',
      'hr-common',
      'What are you looking for in your next role?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Align this with the job description. "I want to work on a product that impacts millions of users, and I want to be surrounded by senior engineers I can learn from."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-022',
      'hr-common',
      'How quickly can you learn a new codebase?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"Very quickly. My strategy is to first read the architecture docs, then set up the local environment, run the test suite, and ask for a small ''good first issue'' bug fix to get my hands dirty immediately."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-023',
      'hr-common',
      'What is your opinion on Pair Programming?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"I find it highly effective for onboarding new hires or tackling extremely complex, high-risk logic. I don''t think it''s necessary for everyday boilerplate tasks, but it is a great tool in the toolkit."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-024',
      'hr-common',
      'What is your opinion on Test-Driven Development (TDD)?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"I see the value in it, especially for writing core business logic or utility functions where the inputs and outputs are clear. For UI development, I often find it slows down rapid prototyping, but I always ensure high test coverage regardless."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-025',
      'hr-common',
      'Do you prefer working alone or as part of a team?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"I enjoy a mix. I need quiet, focused time to write complex code, but I rely heavily on the team for architectural brainstorming, code reviews, and unblocking each other."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-026',
      'hr-common',
      'How do you evaluate a new tool or framework?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"I don''t just chase hype. I build a small Proof of Concept. I evaluate its documentation, the size of its community (GitHub stars/issues), its performance benchmarks, and how easily it integrates into our existing stack."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-027',
      'hr-common',
      'What is the most interesting technical article you read recently?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Have an answer ready. E.g., "I recently read an engineering blog post from Discord about how they migrated from Go to Rust to solve latency spikes caused by Garbage Collection."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-028',
      'hr-common',
      'If you were hired, what would you accomplish in your first 30 days?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"I would focus on absorbing the architecture, meeting the key stakeholders, completing my onboarding, and pushing at least one small feature or bug fix to production to understand the deployment pipeline."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-029',
      'hr-common',
      'What motivates you?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"I am motivated by solving complex problems that have a tangible impact on the end-user, and by working alongside a team of smart people who challenge me to grow."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-030',
      'hr-common',
      'How do you handle working with legacy code?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"I don''t complain about it; legacy code pays the bills. I approach it carefully. I write tests around the existing behavior before making any changes (characterization testing), and I slowly refactor using the Strangler pattern."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-031',
      'hr-common',
      'Reverse Interview: Ask about the Day-to-Day.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"What does a typical day look like for an engineer on this team? What percentage of time is spent coding versus in meetings?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-032',
      'hr-common',
      'Reverse Interview: Ask about Team Structure.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"How large is the team, and what is the ratio of junior to senior engineers? How does the engineering team interact with product and design?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-033',
      'hr-common',
      'Reverse Interview: Ask about Tech Stack.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"I saw you use React. Are you using Next.js? How are you handling state management currently?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-034',
      'hr-common',
      'Reverse Interview: Ask about Tech Debt.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"How does the team balance delivering new features with paying down technical debt? Is time allocated for refactoring?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-035',
      'hr-common',
      'Reverse Interview: Ask about Onboarding.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"What does the onboarding process look like for the first 30 days? Is there a formal mentorship program?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-036',
      'hr-common',
      'Reverse Interview: Ask about Deployments.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"How often do you deploy to production? What does your CI/CD pipeline look like?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-037',
      'hr-common',
      'Reverse Interview: Ask about Challenges.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"What is the biggest technical challenge the engineering team is currently facing?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-038',
      'hr-common',
      'Reverse Interview: Ask the Interviewer directly.',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"What is your favorite part about working here? What is one thing you would change?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-039',
      'hr-common',
      'Reverse Interview: Ask about Performance.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"How is performance measured for engineers here? What does success look like in the first 6 months?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-040',
      'hr-common',
      'Reverse Interview: Ask about Company Future.',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"Where do you see the company/product going in the next 2-3 years, and how does this team contribute to that vision?"',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-041',
      'hr-common',
      'Tell me about a time you had to learn something you had absolutely no prior experience in.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'Focus on your learning methodology. "I had never touched AWS. I read the whitepapers, built a personal project using EC2 and S3, and got my Cloud Practitioner certification within a month."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-042',
      'hr-common',
      'Describe your process for estimating a task.',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"I break the task down into the smallest possible sub-tasks. I estimate each sub-task based on past experience, factor in time for testing and code review, and add a 20% buffer for unknown unknowns."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-043',
      'hr-common',
      'What is the difference between Good code and Great code?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"Good code works and is bug-free. Great code is written for the NEXT developer. It is highly readable, well-documented, loosely coupled, and easy to delete or replace."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-044',
      'hr-common',
      'How do you prioritize when everything is a Priority 1?',
      'hard',
      ARRAY[]::TEXT[],
      '',
      '"I ask for clarification on the business impact. If everything is P1, nothing is. I force a rank-ordering based on immediate revenue impact or critical system stability, and tackle the absolute top one first."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-045',
      'hr-common',
      'What is a common misconception people have about you?',
      'medium',
      ARRAY[]::TEXT[],
      '',
      '"Because I am quiet in large meetings, people sometimes think I''m not engaged. In reality, I''m actively listening and synthesizing the information. I usually follow up afterward with a detailed written proposal."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-046',
      'hr-common',
      'If you could design your ideal job, what would it look like?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Align it with the job you are applying for. "It would involve solving complex backend scaling issues, working with a collaborative team, and having a manager who trusts me to own the architecture."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-047',
      'hr-common',
      'What are the first 3 things you do when you sit down at your desk in the morning?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      '"1. Check monitoring alerts/Slack for any critical overnight issues. 2. Review my PRs and unblock teammates. 3. Write down my top 3 priorities for the day before opening my IDE."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-048',
      'hr-common',
      'Tell me about a time you automated yourself out of a job (or task).',
      'medium',
      ARRAY[]::TEXT[],
      '',
      'A great flex. "I spent 5 hours a week manually provisioning servers. I wrote Terraform scripts to do it in 5 minutes. My manager was thrilled and moved me onto higher-value feature development."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-049',
      'hr-common',
      'How do you handle a situation where you don''t know the answer during an interview?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'Don''t lie. "I don''t know the exact syntax for that off the top of my head, but in a real-world scenario, I would consult the documentation for [Technology] or search for how to implement [Concept]."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;
INSERT INTO public.questions (id, topic_id, title, difficulty, company_tags, content, solution, hints) VALUES (
      'hrc-050',
      'hr-common',
      'Do you have any final questions for us?',
      'easy',
      ARRAY[]::TEXT[],
      '',
      'ALWAYS SAY YES. Have at least 3 reverse-interview questions prepared (see HRC-031 to HRC-040). Never say "No, you covered everything."',
      ARRAY[]::TEXT[]
    ) ON CONFLICT (id) DO UPDATE SET title = EXCLUDED.title;

